    def _cmd_not_found(self, cmd: str, args: List[str]) -> List[dict]:
        """Smart command-not-found handler with fuzzy suggestions (C8)."""
        import difflib
        # ── Belt-and-suspenders NL intercept (catches anything that slipped dispatch) ──
        try:
            _nf_nl = self._nl_intercept(cmd, args)
            if _nf_nl is not None:
                return _nf_nl
        except Exception:
            pass
        # Build list of all known commands
        known = sorted(
            name[5:].replace("_", "-")
            for name in dir(self)
            if name.startswith("_cmd_") and not name.startswith("_cmd_not_")
        )
        # Fuzzy match: up to 3 close suggestions
        suggestions = difflib.get_close_matches(cmd, known, n=3, cutoff=0.5)
        out = [_line(f"bash: {cmd}: command not found", "error")]
        if suggestions:
            # Emit as clickable suggest chips
            chips = " · ".join(suggestions)
            out.append({"t": "suggest", "s": chips, "prefix": "  Did you mean:"})
        # ── core.suggest deterministic layer ────────────────────────────────
        try:
            import sys as _sys_nf
            _root_nf = str(__import__("pathlib").Path(__file__).parent.parent.parent)
            if _root_nf not in _sys_nf.path:
                _sys_nf.path.insert(0, _root_nf)
            from core.suggest import get_suggester as _gsnf
            _ctx_nf = {
                "level": self.gs.level,
                "xp": self.gs.xp,
                "commands_run": getattr(self.gs, "commands_run", 0),
                "story_beats": list(getattr(self.gs, "story_beats", [])),
                "flags": list(getattr(self.gs, "flags", [])),
            }
            _sugs_nf = _gsnf().get_suggestions(partial=cmd, context=_ctx_nf)
            _smart = [s["command"] for s in _sugs_nf if s["command"] not in suggestions][:3]
            if _smart:
                out.append({"t": "suggest", "s": " · ".join(_smart), "prefix": "  Smart suggestions:"})
        except Exception:
            pass
        # Contextual hints based on what was typed — also emit as suggest chips
        _CONTEXT_HINTS: List[tuple] = [
            ({"net", "ip", "inet", "network", "ping", "socket"}, "ping · ifconfig · netstat · nmap · nc"),
            ({"git", "commit", "push", "pull", "branch", "merge"}, "git status · git log · git commit · git push"),
            ({"hack", "exploit", "pwn", "root", "priv", "escalate"}, "exploit · hack · scan · ascend"),
            ({"log", "journal", "sys", "kern", "dmesg"}, "journalctl · dmesg · tail /var/log/nexus.log"),
            ({"agent", "npc", "serena", "ada", "gordon", "raven"}, "talk ada · agents · ask ada help"),
            ({"faction", "rep", "guild", "monk", "serial", "atonal"}, "faction · faction join resistance · faction rep"),
            ({"logic", "gate", "and", "or", "xor", "nand"}, "logic gate AND · logic labyrinth · logic load 1"),
            ({"set", "pitch", "forte", "prime", "tone", "serial"}, "set puzzles · set analyze C E G"),
            ({"sat", "satisfy", "cnf", "dpll", "boolean", "clause"}, "sat list · sat load 1"),
            ({"sort", "bubble", "quick", "merge", "heap", "algo"}, "sort bubble · sort quick · sort count"),
            ({"fsm", "automaton", "state", "dfa", "nfa", "machine"}, "fsm list · fsm load 1"),
            ({"dp", "dynamic", "fib", "knapsack", "lis", "lcs", "edit"}, "dp list · dp load 1"),
            ({"lore", "story", "chronicle", "archive", "history"}, "lore · chronicle · map · arcs"),
            ({"bank", "credit", "balance", "transfer", "wallet"}, "bank balance · bank transfer ada 100"),
            ({"research", "tech", "unlock", "upgrade"}, "research list · research unlock 1"),
            ({"wiki", "help", "man", "hint", "explain", "what"}, "help · man ls · wiki CHIMERA · hint"),
            ({"lattice", "polyglot", "cultivat", "language", "nodes", "meta"}, "lattice · polyglot · lore lattice · lattice cultivate"),
            ({"timer", "countdown", "containment", "loop", "72", "hour", "clock"}, "timer · anchor · remnant · lore containment"),
            ({"remnant", "shard", "echo", "persist", "upgrade", "carry"}, "remnant · remnant upgrades · remnant spend anchor_perm"),
            ({"anchor", "pause", "freeze", "temporal", "stop.*time", "time.*stop"}, "anchor activate · anchor release · anchor status"),
            ({"proficiency", "fluency", "mastery", "matrix", "skill.*lang", "lang.*skill"}, "proficiency matrix · proficiency abilities · proficiency python"),
            ({"scrape", "web.*data", "extract", "harvest", "crawl"}, "scrape · scrape darknode-7.internal · proficiency python"),
            ({"memdump", "memory.*dump", "heap", "process.*mem", "raw.*mem"}, "memdump · memdump 1 · proficiency c"),
            ({"exploit", "safe.*exploit", "vuln", "zero.*day", "cve"}, "safe_exploit · safe_exploit chimera-proxy.net · proficiency rust"),
            ({"inject", "xss", "dom", "browser.*hack", "js.*inject"}, "inject · inject output · proficiency javascript"),
            ({"chain", "pipeline", "pipe", "automat", "script.*chain"}, "chain ls /var/log | grep nexus | sort · proficiency bash"),
            ({"shenzhen", "microcontrol", "mcu", "chip", "assembly", "asm", "gen.*pin", "slp", "mc4000"}, "shenzhen list · shenzhen load 1 · shenzhen hint 1"),
            ({"life", "conway", "cellular", "automata", "blinker", "glider", "b3s23"}, "life list · life load 1 · life next · life run"),
            ({"graph.*theory", "shortest.*path", "dijkstra", "tsp", "coloring", "flow.*network", "spanning"}, "graph-theory list · graph-theory load 1 · graph-theory hint 1"),
            ({"graph", "node", "edge", "vertex", "daedalus"}, "graph-theory list · graph [agents|factions|trust] · lattice nodes"),
            ({"number.*theory", "prime", "factor", "rsa", "modular", "gcd", "euclid", "crt", "discrete.*log", "semiprime", "bezout"}, "number-theory list · number-theory load 1 · number-theory hint 1"),
            ({"basement", "dungeon", "crawl", "library.*below", "below.*library", "opt.*basement", "rogue"}, "basement start · basement map · basement go north · basement fight"),
            ({"sleep", "dream", "rem", "rest", "tired", "exhausted"}, "sleep"),
            ({"compose", "serial", "tone.*row", "twelve.*tone", "atonal", "music", "chimera.*gothic", "resistance.*march", "zero.*elegy"}, "compose list · compose gothic · compose march · compose all"),
            ({"evolve", "genetic", "algo.*crack", "payload.*crack", "tumbler", "mutation", "crossover", "population"}, "evolve list · evolve easy · evolve medium · evolve hard"),
        ]
        cmd_lower = cmd.lower()
        matched_hint = False
        for keywords, hint_cmds in _CONTEXT_HINTS:
            if any(k in cmd_lower for k in keywords):
                out.append({"t": "suggest", "s": hint_cmds, "prefix": "  Tip:"})
                matched_hint = True
                break
        if not matched_hint:
            out.append({"t": "suggest", "s": "help · man " + cmd + " · tutorial · wiki", "prefix": "  Try:"})

        # ── Cypher-style in-character commentary for common player mistakes ──
        _cypher_quips = []
        cmd_lower = cmd.lower()
        raw_input = cmd  # original casing matters here
        # Python statements accidentally typed in bash
        if raw_input.startswith("import ") or cmd_lower in ("import", "print", "def", "class", "return"):
            _cypher_quips = [
                _lore(f"  [CYPHER]: You're writing Python. In a bash shell. Bold choice."),
                _dim(f"  [CYPHER]: Try: `python3 -c \"import ...\"` — or just `vi script.py`"),
            ]
        # Windows-style paths
        elif raw_input.startswith("C:\\") or raw_input.startswith("C:/") or "\\" in raw_input:
            _cypher_quips = [
                _lore("  [CYPHER]: That's a Windows path. Wrong hemisphere."),
                _dim("  [CYPHER]: Paths here use forward slashes: /home/ghost, /var/log, /tmp"),
            ]
        # Bare URL typed as a command
        elif raw_input.startswith("http://") or raw_input.startswith("https://"):
            _cypher_quips = [
                _lore("  [CYPHER]: You typed a URL, not a command."),
                _dim("  [CYPHER]: Try: `curl " + raw_input + "` — or `wget " + raw_input + "`"),
            ]
        # Shell comment typed directly
        elif raw_input.startswith("#"):
            _cypher_quips = [
                _lore("  [CYPHER]: That's a comment. The shell doesn't run comments."),
                _dim("  [CYPHER]: Remove the # and try again."),
            ]
        # Sudo without a real command
        elif cmd_lower == "sudo":
            _cypher_quips = [
                _lore("  [CYPHER]: `sudo` what? You need to give it a command."),
                _dim("  [CYPHER]: Example: `sudo find /opt -name '*.key'`"),
            ]
        # Generic Cypher quip for completely unknown inputs
        else:
            import random as _rng2
            _generic_cypher = [
                f"  [CYPHER]: `{cmd}`? Where did you read that? Not in my manual.",
                f"  [CYPHER]: Never seen `{cmd}` before. Is it new? Is it a typo? Hard to say.",
                f"  [CYPHER]: That's not a real command. But hey, neither was I, once.",
                f"  [CYPHER]: `{cmd}` doesn't exist here. `help` does. Might be worth checking.",
                f"  [CYPHER]: Incorrect. But interesting. Keep experimenting.",
            ]
            _cypher_quips = [_lore(_rng2.choice(_generic_cypher))]

        out.extend(_cypher_quips)

        # Agent observer commentary (additional context-aware NPC reactions)
        commentary = self.agent_observer.observe_error("cmd_not_found", cmd, self.gs)
        out.extend(commentary)
        return out

    def _read_file(self, path: str):
        """Return (content: str, error: str | None) — helper for editor/binary commands."""
        r = self.fs.cat(path)
        if r.get("error"):
            return "", r["error"]
        return r.get("content", ""), None

    def _cmd_exec_script(self, cmd_or_args, args: List[str] = None) -> List[dict]:
        """exec_script <path> — simulate running a script; also handles ./script.sh dispatch."""
        if args is None:
            # Called via normal dispatch: exec_script path [args...]
            raw_args = cmd_or_args if isinstance(cmd_or_args, list) else [cmd_or_args]
            if not raw_args:
                return _err("Usage: exec_script <script_path> [args...]")
            script_path = raw_args[0]
            if not script_path.startswith("/"):
                script_path = f"{self.fs.get_cwd()}/{script_path}"
        else:
            # Called from ./ dispatcher: cmd_or_args is the raw command (e.g. "./run.sh")
            script_path = cmd_or_args[2:]  # strip leading ./
            if not script_path.startswith("/"):
                script_path = f"{self.fs.get_cwd()}/{script_path}"
        r = self.fs.cat(script_path)
        if r.get("error"):
            return _err(f"-bash: {script_path}: No such file or directory")
        content = r.get("content", "")
        preview = content[:120].replace("\n", "  ")
        return [
            _line(f"[*] Executing: {script_path}", "system"),
            _line(f"    {preview}", "dim") if preview else _line("    (empty script)", "dim"),
            _line("(Script simulation complete)", "dim"),
        ]

