    def _cmd_less(self, args):
        return self._cmd_more(args)

    def _cmd_more(self, args):
        file = next((a for a in args if not a.startswith("-")), None)
        content = self._pipe_stdin if file is None else None
        if file:
            r = self.fs.cat(file)
            if r.get("error"):
                return _err(r["error"])
            content = r["content"]
        if content is None:
            return _err("more: missing operand")
        lines = content.split("\n")
        out = [_line(l) for l in lines[:40]]
        if len(lines) > 40:
            out.append(_dim(f"... ({len(lines)-40} more lines)"))
        return out

    @staticmethod
    def _parse_n_flag(args: List[str], default: int = 10):
        """Parse -n N, -nN, or -N flag from args. Returns (n, cleaned_args)."""
        import re as _re
        n = default
        clean = []
        i = 0
        while i < len(args):
            a = args[i]
            # -n N (two-arg form)
            if a == "-n" and i + 1 < len(args):
                try:
                    n = int(args[i + 1])
                    i += 2
                    continue
                except ValueError:
                    pass
            # -nN combined (e.g. -n10)
            m = _re.match(r'^-n(\d+)$', a)
            if m:
                n = int(m.group(1))
                i += 1
                continue
            # -N combined (e.g. -10 or -20)
            m = _re.match(r'^-(\d+)$', a)
            if m:
                n = int(m.group(1))
                i += 1
                continue
            clean.append(a)
            i += 1
        return n, clean

    def _cmd_head(self, args):
        n, args = self._parse_n_flag(args, 10)
        file = next((a for a in args if not a.startswith("-")), None)
        content = self._pipe_stdin if file is None else None
        if file:
            r = self.fs.cat(file)
            if r.get("error"):
                return _err(r["error"])
            content = r["content"]
        if content is None:
            return _err("head: missing operand")
        return [_line(l) for l in content.split("\n")[:n]]

    def _cmd_tail(self, args):
        follow = "-f" in args
        args = [a for a in args if a != "-f"]
        n, args = self._parse_n_flag(args, 10)
        file = next((a for a in args if not a.startswith("-")), None)
        content = self._pipe_stdin if file is None else None
        if file:
            r = self.fs.cat(file)
            if r.get("error"):
                return _err(r["error"])
            content = r["content"]
        if content is None:
            return _err("tail: missing operand")
        lines = content.split("\n")
        out = [_line(l) for l in lines[-n:]]
        if follow:
            out += [
                _dim(f"  tail: following {file} — press Ctrl+C to stop"),
                _lore("  [WATCHER]: In this system, logs watch back."),
            ]
        return out

    def _cmd_mkdir(self, args):
        if not args:
            return _err("mkdir: missing operand")
        parents = "-p" in args
        targets = [a for a in args if not a.startswith("-")]
        out = []
        for t in targets:
            r = self.fs.mkdir(t, parents)
            if r.get("error"):
                out.extend(_err(r["error"]))
        return out

    def _cmd_touch(self, args):
        if not args:
            return _err("touch: missing operand")
        for t in args:
            existing = self.fs.cat(t)
            if existing.get("error"):
                self.fs.write_file(t, "")
        return []

    def _cmd_rm(self, args):
        recursive = "-r" in args or "-rf" in args or "-fr" in args
        targets = [a for a in args if not a.startswith("-")]
        out = []
        for t in targets:
            r = self.fs.rm(t, recursive)
            if r.get("error"):
                out.extend(_err(r["error"]))
        # Risky action: rm -rf (especially of log files)
        if recursive or any("/var/log" in t or "/tmp" in t for t in targets):
            risky = "rm_rf" if recursive else "no_log_cleanup"
            out.extend(self.agent_observer.observe_risky(risky, self.gs))
        return out

    def _cmd_mv(self, args):
        if len(args) < 2:
            return _err("mv: missing destination")
        r = self.fs.mv(args[0], args[1])
        return _err(r["error"]) if r.get("error") else []

    def _cmd_cp(self, args):
        if len(args) < 2:
            return _err("cp: missing destination")
        r = self.fs.cp(args[0], args[1])
        return _err(r["error"]) if r.get("error") else []

    def _cmd_stat(self, args):
        if not args:
            return _err("stat: missing operand")
        r = self.fs.stat(args[0])
        if r.get("error"):
            return _err(r["error"])
        n = r["node"]
        p = r["path"]
        return [
            _line(f"  File: {p}"),
            _line(f"  Type: {n.get('type', '?')}"),
            _line(f"  Permissions: {n.get('perms', '?')}"),
            _line(f"  Owner: {n.get('owner', '?')}"),
            _line(f"  Modified: {n.get('mtime', '?')[:19]}"),
            _line(f"  Size: {n.get('size', 0)} bytes"),
        ]

    def _cmd_file(self, args):
        if not args:
            return _err("file: missing operand")
        r = self.fs.stat(args[0])
        if r.get("error"):
            return _err(r["error"])
        n = r["node"]
        t = "directory" if n["type"] == "dir" else "ASCII text"
        return [_line(f"{args[0]}: {t}")]

    def _cmd_find(self, args):
        if not args:
            return _err("find: missing path")
        # Check GTFOBins exploit
        raw = " ".join(args)
        if "-exec" in raw and ("/bin/sh" in raw or "/bin/bash" in raw) and self._has_sudo(args):
            return self._gtfobins_exploit()
        start = args[0] if args and not args[0].startswith("-") else "."
        name_pat = None
        perm_pat = None
        type_f = None
        i = 0
        while i < len(args):
            if args[i] == "-name" and i + 1 < len(args):
                name_pat = args[i + 1]
                i += 2
            elif args[i] == "-perm" and i + 1 < len(args):
                perm_pat = args[i + 1]
                i += 2
            elif args[i] == "-type" and i + 1 < len(args):
                type_f = args[i + 1]
                i += 2
            else:
                i += 1
        results = self.fs.find(start, name_pat, perm_pat, type_f)
        if perm_pat and ("u=s" in perm_pat or "4000" in perm_pat):
            results = ["/usr/bin/sudo", "/usr/bin/newgrp", "/usr/bin/passwd"] + results
            self.gs.add_xp(15, "security")
        return [_line(r) for r in results] if results else _dim("(no results)")

    def _has_sudo(self, args: List[str]) -> bool:
        # ghost always has: (root) NOPASSWD: /usr/bin/find
        # _root_shell is the RESULT of the exploit, not a prerequisite
        return True

