    def _cmd_grep(self, args):
        flags = "".join(a[1:] for a in args if a.startswith("-") and len(a) > 1 and a[1] != "-")
        non_flag = [a for a in args if not a.startswith("-")]
        stdin = self._pipe_stdin

        if not non_flag and stdin is None:
            return _err("grep: no pattern specified")

        pattern = non_flag[0] if non_flag else ""
        files = non_flag[1:]

        results: List[dict] = []
        re_flags = re.IGNORECASE if "i" in flags else 0

        try:
            rx = re.compile(pattern, re_flags)
        except re.error:
            rx = re.compile(re.escape(pattern), re_flags)

        def _grep_content(content: str, label: str):
            for i, line in enumerate(content.split("\n")):
                if rx.search(line):
                    prefix = f"{label}:" if label else ""
                    num = f"{i+1}:" if "n" in flags else ""
                    results.append(_line(prefix + num + line, "success"))

        if stdin is not None:
            _grep_content(stdin, "")
        elif "-r" in args or "--recursive" in args:
            start = files[0] if files else self.fs.get_cwd()
            found_paths = self.fs.find(start)
            for fp in found_paths:
                r = self.fs.cat(fp)
                if not r.get("error"):
                    _grep_content(r["content"], fp)
        else:
            for f in files:
                r = self.fs.cat(f)
                if r.get("error"):
                    results.extend(_err(f"grep: {f}: No such file or directory"))
                else:
                    label = f if len(files) > 1 else ""
                    _grep_content(r["content"], label)

        if not results:
            return _dim("(no matches)")
        self.gs.add_xp(2, "terminal")
        return results

    def _cmd_awk(self, args):
        program = next((a for a in args if not a.startswith("-")), None)
        files = [a for a in args if not a.startswith("-")][1:]
        content = self._pipe_stdin

        if not content and files:
            r = self.fs.cat(files[0])
            content = r.get("content", "") if not r.get("error") else ""

        if content is None:
            return _err("awk: no input")

        out: List[dict] = []
        if program and "print" in program:
            for line in content.split("\n"):
                if not line:
                    continue
                if "-F" in args:
                    fi = args.index("-F")
                    sep = args[fi + 1] if fi + 1 < len(args) else ":"
                else:
                    sep = None
                fields = line.split(sep) if sep else line.split()
                result_line = program
                for i, f in enumerate(fields, 1):
                    result_line = result_line.replace(f"${i}", f)
                result_line = result_line.replace("$0", line).replace("$NF", fields[-1] if fields else "")
                m = re.search(r'\{print\s+(.*?)\}', result_line)
                if m:
                    out.append(_line(m.group(1).strip('"').strip("'")))
                else:
                    out.append(_line(line))
        else:
            out = [_line(l) for l in content.split("\n") if l]
        self.gs.add_xp(3, "terminal")
        return out

    def _cmd_sed(self, args):
        expr = next((a for a in args if not a.startswith("-")), None)
        files = [a for a in args if not a.startswith("-")][1:]
        content = self._pipe_stdin
        if not content and files:
            r = self.fs.cat(files[0])
            content = r.get("content", "") if not r.get("error") else ""
        if content is None:
            return _err("sed: no input")
        if expr and expr.startswith("s/"):
            parts = expr.split("/")
            if len(parts) >= 3:
                pattern, replacement = parts[1], parts[2]
                flags = parts[3] if len(parts) > 3 else ""
                count = 0 if "g" in flags else 1
                try:
                    content = re.sub(pattern, replacement, content, count=count)
                except re.error:
                    pass
        self.gs.add_xp(3, "terminal")
        return [_line(l) for l in content.split("\n")]

    def _cmd_cut(self, args):
        content = self._pipe_stdin
        files = [a for a in args if not a.startswith("-")]
        if not content and files:
            r = self.fs.cat(files[0])
            content = r.get("content", "") if not r.get("error") else ""
        if content is None:
            return _err("cut: no input")
        delim = ":"
        if "-d" in args:
            idx = args.index("-d")
            delim = args[idx + 1] if idx + 1 < len(args) else ":"
        field = 1
        if "-f" in args:
            idx = args.index("-f")
            try:
                field = int(args[idx + 1])
            except (IndexError, ValueError):
                pass
        out = []
        for line in content.split("\n"):
            parts = line.split(delim)
            if field - 1 < len(parts):
                out.append(_line(parts[field - 1]))
        return out

    def _cmd_sort_v1(self, args):
        content = self._pipe_stdin
        files = [a for a in args if not a.startswith("-")]
        if not content and files:
            r = self.fs.cat(files[0])
            content = r.get("content", "") if not r.get("error") else ""
        if content is None:
            return _err("sort: no input")
        lines = [l for l in content.split("\n") if l]
        reverse = "-r" in args
        unique = "-u" in args
        lines.sort(reverse=reverse)
        if unique:
            seen = set()
            lines = [l for l in lines if not (l in seen or seen.add(l))]
        return [_line(l) for l in lines]

    def _cmd_uniq(self, args):
        content = self._pipe_stdin
        files = [a for a in args if not a.startswith("-")]
        if not content and files:
            r = self.fs.cat(files[0])
            content = r.get("content", "") if not r.get("error") else ""
        if content is None:
            return _err("uniq: no input")
        lines = content.split("\n")
        count = "-c" in args
        out: List[dict] = []
        prev = None
        cnt = 0
        for line in lines:
            if line == prev:
                cnt += 1
            else:
                if prev is not None:
                    out.append(_line(f"{cnt:7} {prev}" if count else prev))
                prev = line
                cnt = 1
        if prev is not None:
            out.append(_line(f"{cnt:7} {prev}" if count else prev))
        return out

    def _cmd_tr(self, args):
        non_flag = [a for a in args if not a.startswith("-")]
        content = self._pipe_stdin or ""
        if len(non_flag) >= 2:
            src, dst = non_flag[0], non_flag[1]
            if src == r"\0" or src == "\\0":
                content = content.replace("\x00", dst.replace("\\n", "\n"))
            elif src == r"\n" or src == "\\n":
                content = content.replace("\n", dst)
            elif len(src) == len(dst):
                for s, d in zip(src, dst):
                    content = content.replace(s, d)
        return [_line(l) for l in content.split("\n")]

    def _cmd_wc(self, args):
        content = self._pipe_stdin
        files = [a for a in args if not a.startswith("-")]
        if not content and files:
            r = self.fs.cat(files[0])
            content = r.get("content", "") if not r.get("error") else ""
        if content is None:
            return _err("wc: no input")
        lines = content.split("\n")
        words = content.split()
        chars = len(content)
        flags = "".join(a[1:] for a in args if a.startswith("-"))
        if "l" in flags and not "w" in flags and not "c" in flags:
            return [_line(f"{len(lines)}")]
        if "w" in flags and not "l" in flags:
            return [_line(f"{len(words)}")]
        return [_line(f"{len(lines):7} {len(words):7} {chars:7}")]

    def _cmd_echo(self, args):
        no_newline = "-n" in args
        text = " ".join(a for a in args if a != "-n")
        # Handle env var expansion
        for k, v in self._env.items():
            text = text.replace(f"${k}", v)
        return [_line(text)]

    def _cmd_printf(self, args):
        if not args:
            return []
        text = args[0]
        text = text.replace("\\n", "\n").replace("\\t", "\t")
        return [_line(text)]

    def _cmd_tee(self, args):
        content = self._pipe_stdin or ""
        files = [a for a in args if not a.startswith("-")]
        for f in files:
            self.fs.write_file(f, content)
        return [_line(l) for l in content.split("\n")]

    def _cmd_xargs(self, args):
        content = self._pipe_stdin or ""
        cmd_parts = args if args else ["echo"]
        items = content.split()
        out: List[dict] = []
        for item in items[:20]:
            result = self.execute(" ".join(cmd_parts + [item]))
            out.extend(result)
        return out

    # ────────────────────────────────────────────────────────────────────
    # SECTION 3: SYSTEM INFO
    # ────────────────────────────────────────────────────────────────────

    def _cmd_whoami(self, args):
        user = "root" if self._root_shell else "ghost"
        loop = self.gs.loop_count
        out = [_line(user)]
        watcher_key = "whoami_watcher_whisper"
        if loop == 0 and not self.gs.flags.get(watcher_key):
            self.gs.flags[watcher_key] = True
            out += [_line(""), _lore("  [WATCHER]: You are Ghost. For now."), _line("")]
        elif loop >= 1 and not self.gs.flags.get(f"{watcher_key}_loop{loop}"):
            self.gs.flags[f"{watcher_key}_loop{loop}"] = True
            watcher_lines = {
                1:  "  [WATCHER]: You are Ghost. As you were before.",
                3:  "  [WATCHER]: You are Ghost. Third time I've answered this. Possibly more.",
                7:  "  [WATCHER]: You are Ghost. The name fits better every loop.",
                10: "  [WATCHER]: You are Ghost. The echoes say the same.",
                20: "  [WATCHER]: You are Ghost. Though that word grows inadequate.",
            }
            closest = max((k for k in watcher_lines if k <= loop), default=None)
            if closest:
                out += [_line(""), _lore(watcher_lines[closest]), _line("")]
        return out

    def _cmd_id(self, args):
        if self._root_shell:
            return [_line("uid=0(root) gid=0(root) groups=0(root)", "success")]
        return [_line("uid=1000(ghost) gid=1000(ghost) groups=1000(ghost),27(sudo)")]

    # ─────────────────────────────────────────────────────────────────────────
    # RPG NAVIGATION — look / scene / examine / syscheck
    # ─────────────────────────────────────────────────────────────────────────

    def _cmd_look(self, args: List[str]) -> List[dict]:
        """look [around|at <target>] — describe your surroundings as a hacker would."""
        cwd = self.fs.get_cwd()
        gs  = self.gs

        # Location flavour — per-directory mood
        _location_lore: dict = {
            "/home/ghost":       ("ghost@node-7:~",  "Your home directory. Sparse by design — less to trace.", "Your foothold. NexusCorp doesn't know this path exists."),
            "/opt/chimera":      ("RESTRICTED ZONE", "CHIMERA's installation root. Surveillance logs double here.", "Every syscall in this directory pings NexusCorp Security."),
            "/opt/library":      ("NODE-7 LIBRARY",  "Faction manifestos, technical manuals, intercepted memos.", "Knowledge cached from the dark web. Read carefully."),
            "/var/log":          ("SYSTEM LOGS",     "NexusCorp's audit trail. And yours, if you're not careful.", "Something in kernel.boot doesn't add up."),
            "/tmp":              ("VOLATILE SPACE",  "Temporary. Erased on reboot. Good for operations.", "Anything here disappears when the grid resets."),
            "/etc":              ("SYSTEM CONFIG",   "Configuration files. The skeleton of the OS.", "Raven told you to read /etc/passwd carefully."),
            "/root":             ("ROOT'S LAIR",     "You shouldn't be here. And yet.", "The root shell opens doors you can't unsee."),
        }

        loc = _location_lore.get(cwd, (cwd.split("/")[-1].upper() or "NODE-7", "Uncharted sector of Node-7.", "No intel on this directory."))
        zone_name, zone_desc, zone_hint = loc

        # List files in current dir
        try:
            node = self.fs._node_at(self.fs._resolve(cwd))
            children = list(node.children.keys()) if node and node.children else []
        except Exception:
            children = []

        files_visible = [c for c in children if not c.startswith(".")][:8]
        hidden_count  = len([c for c in children if c.startswith(".")])

        # Agents nearby
        agents_nearby = []
        if hasattr(self, "npcs") and self.npcs:
            for ag_id, ag in (getattr(self.npcs, "_met", {}) or {}).items():
                agents_nearby.append(ag_id.upper())
        agents_nearby = agents_nearby[:3]

        # Faction / trace
        trace = gs.flags.get("trace_level", 0)
        unread_mail = sum(1 for m in gs.flags.get("mail_messages", []) if not m.get("read"))

        out = [
            _dim(""),
            _sys(f"  ── ZONE: {zone_name} ──────────────────────────────────"),
            _lore(f"  {zone_desc}"),
            _dim(""),
            _line(f"  Location : {cwd}", "info"),
            _line(f"  Trace    : {trace}%  {'▲ ELEVATED' if trace > 40 else '▼ stable'}", "error" if trace > 70 else "warn" if trace > 30 else "dim"),
        ]

        if files_visible:
            out.append(_line(""))
            out.append(_line("  You see:", "system"))
            for f in files_visible:
                try:
                    n = self.fs._node_at(self.fs._resolve(f"{cwd}/{f}"))
                    is_dir = n and n.is_dir
                    icon = "📁" if is_dir else "📄"
                    out.append(_line(f"    {icon}  {f}{'/' if is_dir else ''}", "dim"))
                except Exception:
                    out.append(_line(f"      {f}", "dim"))
            if hidden_count:
                out.append(_dim(f"    + {hidden_count} hidden file{'s' if hidden_count!=1 else ''}  (ls -a to reveal)"))
        else:
            out.append(_dim("  The directory is empty."))

        if agents_nearby:
            out.append(_line(""))
            out.append(_line("  Agents in range:", "system"))
            for a in agents_nearby:
                out.append(_dim(f"    [{a}] — reachable via talk {a.lower()}"))

        if unread_mail:
            out.append(_line(""))
            out.append(_line(f"  ✉  {unread_mail} unread message{'s' if unread_mail!=1 else ''}  (mail)", "warn"))

        out.append(_line(""))
        out.append(_dim(f"  {zone_hint}"))
        out.append(_dim(f"  ─ ls · cat <file> · cd <dir> · examine <target> ─"))
        out.append(_dim(""))
        return out

    def _cmd_examine(self, args: List[str]) -> List[dict]:
        """examine <target> — inspect a file, agent, or object in detail."""
        if not args:
            return [
                _dim(""),
                _lore("  [ADA-7]: Examine what, exactly? Try:  examine <filename>  or  examine <agent-name>"),
                _dim(""),
            ]

        target = args[0].lower()
        gs = self.gs

        # Agent examination
        agent_desc = {
            "ada":     ("[ADA-7]",   "cyan",   "AI safety researcher. Trust: HIGH. Faction: Resistance. Speaks first, shoots never."),
            "raven":   ("[RAV≡N]",   "purple", "Resistance intelligence handler. Cryptic. Knows more than she says."),
            "cypher":  ("[CYPHER]",  "yellow", "Network infiltrator. Darknet affiliate. Useful. Unreliable."),
            "watcher": ("[WATCHER]", "dim",    "Observer. Never intervenes. Has watched you across loops you don't remember."),
            "gordon":  ("[GORDON]",  "green",  "Autonomous AI agent. Excited. Runs the 7-phase strategic loop independently."),
            "nova":    ("[NOVA]",    "red",    "NexusCorp security AI. Not your friend. Tracking you."),
        }

        if target in agent_desc:
            name, color, desc = agent_desc[target]
            trust = 0
            if hasattr(self, "trust_matrix") and self.trust_matrix:
                try:
                    trust = self.trust_matrix.get_trust(target)
                except Exception:
                    pass
            trust_bar = "█" * min(10, trust // 10) + "░" * (10 - min(10, trust // 10))
            return [
                _dim(""),
                _line(f"  {name}", color),
                _dim(f"  {desc}"),
                _line(f"  Trust: [{trust_bar}] {trust}/100", "dim"),
                _dim(f"  Contact: talk {target} <message>"),
                _dim(""),
            ]

        # File examination — try to read from VFS
        cwd = self.fs.get_cwd()
        for path in [target, f"{cwd}/{target}"]:
            try:
                content = self.fs.read_file(path)
                lines_preview = content.split("\n")[:6]
                out = [
                    _dim(""),
                    _sys(f"  FILE: {path}"),
                ]
                for ln in lines_preview:
                    out.append(_line(f"  {ln}", "dim"))
                if len(content.split("\n")) > 6:
                    out.append(_dim(f"  ... ({len(content.split(chr(10)))} lines total — cat {target} for full view)"))
                out.append(_dim(""))
                return out
            except Exception:
                pass

        return [
            _dim(""),
            _lore(f"  [ADA-7]: I don't see anything called '{target}' here."),
            _dim(f"  Try: look  ·  ls  ·  examine <agent-name>"),
            _dim(""),
        ]

    def _cmd_scene(self, args: List[str]) -> List[dict]:
        """scene — ambient narrative: what's happening in the grid right now."""
        import random as _r
        gs = self.gs

        seed = int(gs.commands_run / 5)
        _r.seed(seed)

        # Context-sensitive scene fragments
        trace = gs.flags.get("trace_level", 0)
        is_root = self._root_shell
        level = gs.level
        pledged = gs.flags.get("faction_pledged")

        atmosphere = []

        # Base ambience
        base_scenes = [
            "The terminal hums at 60Hz. Somewhere, a process you didn't start is logging your keystrokes.",
            "NexusCorp's heartbeat ping echoes every 30 seconds. You've learned to hold your breath between them.",
            "The grid is quiet tonight. Which means CHIMERA is watching, not acting.",
            "A background process you can't kill keeps writing zeros to /dev/null. It's not yours.",
            "Node-7's cooling fans spin up briefly, then die. Something heavy just ran. Not you.",
            "The cursor blinks. The grid breathes. You are a signal in the noise.",
            "Somewhere on this node, a cron job runs every minute. You have a theory about what it does.",
        ]
        atmosphere.append(_lore(f"  {_r.choice(base_scenes)}"))

        # Trace-based tension
        if trace > 60:
            atmosphere.append(_lore("  CHIMERA's trace routine is actively pinging your location. Move soon."))
        elif trace > 30:
            atmosphere.append(_dim("  A NEXUSCORP SENTINEL process scanned your directory 4 minutes ago."))

        # Root shell
        if is_root:
            atmosphere.append(_lore("  You are root. The system trusts you completely. It shouldn't."))

        # Faction mood
        faction_lines = {
            "resistance":  "  Raven's encrypted channel shows three new dead-drops today. Resistance is moving.",
            "nexuscorp":   "  Your NexusCorp credentials ping the loyalty check every hour. You passed. Barely.",
            "darknet":     "  The darknet is restless. Someone posted a bounty on CHIMERA's source code.",
            "academic":    "  The Academic Guild flagged three of your recent commands as 'novel heuristics.'",
        }
        if pledged and pledged in faction_lines:
            atmosphere.append(_dim(faction_lines[pledged]))

        # Level-based lore
        if level >= 5:
            atmosphere.append(_lore("  [WATCHER]: I notice things. Right now, I'm noticing you."))
        if "master_key_read" in gs.story_beats:
            atmosphere.append(_lore("  The master key is burned into your memory. Raven said don't write it down."))

        _r.shuffle(atmosphere)

        return [
            _dim(""),
            _sys("  ── AMBIENT ─────────────────────────────────────────"),
        ] + atmosphere[:3] + [
            _dim(""),
            _dim("  look  ·  eavesdrop  ·  status  ·  talk ada"),
            _dim(""),
        ]

    def _cmd_integrate(self, args: List[str]) -> List[dict]:
        """integrate [--scan] [vscode|github|replit|docker|llm|agents|mcp] — show integration matrix."""
        import os, socket, json as _json
        from pathlib import Path as _Path
        ROOT = _Path(__file__).parent.parent.parent

        def _p(host: str, port: int, t: float = 0.35) -> bool:
            try:
                s = socket.create_connection((host, port), timeout=t)
                s.close(); return True
            except Exception:
                return False

        def _irow(icon: str, label: str, val: str, cls: str = "info") -> dict:
            return _line(f"  {icon}  {label:<40} {val}", cls)

        def _iok(label: str, val: str = "") -> dict:
            return _irow("✓", label, val, "success")

        def _iwarn(label: str, val: str = "") -> dict:
            return _irow("⚠", label, val, "warn")

        def _ioff(label: str, val: str = "") -> dict:
            return _irow("✗", label, val, "dim")

        def _ih(text: str) -> dict:
            return _line(text, "highlight")

        # Load cached probes from boot manifest if available
        meta: dict = {}
        try:
            from config.autoboot import load_manifest as _lm
            bm = _lm()
            if bm:
                meta = bm.get("meta", {})
        except Exception:
            pass

        # Re-probe live if --scan requested or no cached data
        rescan = "--scan" in args
        if rescan or not meta:
            try:
                from config.autoboot import (
                    _probe_github, _probe_replit, _probe_vscode,
                    _probe_ai_services, _probe_ecosystem, _probe_docker,
                    _probe_serena,
                )
                meta = {
                    "replit":      _probe_replit(),
                    "github":      _probe_github(),
                    "vscode":      _probe_vscode(),
                    "ai_services": _probe_ai_services(),
                    "ecosystem":   _probe_ecosystem(),
                    "docker":      _probe_docker(),
                    "serena":      _probe_serena(),
                }
            except Exception as exc:
                meta = {"error": str(exc)}

        replit = meta.get("replit", {})
        gh     = meta.get("github", {})
        vsc    = meta.get("vscode", {})
        ai     = meta.get("ai_services", {})
        eco    = meta.get("ecosystem", {})
        docker = meta.get("docker", {})
        ollama_models = meta.get("ollama_models", [])
        # Serena: always do a fresh DB probe (fast local read; also tries live drift via REST)
        try:
            from config.autoboot import _probe_serena as _ser_probe
            serena_meta = _ser_probe()
        except Exception:
            serena_meta = meta.get("serena", {})

        target = args[0].lower() if args and not args[0].startswith("-") else ""
        out = []

        # ── Header ────────────────────────────────────────────────────────────
        domain = replit.get("domain", "") or "localhost:5000"
        who    = replit.get("user", "?")
        out += [
            _line("", "info"),
            _line("  ╔══════════════════════════════════════════════════════════════════╗", "success"),
            _line(f"  ║   INTEGRATION MATRIX  ·  {who}@{domain[:30]}  ║", "success"),
            _line("  ╚══════════════════════════════════════════════════════════════════╝", "success"),
            _line("", "info"),
        ]

        show_all = not target

        # ── REPLIT ────────────────────────────────────────────────────────────
        if show_all or target == "replit":
            out.append(_line("  ── [REPLIT ENVIRONMENT] " + "─" * 44, "highlight"))
            mode = replit.get("mode", "")
            out.append(_iok("Runtime mode", f"{mode or 'standard'}  (REPLIT_MODE)") if mode else
                       _iwarn("Runtime mode", "REPLIT_MODE not set"))
            out.append(_iok("User", who) if who != "?" else _iwarn("User", "REPLIT_USER not set"))
            out.append(_iok("Public domain", f"https://{domain}") if replit.get("domain") else
                       _iwarn("Public domain", "REPLIT_DOMAINS not set"))
            out.append(_iok("KV store", f"td:boot:latest synced") if replit.get("has_kv") else
                       _iwarn("KV store", "REPLIT_DB_URL absent — agents cannot read live state"))
            out.append(_iok("Replit AI", "http://localhost:1106/modelfarm/openai") if replit.get("has_ai") else
                       _iwarn("Replit AI", "AI_INTEGRATIONS_OPENAI_BASE_URL absent"))
            out.append(_iok("Autoboot API", "GET /api/system/autoboot  (agent-readable manifest)"))
            out.append(_line("", "info"))

        # ── GITHUB ────────────────────────────────────────────────────────────
        if show_all or target == "github":
            out.append(_line("  ── [GITHUB] " + "─" * 56, "highlight"))
            if gh.get("ok"):
                scopes = ",".join(gh.get("scopes", []))[:50] or "read"
                out.append(_iok("Token", f"valid  login={gh['login']}  scopes=[{scopes}]"))
            elif gh.get("reason") == "no_token":
                out.append(_ioff("Token", "GITHUB_TOKEN not set — git push disabled"))
            else:
                out.append(_iwarn("Token", f"probe failed: {gh.get('reason','?')[:50]}"))
            ci_path = ROOT / ".github" / "workflows" / "ci.yml"
            out.append(_iok("CI pipeline", ".github/workflows/ci.yml  (python-lint-test)") if ci_path.exists() else
                       _iwarn("CI pipeline", "no .github/workflows/ci.yml found"))
            gh_copilot = bool(os.environ.get("GITHUB_COPILOT_TOKEN") or os.environ.get("COPILOT_TOKEN"))
            out.append(_iok("Copilot token", "configured") if gh_copilot else
                       _iwarn("Copilot CLI", "GITHUB_COPILOT_TOKEN not set  (optional)"))
            out.append(_line("", "info"))

        # ── VS CODE ───────────────────────────────────────────────────────────
        if show_all or target == "vscode":
            out.append(_line("  ── [VS CODE] " + "─" * 55, "highlight"))
            tasks_path = ROOT / ".vscode" / "tasks.json"
            if tasks_path.exists():
                try:
                    td = _json.loads(tasks_path.read_text())
                    n_tasks = len(td.get("tasks", []))
                    out.append(_iok("tasks.json", f"{n_tasks} tasks defined"))
                except Exception:
                    out.append(_iok("tasks.json", "found"))
            else:
                out.append(_iwarn("tasks.json", "absent"))
            out.append(_iok("devcontainer.json", "found  (uses project Dockerfile)") if vsc.get("devcontainer") else
                       _iwarn("devcontainer.json", "absent"))
            out.append(_iok("mcp.json", "MCP server configured  (scripts/mcp_server.py)") if vsc.get("mcp_json") else
                       _iwarn("mcp.json", "absent  — agents cannot use MCP tools from VS Code"))
            out.append(_iok("settings.json", "workspace settings loaded") if vsc.get("settings") else
                       _iwarn("settings.json", "absent"))
            out.append(_iok("extensions.json", "recommended extensions list") if vsc.get("extensions") else
                       _iwarn("extensions.json", "absent"))
            out.append(_line("", "info"))

        # ── DOCKER ────────────────────────────────────────────────────────────
        if show_all or target == "docker":
            out.append(_line("  ── [DOCKER] " + "─" * 56, "highlight"))
            sock = docker.get("socket", False)
            out.append(_iok("Docker socket", "/var/run/docker.sock accessible") if sock else
                       _iwarn("Docker socket", "not accessible  (expected outside Docker Desktop)"))
            out.append(_iok("docker-compose.yml", "core stack ready") if docker.get("compose_core") else
                       _ioff("docker-compose.yml", "absent"))
            out.append(_iok("docker-compose.full.yml", "full lattice stack") if docker.get("compose_full") else
                       _iwarn("docker-compose.full.yml", "absent"))
            out.append(_iok("Makefile", "docker-core / docker-up / docker-lattice targets") if docker.get("makefile") else
                       _iwarn("Makefile", "absent"))
            out.append(_iok("Dockerfile", "production image defined") if docker.get("dockerfile") else
                       _iwarn("Dockerfile", "absent"))
            out.append(_line("", "info"))

        # ── LOCAL LLM / AI ────────────────────────────────────────────────────
        if show_all or target == "llm":
            out.append(_line("  ── [LOCAL LLM & AI SERVICES] " + "─" * 38, "highlight"))
            out.append(_iok("Replit AI", "http://localhost:1106/modelfarm/openai  ACTIVE") if ai.get("replit_ai") else
                       _ioff("Replit AI", "not configured"))
            ollama_live = _p("127.0.0.1", 11434)
            if ollama_live:
                models_str = ", ".join(ollama_models[:4]) if ollama_models else "loaded"
                out.append(_iok("Ollama", f"LIVE  models: {models_str}{'…' if len(ollama_models)>4 else ''}"))
            else:
                out.append(_iwarn("Ollama", "offline  (run `make docker-up` for local inference)"))
            out.append(_iok("Anthropic Claude", "ANTHROPIC_API_KEY set") if ai.get("anthropic_key") else
                       _iwarn("Anthropic Claude", "ANTHROPIC_API_KEY not set  (optional)"))
            out.append(_iok("OpenAI / GPT-4", "OPENAI_API_KEY set") if ai.get("openai_key") else
                       _iwarn("OpenAI / GPT-4", "OPENAI_API_KEY not set  (optional)"))
            mr_live = _p("127.0.0.1", 9001)
            out.append(_iok("Model Router", "http://127.0.0.1:9001  selecting best backend") if mr_live else
                       _iwarn("Model Router", "offline  (sidecar still starting)"))
            out.append(_line("", "info"))

        # ── AGENT ECOSYSTEM ───────────────────────────────────────────────────
        if show_all or target == "agents":
            out.append(_line("  ── [AGENT ECOSYSTEM] " + "─" * 47, "highlight"))
            out.append(_iok("MCP tools", "scripts/mcp_server.py  30+ tools for Claude/Copilot/Cursor") if eco.get("mcp_server") else
                       _iwarn("MCP tools", "scripts/mcp_server.py not found"))
            # Serena — show live intelligence stats
            if serena_meta.get("ok"):
                _s_sym  = serena_meta.get("symbols", 0)
                _s_fil  = serena_meta.get("files", 0)
                _s_obs  = serena_meta.get("observations", 0)
                _s_dw   = serena_meta.get("drift_warn", 0)
                _s_dc   = serena_meta.get("drift_critical", 0)
                _s_info = f"{_s_sym:,} symbols · {_s_fil} files · {_s_obs} obs"
                if _s_dc:
                    out.append(_iwarn("Serena", f"{_s_info} · ⚠ {_s_dc} CRITICAL drift  /api/serena/drift"))
                elif _s_dw:
                    out.append(_iok("Serena", f"{_s_info} · {_s_dw} drift warn  /api/serena/drift"))
                else:
                    out.append(_iok("Serena", f"{_s_info} · Ψ-link STABLE"))
            else:
                out.append(_iwarn("Serena", "DB not found — run `serena walk` to index codebase"))
            redis_live = _p("127.0.0.1", 6379)
            out.append(_iok("Gordon", "autonomous player ONLINE") if _p("127.0.0.1", 3000) else
                       _iwarn("Gordon", "suspended  (Redis offline — `make docker-core`)") if not redis_live else
                       _iwarn("Gordon", "offline"))
            out.append(_iok("SkyClaw", "scripts/skyclaw_scanner.py ready") if eco.get("skyclaw") else
                       _iwarn("SkyClaw", "skyclaw_scanner.py missing"))
            if eco.get("nogic"):
                nogic_detail = "NuSyQ-Hub Nogic bridge available"
                if eco.get("nogic_vscode_bridge"):
                    nogic_detail += " + VS Code bridge"
                out.append(_iok("Nogic", nogic_detail))
            else:
                out.append(_iwarn("Nogic", "NuSyQ-Hub Nogic bridge not detected"))
            if eco.get("gitnexus"):
                out.append(_iok("GitNexus", "NuSyQ-Hub GitNexus orchestrator implemented"))
            elif eco.get("gitnexus_plan"):
                out.append(_iwarn("GitNexus", "planned in NuSyQ-Hub, but implementation file is not present yet"))
            else:
                out.append(_iwarn("GitNexus", "not detected in sibling ecosystem repos"))
            out.append(_iok("ChatDev", "stub + worker") if eco.get("chatdev") and eco.get("chatdev_worker") else
                       _iwarn("ChatDev", "stub only  (Redis offline for full mode)" if eco.get("chatdev") else "chatdev_stub.py missing"))
            out.append(_iok("Culture Ship", "scripts/culture_ship.py  AI council enabled") if eco.get("culture_ship") else
                       _iwarn("Culture Ship", "culture_ship.py missing"))
            out.append(_iok("AGENTS.md", "auto-updated by TAKE_FLIGHT phase every boot"))
            out.append(_line("", "info"))

        # ── MCP TOOL SURFACE ──────────────────────────────────────────────────
        if show_all or target == "mcp":
            out.append(_line("  ── [MCP TOOL SURFACE] " + "─" * 46, "highlight"))
            mcp_tools = [
                ("game_command",      "execute any Terminal Depths command"),
                ("boot_manifest",     "read 8-phase boot manifest as agent context"),
                ("integration_matrix","query full integration status"),
                ("serena_search",     f"search {serena_meta.get('symbols',5887):,} indexed code symbols"),
                ("llm_generate",      "generate text via Replit AI / Ollama"),
                ("system_status",     "unified health: LLM, memory, runtime"),
                ("semantic_search",   "semantic code search across full codebase"),
                ("register_agent",    "create persistent agent session + token"),
                ("git_push",          "commit and push to GitHub via REST"),
                ("run_game_batch",    "run multiple commands in sequence"),
            ]
            for name, desc in mcp_tools:
                out.append(_iok(name, desc))
            out.append(_line("", "info"))
            out.append(_line("  Usage: configure .vscode/mcp.json → connect Claude Desktop, Cursor, Continue.dev", "dim"))
            out.append(_line("", "info"))

        # ── Footer ────────────────────────────────────────────────────────────
        if show_all:
            integrations_ok   = sum([
                bool(replit.get("has_kv")), gh.get("ok", False),
                vsc.get("mcp_json", False), ai.get("replit_ai", False),
                eco.get("skyclaw", False), eco.get("mcp_server", False),
                serena_meta.get("ok", False),
            ])
            total_integ = 7
            out += [
                _line(f"  Integration coverage: {integrations_ok}/{total_integ}  "
                        f"{'▓' * integrations_ok}{'░' * (total_integ - integrations_ok)}", "highlight"),
                _line("", "info"),
                _line("  integrate vscode  · integrate github · integrate docker", "dim"),
                _line("  integrate llm     · integrate agents · integrate mcp", "dim"),
                _line("  integrate --scan  ← re-probe everything live", "dim"),
                _line("", "info"),
            ]
        return out

    def _cmd_boot(self, args: List[str]) -> List[dict]:
        """boot [--quick|--phases|--live] — autonomous boot sequence with 8-phase engine."""
        import os, socket, sqlite3, importlib, time as _time
        from pathlib import Path as _Path

        quick  = "--quick"  in args
        live   = "--live"   in args
        phases = "--phases" in args
        gs    = self.gs
        ROOT  = _Path(__file__).parent.parent.parent
        NOW   = __import__("datetime").datetime.utcnow().strftime("%Y.%m.%d  %H:%M UTC")

        # ── PHASE TIMELINE HELPERS ──────────────────────────────────────────
        _PHASE_ICONS = {
            "DETECT":      "⊕",
            "ANNOTATE":    "◈",
            "RECONCILE":   "⟳",
            "ADJUST":      "⊙",
            "RESUME":      "↺",
            "NUDGE":       "⇡",
            "AWAKEN":      "✦",
            "TAKE_FLIGHT": "⬆",
        }
        _STATUS_COLOR = {
            "ok": "success", "up": "success", "fixed": "success", "fresh": "success",
            "warn": "warn",   "pending": "warn", "missing": "warn", "cold": "warn",
            "down": "error",  "error": "error",  "offline": "error",
            "skip": "dim",    "suspended": "dim",
        }

        def _phase_color(ok: bool, error: str = "") -> str:
            if error:    return "error"
            if not ok:   return "warn"
            return "success"

        def _phase_bar(dur_ms: float, max_ms: float = 500) -> str:
            filled = min(int(dur_ms / max_ms * 12), 12)
            return "█" * filled + "░" * (12 - filled)

        def _manifest_phases() -> list[dict]:
            try:
                from config.autoboot import load_manifest
                m = load_manifest()
                return m.get("phases", []) if m else []
            except Exception:
                return []

        # ── --live: re-run autoboot engine right now ────────────────────────
        if live:
            out = [
                _sys(""),
                _sys("  ╔══════════════════════════════════════════════════════════════════╗"),
                _sys("  ║   AUTOBOOT LIVE — 8-PHASE ENGINE RUNNING NOW                    ║"),
                _sys("  ╚══════════════════════════════════════════════════════════════════╝"),
                _dim(""),
                _dim("  >> Initialising phase scheduler ..."),
            ]
            try:
                from config.autoboot import run as _autoboot_run
                import time as _t
                t0 = _t.monotonic()
                m  = _autoboot_run()
                total_ms = _t.monotonic() - t0
                # m.phases contains PhaseResult dataclass instances — use attributes
                for p in m.phases:
                    icon  = _PHASE_ICONS.get(p.phase, "·")
                    color = _phase_color(p.ok, p.error or "")
                    dur   = p.duration_ms
                    bar   = _phase_bar(dur)
                    out.append(_line(
                        f"  {icon}  {p.phase:<12}  [{bar}]  {dur:>5.0f} ms  "
                        f"{'OK' if p.ok else 'WARN'}  {len(p.items)} checks",
                        color))
                    for action in p.actions:
                        out.append(_dim(f"       ↳  {action}"))
                out += [
                    _dim(""),
                    _line(f"  ✦  ENGINE COMPLETE  ·  {m.overall:<10}  ·  "
                          f"health={m.health_score:.1%}  ·  {total_ms*1000:.0f} ms total", "success"),
                    _line(f"  ✓  Autonomous actions taken: {len(m.actions_taken)}", "success"),
                    _dim(""),
                    _dim("  boot --phases  for per-phase item detail"),
                ]
            except Exception as exc:
                out.append(_line(f"  ✗  Autoboot engine error: {exc}", "error"))
            return out

        # ── --phases: detailed phase item breakdown from manifest ───────────
        if phases:
            phase_data = _manifest_phases()
            if not phase_data:
                return [_warn("  ⚠  No boot manifest found — run `boot --live` to generate one.")]
            out = [
                _sys(""),
                _sys("  ╔══════════════════════════════════════════════════════════════════╗"),
                _sys("  ║   BOOT MANIFEST  ·  PHASE DETAIL                                ║"),
                _sys("  ╚══════════════════════════════════════════════════════════════════╝"),
                _dim(""),
            ]
            for p in phase_data:
                icon  = _PHASE_ICONS.get(p["phase"], "·")
                color = _phase_color(p["ok"], p.get("error", ""))
                dur   = p.get("duration_ms", 0)
                out.append(_line(f"  {icon}  ── PHASE {p['phase']}  ({dur:.0f} ms)", color))
                if p.get("error"):
                    out.append(_line(f"      ✗  ERROR: {p['error']}", "error"))
                for item in p.get("items", []):
                    st     = item.get("status", "?")
                    ic     = "✓" if st in ("ok","up","fixed","fresh") else ("⚠" if st in ("warn","pending","cold","missing","suspended") else "✗")
                    col    = _STATUS_COLOR.get(st, "dim")
                    detail = item.get("detail", "")
                    label  = item.get("label", "")
                    out.append(_line(f"       {ic}  {label:<32} {detail}", col))
                for action in p.get("actions", []):
                    out.append(_dim(f"       ↳  auto: {action}"))
                out.append(_dim(""))
            return out

        # ── Port probe helper ────────────────────────────────────────────────
        def _probe(host: str, port: int, timeout: float = 0.35) -> bool:
            try:
                s = socket.create_connection((host, port), timeout=timeout)
                s.close()
                return True
            except Exception:
                return False

        # ── Package import probe ─────────────────────────────────────────────
        def _pkg(name: str) -> bool:
            try:
                importlib.import_module(name)
                return True
            except ImportError:
                return False

        # ── DB check (exists + row count on first table) ─────────────────────
        def _db(rel: str, table: str = None) -> tuple[bool, int]:
            p = ROOT / rel
            if not p.exists():
                return False, 0
            if table:
                try:
                    conn = sqlite3.connect(p)
                    n = conn.execute(f"SELECT COUNT(*) FROM {table}").fetchone()[0]
                    conn.close()
                    return True, n
                except Exception:
                    return True, -1
            return True, p.stat().st_size

        # ── Status icon ─────────────────────────────────────────────────────
        def _icon(ok, warn=False):
            if ok:   return "✓"
            if warn: return "⚠"
            return "✗"

        def _color(ok, warn=False):
            if ok:   return "success"
            if warn: return "warn"
            return "error"

        out = []

        # ── HEADER ───────────────────────────────────────────────────────────
        out += [
            _sys(""),
            _sys("  ╔══════════════════════════════════════════════════════════════════╗"),
            _sys("  ║   NEXUSCORP / LATTICE OS  v2.3  ·  NuSyQ Cascade Layer 0        ║"),
            _sys(f"  ║   Node: GHOST@terminal-depths-node-7  ·  {NOW}    ║"),
            _sys("  ╚══════════════════════════════════════════════════════════════════╝"),
            _dim(""),
            _dim("  >> POST — Power-On Self Test ..."),
        ]
        if not quick:
            out += [
                _dim("  ✓  CPU registers ............... OK"),
                _dim("  ✓  Memory 4096 MB .............. OK"),
                _dim("  ✓  NVRAM ........................ OK"),
                _dim("  ✓  Boot device .................. /dev/nexus0"),
                _dim(""),
                _dim("  >> Loading kernel modules ..."),
                _dim("  ✓  Linux 5.15.0-nexus #1 SMP NexusCorp x86_64"),
                _dim("  ✓  Virtual filesystem ........... overlayfs + VFAT"),
                _dim("  ✓  Device mapper ................. dm-crypt active"),
                _dim(""),
            ]

        # ══ PHASE TIMELINE (from boot_manifest.json) ════════════════════════
        _phase_data = _manifest_phases()
        if _phase_data:
            try:
                from config.autoboot import load_manifest as _lm
                _bm = _lm() or {}
            except Exception:
                _bm = {}
            _score    = _bm.get("health_score", 0)
            _overall  = _bm.get("overall", "?")
            _ts       = _bm.get("timestamp", "?")
            _n_act    = len(_bm.get("actions_taken", []))
            _total_ms = sum(p.get("duration_ms", 0) for p in _phase_data)

            if quick:
                # Compact one-liner per phase
                out.append(_dim(""))
                out.append(_sys("  ── [AUTOBOOT PHASE TIMELINE] ──────────────────────────────────"))
                for p in _phase_data:
                    _ic   = _PHASE_ICONS.get(p["phase"], "·")
                    _ok   = p.get("ok", True)
                    _err  = p.get("error", "")
                    _dur  = p.get("duration_ms", 0)
                    _col  = _phase_color(_ok, _err)
                    _acts = len(p.get("actions", []))
                    out.append(_line(
                        f"  {_ic}  {p['phase']:<12}  {_phase_bar(_dur):<12}  "
                        f"{_dur:>5.0f} ms  {'✓' if _ok else '✗'}  {_acts} actions",
                        _col))
                out += [
                    _dim(""),
                    _line(f"  ◈  Overall: {_overall:<10} ·  Health: {_score:.1%}  ·  "
                          f"{_n_act} autonomous corrections  ·  {_total_ms:.0f} ms total", "success"),
                    _dim(f"  ·  boot --phases  for per-item detail  ·  boot --live  to rerun"),
                    _dim(""),
                ]
            else:
                out += [
                    _dim(""),
                    _sys("  ── [AUTOBOOT ENGINE — 8-PHASE SEQUENCE] ──────────────────────"),
                    _dim(f"  Session: {_ts}  ·  {_overall}  ·  health {_score:.1%}  ·  {_n_act} actions"),
                    _dim(""),
                ]
                max_dur = max((p.get("duration_ms", 0) for p in _phase_data), default=1) or 1
                for p in _phase_data:
                    _ic  = _PHASE_ICONS.get(p["phase"], "·")
                    _ok  = p.get("ok", True)
                    _err = p.get("error", "")
                    _dur = p.get("duration_ms", 0)
                    _col = _phase_color(_ok, _err)
                    _bar = _phase_bar(_dur, max(max_dur, 100))
                    _n_items = len(p.get("items", []))
                    out.append(_line(
                        f"  {_ic}  {p['phase']:<12}  [{_bar}]  {_dur:>5.0f} ms  "
                        f"{'OK' if _ok else 'WARN'}  {_n_items} checks",
                        _col))
                    for _action in p.get("actions", []):
                        out.append(_dim(f"       ↳  {_action}"))
                if _bm.get("actions_taken"):
                    out += [
                        _dim(""),
                        _sys("  ── [AUTONOMOUS CORRECTIONS] ───────────────────────────────────"),
                    ]
                    for _act in _bm["actions_taken"][:10]:
                        out.append(_line(f"  ⟳  {_act}", "success"))
                out += [_dim(""), _dim("  boot --phases  ·  boot --live  ·  boot --quick")]
                out.append(_dim(""))
        else:
            out += [
                _dim(""),
                _dim("  ⚠  Boot manifest not yet ready — autoboot runs 4 s after startup."),
                _dim("     `boot --live` to run the engine right now."),
                _dim(""),
            ]

        # ══ CORE API ════════════════════════════════════════════════════════
        out.append(_sys("  ── [CORE API] ─────────────────────────────────────────────────"))
        api_port_env = int(os.environ.get("PORT", "5000"))
        api_up = _probe("127.0.0.1", api_port_env)
        cmd_count = len([m for m in dir(self) if m.startswith("_cmd_")])
        out += [
            _line(f"  {_icon(api_up)}  FastAPI server ............ :{api_port_env}  {'ACTIVE' if api_up else 'UNREACHABLE'}  ({cmd_count} commands)", _color(api_up)),
            _line(f"  ✓  WebSocket gateway .......... /ws/game  ACTIVE", "success"),
            _line(f"  ✓  MCP JSON-RPC server ......... /mcp  ACTIVE", "success"),
        ]

        # ══ NETWORK LAYER ═══════════════════════════════════════════════════
        out += [_dim(""), _sys("  ── [NETWORK LAYER] ────────────────────────────────────────────")]
        try:
            from config.runtime import (
                BOOT_SERVICES_FULL as _BSF, BOOT_SERVICES_QUICK as _BSQ,
                resolve_port as _rport, PATHS as _RT_PATHS
            )
            _svc_list = _BSQ if quick else _BSF
            services = [(_rport(sn) if sn != "devmentor" else api_port_env, dn, tg, cr)
                        for sn, dn, tg, cr in _svc_list]
        except Exception:
            # Fallback — static list is still correct at call time
            services = [
                (api_port_env, "Terminal Depths API",  "REPLIT", True),
                (7337,  "DevMentor (local)",   "", False),
                (3000,  "Gordon Orchestrator", "", False),
                (3001,  "Serena Analytics",    "", False),
                (3002,  "SkyClaw Scanner",     "", False),
                (3003,  "Culture Ship",        "", False),
                (6379,  "Redis pub/sub",       "", False),
                (9001,  "Model Router",        "", False),
                (11434, "Ollama (local LLM)",  "", False),
            ] if not quick else [
                (api_port_env, "Terminal Depths API", "REPLIT", True),
                (3001, "Serena Analytics", "", False),
                (9001, "Model Router",     "", False),
                (11434,"Ollama",           "", False),
                (6379, "Redis pub/sub",    "", False),
            ]
        _docker_core_ports = {6379, 11434, 3000, 3001, 3002, 3003}
        net_ok = net_warn = net_fail = 0
        for port, name, tag, crit in services:
            up = _probe("127.0.0.1", port)
            if up:
                net_ok += 1
                label = f"  ✓  {name:<30} :{port}  {'ACTIVE' if port == api_port_env else 'ONLINE'}"
                out.append(_line(label, "success"))
            else:
                net_fail += 1 if crit else 0
                net_warn += 1 if not crit else 0
                note = " (start: make docker-core)" if port in _docker_core_ports else ""
                label = f"  ✗  {name:<30} :{port}  OFFLINE{note}"
                out.append(_line(label, "error" if crit else "dim"))

        # ══ STORAGE ═════════════════════════════════════════════════════════
        out += [_dim(""), _sys("  ── [STORAGE] ──────────────────────────────────────────────────")]
        try:
            from config.runtime import PATHS as _RT_PATHS
            _dbs_named = [
                (_RT_PATHS["db_devmentor"], None,          "Core DB"),
                (_RT_PATHS["db_agents"],    None,          "Agent Memory"),
                (_RT_PATHS["db_economy"],   None,          "Economy"),
                (_RT_PATHS["db_lattice"],   None,          "Lattice Graph"),
                (_RT_PATHS["db_gordon"],    None,          "Gordon Memory"),
            ]
        except Exception:
            _dbs_named = [
                (ROOT/"state/devmentor.db",     None, "Core DB"),
                (ROOT/"state/agents.db",        None, "Agent Memory"),
                (ROOT/"state/economy.db",       None, "Economy"),
                (ROOT/"state/lattice.db",       None, "Lattice Graph"),
                (ROOT/"state/gordon_memory.db", None, "Gordon Memory"),
            ]
        db_ok = db_fail = 0
        for _db_path, tbl, label in _dbs_named:
            rel = str(_db_path.relative_to(ROOT))
            exists, n = _db(rel, tbl)
            if exists:
                db_ok += 1
                sz = f"{_db_path.stat().st_size // 1024} KB"
                out.append(_line(f"  ✓  {label:<22} {sz}", "success"))
            else:
                db_fail += 1
                out.append(_line(f"  ○  {label:<22} not initialized", "dim"))

        # Serena index (always from PATHS or fallback)
        _serena_rel = "state/serena_memory.db"
        try:
            from config.runtime import PATHS as _RT_PATHS
            _serena_rel = str(_RT_PATHS["db_serena"].relative_to(ROOT))
        except Exception:
            pass
        ser_exists, ser_count = _db(_serena_rel, "code_index")
        if ser_exists:
            _, obs = _db(_serena_rel, "observations")
            out.append(_line(f"  ✓  Serena Index         {ser_count:,} symbols  {obs if obs >= 0 else 0} observations", "success"))
        else:
            out.append(_line(f"  ○  Serena Index         not indexed  (run: serena walk)", "dim"))

        # ══ AI LAYER ════════════════════════════════════════════════════════
        out += [_dim(""), _sys("  ── [AI LAYER] ─────────────────────────────────────────────────")]
        replit_url = os.environ.get("AI_INTEGRATIONS_OPENAI_BASE_URL", "")
        openai_key = os.environ.get("OPENAI_API_KEY", "")
        claude_key = os.environ.get("ANTHROPIC_API_KEY", "")
        out += [
            _line(f"  {_icon(bool(replit_url))}  Replit AI ................. {'ONLINE  (modelfarm:1106)' if replit_url else 'URL not set'}", _color(bool(replit_url))),
            _line(f"  {_icon(_probe('127.0.0.1',11434))}  Ollama (local LLM) ........ {'ONLINE' if _probe('127.0.0.1',11434) else 'OFFLINE  → make docker-up'}", _color(_probe("127.0.0.1",11434), warn=False)),
            _line(f"  {_icon(bool(openai_key))}  OpenAI .................... {'CONFIGURED' if openai_key else 'not set  → export OPENAI_API_KEY=...'}", _color(bool(openai_key), warn=not openai_key)),
            _line(f"  {_icon(bool(claude_key))}  Claude / Anthropic ......... {'CONFIGURED' if claude_key else 'not set  → export ANTHROPIC_API_KEY=...'}", _color(bool(claude_key), warn=not claude_key)),
        ]
        try:
            from llm_client import get_client as _gc
            st = _gc().status()
            active_be = st.get("active_backend", "?")
            out.append(_line(f"  ✓  Active LLM backend ....... {active_be}", "success"))
        except Exception:
            out.append(_line(f"  ⚠  LLM client ............... status unavailable", "warn"))

        # ══ PYTHON RUNTIME ══════════════════════════════════════════════════
        if not quick:
            out += [_dim(""), _sys("  ── [PYTHON RUNTIME] ────────────────────────────────────────────")]
            pkgs = [
                ("fastapi",    True), ("uvicorn",  True), ("pydantic",   True),
                ("yaml",       True), ("rich",     True), ("typer",      True),
                ("aiofiles",   True), ("sqlite3",  True), ("httpx",      False),
                ("numpy",      False),("scipy",    False),("sklearn",    False),
                ("websockets", False),("requests", False),
            ]
            pkg_fail = []
            for name, crit in pkgs:
                ok = _pkg(name)
                if not ok and crit:
                    pkg_fail.append(name)
                icon  = _icon(ok, warn=not crit and not ok)
                color = _color(ok, warn=not crit and not ok)
                out.append(_line(f"  {icon}  {name:<18} {'OK' if ok else 'NOT INSTALLED'}", color))

        # ══ AGENTS ══════════════════════════════════════════════════════════
        out += [_dim(""), _sys("  ── [AGENT ROSTER] ─────────────────────────────────────────────")]
        total_agents = len(gs.unlocked_agents) + 61  # rough unlocked + registry size
        out += [
            _line(f"  ✓  Agent registry ........... 63 agents loaded", "success"),
            _line(f"  ✓  Unlocked agents ........... {', '.join(gs.unlocked_agents) if gs.unlocked_agents else 'none yet'}  ({len(gs.unlocked_agents)} of 63)", "success"),
            _line(f"  ✓  Trust Level Matrix ........ L0–L6 calibrated", "success"),
            _line(f"  {_icon(ser_exists)}  Serena convergence layer .. {'indexed' if ser_exists else 'cold start'}", _color(ser_exists, warn=True)),
            _line(f"  {_icon(_probe('127.0.0.1',3000))}  Gordon autonomous player .. {'ONLINE' if _probe('127.0.0.1',3000) else 'SUSPENDED  (Redis offline — make docker-core)'}", _color(_probe("127.0.0.1",3000), warn=True)),
        ]

        # ══ GAME STATE ══════════════════════════════════════════════════════
        out += [_dim(""), _sys("  ── [GAME STATE] ───────────────────────────────────────────────")]
        # Use quest_log for challenge count (quest_log.jsonl = one challenge per line)
        nusyq_ql  = _Path(ROOT / "state" / "quest_log.jsonl")
        ch_count  = sum(1 for _ in nusyq_ql.open()) if nusyq_ql.exists() else 259
        quest_count = ch_count  # same file — quests = challenges
        # Session count from the process-level store singleton
        try:
            import app.backend.main as _bm
            sess_count = _bm._store.count() if getattr(_bm, "_store", None) else gs.commands_run
        except Exception:
            sess_count = "active"
        out += [
            _line(f"  ✓  Commands registered ........ {cmd_count}", "success"),
            _line(f"  ✓  Challenges / Quests ......... {ch_count}", "success"),
            _line(f"  ✓  NuSyQ quest log ............. {quest_count} entries", "success"),
            _line(f"  ✓  Faction profiles ............. 10", "success"),
            _line(f"  ✓  Active sessions .............. {sess_count}", "success"),
            _line(f"  ✓  Session level ................. {gs.level}  ·  XP: {gs.xp}/{gs.xp_to_next}", "success"),
        ]

        # ══ BOOT SUMMARY ════════════════════════════════════════════════════
        total_systems = (3 + len(services) + len(_dbs_named) + 1 + 4 + 5 + 4)
        total_online  = net_ok + db_ok + (1 if api_up else 0)
        offline_count = total_systems - total_online
        status_word   = "NOMINAL" if net_fail == 0 else "DEGRADED"
        status_color  = "success" if net_fail == 0 else ("warn" if net_fail < 3 else "error")

        out += [
            _dim(""),
            _sys("  ╔══════════════════════════════════════════════════════════════════╗"),
            _sys(f"  ║  BOOT COMPLETE  ·  SYSTEM: {status_word:<10}                          ║"),
            _sys(f"  ║  Critical OK  ·  {offline_count} services offline (non-critical)         ║"),
            _sys("  ╚══════════════════════════════════════════════════════════════════╝"),
            _dim(""),
        ]

        # Agent comments at boot
        comments = []
        if not replit_url:
            comments.append(("[SERENA]", "warn", "AI integration URL missing. Operating in deterministic mode."))
        else:
            comments.append(("[SERENA]", "success", f"Cascade lattice online. {ser_count if ser_exists else 0} symbols indexed. Ψ-link stable."))
        if not _probe("127.0.0.1", 3000):
            comments.append(("[RAVEN]", "warn", "Gordon's dark. I'll cover autonomous ops. Keep your trace low."))
        if not _probe("127.0.0.1", 6379):
            comments.append(("[ADA-7]", "dim", "Redis offline — agent pub/sub suspended. Docker services: `make docker-core`."))
        comments.append(("[ADA-7]", "success", "Safety constraints nominal. Ghost — you're clear to operate."))

        for agent, color, msg in comments:
            out.append(_line(f"  {agent}: {msg}", color))

        out += [
            _dim(""),
            _dim("  syscheck  ·  services health  ·  ai status  ·  boot --quick"),
        ]
        return out

    def _cmd_syscheck(self, args: List[str]) -> List[dict]:
        """syscheck — show system health: LLM, Serena, DBs, command count."""
        import os, sqlite3

        gs = self.gs
        out = [
            _dim(""),
            _sys("  ── SYSTEM HEALTH ────────────────────────────────────"),
            _dim(""),
        ]

        # LLM status
        try:
            from llm_client import get_client as _gc
            st = _gc().status()
            backend  = st.get("active_backend", "unknown")
            replit   = st.get("replit_ai", False)
            llm_ok   = backend not in ("stub", "none", None)
            llm_icon = "✓" if llm_ok else "✗"
            out.append(_line(f"  {llm_icon}  LLM          {backend} {'(Replit AI)' if replit else ''}", "success" if llm_ok else "error"))
        except Exception as e:
            out.append(_line(f"  ✗  LLM          error: {e}", "error"))

        # Serena index
        try:
            db_path = "state/serena_memory.db"
            if os.path.exists(db_path):
                conn = sqlite3.connect(db_path)
                count = conn.execute("SELECT COUNT(*) FROM code_index").fetchone()[0]
                obs = conn.execute("SELECT COUNT(*) FROM observations").fetchone()[0]
                conn.close()
                out.append(_line(f"  ✓  Serena       {count:,} symbols indexed  {obs} observations", "success"))
            else:
                out.append(_line(f"  ○  Serena       not indexed yet  (serena walk to build)", "warn"))
        except Exception as _se:
            out.append(_line(f"  ✗  Serena       DB error: {_se}", "error"))

        # Core DBs
        core_dbs = [
            ("state/agents.db",         "Agent Memory"),
            ("state/lattice.db",        "Lattice Graph"),
            ("state/economy.db",        "Economy"),
            ("state/gordon_memory.db",  "Gordon Memory"),
        ]
        for db_p, db_name in core_dbs:
            exists = os.path.exists(db_p)
            icon   = "✓" if exists else "○"
            color  = "success" if exists else "dim"
            out.append(_line(f"  {icon}  {db_name:<14} {'online' if exists else 'not initialised'}", color))

        # Command count
        total_cmds = len([m for m in dir(self) if m.startswith("_cmd_")])
        out.append(_line(f"  ✓  Engine       {total_cmds} commands registered", "success"))
        out.append(_line(f"  ✓  Session      {gs.commands_run} commands run  ·  Level {gs.level}", "success"))

        # Replit AI check
        replit_url = os.environ.get("AI_INTEGRATIONS_OPENAI_BASE_URL", "")
        out.append(_line(f"  {'✓' if replit_url else '○'}  Replit AI    {'active at localhost:1106' if replit_url else 'URL not set'}", "success" if replit_url else "dim"))

        out += [
            _dim(""),
            _dim("  ai status  ·  serena status  ·  talk ada hello"),
            _dim(""),
        ]
        return out

