    def _cmd_ping(self, args):
        host = next((a for a in args if not a.startswith("-")), "")
        if not host:
            return _err("ping: missing host")
        count_arg = args[args.index("-c") + 1] if "-c" in args else "4"
        try:
            count = int(count_arg)
        except ValueError:
            count = 4
        count = min(count, 4)
        ip_map = {"nexus.corp": "10.0.1.100", "chimera-control": "10.0.1.254", "gateway": "10.0.1.1", "localhost": "127.0.0.1"}
        ip = ip_map.get(host, "10.0.1.99")
        out = [_line(f"PING {host} ({ip}) 56(84) bytes of data.")]
        for i in range(count):
            ms = 12 + i * 3
            out.append(_line(f"64 bytes from {ip}: icmp_seq={i+1} ttl=64 time={ms}.{i}ms"))
        out.append(_line(f"\n--- {host} ping statistics ---"))
        out.append(_line(f"{count} packets transmitted, {count} received, 0% packet loss"))
        self.gs.add_xp(5, "networking")
        return out

