    def _cmd_sudo(self, args):
        if not args:
            return _err("usage: sudo <command>")
        if args[0] == "-l":
            return [
                _line("Matching Defaults entries for ghost on node-7:"),
                _line("    env_reset, mail_badpass"),
                _line(""),
                _line("User ghost may run the following commands on node-7:"),
                _line("    (root) NOPASSWD: /usr/bin/find", "success"),
                _line(""),
                _line(">> GTFOBins: sudo find . -exec /bin/sh \\;", "warn"),
            ]
        if args[0] == "find" or (args[0] == "-u" and "root" in args and "find" in args):
            full_args = args[1:] if args[0] == "find" else args[3:]
            return self._cmd_find(full_args)
        if args[0] == "su":
            if self._root_shell:
                return [_line("root@node-7:~#", "root")]
            return [_line("sudo: su: authentication failure", "error")]
        # Network commands — give real equivalents instead of flat rejection
        cmd_name = args[0]
        _net_cmds = {"netstat", "ss", "ifconfig", "ip", "route", "arp", "iptables"}
        if cmd_name in _net_cmds:
            out = [_err(f"sudo: {cmd_name}: not in sudoers — ghost can only sudo: /usr/bin/find")]
            out += [
                _dim("  (ghost's sudo is limited to /usr/bin/find for GTFOBins escalation)"),
                _dim("  Try these without sudo:"),
            ]
            if cmd_name in ("netstat", "ss"):
                out += [_ok("    ss -tulnp"), _ok("    netstat -tulnp"), _ok("    cat /proc/net/tcp")]
            elif cmd_name in ("ifconfig", "ip"):
                out += [_ok("    ip addr"), _ok("    ip route"), _ok("    ifconfig")]
            out.append({"t": "suggest", "s": "ss -tulnp · ip addr · cat /proc/net/tcp · nmap", "prefix": "  Network:"})
            return out
        return _err(f"sudo: {cmd_name}: command not found or not in sudoers\n(ghost can only sudo: /usr/bin/find)")

