    def _cmd_base64(self, args):
        content = self._pipe_stdin
        file = next((a for a in args if not a.startswith("-")), None)
        if not content and file:
            r = self.fs.cat(file)
            content = r.get("content", "") if not r.get("error") else None
        decode = "-d" in args or "--decode" in args
        if content is None:
            return _err("base64: no input")
        content = content.strip()
        try:
            if decode:
                # Strip any [BASE64]: prefix from mission.enc style files
                text = re.sub(r'^\[BASE64\]:\s*', '', content)
                result = base64.b64decode(text + "==").decode("utf-8", errors="replace")
                self.gs.add_xp(15, "security")
                return [_line(result)]
            else:
                result = base64.b64encode(content.encode()).decode()
                return [_line(result)]
        except Exception as e:
            return _err(f"base64: invalid input: {e}")

    def _cmd_xxd(self, args):
        file = next((a for a in args if not a.startswith("-")), None)
        content = self._pipe_stdin or ""
        if file:
            r = self.fs.cat(file)
            content = r.get("content", "") if not r.get("error") else ""
        out = []
        for i, chunk in enumerate([content[j:j+16] for j in range(0, min(len(content), 256), 16)]):
            hex_part = " ".join(f"{ord(c):02x}" for c in chunk).ljust(47)
            asc_part = "".join(c if 32 <= ord(c) < 127 else "." for c in chunk)
            out.append(_line(f"{i*16:08x}: {hex_part}  {asc_part}"))
        return out or _dim("(empty)")

    def _cmd_hexdump_v1(self, args):
        return self._cmd_xxd(args)

    def _cmd_md5sum(self, args):
        file = next((a for a in args if not a.startswith("-")), None)
        content = self._pipe_stdin or ""
        if file:
            r = self.fs.cat(file)
            content = r.get("content", "") if not r.get("error") else ""
        h = hashlib.md5(content.encode()).hexdigest()
        label = file or "-"
        return [_line(f"{h}  {label}")]

    def _cmd_sha256sum(self, args):
        file = next((a for a in args if not a.startswith("-")), None)
        content = self._pipe_stdin or ""
        if file:
            r = self.fs.cat(file)
            content = r.get("content", "") if not r.get("error") else ""
        h = hashlib.sha256(content.encode()).hexdigest()
        label = file or "-"
        return [_line(f"{h}  {label}")]

    def _cmd_openssl(self, args):
        sub = args[0] if args else ""
        if "enc" in sub:
            return [_line("Encrypting... (simulated)", "dim")]
        if "genrsa" in sub:
            return [_line("Generating RSA private key, 2048 bit long modulus"), _line("...+++++")]
        return [_line("OpenSSL 1.1.1f  31 Mar 2020")]

