    def _install_pkg(self, args, manager: str) -> List[dict]:
        if not args or args[0] not in ("install", "i", "add"):
            return [_line(f"{manager}: {' '.join(args)}", "dim")]
        pkgs = [a for a in args[1:] if not a.startswith("-")]
        if not pkgs:
            return _err(f"{manager}: no packages specified")
        out: List[dict] = []
        for pkg in pkgs:
            if pkg not in self._installed_pkgs:
                self._installed_pkgs.add(pkg)
                self.gs.add_xp(10, "terminal")
                out.append(_line(f"[*] Installing {pkg}...", "system"))
                out.append(_ok(f"[+] {pkg} installed successfully"))
            else:
                out.append(_dim(f"{pkg} is already the newest version."))
        return out

    # ────────────────────────────────────────────────────────────────────
