    def _cmd_git(self, args):
        """git <subcommand> — real git operations on mounted repos and the workspace."""
        import subprocess as _sp, os as _os, shutil as _sh
        sub = args[0] if args else ""
        rest = args[1:]
        self.gs.add_xp(3, "git")

        # Determine working directory:
        # If the game's cwd is under a mount, use the real path.
        _real_cwd = self.fs._mounted_real_path(self.fs.cwd)
        _work_dir = _real_cwd if _real_cwd else _os.getcwd()

        def _run(*cmd, cwd=None, timeout=15):
            env = dict(_os.environ)
            token = env.get("GITHUB_TOKEN", "")
            if token:
                env["GIT_ASKPASS"] = "echo"
                env["GIT_USERNAME"] = "x-token"
                env["GIT_PASSWORD"] = token
            try:
                r = _sp.run(
                    cmd, capture_output=True, text=True, timeout=timeout,
                    cwd=cwd or _work_dir, env=env,
                )
                return r.stdout.strip() + (("\n" + r.stderr.strip()) if r.returncode else ""), r.returncode
            except _sp.TimeoutExpired:
                return f"git {cmd[1]}: timed out after {timeout}s", 1
            except Exception as e:
                return str(e), 1

        if not _sh.which("git"):
            return [_line("git: not found — install git to use real git commands", "error")]

        # ── STATUS ────────────────────────────────────────────────────────
        if sub == "status":
            out_txt, rc = _run("git", "status")
            if rc:
                return [_line("On branch main\nnothing to commit, working tree clean (virtual)", "dim")]
            return [_line(l) for l in out_txt.splitlines()] + [_dim(f"  cwd: {_work_dir}")]

        # ── LOG ───────────────────────────────────────────────────────────
        if sub == "log":
            out_txt, rc = _run("git", "log", "--oneline", "--decorate", "-15")
            if rc or not out_txt:
                return [
                    _line("commit a4f8e2c1 (HEAD -> main)", "warn"),
                    _line("    [CLASSIFIED] Initial commit — investigation notes"),
                    _dim("  (simulated — no real git history in current path)"),
                ]
            return [_line(l, "warn" if l.startswith("commit") or l[0:8].strip().isalnum() else "") for l in out_txt.splitlines()]

        # ── DIFF ──────────────────────────────────────────────────────────
        if sub == "diff":
            out_txt, rc = _run("git", "diff", "--stat")
            if not out_txt:
                return [_dim("  (no differences — working tree is clean)")]
            return [_line(l) for l in out_txt.splitlines()]

        # ── PULL ──────────────────────────────────────────────────────────
        if sub == "pull":
            out_txt, rc = _run("git", "pull", "--rebase", timeout=30)
            color = "success" if not rc else "error"
            out = [_line(l, color) for l in out_txt.splitlines()]
            if not rc:
                self.gs.add_xp(10, "git")
                out.append(_dim("  Msg⛛{git.pull.complete}"))
            return out

        # ── FETCH ────────────────────────────────────────────────────────
        if sub == "fetch":
            out_txt, rc = _run("git", "fetch", "--all", timeout=20)
            return [_line(l, "success" if not rc else "error") for l in out_txt.splitlines() or ["Fetched."]]

        # ── CLONE ────────────────────────────────────────────────────────
        if sub == "clone":
            if not rest:
                return [_line("usage: git clone <url> [<dir>]", "error")]
            url = rest[0]
            # Inject token for HTTPS GitHub URLs
            token = _os.environ.get("GITHUB_TOKEN", "")
            if token and "github.com" in url and url.startswith("https://"):
                url = url.replace("https://", f"https://x-token:{token}@")
            target = rest[1] if len(rest) > 1 else url.rstrip("/").split("/")[-1].removesuffix(".git")
            _repos_dir = _os.path.join(_os.getcwd(), "state", "repos")
            _os.makedirs(_repos_dir, exist_ok=True)
            _target_path = _os.path.join(_repos_dir, target)
            if _os.path.isdir(_target_path):
                return [_line(f"  Destination '{target}' already exists. Use: git pull", "warn"),
                        _dim(f"  Path: {_target_path}")]
            out_txt, rc = _run("git", "clone", url, _target_path, cwd=_repos_dir, timeout=60)
            if rc:
                return [_line(f"  Clone failed: {out_txt[:200]}", "error")]
            # Auto-mount into VFS
            _vpath = f"/repos/{target}"
            _mounted = self.fs.mount(_vpath, _target_path)
            self.gs.add_xp(25, "git")
            self.gs.flags.setdefault("mounted_repos", {})[target] = _target_path
            return [
                _line(f"  Cloning into '{target}'…", "dim"),
                _line(f"  ✓ Cloned to {_target_path}", "success"),
                _line(f"  ✓ Mounted at {_vpath}", "success"),
                _dim(f"  cd {_vpath}  — to browse the repo"),
                _dim("  Msg⛛{git.clone.complete}"),
                _suggest(f"cd {_vpath} · ls {_vpath} · repos"),
            ]

        # ── PUSH (consent-guarded) ────────────────────────────────────────
        if sub == "push":
            _write_enabled = self.gs.flags.get("git_write_enabled", False)
            if not _write_enabled:
                return [
                    _line("  git push: write operations require consent.", "warn"),
                    _dim("  Run: git write enable  — to unlock push/commit"),
                ]
            out_txt, rc = _run("git", "push", *rest, timeout=30)
            return [_line(l, "success" if not rc else "error") for l in out_txt.splitlines()]

        # ── WRITE ENABLE / DISABLE ────────────────────────────────────────
        if sub == "write":
            mode = rest[0].lower() if rest else "status"
            if mode == "enable":
                self.gs.flags["git_write_enabled"] = True
                return [_line("  Git write mode: ENABLED", "warn"),
                        _dim("  commit and push commands are now live."),
                        _dim("  Disable with: git write disable")]
            elif mode == "disable":
                self.gs.flags["git_write_enabled"] = False
                return [_line("  Git write mode: DISABLED (read-only)", "success")]
            else:
                enabled = self.gs.flags.get("git_write_enabled", False)
                return [_line(f"  Git write mode: {'ENABLED' if enabled else 'DISABLED'}", "warn" if enabled else "dim")]

        # ── COMMIT ────────────────────────────────────────────────────────
        if sub == "commit":
            _write_enabled = self.gs.flags.get("git_write_enabled", False)
            if not _write_enabled:
                return [_line("  git commit: write mode disabled.", "warn"),
                        _dim("  Run: git write enable")]
            msg = " ".join(rest).lstrip("-m").strip().strip('"\'') or "auto-commit from Terminal Depths"
            out_txt, rc = _run("git", "commit", "-am", msg)
            if not rc:
                self.gs.add_xp(15, "git")
            return [_line(l, "success" if not rc else "error") for l in out_txt.splitlines()]

        # ── BLAME (T5) ───────────────────────────────────────────────────
        if sub == "blame":
            _blame_file = rest[0] if rest else None

            # Agent signature database — who "wrote" what in the lore
            _AGENT_BLAME = {
                "commands.py":      ("ADA-7",      "ada@resistance.net",   "feat: initial recon toolkit"),
                "filesystem.py":    ("ZERO",        "zero@null.void",       "chore: planted the secrets"),
                "gamestate.py":     ("SERENA",      "serena@nexuscorp.int", "feat: surveillance hooks"),
                "session.py":       ("CYPHER",      "cypher@anon.tor",      "fix: obfuscated session trail"),
                "agents.py":        ("RAVEN",       "raven@darknet.io",     "feat: ghost protocol agents"),
                "factions.py":      ("GORDON",      "gordon@localhost",     "feat: faction alignment matrix"),
                "narrative_arcs.py":("MALICE",      "malice@shadow.council","feat: planted narrative trap"),
                "story.py":         ("ADA-7",       "ada@resistance.net",   "docs: embedded mission briefing"),
                "economy.py":       ("GORDON",      "gordon@localhost",     "feat: credit laundering system"),
                "trust_matrix.py":  ("SERENA",      "serena@nexuscorp.int", "feat: trust surveillance layer"),
                "dungeon_engine.py":("ZERO",        "zero@null.void",       "feat: left the basement open"),
                "dream_engine.py":  ("ZERO",        "zero@null.void",       "feat: recursive dream state"),
                "anomaly.py":       ("WATCHER",     "watcher@chimera.sys",  "feat: behavioral telemetry"),
            }

            if _blame_file:
                fname = _blame_file.split("/")[-1]
                # Try real git blame first
                out_txt, rc = _run("git", "blame", "--porcelain", _blame_file)
                if not rc and out_txt:
                    lines = out_txt.splitlines()[:20]
                    self.gs.add_xp(8, "git")
                    return [_line(l, "dim") for l in lines] + [_ok("  +8 XP [git]")]

                # Fallback: lore blame
                agent, email, msg = _AGENT_BLAME.get(fname, ("UNKNOWN", "unknown@void", "???"))
                import random as _rb
                _hash = "".join(_rb.choice("0123456789abcdef") for _ in range(8))
                _lines = [
                    f"^{_hash} ({agent} <{email}> 2089-03-21 00:00:00 +0000  1) {msg}",
                    f" {_hash} ({agent} <{email}> 2089-03-21 00:00:00 +0000  2) # classified",
                    f" {_hash} ({agent} <{email}> 2089-03-21 00:00:00 +0000  3) # do not audit",
                ]
                self.gs.add_xp(8, "git")
                return (
                    [_sys(f"  git blame: {_blame_file}")]
                    + [_line(l, "warn") for l in _lines]
                    + [_dim(""), _ok("  +8 XP [git]")]
                )

            # No file: show all agent attributions as easter egg
            out = [_sys("  ═══ CODEBASE BLAME — AGENT ATTRIBUTION ═══"), _dim("")]
            for fname, (agent, email, msg) in _AGENT_BLAME.items():
                out.append(_line(f"  {agent:<12} {fname:<25} {msg}", "dim"))
            out.append(_dim(""))
            out.append(_dim("  git blame <file>  — inspect a specific file"))
            self.gs.add_xp(5, "git")
            return out

        # ── INIT ─────────────────────────────────────────────────────────
        if sub == "init":
            return [_line("Initialized empty Git repository in .git/", "success")]

        # ── DEFAULT (passthrough for non-destructive commands) ────────────
        _safe = {"branch", "tag", "remote", "stash", "show", "shortlog", "describe", "rev-parse"}
        if sub in _safe:
            out_txt, rc = _run("git", sub, *rest, timeout=10)
            return [_line(l) for l in out_txt.splitlines()] if out_txt else [_dim(f"git {sub}: ok")]

        return [_line(f"git {sub}: ok", "dim"),
                _dim("  Available: status · log · diff · pull · fetch · clone · push · commit · write · branch")]

