    # Ecosystem repos managed by the harvest command
    _ECOSYSTEM_REPOS = [
        ("NuSyQ-Hub",          "https://github.com/KiloMusician/NuSyQ-Hub.git"),
        ("SimulatedVerse",     "https://github.com/KiloMusician/SimulatedVerse.git"),
        ("NuSyQ-Ultimate",     "https://github.com/KiloMusician/-NuSyQ_Ultimate_Repo.git"),
    ]

    def _cmd_repos(self, args):
        """repos — list all mounted repositories and their git status."""
        import os as _os, subprocess as _sp
        self.gs.add_xp(3, "git")
        mounts = self.fs.list_mounts()
        stored = self.gs.flags.get("mounted_repos", {})
        all_repos = {}
        for name, path in stored.items():
            all_repos[name] = path
        for vpath, rpath in mounts.items():
            name = vpath.split("/")[-1]
            all_repos.setdefault(name, rpath)

        if not all_repos:
            return [
                _line("  No repositories mounted.", "dim"),
                _dim("  Clone one with: git clone <url>"),
                _dim("  Or harvest the ecosystem: harvest"),
                _suggest("git clone · harvest"),
            ]

        out = [_line("  ╔══ MOUNTED REPOSITORIES ══╗", "system")]
        for name, rpath in all_repos.items():
            exists = _os.path.isdir(rpath)
            status = "✓ present" if exists else "✗ missing"
            color = "success" if exists else "error"
            branch = ""
            if exists:
                try:
                    r = _sp.run(["git", "branch", "--show-current"], capture_output=True,
                                text=True, cwd=rpath, timeout=4)
                    branch = r.stdout.strip()
                except Exception:
                    pass
            vpath_display = f"/repos/{name}"
            branch_txt = f"  [{branch}]" if branch else ""
            out.append(_line(f"  {status}  {name}{branch_txt}", color))
            out.append(_dim(f"       real: {rpath}"))
            out.append(_dim(f"       virt: {vpath_display}"))

        out += [
            _line(f"  ╚══ {len(all_repos)} repo(s) total ══╝", "system"),
            _suggest("git pull · git status · git log · harvest · mount"),
        ]
        return out

    def _cmd_clone(self, args):
        """clone <url> [name] — clone a GitHub repo and mount it into the VFS."""
        if not args:
            return [
                _line("  usage: clone <github-url> [name]", "error"),
                _dim("  Example: clone https://github.com/KiloMusician/NuSyQ-Hub.git"),
                _suggest("repos · harvest"),
            ]
        # Delegate to the real git clone handler
        return self._cmd_git(["clone"] + args)

    def _cmd_mount(self, args):
        """mount <real-path> [vpath] — mount a real directory into the VFS."""
        import os as _os
        if not args:
            mounts = self.fs.list_mounts()
            if not mounts:
                return [_line("  No active mounts.", "dim"), _suggest("repos · clone · harvest")]
            out = [_line("  ╔══ ACTIVE MOUNTS ══╗", "system")]
            for vp, rp in mounts.items():
                exists = "✓" if _os.path.isdir(rp) else "✗"
                out.append(_line(f"  {exists} {vp}  →  {rp}"))
            out.append(_suggest("cd /repos · git status · repos"))
            return out

        real_path = args[0]
        name = args[1] if len(args) > 1 else _os.path.basename(real_path.rstrip("/"))
        vpath = f"/repos/{name}"
        existed = self.fs.mount(vpath, real_path)
        self.gs.flags.setdefault("mounted_repos", {})[name] = real_path
        self.gs.add_xp(5, "git")
        color = "success" if existed else "warn"
        status = "real directory found" if existed else "mount registered (directory not yet present)"
        return [
            _line(f"  Mounted: {vpath}  →  {real_path}", color),
            _dim(f"  {status}"),
            _suggest(f"ls {vpath} · git status · repos"),
        ]

    def _cmd_harvest(self, args):
        """harvest [--dry-run] — clone all ecosystem repos into state/repos/ and mount them."""
        import os as _os, subprocess as _sp
        dry = "--dry-run" in args or "-n" in args
        token = _os.environ.get("GITHUB_TOKEN", "")

        out = [
            _line("  ╔══════════════════════════════════╗", "system"),
            _line("  ║   REPOSITORY HARVEST INITIATED   ║", "system"),
            _line("  ╚══════════════════════════════════╝", "system"),
            _dim("  Msg⛛{harvest.begin}"),
        ]

        _repos_dir = _os.path.join(_os.getcwd(), "state", "repos")
        _os.makedirs(_repos_dir, exist_ok=True)

        cloned, updated, failed = 0, 0, 0
        for name, url in self._ECOSYSTEM_REPOS:
            _target = _os.path.join(_repos_dir, name)
            out.append(_line(f"\n  [{name}]", "warn"))

            if dry:
                exists = _os.path.isdir(_target)
                action = "update" if exists else "clone"
                out.append(_dim(f"    dry-run: would {action} → {_target}"))
                continue

            # Inject token for HTTPS
            auth_url = url
            if token and "github.com" in url and url.startswith("https://"):
                auth_url = url.replace("https://", f"https://x-token:{token}@")

            if _os.path.isdir(_target):
                # Repo already cloned — update
                try:
                    r = _sp.run(["git", "pull", "--rebase"], capture_output=True,
                                text=True, cwd=_target, timeout=30)
                    if r.returncode == 0:
                        out.append(_line(f"    ✓ Updated: {r.stdout.strip()[:80]}", "success"))
                        updated += 1
                    else:
                        out.append(_line(f"    ⚠ Pull failed: {r.stderr.strip()[:80]}", "warn"))
                        failed += 1
                except Exception as e:
                    out.append(_line(f"    ✗ Error: {e}", "error"))
                    failed += 1
            else:
                # Clone fresh
                try:
                    r = _sp.run(["git", "clone", auth_url, _target],
                                capture_output=True, text=True, timeout=60)
                    if r.returncode == 0:
                        out.append(_line(f"    ✓ Cloned → {_target}", "success"))
                        cloned += 1
                    else:
                        msg = r.stderr.strip()[:120]
                        if "Repository not found" in msg or "not found" in msg.lower():
                            out.append(_line(f"    ✗ Not found (private or non-existent)", "error"))
                        elif "Authentication failed" in msg:
                            out.append(_line(f"    ✗ Auth failed — check GITHUB_TOKEN", "error"))
                        else:
                            out.append(_line(f"    ✗ {msg[:80]}", "error"))
                        failed += 1
                        continue
                except Exception as e:
                    out.append(_line(f"    ✗ Exception: {e}", "error"))
                    failed += 1
                    continue

            # Mount into VFS regardless of whether just cloned or already existed
            _vpath = f"/repos/{name}"
            self.fs.mount(_vpath, _target)
            self.gs.flags.setdefault("mounted_repos", {})[name] = _target
            out.append(_dim(f"    mounted: {_vpath}"))

        if not dry:
            self.gs.add_xp(50, "git")
            self.gs.add_story_beat("harvest_complete")
            out += [
                _line(f"\n  ╔══ HARVEST COMPLETE: +{cloned} cloned, +{updated} updated, {failed} failed ══╗", "success"),
                _dim("  Msg⛛{harvest.complete}"),
                _suggest("repos · ls /repos · git status · gordon awaken"),
            ]
        else:
            out.append(_dim("\n  dry-run complete — pass no flags to execute"))
        return out

