    def _cmd_exploit(self, args):
        target = args[0] if args else ""
        if target == "chimera":
            if not self._root_shell:
                # ── Creative glitch: the exploit tries to run but UID check slams it ──
                import random as _rng
                glitch_chars = ["█", "▓", "▒", "░", "▄", "▀", "■", "▪"]
                glitch = "".join(_rng.choice(glitch_chars) for _ in range(28))
                return [
                    _line("", "dim"),
                    _err("╔══════════════════════════════════════════════════════╗"),
                    _err("║  ✗ EXPLOIT FAILED — UID CHECK REJECTED               ║"),
                    _err("╚══════════════════════════════════════════════════════╝"),
                    _line(""),
                    _line("  uid=1000(ghost) — CHIMERA auth layer requires uid=0 (root).", "error"),
                    _line("  Your payload reached the target. Then the UID gate vaporized it.", "dim"),
                    _line(""),
                    _line(f"  {glitch} PROCESS TERMINATED {glitch[:14]}", "error"),
                    _line(""),
                    _line("  [CYPHER]: Ha. You tried it without root. Bold. Catastrophically wrong, but bold.", "npc"),
                    _line("  [CYPHER]: Listen — GTFOBins. The sudo path is already open.", "npc"),
                    _line("  [CYPHER]: sudo find . -exec /bin/sh \\;   ← do that first.", "npc"),
                    _line(""),
                    _line("  ESCALATION PATH:", "warn"),
                    _line("    1. sudo -l                          ← confirm sudo rights", "dim"),
                    _line("    2. sudo find . -exec /bin/sh \\;   ← GTFOBins shell", "dim"),
                    _line("    3. exploit chimera                  ← NOW it will work", "dim"),
                    _line(""),
                ]
            if not self._chimera_connected:
                import random as _rng_nc
                _glitch2 = "".join(_rng_nc.choice("▓▒░█■▪▄▀") for _ in range(24))
                _noise2 = "".join(_rng_nc.choice("01") for _ in range(40))
                return [
                    _line("", "dim"),
                    _err("╔══════════════════════════════════════════════════════╗"),
                    _err("║  ✗ EXPLOIT FAILED — CONNECTION REFUSED               ║"),
                    _err("╚══════════════════════════════════════════════════════╝"),
                    _line(""),
                    _line(f"  [{_noise2}]", "dim"),
                    _line("  Payload launched. CHIMERA auth layer returned RST ACK.", "dim"),
                    _line("  You need an active session on port 8443 before exploiting.", "dim"),
                    _line(""),
                    _line(f"  {_glitch2} SOCKET RESET {_glitch2[:12]}", "error"),
                    _line(""),
                    _line("  [CYPHER]: You skipped the handshake. CHIMERA needs an open session.", "npc"),
                    _line("  [CYPHER]: Connect first, THEN drop the payload.", "npc"),
                    _line(""),
                    _line("  CORRECT SEQUENCE:", "warn"),
                    _line("    1. nc chimera-control 8443   ← open session", "dim"),
                    _line("    2. exploit chimera           ← NOW send the payload", "dim"),
                    _line(""),
                ]
            self._chimera_exploited = True
            self.gs.unlock("chimera_exploited")
            self.gs.add_xp(100, "security")

            # ITEM 11 — COLLECTION QUEST: RARE EXPLOITS
            collected = self.gs.flags.setdefault("collected_exploits", [])
            exploit_id = f"exploit_{target}"
            if exploit_id not in collected:
                collected.append(exploit_id)
                count = len(collected)
                if count == 3: self.gs.add_story_beat("exploits_3")
                if count == 6: self.gs.add_story_beat("exploits_6")
                if count == 10:
                    self.gs.add_story_beat("exploits_10")
                    self.gs.unlock("EXPLOIT_COLLECTOR")
                    self.gs.add_xp(500, "security")

            # Wire faction rep
            _chimera_rep = self._faction_rep_event("chimera_hack")
            return [
                _line(""),
                _line("╔══════════════════════════════════════════════╗", "success"),
                _line("║   CHIMERA EXPLOIT SUCCESSFUL                 ║", "success"),
                _line("╠══════════════════════════════════════════════╣", "success"),
                _line("║   AUTH_TOKEN authenticated: NX-CHIM-...      ║", "success"),
                _line("║   Master key uploaded to control interface   ║", "success"),
                _line("║   Surveillance network: COMPROMISED          ║", "success"),
                _line("║   847 endpoints: OFFLINE                     ║", "success"),
                _line("╚══════════════════════════════════════════════╝", "success"),
                _line(""),
                _line(">> CHIMERA is down. 847 surveillance endpoints are offline.", "success"),
                _line(">> Run `exfil` to transmit evidence to Ada.", "dim"),
            ] + _chimera_rep
        # ── Secondary exploitable nodes ──────────────────────────────────────────
        _node_targets = {
            "node-1": {
                "req_root": False,
                "xp": 35, "skill": "security",
                "beat": "node1_exploited",
                "flavor": "Node-1 auth crumbled — basic OpenSSH vuln, CVE-2019-6111.",
                "loot": "user credentials cached in /etc/shadow.bak",
            },
            "nexus-gateway": {
                "req_root": False,
                "xp": 50, "skill": "security",
                "beat": "nexus_gateway_exploited",
                "flavor": "Nexus gateway fell to an unpatched Nginx path traversal.",
                "loot": "internal routing table — 14 hidden subnets revealed",
            },
            "nexus-db": {
                "req_root": True,
                "xp": 70, "skill": "security",
                "beat": "nexus_db_exploited",
                "flavor": "PostgreSQL pg_hba bypass — unauthenticated query accepted.",
                "loot": "847 employee records + CHIMERA endpoint map",
            },
            "collector-node": {
                "req_root": False,
                "xp": 45, "skill": "security",
                "beat": "collector_exploited",
                "flavor": "Collector node had debug mode enabled. Classic.",
                "loot": "telemetry streams — CHIMERA data collection patterns exposed",
            },
            "darknet-relay-7": {
                "req_root": False,
                "xp": 40, "skill": "security",
                "beat": "darknet_relay_exploited",
                "flavor": "Tor relay running ancient Tor 0.3.4 — timing attack succeeded.",
                "loot": "shadow_council relay IDs — partial deanonymization",
            },
            "watcher-relay": {
                "req_root": True,
                "xp": 60, "skill": "security",
                "beat": "watcher_relay_exploited",
                "flavor": "Watcher surveillance relay — compromised. Ironic.",
                "loot": "surveillance logs — Ada's movements tracked for 6 months",
            },
        }
        if target in _node_targets:
            info = _node_targets[target]
            if info["req_root"] and not self._root_shell:
                return [
                    _err(f"exploit: {target} requires uid=0 (run `sudo find . -exec /bin/sh \\;` first)"),
                    _line("  This node has kernel-level auth. Root access required.", "dim"),
                ]
            beat = info["beat"]
            if beat in self.gs.story_beats:
                return [_line(f"  {target} already compromised.", "dim"),
                        _line(f"  Loot: {info['loot']}", "success")]
            # R7 — skill check with gear + crafting buffs applied
            _r7_gear_bonus = 0
            _r7_craft_bonus = 0
            try:
                from app.game_engine.gear_system import GearSystem as _GSR7
                _r7_gear_bonus = _GSR7().get_bonus(self.gs, "exploit")
            except Exception:
                pass
            try:
                from app.game_engine.crafting_engine import CraftingEngine as _CER7
                _r7_craft_bonus = _CER7().get_active_buff_bonus(self.gs, "exploit")
            except Exception:
                pass
            _r7_bonus_total = _r7_gear_bonus + _r7_craft_bonus
            _r7_xp = info["xp"] + (_r7_bonus_total // 5)  # bonus gear gives slight XP boost
            self.gs.unlock(beat)
            self.gs.add_xp(_r7_xp, info["skill"])
            _bonus_line = []
            if _r7_bonus_total > 0:
                _bonus_line = [_line(f"  Gear bonus applied: +{_r7_bonus_total} exploit → +{_r7_bonus_total//5} bonus XP", "info")]
            return [
                _line(""),
                _line(f"  ╔═══ EXPLOIT SUCCESSFUL: {target.upper()} ═══╗", "success"),
                _line(f"  ║  {info['flavor']}", "success"),
                _line(f"  ║  Loot: {info['loot']}", "success"),
                _line(f"  ╚══════════════════════════════════╝", "success"),
                _line(""),
                _line(f"  +{_r7_xp} XP [{info['skill']}]", "success"),
            ] + _bonus_line + [
                _line("  Run `nodes` to claim this node for your territory.", "dim"),
            ]
        # ── chimera-control: high-value target, requires security >= 40 ──────
        if target in ("chimera-control", "chimera_control"):
            sec = self.gs.skills.get("security", 0)
            if sec < 40:
                return [
                    _err("╔══════════════════════════════════════════════════════════╗"),
                    _err("║  ✗ EXPLOIT FAILED — INSUFFICIENT SECURITY SKILL         ║"),
                    _err("╚══════════════════════════════════════════════════════════╝"),
                    _dim(f"  chimera-control requires security >= 40  (yours: {sec})"),
                    _dim("  Raise security skill: forensics  reverse_eng  crack <hash>"),
                ]
            self.gs.add_story_beat("exploit_chimera_control")
            self.gs.add_xp(200, "security")
            return [
                _sys("╔══════════════════════════════════════════════════════════╗"),
                _sys("║  EXPLOIT — chimera-control:8443                         ║"),
                _sys("╚══════════════════════════════════════════════════════════╝"),
                _dim("  [*] Probing TLS endpoint..."),
                _dim("  [*] CVE-2024-9174 — unpatched heartbeat buffer overflow"),
                _line("  [+] Overflow triggered — stack smashed", "warn"),
                _line("  [+] RCE payload delivered — shell obtained", "warn"),
                _dim(""),
                _line("  ► Access: /opt/chimera/core/ — now readable", "success"),
                _line("  ► Access: /opt/chimera/keys/master.key — now accessible", "success"),
                _dim(""),
                _lore("  [CYPHER]: You're in. Don't celebrate. They know within 30 seconds."),
                _dim("  → cat /opt/chimera/keys/master.key  |  forensics /opt/chimera/core/encrypted.dat"),
            ]

        # ── surveillance-mesh: distributed sensor network ──────────────────
        if target in ("surveillance-mesh", "surveillance_mesh"):
            self.gs.add_story_beat("exploit_surveillance_mesh")
            self.gs.add_xp(120, "networking")
            return [
                _sys("=== EXPLOIT — surveillance-mesh ==="),
                _dim("  [*] Scanning DaemonSet pods..."),
                _dim("  [*] Intercepting sensor stream..."),
                _line("  [+] Sensor feed redirected — Ghost invisible to mesh for 300s", "success"),
                _dim("  Active nodes blinded: chimera-node-001 through chimera-node-071"),
                _dim(""),
                _lore("  [ADA-7]: That bought us time. Use it."),
            ]

        # ── nexus-relay / nexus_relay: the mole's transmission node ───────
        if target in ("nexus-relay", "nexus_relay", "nexus-relay-node-3"):
            self.gs.add_story_beat("exploit_nexus_relay")
            self.gs.add_xp(100, "networking")
            self.gs.flags["nexus_relay_hacked"] = True
            return [
                _sys("=== EXPLOIT — NEXUS_RELAY_NODE-3 ==="),
                _dim("  [*] Targeting relay node..."),
                _dim("  [*] Injecting packet sniffer..."),
                _line("  [+] Sniffer active — capturing all relay traffic", "success"),
                _dim(""),
                _line("  CAPTURED TRANSMISSION:", "warn"),
                _dim("  02:03:47 → NEXUS_CORE  [ENCRYPTED]  [sender: UNKNOWN_AGENT]"),
                _dim("  02:03:48 → ACK received"),
                _dim(""),
                _lore("  Someone is using this relay. Check /var/log/agent_comms.log"),
                _dim("  mole clue +1 acquired"),
            ]

        return _err(f"exploit: unknown target '{target}' — try: node-1, nexus-gateway, nexus-db, collector-node, darknet-relay-7, watcher-relay, chimera, chimera-control, surveillance-mesh, nexus-relay")

