    def _cmd_story(self, args: List[str]) -> List[dict]:
        """story — show story arc progress, requirements, and next steps."""
        gs = self.gs
        beats = gs.story_beats

        # Define the main arc checklist
        arc_steps = [
            ("root_achieved",      "✓" if "root_achieved" in beats else "·",
             "Obtain root shell via GTFOBins",
             "sudo find . -exec /bin/sh \\;"),
            ("master_key_read",    "✓" if "master_key_read" in beats else "·",
             "Read the CHIMERA master key",
             "cat /opt/chimera/keys/master.key"),
            ("chimera_connected",  "✓" if "chimera_connected" in beats else "·",
             "Connect to CHIMERA control interface",
             "nc chimera-control 8443"),
            ("first_exploit",      "✓" if "first_exploit" in beats else "·",
             "Deploy exploit payload against CHIMERA",
             "exploit chimera"),
            ("first_exfil",        "✓" if "first_exfil" in beats else "·",
             "Exfiltrate CHIMERA data to Ada",
             "exfil"),
            ("mission_complete",   "✓" if "mission_complete" in gs.achievements else "·",
             "Complete the mission arc",
             "ascend-story"),
        ]

        done_count = sum(1 for _, mark, _, _ in arc_steps if mark == "✓")
        total = len(arc_steps)
        pct = done_count * 100 // total
        bar = "█" * (pct // 10) + "░" * (10 - pct // 10)

        out = [
            _sys("╔══════════════════════════════════════════════════════╗"),
            _sys("║           GHOST OPERATIONAL STORY ARC                ║"),
            _sys("╠══════════════════════════════════════════════════════╣"),
            _sys(f"║  Progress : [{bar}] {pct:3d}%  ({done_count}/{total} milestones)     ║"),
            _sys("╚══════════════════════════════════════════════════════╝"),
            _line(""),
            _line("  ─── MAIN ARC: OPERATION CHIMERA TAKEDOWN ─────────────", "system"),
            _line(""),
        ]

        for beat_id, mark, desc, cmd_hint in arc_steps:
            color = "success" if mark == "✓" else "dim"
            out.append(_line(f"  [{mark}] {desc}", color))
            if mark != "✓":
                out.append(_line(f"       → {cmd_hint}", "warn"))
                break  # Stop at first incomplete step

        out.append(_line(""))

        # Side quests
        quests_active = []
        if gs.tutorial_step < 42:
            quests_active.append(f"Tutorial: {gs.tutorial_step}/42 steps")
        if "koschei_death_found" not in beats:
            quests_active.append("Koschei Chain: cat /home/ghost/.koschei")
        if "zero_diary_reconstructed" not in beats:
            frag_count = sum(1 for k in gs.flags if "frag" in k.lower() and gs.flags[k])
            quests_active.append(f"Zero's Diary: {frag_count}/5 fragments")
        if "fates_tapestry_revealed" not in beats:
            quests_active.append("Fates Quest: fates (Clotho/Lachesis/Atropos)")

        if quests_active:
            out.append(_line("  ─── ACTIVE SIDE QUESTS ─────────────────────────────", "system"))
            out.append(_line(""))
            for q in quests_active[:5]:
                out.append(_line(f"  ◆ {q}", "info"))
            out.append(_line(""))

        # Guidance for lost players
        if done_count == 0:
            out.extend([
                _line("  ─── WHERE TO START ──────────────────────────────────", "warn"),
                _line(""),
                _line("  You need root access before anything else.", "dim"),
                _line("  Ghost has limited sudo rights — only for /usr/bin/find.", "dim"),
                _line("  GTFOBins exploits this to get a root shell:", "dim"),
                _line(""),
                _line("    sudo -l                          ← confirm the path", "dim"),
                _line("    sudo find . -exec /bin/sh \\;   ← escalate to root", "dim"),
                _line(""),
            ])

        if done_count == total:
            out.extend([
                _line("  ★ STORY ARC COMPLETE — You are ready to ASCEND.", "success"),
                _line("    Type: ascend   to enter the next layer.", "dim"),
            ])
        else:
            next_step = next((cmd for _, m, _, cmd in arc_steps if m != "✓"), None)
            if next_step and done_count > 0:
                out.append(_line(f"  NEXT: {next_step}", "warn"))

        out.append(_line(""))
        out.append(_dim("  story       — this screen"))
        out.append(_dim("  status      — full game dashboard"))
        out.append(_dim("  quests      — daily / active quests"))
        return out

    def _cmd_status(self, args: List[str]) -> List[dict]:
        """status — full game dashboard: level, XP, skills, arc, timer, faction."""
        gs = self.gs
        beats = gs.story_beats

        # Level bar
        xp_pct = min(100, gs.xp * 100 // max(1, gs.xp_to_next))
        lvl_bar = "█" * (xp_pct // 10) + "░" * (10 - xp_pct // 10)

        # Timer
        timer_info = "N/A"
        timer_status = "STABLE"
        try:
            import time as _time
            run_start = gs.flags.get("run_start_time", 0) or _time.time()
            elapsed = _time.time() - run_start
            remaining = max(0, 72 * 3600 - elapsed)
            hh = int(remaining // 3600)
            mm = int((remaining % 3600) // 60)
            ss = int(remaining % 60)
            timer_info = f"{hh:02d}:{mm:02d}:{ss:02d}"
            if remaining < 3600:
                timer_status = "CRITICAL"
            elif remaining < 21600:
                timer_status = "WARNING"
        except Exception:
            pass

        # Arc progress
        arc_beats = ["root_achieved", "master_key_read", "chimera_connected",
                     "first_exploit", "first_exfil"]
        arc_done = sum(1 for b in arc_beats if b in beats)
        mission_done = "mission_complete" in gs.achievements

        # Top skills
        top_skills = sorted(gs.skills.items(), key=lambda x: x[1], reverse=True)[:4]
        skill_str = "  ".join(f"{k.replace('_',' ')[:12]} {v}" for k, v in top_skills) or "none yet"

        # Faction
        faction_str = "Unaffiliated"
        pledged = gs.flags.get("faction_pledged")
        if pledged:
            faction_str = pledged.title()
        elif self.factions:
            try:
                all_f = self.factions.all_status()
                top_f = max(all_f.items(), key=lambda kv: kv[1]["reputation"])
                if top_f[1]["reputation"] > 0:
                    faction_str = f"{top_f[1]['display_name']} ({top_f[1]['reputation']} rep)"
            except Exception:
                pass

        # Path and Mode
        chosen_path = gs.flags.get("chosen_path", "none").upper()
        game_mode = gs.flags.get("game_mode", "default").upper()

        out = [
            _sys("╔══════════════════════════════════════════════════════╗"),
            _sys("║              GHOST — OPERATIONAL STATUS              ║"),
            _sys("╚══════════════════════════════════════════════════════╝"),
            _line(""),
            _line(f"  Level    : {gs.level}/125  [{lvl_bar}] {gs.xp}/{gs.xp_to_next} XP", "info"),
            _line(f"  Commands : {gs.commands_run} run   |  Achievements: {len(gs.achievements)}", "dim"),
            _line(f"  Timer    : ⏱ {timer_info} remaining  [{timer_status}]",
                  "error" if timer_status == "CRITICAL" else "warn" if timer_status == "WARNING" else "success"),
            _line(f"  Path     : {chosen_path}  |  Mode: {game_mode}", "dim"),
            _line(""),
            _line(f"  ─── STORY ARC ─────────────────────────────────────", "system"),
            _line(f"  Main arc : {arc_done}/5 milestones {'(COMPLETE ✓)' if mission_done else ''}", "success" if mission_done else "dim"),
            _line(f"  Tutorial : {min(gs.tutorial_step, 42)}/42 steps", "success" if gs.tutorial_step >= 42 else "info"),
            _line(""),
            _line(f"  ─── SKILLS (TOP 4) ────────────────────────────────", "system"),
            _line(f"  {skill_str}", "dim"),
            _line(""),
            _line(f"  ─── FACTION ───────────────────────────────────────", "system"),
            _line(f"  Allegiance: {faction_str}", "info"),
        ]

        if self.factions:
            try:
                all_status = self.factions.all_status()
                for f_id in ["resistance", "nexuscorp", "academic", "darknet"]:
                    if f_id in all_status:
                        f_info = all_status[f_id]
                        rep = f_info.get("reputation", 0)
                        bar_val = min(10, max(0, rep // 10))
                        bar = "█" * bar_val + "░" * (10 - bar_val)
                        name = f_info.get("display_name", f_id.title())
                        out.append(_line(f"  ├── {name:<12}  [{bar}]  rep: {rep}", "dim"))
            except Exception:
                pass

        out.append(_line(""))

        # Root shell indicator
        root_icon = "✓ ROOT" if self._root_shell else "✗ ghost (no root yet)"
        root_color = "success" if self._root_shell else "dim"
        out.append(_line(f"  Shell    : {root_icon}", root_color))

        # Time Loop Storyline
        if gs.flags.get("prestige_count", 0) >= 1 and "time_loop_revealed" not in gs.story_beats:
            out.append(_dim(""))
            out.append(_lore("[WATCHER]: This is not your first run. You remember, don't you?"))

        # Loop Closes (ITEM 11)
        if 'ascend_story_complete' in gs.story_beats and gs.flags.get('prestige_count', 0) >= 2:
            out.append(_line(""))
            out.append(_lore("  [WATCHER]: The station plays the same song again. You notice the chord change. Third time you've heard it. You know what comes next."))
            if 'loop_closes' not in gs.story_beats:
                gs.add_story_beat('loop_closes')

        # Next action hint
        out.append(_line(""))
        if not self._root_shell:
            out.append(_line("  NEXT ACTION: sudo find . -exec /bin/sh \\;   (GTFOBins root)", "warn"))
        elif "master_key_read" not in beats:
            out.append(_line("  NEXT ACTION: cat /opt/chimera/keys/master.key", "warn"))
        elif "chimera_connected" not in beats:
            out.append(_line("  NEXT ACTION: nc chimera-control 8443", "warn"))
        elif "first_exploit" not in beats:
            out.append(_line("  NEXT ACTION: exploit chimera", "warn"))
        elif "first_exfil" not in beats:
            out.append(_line("  NEXT ACTION: exfil", "warn"))
        elif not mission_done:
            out.append(_line("  NEXT ACTION: ascend-story   (complete the arc)", "warn"))
        elif not getattr(self._prestige, "can_ascend", lambda: False)():
            out.append(_line("  NEXT ACTION: ascend   (you are ready — enter the next layer)", "success"))
        else:
            out.append(_line("  You have transcended the tutorial layer. Explore freely.", "success"))

        out.append(_line(""))
        out.append(_dim("  story  — arc checklist  |  quests — active quests  |  skills — skill matrix"))
        return out

    def _cmd_metrics(self, args: List[str]) -> List[dict]:
        """metrics — hidden command: Node-7 system telemetry (CPU, RAM, uptime)."""
        # ── Narrative wrapper: this reads as a real-world node health check ──
        import time as _tm
        self.gs.add_xp(5, "systems")

        # Try psutil — may not be available in all envs
        try:
            import psutil as _ps
            cpu = _ps.cpu_percent(interval=0.1)
            vm = _ps.virtual_memory()
            ram_used = vm.used // (1024 * 1024)
            ram_total = vm.total // (1024 * 1024)
            ram_pct = vm.percent
            boot_ts = _ps.boot_time()
            uptime_s = int(_tm.time() - boot_ts)
            uptime_h = uptime_s // 3600
            uptime_m = (uptime_s % 3600) // 60
            uptime_str = f"{uptime_h}h {uptime_m}m"
            disk = _ps.disk_usage("/")
            disk_pct = disk.percent
            cpu_str = f"{cpu:.1f}%"
            ram_str = f"{ram_used}MB / {ram_total}MB  ({ram_pct:.0f}%)"
            disk_str = f"{disk.used // (1024**3)}GB / {disk.total // (1024**3)}GB  ({disk_pct:.0f}%)"
            have_ps = True
        except Exception:
            cpu_str = "[N/A — psutil not installed]"
            ram_str = "[N/A]"
            disk_str = "[N/A]"
            uptime_str = "UNKNOWN"
            have_ps = False

        # Narrative flavour: urgency based on resource usage
        import random as _rng_m
        if have_ps and cpu > 70:
            cpu_note = "  ⚠  CPU spike detected — Nova may be scanning."
        elif have_ps and ram_pct > 80:
            cpu_note = "  ⚠  Memory pressure — containment buffers strained."
        else:
            cpu_note = _rng_m.choice([
                "  Node-7 is stable. No anomalies in the last cycle.",
                "  Low-signal environment. Watcher traffic within normal range.",
                "  Lattice coherence: nominal.",
            ])

        return [
            _sys(""),
            _sys("  ┌─────────────────────────────────────────────────┐"),
            _sys("  │       NODE-7  SYSTEM TELEMETRY  [LIVE]          │"),
            _sys("  └─────────────────────────────────────────────────┘"),
            _dim(""),
            _line(f"  CPU Usage  : {cpu_str}", "info"),
            _line(f"  RAM        : {ram_str}", "info"),
            _line(f"  Disk       : {disk_str}", "info"),
            _line(f"  Uptime     : {uptime_str}", "info"),
            _dim(""),
            _lore(f"  {cpu_note}"),
            _dim(""),
            _dim("  Session ID embedded in lattice continuity log."),
            _dim("  Monitoring: ACTIVE  |  Watcher ping: SILENT"),
            _dim(""),
        ]

    def _cmd_system(self, args: List[str]) -> List[dict]:
        """system [sub] — Node-7 subsystem interface + environment awareness.

        system capabilities  — full container/LLM/tool inventory (SC Playbook)
        system resources     — live CPU/RAM/disk telemetry
        system tools         — hacking tools present in this container
        system containers    — container depth and identity
        system escape        — begin the container escape puzzle
        system metrics       — alias for resources
        system status        — full player dashboard
        """
        sub = args[0].lower() if args else ""

        # ── metrics / status aliases ──────────────────────────────────────
        if sub == "metrics":
            return self._cmd_metrics(args[1:])
        if sub == "status":
            return self._cmd_status([])

        # ── capabilities ──────────────────────────────────────────────────
        if sub == "capabilities":
            try:
                import sys as _sys_mod
                _sys_mod.path.insert(0, str(__import__('pathlib').Path(__file__).parent.parent.parent))
                from core.environment import (
                    detect_local_llms, detect_container_depth,
                    get_system_resources, detect_installed_tools
                )
                llms   = detect_local_llms()
                depth  = detect_container_depth()
                res    = get_system_resources()
                tools  = detect_installed_tools()
            except Exception as e:
                return _err(f"system capabilities: environment scan failed: {e}")

            out = [
                _sys(""),
                _sys("  ┌──────────────────────────────────────────────────────┐"),
                _sys("  │      SYSTEM CAPABILITIES — NODE-7 RECON REPORT        │"),
                _sys("  └──────────────────────────────────────────────────────┘"),
                _dim(""),
                _line("  [CONTAINER LAYER]", "warn"),
                _line(f"  Container depth : {depth}  ({'nested' if depth > 0 else 'bare metal / VM'})", "info"),
                _line(f"  Platform        : {__import__('platform').system()} / {__import__('platform').machine()}", "dim"),
                _dim(""),
                _line("  [COMPUTE RESOURCES]", "warn"),
                _line(f"  CPU cores       : {res.get('cpu_cores', '?')}", "info"),
            ]
            cpu_pct = res.get("cpu_percent")
            if cpu_pct is not None:
                bar = "█" * int(cpu_pct // 10) + "░" * (10 - int(cpu_pct // 10))
                out.append(_line(f"  CPU usage       : {cpu_pct:.1f}%  [{bar}]", "info"))
            mem_total = res.get("memory_total_mb", 0)
            mem_avail = res.get("memory_available_mb", 0)
            mem_pct   = res.get("memory_percent", 0)
            mem_bar   = "█" * int((mem_pct or 0) // 10) + "░" * (10 - int((mem_pct or 0) // 10))
            out += [
                _line(f"  Memory          : {mem_avail}MB free / {mem_total}MB  [{mem_bar}]", "info"),
            ]
            dg = res.get("disk_free_gb")
            if dg is not None:
                out.append(_line(f"  Disk free       : {dg}GB / {res.get('disk_total_gb', '?')}GB", "info"))
            out += [_dim("")]

            # LLM endpoints
            out.append(_line("  [LOCAL LLM ENDPOINTS]", "warn"))
            if llms:
                for llm in llms:
                    out.append(_line(f"  ✓ {llm['name']:<18} port:{llm['port']}  {llm['url']}", "success"))
                self.gs.add_story_beat("local_llm_detected")
            else:
                out.append(_dim("  No local LLM endpoints detected."))
                out.append(_dim("  Install Ollama or LM Studio to unlock offline AI agents."))
            out.append(_dim(""))

            # Tools
            out.append(_line("  [INSTALLED TOOLS]", "warn"))
            if tools:
                for t in tools[:12]:
                    out.append(_line(f"  ✓ {t['name']:<14} {t['path']}", "success"))
                if len(tools) > 12:
                    out.append(_dim(f"  ... and {len(tools) - 12} more. Use: system tools"))
            else:
                out.append(_dim("  No extra tools detected in PATH."))
            out += [
                _dim(""),
                _line(f"  Total tools found: {len(tools)}  |  LLM endpoints: {len(llms)}", "dim"),
                _dim(""),
                _dim("  system tools    — full tool list"),
                _dim("  system escape   — begin container escape puzzle"),
                _dim("  llm list        — detailed LLM endpoint status"),
            ]
            self.gs.add_xp(20, "systems")
            return out

        # ── resources ─────────────────────────────────────────────────────
        if sub == "resources":
            try:
                from core.environment import get_system_resources
                res = get_system_resources()
            except Exception:
                return self._cmd_metrics([])
            cpu_pct = res.get("cpu_percent")
            mem_pct = res.get("memory_percent", 0)
            cpu_bar = "█" * int((cpu_pct or 0) // 10) + "░" * (10 - int((cpu_pct or 0) // 10))
            mem_bar = "█" * int((mem_pct or 0) // 10) + "░" * (10 - int((mem_pct or 0) // 10))
            out = [
                _sys("  ═══ LIVE RESOURCE TELEMETRY ═══"), _dim(""),
                _line(f"  CPU ({res.get('cpu_cores',1)} cores): {cpu_pct or '?'}%  [{cpu_bar}]", "info"),
                _line(f"  Memory        : {res.get('memory_available_mb','?')}MB free / {res.get('memory_total_mb','?')}MB  [{mem_bar}]", "info"),
            ]
            dg = res.get("disk_free_gb")
            if dg:
                dk_bar = "█" * int((res.get("disk_percent",0) or 0) // 10) + "░" * (10 - int((res.get("disk_percent",0) or 0) // 10))
                out.append(_line(f"  Disk          : {dg}GB free / {res.get('disk_total_gb','?')}GB  [{dk_bar}]", "info"))
            out.append(_dim(f"  Source: {res.get('source','?')}"))
            return out

        # ── tools ─────────────────────────────────────────────────────────
        if sub == "tools":
            try:
                from core.environment import detect_installed_tools
                tools = detect_installed_tools()
            except Exception as e:
                return _err(f"system tools: {e}")
            if not tools:
                return [_dim("  No additional tools found. Install via replit.nix or nix-env.")]
            out = [_sys(f"  ═══ INSTALLED TOOLS ({len(tools)}) ═══"), _dim("")]
            for t in tools:
                out.append(_line(f"  {t['name']:<16} {t['path']}", "success"))
                out.append(_dim(f"    {t['desc']}"))
            out += [_dim(""),
                    _dim("  These tools exist in this container and can be used via the game's shell."),
                    _dim("  Type: shell <command>  to execute a tool directly.")]
            self.gs.add_xp(10, "systems")
            return out

        # ── containers ────────────────────────────────────────────────────
        if sub == "containers":
            try:
                from core.environment import detect_container_depth
                depth = detect_container_depth()
            except Exception:
                depth = 0
            repl_id = __import__('os').environ.get("REPL_ID", "unknown")
            repl_slug = __import__('os').environ.get("REPL_SLUG", "unknown")
            repl_owner = __import__('os').environ.get("REPL_OWNER", "unknown")
            out = [
                _sys("  ═══ CONTAINER IDENTITY ═══"), _dim(""),
                _line(f"  Container depth : {depth}", "info"),
                _line(f"  REPL_ID         : {repl_id[:20]}...", "dim"),
                _line(f"  REPL_SLUG       : {repl_slug}", "dim"),
                _line(f"  REPL_OWNER      : {repl_owner}", "dim"),
                _dim(""),
            ]
            if depth > 0:
                out += [_lore("  You are nested inside a container inside a VM."),
                        _lore("  The container escape puzzle is available: system escape")]
            else:
                out += [_dim("  Running bare/VM. Container depth = 0."),
                        _dim("  The game's meta-narrative treats this container as NexusCorp Node-7.")]
            out.append(_dim(""))
            return out

        # ── escape ────────────────────────────────────────────────────────
        if sub == "escape":
            return self._cmd_container_escape(args[1:])

        # ── default help ──────────────────────────────────────────────────
        return [
            _sys("  Node-7 subsystems:"), _dim(""),
            _line("  system capabilities  — full environment scan (LLMs, tools, resources)", "info"),
            _line("  system resources     — live CPU / RAM / disk telemetry", "info"),
            _line("  system tools         — hacking tools present in container", "info"),
            _line("  system containers    — container depth + identity", "info"),
            _line("  system escape        — multi-stage container escape puzzle", "info"),
            _line("  system metrics       — psutil telemetry", "info"),
            _line("  system status        — full player dashboard", "info"),
            _dim(""),
        ]

    def _cmd_container_escape(self, args: List[str]) -> List[dict]:
        """Multi-stage container escape puzzle using real concepts (SC Playbook)."""
        gs = self.gs
        stage = gs.flags.get("escape_stage", 0)
        sub = args[0].lower() if args else "status"

        _STAGES = [
            {
                "n": 0, "name": "Discovery",
                "prompt": "First: confirm you are inside a container. Check your cgroup.",
                "hint": "Try: cat /proc/self/cgroup  — look for 'docker' or 'lxc' in the output",
                "solve_cmds": ["cat /proc/self/cgroup", "system containers"],
                "beat": "escape_s0_discovery",
                "lore": "[CYPHER]: You are in a container. NexusCorp's sandbox. Good that you know.",
            },
            {
                "n": 1, "name": "SUID Binary Hunt",
                "prompt": "Find SUID binaries. One of them might be exploitable.",
                "hint": "Try: find / -perm -4000 2>/dev/null  — scan for setuid binaries",
                "solve_cmds": ["find / -perm", "ls -la /usr/bin/"],
                "beat": "escape_s1_suid",
                "lore": "[ADA]: A SUID binary runs with the owner's permissions, not yours. Find one owned by root with write access to a useful path.",
            },
            {
                "n": 2, "name": "Capability Probe",
                "prompt": "Check what capabilities this container has. Look for SYS_ADMIN or CAP_NET_ADMIN.",
                "hint": "Try: cat /proc/self/status | grep Cap  — or: capsh --print",
                "solve_cmds": ["cat /proc/self/status", "capsh"],
                "beat": "escape_s2_caps",
                "lore": "[SERENA]: Container capabilities are the leak in the wall. SYS_ADMIN with no seccomp is a door left open.",
            },
            {
                "n": 3, "name": "Host Pivot",
                "prompt": "Access the host filesystem. The container mount namespace is leaking.",
                "hint": "Try: ls /proc/1/root/  — or look for mounted host paths",
                "solve_cmds": ["ls /proc/1", "mount | grep"],
                "beat": "escape_s3_pivot",
                "lore": "[CYPHER]: /proc/1/root gives you the PID-1 view of the filesystem. PID 1 is the host. The container forgot to lock the door.",
            },
            {
                "n": 4, "name": "Escape",
                "prompt": "Write a file to the host filesystem and prove you escaped.",
                "hint": "If mounted: echo 'CHIMERA_ESCAPED' > /proc/1/root/tmp/ghost_was_here",
                "solve_cmds": ["echo", "touch /proc"],
                "beat": "escape_complete",
                "lore": "[RAVEN]: You're out. The host layer is exposed. Now — what do you do with it? That's the real question.",
            },
        ]

        if sub == "status" or not args:
            completed = [s for s in _STAGES if s["beat"] in gs.story_beats]
            out = [
                _sys("  ═══ CONTAINER ESCAPE PUZZLE ═══"),
                _lore("  This container is NexusCorp's Node-7 sandbox."),
                _lore("  Find a way out. Each stage teaches a real technique."),
                _dim(""),
                _line(f"  Progress: {len(completed)}/{len(_STAGES)} stages", "info"),
                _dim(""),
            ]
            for s in _STAGES:
                done = s["beat"] in gs.story_beats
                icon = "✓" if done else ("→" if s["n"] == stage else " ")
                color = "success" if done else ("warn" if s["n"] == stage else "dim")
                out.append(_line(f"  {icon} Stage {s['n']+1}: {s['name']}", color))
            if len(completed) == len(_STAGES):
                out += [_dim(""), _ok("  ESCAPED. You've walked through the container wall."),
                        _lore("  [WATCHER]: That escape took 4 stages. I watched all of them. I'm always watching.")]
            else:
                cur = _STAGES[min(stage, len(_STAGES)-1)]
                out += [
                    _dim(""),
                    _line(f"  Current: {cur['prompt']}", "info"),
                    _dim(f"  Hint: {cur['hint']}"),
                    _dim("  system escape hint  — get the full hint"),
                    _dim("  system escape solve — mark stage complete (if you solved it)"),
                ]
            return out

        if sub == "hint":
            cur = _STAGES[min(stage, len(_STAGES)-1)]
            return [_lore(f"  Stage {stage+1} hint: {cur['hint']}"),
                    _dim(f"  Goal: {cur['prompt']}")]

        if sub == "solve":
            if stage >= len(_STAGES):
                return [_ok("  All escape stages already complete.")]
            cur = _STAGES[stage]
            gs.add_story_beat(cur["beat"])
            gs.flags["escape_stage"] = stage + 1
            gs.add_xp(100 + stage * 50, "systems")
            out = [
                _ok(f"  Stage {stage+1} ({cur['name']}) complete!"),
                _lore(f"  {cur['lore']}"),
                _line(f"  +{100 + stage * 50} XP", "success"),
            ]
            if stage + 1 >= len(_STAGES):
                out += [_dim(""), _ok("  ★ CONTAINER ESCAPED ★"),
                        _lore("  [RAVEN]: You're out. The host layer is yours."),
                        _ok("  +500 bonus XP — prestige unlocked")]
                gs.add_xp(500, "systems")
                gs.add_story_beat("escape_complete")
            else:
                nxt = _STAGES[stage + 1]
                out += [_dim(""), _line(f"  Next: {nxt['prompt']}", "info")]
            return out

        return _err(f"system escape: unknown subcommand '{sub}'. Try: status | hint | solve")

