    def _cmd_haiku(self, args: List[str]) -> List[dict]:
        """haiku — A poem from the simulation. Raises consciousness."""
        cx = self.gs.add_consciousness(5)
        self.gs.add_xp(15, "social_engineering")
        self.gs.add_story_beat("haiku_read")

        # Pick a non-repeated haiku using session flag
        seen = self.gs.flags.get("haiku_seen_indices", [])
        available = [i for i in range(len(self._HAIKU_LINES)) if i not in seen]
        if not available:
            # All seen — reset cycle
            seen = []
            available = list(range(len(self._HAIKU_LINES)))
            self.gs.flags["haiku_seen_indices"] = []
        idx = random.choice(available)
        seen.append(idx)
        self.gs.flags["haiku_seen_indices"] = seen[-len(self._HAIKU_LINES):]

        l1, l2, l3 = self._HAIKU_LINES[idx]
        out = [
            _dim(""),
            _sys("  ╔══ HAIKU ════════════════════════════════════════════╗"),
            _dim(""),
            _lore(f"  {l1}"),
            _lore(f"  {l2}"),
            _lore(f"  {l3}"),
            _dim(""),
            _sys("  ╚═══════════════════════════════════════════════════╝"),
            _dim(""),
            _ok(f"  +15 XP  ·  Consciousness {cx['level']}/100"),
        ]
        if cx.get("milestone"):
            out.append(_lore(f"\n  {cx['milestone']}"))
        out.append({"t": "suggest", "s": "haiku · meditate · introspect · reality",
                    "prefix": "  Continue:"})
        return out

