    def _cmd_arcs(self, args: List[str]) -> List[dict]:
        """arcs  — view all narrative arc statuses"""
        session = self._get_session()
        if not session or not hasattr(session, "arc_engine"):
            return _err("Arc system not available.")
        statuses = session.arc_engine.all_arc_statuses()
        out = [_line("=== NARRATIVE ARCS ===", "system"), _line("")]
        for arc_id, status in statuses.items():
            if not status:
                continue
            color = {"inactive": "dim", "active": "warn", "completed": "success", "failed": "error"}.get(status["status"], "info")
            step_str = f"Step {status['step_index']}/{status['total_steps']}" if status["status"] == "active" else ""
            out.append(_line(f"  {arc_id:<15} [{status['status'].upper():10}] {step_str}", color))
        out.append(_line(""))
        active = [a for a, s in statuses.items() if s and s["status"] == "active"]
        if active:
            out.append(_line(f"  Active arcs: {', '.join(active)}", "warn"))
        else:
            out.append(_line("  No active arcs. Progress the story to unlock them.", "dim"))
        return out

