    def _cmd_history(self, args):
        n = 20
        if args and args[0].isdigit():
            n = int(args[0])
        if not self.history:
            return [_line("(no history yet)", "dim")]
        entries = self.history[-n:]
        out: List[dict] = [_line("  NUM  TIMESTAMP            COMMAND", "dim")]
        base_idx = len(self.history) - len(entries)
        for i, entry in enumerate(entries):
            if isinstance(entry, dict):
                ts = entry.get("ts", "")
                cmd_str = entry.get("cmd", "")
                ok = entry.get("ok", True)
                status = "" if ok else " [ERR]"
                out.append(_line(f"  {base_idx+i+1:4}  {ts:<20} {cmd_str}{status}", "dim"))
            else:
                out.append(_line(f"  {base_idx+i+1:4}  {entry}", "dim"))
        return out

