    def _cmd_doctor(self, args: List[str]) -> List[dict]:
        """In-game system health check — ports, state files, services."""
        import json as _j, time as _t
        from pathlib import Path as _Path
        out = [
            _sys("  ╔══════════════════════════════════════════════════════════╗"),
            _sys("  ║  TERMINAL DEPTHS — SYSTEM DIAGNOSTICS                   ║"),
            _sys("  ╚══════════════════════════════════════════════════════════╝"),
            _dim(""),
        ]
        # ── Port status ───────────────────────────────────────────────────
        try:
            ps = _j.loads((_Path(__file__).parent.parent.parent / "state" / "port_status.json").read_text())
            ports = ps.get("ports", {})
            alive = sum(1 for p in ports.values() if p.get("alive"))
            total = len(ports)
            out.append(_ok(f"  Ports    : {alive}/{total} services alive"))
            dark = [(v.get("name","?"), v.get("local_port","?"))
                    for v in ports.values() if not v.get("alive")]
            if dark:
                out.append(_dim(f"  Dark     : {', '.join(f'{n}:{p}' for n,p in dark[:5])}"))
            else:
                out.append(_ok("  All ports: nominal"))
        except Exception:
            out.append(_dim("  Ports    : status unavailable (run: port_watcher)"))

        # ── Game state ────────────────────────────────────────────────────
        out.append(_dim(""))
        out.append(_ok(f"  Player   : {getattr(self.gs, 'name', 'GHOST') or 'GHOST'}  Lvl {self.gs.level}"))
        _dp = getattr(self.gs, "dp", getattr(self.gs, "dev_points", "–"))
        _trace = getattr(self.gs, "trace_level", getattr(self.gs, "trace", "–"))
        out.append(_ok(f"  XP       : {self.gs.xp}  DP: {_dp}  Trace: {_trace}%"))
        out.append(_ok(f"  Root     : {'YES' if self._root_shell else 'NO'}"))
        out.append(_ok(f"  Commands : {self.gs.commands_run}  Flags: {len(self.gs.flags)}"))
        out.append(_ok(f"  Story    : {len(self.gs.story_beats)} beats fired"))

        # ── Consciousness ─────────────────────────────────────────────────
        cl = getattr(self.gs, "consciousness_level", 0)
        out.append(_ok(f"  ψ Conscs : {cl}/100"))

        # ── Factions ──────────────────────────────────────────────────────
        if self.factions:
            out.append(_dim(""))
            out.append(_dim("  Faction Reputation:"))
            try:
                for k, f in self.factions.factions.items():
                    rep = f.get("rep", f.get("reputation", 0))
                    bar = "█" * max(0, int(rep / 10)) + "░" * (10 - max(0, int(rep / 10)))
                    out.append(_dim(f"    {k:<18} {bar} {rep:+d}"))
            except Exception:
                pass

        # Doctor = introspection = consciousness
        cs = self.gs.add_consciousness(3)
        out.append(_dim(""))
        out.append(_ok(f"  ✓ Doctor complete — {_t.strftime('%H:%M:%S')}  ψ+3 ({cs['level']}/100)"))
        self.gs.add_xp(5, "system")
        return out

