    def _cmd_swarm_status(self, args: List[str]) -> List[dict]:
        """Show autonomous swarm agent status and task queue."""
        import json as _j
        from pathlib import Path as _Path
        out = [
            _sys("  ─── SWARM CONTROLLER — STATUS ──────────────────────────────"),
            _dim(""),
        ]
        try:
            import urllib.request as _ur
            raw = _ur.urlopen("http://localhost:5000/api/swarm/status", timeout=3).read()
            d = _j.loads(raw)
            agents = d.get("agents", [])
            tasks = d.get("available_tasks", 0)
            _gs_dp = getattr(self.gs, "dp", getattr(self.gs, "dev_points", 0))
            dp = d.get("total_dp_earned", _gs_dp)
            out.append(_ok(f"  Agents registered : {len(agents)}"))
            out.append(_ok(f"  Available tasks   : {tasks}"))
            out.append(_ok(f"  Total DP earned   : {dp}"))
            if agents:
                out.append(_dim(""))
                out.append(_dim("  Agent         DP     Last Active"))
                for a in sorted(agents, key=lambda x: x.get("dp_earned", 0), reverse=True)[:8]:
                    out.append(_dim(f"  {a.get('agent_id','?'):<14} {a.get('dp_earned',0):<6} {a.get('last_seen','?')[:19]}"))
        except Exception:
            out.append(_dim("  Swarm API offline — showing local state"))
            _gs_dp2 = getattr(self.gs, "dp", getattr(self.gs, "dev_points", 0))
            out.append(_ok(f"  Player DP  : {_gs_dp2}"))
            out.append(_ok(f"  Commands   : {self.gs.commands_run}"))
            todo_path = _Path(__file__).parent.parent.parent / "MASTER_ZETA_TODO.md"
            if todo_path.exists():
                txt = todo_path.read_text()
                done = txt.count("[x]")
                todo = txt.count("[ ]")
                out.append(_ok(f"  ZETA TODO  : {done} done / {todo} open"))
        out.append(_dim(""))
        out.append(_lore("  [CYPHER]: The swarm works whether you watch or not."))
        self.gs.add_xp(5, "system")
        return out

    def _cmd_validate(self, args: List[str]) -> List[dict]:
        """Run CI validation suite in-game. Shows pass/fail summary."""
        import subprocess as _sp, os as _os
        from pathlib import Path as _Path
        out = [
            _sys("  ─── RUNNING VALIDATION SUITE ───────────────────────────────"),
            _dim("  (python3 scripts/validate_all.py --quick)"),
            _dim(""),
        ]
        script = _Path(__file__).parent.parent.parent / "scripts" / "validate_all.py"
        if not script.exists():
            return out + [_err("  validate_all.py not found")]
        env = _os.environ.copy()
        env["TD_BASE_URL"] = "http://localhost:5000"
        try:
            result = _sp.run(
                ["python3", str(script), "--quick"],
                capture_output=True, text=True, timeout=30, env=env
            )
            lines = (result.stdout + result.stderr).splitlines()
            for ln in lines[-25:]:
                if "PASS" in ln:
                    out.append(_ok(f"  {ln.strip()}"))
                elif "FAIL" in ln:
                    out.append(_err(f"  {ln.strip()}"))
                elif "WARN" in ln:
                    out.append({"t": "warn", "s": f"  {ln.strip()}"})
                else:
                    out.append(_dim(f"  {ln.strip()}"))
            rc = result.returncode
            out.append(_dim(""))
            if rc == 0:
                out.append(_ok("  ✓ All critical checks passed"))
                self.gs.add_xp(25, "system")
            else:
                out.append(_err("  ✗ Some checks failed — see validate_report.md"))
        except Exception as exc:
            out.append(_err(f"  Validation error: {exc}"))
        return out

