    def _playbook_path(self) -> str:
        return os.path.abspath(
            os.path.join(os.path.dirname(__file__), "..", "..", "state", "playbook.json")
        )

    def _load_playbook_manifest(self) -> Tuple[Optional[dict], str, Optional[str]]:
        path = self._playbook_path()
        try:
            with open(path, "r", encoding="utf-8") as fh:
                return json.load(fh), path, None
        except FileNotFoundError:
            return None, path, "playbook data not found"
        except json.JSONDecodeError as exc:
            return None, path, f"playbook data is invalid JSON: {exc}"
        except OSError as exc:
            return None, path, f"playbook data could not be read: {exc}"

    def _history_has_command(self, expected: str) -> bool:
        for entry in self.history:
            raw = (entry.get("cmd") or "").strip()
            if raw == expected or raw.startswith(expected + " "):
                return True
        return False

    def _playbook_condition_met(self, rule: Optional[dict]) -> bool:
        if not rule:
            return False
        beats = set(getattr(self.gs, "story_beats", []))
        achievements = set(getattr(self.gs, "achievements", []))
        flags = getattr(self.gs, "flags", {}) or {}
        commands_run = getattr(self.gs, "commands_run", len(self.history))

        if rule.get("requires_root") and not self._root_shell:
            return False
        if "commands_run_gte" in rule and commands_run < int(rule["commands_run_gte"]):
            return False
        if "commands_run_lte" in rule and commands_run > int(rule["commands_run_lte"]):
            return False
        if rule.get("story_beats_any") and not any(b in beats for b in rule["story_beats_any"]):
            return False
        if rule.get("story_beats_missing") and any(b in beats for b in rule["story_beats_missing"]):
            return False
        if rule.get("achievements_any") and not any(a in achievements for a in rule["achievements_any"]):
            return False
        if rule.get("achievements_missing") and any(a in achievements for a in rule["achievements_missing"]):
            return False
        if rule.get("flags_any") and not any(bool(flags.get(k)) for k in rule["flags_any"]):
            return False
        if rule.get("flags_missing") and any(bool(flags.get(k)) for k in rule["flags_missing"]):
            return False
        if rule.get("commands_any") and not any(self._history_has_command(cmd) for cmd in rule["commands_any"]):
            return False
        return True

    def _resolve_playbook_arc(self, manifest: dict) -> Tuple[Optional[str], Optional[dict]]:
        arcs = manifest.get("arcs", {})
        if not arcs:
            return None, None
        default_arc = manifest.get("default_arc")
        if default_arc in arcs:
            return default_arc, arcs[default_arc]
        for arc_id, arc in arcs.items():
            activation = arc.get("activation", {})
            if not activation or self._playbook_condition_met(activation):
                return arc_id, arc
        arc_id = next(iter(arcs))
        return arc_id, arcs[arc_id]

    def _cmd_playbook(self, args: List[str]) -> List[dict]:
        """playbook [persona] — show the operator sequence for the active story arc."""
        manifest, path, error = self._load_playbook_manifest()
        if error or manifest is None:
            return [
                _line(f"playbook: {error or 'unknown error'}", "error"),
                _line(f"Source: {path}", "dim"),
            ]

        arc_id, arc = self._resolve_playbook_arc(manifest)
        if not arc:
            return [
                _line("playbook: no arcs defined in playbook data", "error"),
                _line(f"Source: {path}", "dim"),
            ]

        persona = (args[0].lower() if args else "").strip()
        steps = arc.get("optimal_sequence", [])
        subtitle = "optimal"
        if persona:
            persona_steps = arc.get("personas", {}).get(persona, {}).get("sequence")
            if persona_steps:
                steps = persona_steps
                subtitle = persona

        current_idx = None
        completion_flags: List[bool] = []
        for idx, step in enumerate(steps):
            done = self._playbook_condition_met(step.get("complete_when"))
            completion_flags.append(done)
            if not done and current_idx is None:
                current_idx = idx

        out = [
            _sys("  ╔══════════════════════════════════════════════════════╗"),
            _sys("  ║            TERMINAL DEPTHS PLAYBOOK                 ║"),
            _sys("  ╚══════════════════════════════════════════════════════╝"),
            _dim(""),
            _ok(f"  Arc      : {arc.get('title', arc_id)}"),
            _ok(f"  View     : {subtitle}"),
            _ok(f"  Root     : {'YES' if self._root_shell else 'NO'}"),
            _ok(f"  Commands : {len(self.history)}  |  Story beats: {len(getattr(self.gs, 'story_beats', []))}"),
            _dim(f"  Source   : {path}"),
            _dim(""),
        ]

        for idx, step in enumerate(steps):
            done = completion_flags[idx]
            if done:
                marker, color = "✓", "success"
            elif current_idx == idx:
                marker, color = "→", "warn"
            else:
                marker, color = "·", "dim"

            title = step.get("title") or step.get("id") or step.get("command", f"step {idx + 1}")
            command = step.get("command", "")
            why = step.get("why", "")

            out.append(_line(f"  [{marker}] {title}", color))
            if command:
                out.append(_line(f"       {command}", "success" if current_idx == idx else "info"))
            if why:
                out.append(_line(f"       {why}", "dim"))

        out.append(_dim(""))
        if current_idx is not None:
            out.append(_line("  Next action:", "warn"))
            out.append(_line(f"    {steps[current_idx].get('command', 'No command defined')}", "success"))
        else:
            out.append(_line("  Playbook complete for this arc.", "success"))

        if arc.get("personas"):
            available = " · ".join(sorted(arc["personas"].keys()))
            out.append(_dim(""))
            out.append(_line(f"  Persona views: {available}", "dim"))
            out.append(_line("  Usage: playbook <persona>", "dim"))
        return out

    def _cmd_suggest(self, args: List[str]) -> List[dict]:
        """suggest / next — state-aware ordered list of recommended commands to try."""
        gs = self.gs
        level      = gs.level
        beats      = set(gs.story_beats)
        skills     = gs.skills  # dict skill→xp
        cmds_run   = gs.commands_run
        is_root    = self._root_shell
        con_level  = getattr(gs, "consciousness_level", 0)

        def skill_pct(s: str) -> int:
            return min(100, int(skills.get(s, 0)))

        out = [
            _line("═══════════════════════════════════════════════════", "dim"),
            _line("  GHOST SUGGESTED COMMAND QUEUE", "warn"),
            _line(f"  Level {level} · {cmds_run} commands run · Root: {'YES' if is_root else 'no'}", "dim"),
            _line("═══════════════════════════════════════════════════", "dim"),
            _line(""),
        ]

        queue: list[tuple[int, str, str, str]] = []  # (priority, label, cmds_hint, reason)

        # ── IMMEDIATE STORY GATES ──────────────────────────────────────────
        if "mole_files_seeded" in beats and "mole_exposed" not in beats:
            queue.append((1, "MOLE INVESTIGATION", "cat /home/ghost/.investigation/suspect_list.txt", "You have clue files — find and expose the mole"))
            queue.append((1, "MOLE INVESTIGATION", "ls /home/ghost/.investigation/", "Check all evidence files you've collected"))
        if is_root and "chimera_exploited" not in beats:
            queue.append((2, "CHIMERA ENDGAME", "cat /opt/chimera/keys/master.key", "You have root — grab the master key"))
            queue.append((2, "CHIMERA ENDGAME", "exploit chimera", "Trigger the CHIMERA exploit sequence"))
        if is_root and "chimera_exploited" in beats and "ascended" not in beats:
            queue.append((2, "ASCENSION", "ascend", "You've exploited CHIMERA — time to ascend"))
        if "ascended" not in beats and level >= 7:
            queue.append((3, "STORY", "ascend", "Level 7+ — the ascension gate is open"))
        if "zero_diary_reconstructed" not in beats and level >= 5:
            queue.append((3, "STORY", "diary", "Reconstruct ZERO's lost journals from filesystem fragments"))
        if "fates_started" not in beats and level >= 6:
            queue.append((3, "STORY", "fates", "Clotho/Lachesis/Atropos questline — starts at level 6"))
        if con_level >= 1 and "reality_checked" not in beats:
            queue.append((3, "CONSCIOUSNESS", "reality", "Your consciousness is elevated — type `reality` to see underneath"))

        # ── SKILL GAPS ────────────────────────────────────────────────────
        net_pct  = skill_pct("networking")
        prog_pct = skill_pct("programming")
        git_pct  = skill_pct("git")
        sec_pct  = skill_pct("security")

        if net_pct < 30:
            queue.append((4, f"NETWORKING ({net_pct}%)", "nmap 10.0.0.0/24", "Scan the grid — builds networking XP fast"))
            queue.append((4, f"NETWORKING ({net_pct}%)", "ss -tulnp", "List listening ports (ss replaces netstat)"))
            queue.append((4, f"NETWORKING ({net_pct}%)", "ping chimera-control", "Test reachability to control node"))
            queue.append((4, f"NETWORKING ({net_pct}%)", "nc chimera-control 8443", "Netcat to the CHIMERA control port"))
        elif net_pct < 60:
            queue.append((4, f"NETWORKING ({net_pct}%)", "dig chimera-control", "DNS lookup — networking XP"))
            queue.append((4, f"NETWORKING ({net_pct}%)", "nc -lvnp 4444", "Open a listener — reverse shell setup"))
        if prog_pct < 30:
            queue.append((5, f"PROGRAMMING ({prog_pct}%)", "polyglot run python", "Run Python in the proficiency matrix (+6 XP)"))
            queue.append((5, f"PROGRAMMING ({prog_pct}%)", "polyglot run bash", "Run Bash in the proficiency matrix (+6 XP)"))
            queue.append((5, f"PROGRAMMING ({prog_pct}%)", "python3 -c \"print('online')\"", "Quick Python execution"))
        elif prog_pct < 60:
            queue.append((5, f"PROGRAMMING ({prog_pct}%)", "polyglot run javascript", "Expand language matrix — unlock inject ability"))
            queue.append((5, f"PROGRAMMING ({prog_pct}%)", "polyglot run rust", "Rust proficiency — unlocks safe_exploit"))
        if git_pct < 25:
            queue.append((6, f"GIT ({git_pct}%)", "git status", "Git basics — builds git XP"))
            queue.append((6, f"GIT ({git_pct}%)", "git log --oneline", "Read commit history"))
            queue.append((6, f"GIT ({git_pct}%)", "git diff HEAD~1 HEAD", "Diff between commits"))

        # ── FACTION REP ────────────────────────────────────────────────────
        try:
            factions = self.factions
            res_rep = factions.get_rep("RESISTANCE")
            cor_rep = factions.get_rep("CORPORATION")
            guild_rep = factions.get_rep("SPECIALIST_GUILD") or factions.get_rep("ACADEMIC")
            if res_rep < 30:
                queue.append((7, "FACTION: RESISTANCE", "talk raven", "Raven is resistance — talking builds rep"))
            if guild_rep < 20:
                queue.append((7, "FACTION: GUILD", "challenges", "Complete challenges — each one adds Guild rep"))
                queue.append((7, "FACTION: GUILD", "challenge list", "See available challenges"))
        except Exception:
            pass

        # ── LANGUAGE MATRIX ───────────────────────────────────────────────
        if level >= 3:
            queue.append((8, "LANGUAGE MATRIX", "proficiency matrix", "See all 51 language proficiencies and unlock gates"))
        if level >= 5:
            queue.append((8, "LANGUAGE MATRIX", "polyglot run c", "C proficiency → unlocks memdump at 50"))
            queue.append((8, "LANGUAGE MATRIX", "polyglot run javascript", "JS proficiency → unlocks inject at 40"))

        # ── ALWAYS USEFUL ──────────────────────────────────────────────────
        if "lore_chimera" not in beats:
            queue.append((9, "LORE", "lore chimera", "Read Project CHIMERA declassified dossier"))
        queue.append((9, "LORE", "lore echo-loop", "Understand the 72-hour containment mechanic"))
        queue.append((10, "EXPLORATION", "map", "Full node map — find dark nodes"))
        queue.append((10, "EXPLORATION", "arcs", "See all narrative arcs and their progress"))
        queue.append((10, "AGENTS", "agents", "Full agent roster with trust and faction data"))
        if level >= 4:
            queue.append((10, "HACKING", "sudo -l", "Confirm your sudo privileges (GTFOBins path)"))
            queue.append((10, "HACKING", "find / -perm -u=s -type f 2>/dev/null", "Find SUID binaries — priv esc path"))

        # Sort by priority and render
        queue.sort(key=lambda x: x[0])
        current_label = None
        rank = 0
        for pri, label, cmd, reason in queue[:18]:
            if label != current_label:
                out.append(_line(""))
                out.append(_line(f"  [{label}]", "warn" if pri <= 3 else "info"))
                current_label = label
            rank += 1
            out.append(_line(f"  {rank:>2}. {cmd}", "success"))
            out.append(_line(f"      {reason}", "dim"))

        out += [
            _line(""),
            _line("═══════════════════════════════════════════════════", "dim"),
            {"t": "suggest", "s": "skills · faction · arcs · proficiency matrix · map", "prefix": "  Also check:"},
        ]
        return out

    def _cmd_next(self, args: List[str]) -> List[dict]:
        """next — alias for suggest with compact single-section output."""
        return self._cmd_suggest(args)

    # ── Swarm Console post helper ──────────────────────────────────────
    def _post_to_console(self, sender: str, text: str, room: str = "general"):
        """Fire-and-forget POST to /api/console/message (non-blocking daemon thread)."""
        import threading, urllib.request as _ureq, json as _json, os as _os
        port = int(_os.environ.get("PORT", 5000))
        payload = _json.dumps({"sender": sender, "text": text, "room": room}).encode()
        def _fire():
            try:
                req = _ureq.Request(
                    f"http://127.0.0.1:{port}/api/console/message",
                    data=payload,
                    headers={"Content-Type": "application/json"},
                    method="POST",
                )
                _ureq.urlopen(req, timeout=2)
            except Exception:
                pass
        threading.Thread(target=_fire, daemon=True).start()

    # ── Tutorial commands ──────────────────────────────────────────────
    def _cmd_tutorial(self, args):
        sub = (args[0] if args else "").lower()

        # ── Restart / replay ──────────────────────────────────────────
        if sub in ("restart", "reset", "start", "begin", "redo", "replay"):
            return self._restart_tutorial()

        tut = self.tut
        all_steps = tut.get_all()
        step = tut.step

        # ── tutorial list — section overview ──────────────────────────
        if sub == "list":
            from collections import OrderedDict
            sections: "OrderedDict[str, list]" = OrderedDict()
            for s in all_steps:
                sections.setdefault(s["section"], []).append(s)
            done = tut.progress
            out = [
                _line(""),
                _line("=== TUTORIAL SECTIONS ===", "system"),
                _line(""),
            ]
            for sec_name, steps in sections.items():
                ids = [s["id"] for s in steps]
                sec_done = sum(1 for i in ids if i <= done)
                marker = "✓" if sec_done == len(ids) else ("▶" if sec_done > 0 else " ")
                bar = f"[{sec_done}/{len(ids)}]"
                out.append(_line(f"  {marker} {sec_name:<18} {bar}  steps {ids[0]}–{ids[-1]}", "success" if sec_done == len(ids) else "dim"))
            out.append(_line(""))
            out.append(_line(f"Total: {done}/{len(all_steps)} steps complete ({tut.percent}%)", "system"))
            out.append(_line(""))
            out.append(_line("Type `tutorial <N>` to review any step.  `tutorial back` for previous.", "dim"))
            return out

        # ── tutorial back — show previous step ────────────────────────
        if sub == "back":
            prev_idx = tut.progress - 1
            if prev_idx <= 0:
                return [_line("You're at the beginning — no previous step.", "dim")]
            review = all_steps[prev_idx - 1]
            return self._tutorial_show_step(review, tut.progress, label="← previous")

        # ── tutorial <N> — review any step by number ─────────────────
        if sub.isdigit():
            n = int(sub)
            if n < 1 or n > len(all_steps):
                return [_line(f"Step {n} doesn't exist. Tutorial has {len(all_steps)} steps.", "error")]
            review = tut.get_by_id(n)
            if not review:
                return [_line(f"Step {n} not found.", "error")]
            return self._tutorial_show_step(review, tut.progress, label="review")

        # ── Tutorial complete ─────────────────────────────────────────
        if step is None:
            completions = getattr(self.gs, "tutorial_completions", 0)
            bonus_line = (
                _line("  ★ Replay bonus already claimed — you've been thorough.", "dim")
                if completions >= 2 else
                _line("  Complete it again for a one-time 500 XP replay bonus.", "yellow")
            )
            return [
                _line(""),
                _line("╔═══════════════════════════════════════════════════╗", "success"),
                _line("║         ✓  TUTORIAL COMPLETE — ALL 42 STEPS       ║", "success"),
                _line("╚═══════════════════════════════════════════════════╝", "success"),
                _line(""),
                _line("Your skills are logged. Type `skills` to see your full matrix.", "dim"),
                bonus_line,
                _line(""),
                _line("┌──────────────────────────────────────────────────┐", "system"),
                _line("│  Want to replay?  Type:  tutorial restart         │", "system"),
                _line("│  Short form:             restart tutorial          │", "system"),
                _line("│  Or just:                restart                   │", "system"),
                _line("└──────────────────────────────────────────────────┘", "system"),
                _line(""),
                _line("Type `tutorial list` to see all sections.  `tutorial <N>` to review any step.", "dim"),
                _line(""),
                _line("The Swarm Console (/game-cli/) has more to explore.", "dim"),
            ]

        # ── Current step display ──────────────────────────────────────
        return self._tutorial_show_step(step, tut.progress)

    def _tutorial_show_step(self, step: dict, current_progress: int, label: str = "") -> list:
        """Render a tutorial step card. Does NOT modify game state."""
        tut = self.tut
        all_steps = tut.get_all()
        total = len(all_steps)
        pct = min(100, round(current_progress / total * 100))

        is_done = step["id"] <= current_progress
        is_current = step["id"] == current_progress + 1
        variants = step.get("variants", [])

        status_tag = ""
        if is_done:
            status_tag = " [DONE]"
        elif is_current:
            status_tag = " [CURRENT]"
        elif label == "review":
            status_tag = " [UPCOMING]"

        tag_color = "success" if is_done else ("system" if is_current else "dim")
        header = f"TUTORIAL {step['id']}/{total} — {step['section'].upper()}{status_tag}"
        if label and label not in ("review",):
            header = f"{label.upper()}: {header}"

        out = [
            _line(""),
            _line(f"=== {header} ===", tag_color),
            _line(f"  {step['title']}", "system"),
            _line(""),
            _line(f"  Objective: {step['objective']}", "success"),
            _line(""),
            _line(f"  Hint: {step['hint']}", "dim"),
        ]

        if variants:
            out.append(_line(""))
            out.append(_line("  This step requires multiple commands:", "system"))
            tried = tut._get_tried(step["id"]) if hasattr(tut, "_get_tried") else set()
            for i, v in enumerate(variants):
                done_mark = "✓" if i in tried else "○"
                color = "success" if i in tried else "dim"
                out.append(_line(f"    {done_mark}  {v['cmd']}", color))

        out.append(_line(""))
        out.append(_line(f"  Progress: {current_progress}/{total} ({pct}%)", "dim"))
        out.append(_line(""))

        if not is_done:
            out.append(_line("  Stuck? `tutorial list` for overview · `tutorial restart` to start over · `tutorial back` for previous", "dim"))
        else:
            out.append(_line("  `tutorial list` for section overview · `tutorial <N>` to review any step", "dim"))
        return out

    def _restart_tutorial(self) -> List[dict]:
        """Reset tutorial progress to step 1 and notify the Swarm Console."""
        self.gs.tutorial_step = 0
        tut = self.tut
        step = tut.step
        import random
        commentary = random.choice([
            ("Ada",     "Ghost just reset the tutorial. The grid has a new visitor again."),
            ("Watcher", "Tutorial sequence wiped. Clean slate. I'm watching."),
            ("Cypher",  "Restarting? Bold move. Most people just give up."),
            ("Raven",   "Every loop is a chance to go deeper. Welcome back, Ghost."),
            ("Gordon",  "Tutorial reset logged. This is attempt #15 by my count. Good."),
        ])
        agent_name, agent_msg = commentary
        self._post_to_console(agent_name, agent_msg)
        out = [
            _line(""),
            _line("┌─────────────────────────────────────────────────────┐", "system"),
            _line("│           TUTORIAL RESTARTED FROM STEP 1            │", "system"),
            _line("└─────────────────────────────────────────────────────┘", "system"),
            _line(""),
        ]
        if step:
            out += [
                _line(f"=== TUTORIAL STEP {step['id']}/42 — {step['section'].upper()} ===", "system"),
                _line(""),
                _line(f"Objective: {step['objective']}", "success"),
                _line(""),
                _line(f"Hint: {step['hint']}", "dim"),
            ]
        out.append(_line(""))
        out.append(_lore(f"  {agent_name}: {agent_msg}"))
        out.append(_line(""))
        out.append(_line("The Swarm Console (/game-cli/) just got a notification.", "dim"))
        return out

    def _cmd_restart(self, args: List[str]) -> List[dict]:
        """Handle `restart` — resets the tutorial (most common case) or other targets."""
        # Join all args and strip filler words so "restart the tutorial" works
        sub_raw = " ".join(args).lower().strip()
        # Strip leading article words
        for _strip in ("the ", "a ", "an "):
            if sub_raw.startswith(_strip):
                sub_raw = sub_raw[len(_strip):]
        sub = sub_raw.split()[0] if sub_raw else ""
        if not sub or sub in ("tutorial", "tut", "tutorials", "training", "game", "over",
                               "fresh", "again", "scratch", "beginning", "top", "from"):
            return self._restart_tutorial()
        return [
            _line(f"restart: unknown target '{sub_raw}'", "error"),
            _line("Usage: restart  (resets tutorial)  |  restart tutorial", "dim"),
        ]

    def _cmd_reset(self, args: List[str]) -> List[dict]:
        """Alias for `restart tutorial`."""
        return self._restart_tutorial()

    def _cmd_start(self, args: List[str]) -> List[dict]:
        """start [tutorial|game|over|again|fresh] — begin or restart the tutorial."""
        sub = (args[0] if args else "").lower().strip()
        _RESTART_SUBS = {"tutorial", "game", "over", "again", "fresh", "from", "scratch",
                         "tut", "training", "beginning", "top", "begin", "restart"}
        if not sub or sub in _RESTART_SUBS:
            return self._restart_tutorial()
        # Anything else — just show current tutorial step
        return self._cmd_tutorial([])

