    def _cmd_man(self, args):
        import pathlib, re
        cmd = (args[0] if args else "").strip().lstrip("-")
        if not cmd:
            return [
                _line("man — display manual pages", "cyan"),
                _line("Usage: man <command>", "dim"),
                _line("Try: man ls  |  man nmap  |  man exploit  |  man signal", "dim"),
            ]
        man_dir = pathlib.Path(__file__).parent.parent.parent / "docs" / "commands"
        man_path = man_dir / f"{cmd}.md"
        if man_path.exists():
            raw = man_path.read_text()
            lines_out = []
            for line in raw.splitlines():
                line = line.rstrip()
                if not line:
                    lines_out.append(_line(""))
                    continue
                stripped = line.lstrip()
                if stripped.startswith("## "):
                    lines_out.append(_line(stripped[3:].upper(), "yellow"))
                elif stripped.startswith("# "):
                    lines_out.append(_line(stripped[2:], "cyan"))
                elif stripped.startswith("---"):
                    lines_out.append(_line("─" * 40, "dim"))
                elif stripped.startswith("- ") or stripped.startswith("* "):
                    lines_out.append(_line("  " + stripped[2:], "dim"))
                else:
                    lines_out.append(_line(line))
            return lines_out
        return [
            _line(f"No manual entry for '{cmd}'", "error"),
            _line("Try `help` for in-game command reference, or `man man` for usage.", "dim"),
        ]

