            ("Jan  7 06:00:01", "node-7", "systemd[1]",     "Started Session 1 of User ghost."),
            ("Jan  7 06:00:02", "node-7", "sudo[2041]",     "ghost: COMMAND=/usr/bin/find"),
            ("Jan  7 06:40:00", "node-7", "nexus[1337]",    "CHIMERA sync scheduled. T-minus 120s."),
