    # TEXT EDITORS (vim / vi / nano)
    # ────────────────────────────────────────────────────────────────────

    def _cmd_vim(self, args: List[str]) -> List[dict]:
        """vim / vi — show file content in a read-only display (no interactive mode in browser)."""
        if not args:
            return [
                _sys("VIM — Vi IMproved 9.0"),
                _line("Usage: vim <file>"),
                _line("Note: Interactive editing not available in terminal emulator.", "dim"),
                _line("Use: cat <file> to read, or the write-back API for edits.", "dim"),
            ]
        path = args[0]
        content, err = self._read_file(path)
        if err:
            return [_err(f"vim: {err}")]
        lines_out: List[dict] = [_sys(f"-- VIM -- {path} (read-only) --")]
        for i, ln in enumerate(content.splitlines(), 1):
            lines_out.append(_line(f"{i:4d}  {ln}", "dim" if ln.startswith("#") else None))
        lines_out.append(_line(f"-- {len(content.splitlines())} lines -- Press :q to quit --", "dim"))
        return lines_out

    def _cmd_vi(self, args: List[str]) -> List[dict]:
        return self._cmd_vim(args)

    def _cmd_nano(self, args: List[str]) -> List[dict]:
        """nano — show file content in nano-style display."""
        if not args:
            return [
                _sys("GNU nano 7.2"),
                _line("Usage: nano <file>"),
                _line("[ Read-only in browser terminal ]", "dim"),
            ]
        path = args[0]
        content, err = self._read_file(path)
        if err:
            return [_err(f"nano: {err}")]
        lines_out: List[dict] = [_sys(f"  GNU nano 7.2          {path}")]
        for ln in content.splitlines():
            lines_out.append(_line(f"  {ln}"))
        lines_out.append(_line("^G Help  ^X Exit  ^O Write  ^R Read  ^W Search", "dim"))
        return lines_out

