    # ARCHIVE COMMANDS (tar / zip / gzip)
    # ────────────────────────────────────────────────────────────────────

    def _cmd_tar(self, args: List[str]) -> List[dict]:
        """tar — tape archive (simulated)."""
        if not args:
            return [
                _sys("tar — GNU tar"),
                _line("Usage: tar [options] [archive] [files...]"),
                _line("  tar -czf archive.tar.gz files/   — create compressed archive"),
                _line("  tar -xzf archive.tar.gz          — extract compressed archive"),
                _line("  tar -tzf archive.tar.gz          — list archive contents"),
            ]
        flags = args[0] if args else ""
        archive = args[1] if len(args) > 1 else "archive.tar.gz"
        if "t" in flags:
            return [
                _sys(f"Contents of {archive}:"),
                _line("drwxr-xr-x root/root          0 2026-01-07 06:42 ./"),
                _line("-rw-r--r-- root/root       4096 2026-01-07 06:42 ./data.bin"),
                _line("-rw-r--r-- root/root        512 2026-01-07 06:42 ./config.json"),
            ]
        if "x" in flags:
            return [_ok(f"tar: extracted {archive} to current directory")]
        if "c" in flags:
            files = args[2:] if len(args) > 2 else ["*"]
            return [_ok(f"tar: created {archive} from {', '.join(files)}")]
        return [_err(f"tar: unknown option '{flags}' — try tar --help")]

    def _cmd_zip(self, args: List[str]) -> List[dict]:
        """zip — package and compress files."""
        if not args:
            return [_sys("Usage: zip <archive.zip> <files...>")]
        archive = args[0]
        files = args[1:] if len(args) > 1 else []
        if not files:
            return [_err("zip: nothing to do — specify files")]
        return [_ok(f"  adding: {f} (deflated, 45%)" ) for f in files] + [_ok(f"Archive {archive} created.")]

    def _cmd_unzip(self, args: List[str]) -> List[dict]:
        """unzip — extract a ZIP archive."""
        if not args:
            return [_sys("Usage: unzip <archive.zip> [-d <dest>]")]
        archive = args[0]
        return [
            _sys(f"Archive: {archive}"),
            _line("  inflating: data.bin"),
            _line("  inflating: config.json"),
            _ok(f"Extracted to current directory."),
        ]

    def _cmd_gzip(self, args: List[str]) -> List[dict]:
        """gzip — compress or decompress files."""
        if not args:
            return [_sys("Usage: gzip [-d] <file>")]
        flags = [a for a in args if a.startswith("-")]
        files = [a for a in args if not a.startswith("-")]
        if "-d" in flags or "--decompress" in flags:
            return [_ok(f"gzip: decompressed {f}" ) for f in files]
        return [_ok(f"gzip: compressed {f} → {f}.gz" ) for f in files]

    # ────────────────────────────────────────────────────────────────────
    # BINARY ANALYSIS (strings / od / xxd / hexdump)
    # ────────────────────────────────────────────────────────────────────

    def _cmd_strings(self, args: List[str]) -> List[dict]:
        """strings — extract printable strings from a file."""
        if not args:
            return [_sys("Usage: strings <file>")]
        path = args[0]
        content, err = self._read_file(path)
        if err:
            return [_err(f"strings: {err}")]
        printable = []
        for ln in content.splitlines():
            clean = "".join(c for c in ln if c.isprintable())
            if len(clean) >= 4:
                printable.append(clean)
        if not printable:
            return [_line(f"strings: no printable strings found in {path}", "dim")]
        return [_line(s) for s in printable[:50]]

    def _cmd_od(self, args: List[str]) -> List[dict]:
        """od — octal dump."""
        if not args:
            return [_sys("Usage: od [-x|-c|-t x1] <file>")]
        path = args[-1]
        content, err = self._read_file(path)
        if err:
            return [_err(f"od: {err}")]
        rows: List[dict] = []
        data = content.encode("utf-8", errors="replace")
        for i in range(0, min(len(data), 128), 16):
            chunk = data[i:i+16]
            hex_pairs = " ".join(f"{b:02x}" for b in chunk)
            ascii_repr = "".join(chr(b) if 32 <= b < 127 else "." for b in chunk)
            rows.append(_line(f"{i:08o}  {hex_pairs:<47}  |{ascii_repr}|", "dim"))
        rows.append(_line(f"{len(data):08o}", "dim"))
        return rows

    def _cmd_hexdump(self, args: List[str]) -> List[dict]:
        return self._cmd_xxd(args)

