    # ────────────────────────────────────────────────────────────────────
    # DIFF / COMPARE
    # ────────────────────────────────────────────────────────────────────

    def _cmd_diff(self, args: List[str]) -> List[dict]:
        """diff — compare files line by line."""
        clean = [a for a in args if not a.startswith("-")]
        if len(clean) < 2:
            return [_sys("Usage: diff <file1> <file2>")]
        f1, f2 = clean[0], clean[1]
        c1, e1 = self._read_file(f1)
        c2, e2 = self._read_file(f2)
        if e1:
            return [_err(f"diff: {f1}: {e1}")]
        if e2:
            return [_err(f"diff: {f2}: {e2}")]
        lines1 = c1.splitlines()
        lines2 = c2.splitlines()
        if lines1 == lines2:
            return [_ok(f"Files {f1} and {f2} are identical.")]
        out: List[dict] = []
        for i, (a, b) in enumerate(zip(lines1, lines2)):
            if a != b:
                out.append(_line(f"< {a}", "light-red"))
                out.append(_line(f"> {b}", "light-green"))
        if len(lines1) > len(lines2):
            for ln in lines1[len(lines2):]:
                out.append(_line(f"< {ln}", "light-red"))
        elif len(lines2) > len(lines1):
            for ln in lines2[len(lines1):]:
                out.append(_line(f"> {ln}", "light-green"))
        return out or [_ok("No differences found.")]

    def _cmd_cmp(self, args: List[str]) -> List[dict]:
        return self._cmd_diff(args)

