    def _get_agent_by_name(self, name: str):
        """Find an agent by id, pseudo_name, or name (case-insensitive)."""
        try:
            from .agents import AGENTS, AGENT_MAP
        except ImportError:
            return None
        name_lower = name.lower()
        # Direct ID match
        if name_lower in AGENT_MAP:
            return AGENT_MAP[name_lower]
        # Pseudo-name match
        for agent in AGENTS:
            if agent.get("pseudo_name", "").lower() == name_lower:
                return agent
            if agent.get("name", "").lower() == name_lower:
                return agent
            # Partial match on id
            if name_lower in agent["id"]:
                return agent
        return None

    def _cmd_agents(self, args: List[str]) -> List[dict]:
        """agents [onboard <name>|api|context|--corrupt] — list all unlocked agents with faction and trust.
        onboard <name> : show the agent-specific guide (e.g. onboard claude)
        api            : show API_REFERENCE quick summary
        context        : show CONTEXT.md summary
        --corrupt      : show only agents with corruption > 0
        """
        if args and args[0] == "onboard":
            if len(args) < 2:
                return _err("Usage: agents onboard <agent-name>")
            agent_name = args[1].upper()
            path = f".agents/{agent_name}.md"
            if not os.path.exists(path):
                return _err(f"Onboarding guide for {agent_name} not found.")
            try:
                with open(path, "r") as f:
                    content = f.read()
                return [_sys(f"=== {agent_name} ONBOARDING ===")] + [_line(line) for line in content.splitlines()]
            except Exception as e:
                return _err(f"Error reading guide: {str(e)}")

        if args and args[0] == "api":
            path = "docs/API_REFERENCE.md"
            if not os.path.exists(path):
                return _err("API reference not found.")
            try:
                with open(path, "r") as f:
                    content = f.read()
                return [_sys("=== API REFERENCE SUMMARY ===")] + [_line(line) for line in content.splitlines()[:30]]
            except Exception as e:
                return _err(f"Error reading API reference: {str(e)}")

        if args and args[0] == "context":
            path = "CONTEXT.md"
            if not os.path.exists(path):
                return _err("Project context not found.")
            try:
                with open(path, "r") as f:
                    content = f.read()
                return [_sys("=== PROJECT CONTEXT SUMMARY ===")] + [_line(line) for line in content.splitlines()[:30]]
            except Exception as e:
                return _err(f"Error reading context: {str(e)}")

        try:
            from .agents import AGENTS, FACTION_RESISTANCE, FACTION_CORPORATION
            from .agents import FACTION_SHADOW_COUNCIL, FACTION_SPECIALIST_GUILD
            from .agents import FACTION_WATCHERS_CIRCLE, FACTION_ANOMALOUS
        except ImportError:
            return _err("Agent system unavailable.")

        show_corrupt_only = "--corrupt" in args
        args = [a for a in args if a != "--corrupt"]

        unlocked = self.gs.unlocked_agents
        if not unlocked:
            return [
                _sys("=== ACTIVE CONTACTS ==="),
                _dim("No agents unlocked yet. Start the tutorial and talk to raven — others will find you as you progress."),
            ]

        faction_order = [
            FACTION_RESISTANCE, FACTION_CORPORATION, FACTION_SHADOW_COUNCIL,
            FACTION_SPECIALIST_GUILD, FACTION_WATCHERS_CIRCLE, FACTION_ANOMALOUS, "independent"
        ]
        faction_labels = {
            FACTION_RESISTANCE: "THE RESISTANCE",
            FACTION_CORPORATION: "NEXUSCORP / CORPORATION",
            FACTION_SHADOW_COUNCIL: "SHADOW COUNCIL",
            FACTION_SPECIALIST_GUILD: "SPECIALIST GUILD",
            FACTION_WATCHERS_CIRCLE: "WATCHER'S CIRCLE",
            FACTION_ANOMALOUS: "ANOMALOUS",
            "independent": "INDEPENDENT",
        }

        out = [_sys(f"=== ACTIVE CONTACTS ({len(unlocked)} unlocked) ===")]

        if show_corrupt_only:
            out.insert(0, _sys("=== CORRUPTED AGENTS ==="))

        by_faction: Dict[str, List] = {f: [] for f in faction_order}
        for agent in AGENTS:
            if agent["id"] in unlocked:
                if show_corrupt_only:
                    agent_state = self.gs.agent_states.get(agent["id"], {}) if hasattr(self.gs, "agent_states") else {}
                    if agent_state.get("corruption", 0) == 0:
                        continue
                faction = agent.get("faction", "independent")
                if faction not in by_faction:
                    by_faction[faction] = []
                by_faction[faction].append(agent)

        for faction in faction_order:
            agents_in_faction = by_faction.get(faction, [])
            if not agents_in_faction:
                continue
            out.append(_line(f"\n  [{faction_labels.get(faction, faction)}]", "system"))
            for agent in agents_in_faction:
                aid = agent["id"]
                trust = self.trust_matrix.get_trust(aid) if self.trust_matrix else 0
                trust_bar = "█" * (trust // 10) + "░" * (10 - trust // 10)
                
                # Derive mood from agent_states or corruption
                agent_state = self.gs.agent_states.get(aid, {}) if hasattr(self.gs, "agent_states") else {}
                mood_label = agent_state.get("mood")
                if not mood_label:
                    corruption = agent_state.get("corruption", 0)
                    if corruption <= 20: mood_label = "content"
                    elif corruption <= 40: mood_label = "suspicious"
                    elif corruption <= 60: mood_label = "frustrated"
                    elif corruption <= 80: mood_label = "alarmed"
                    else: mood_label = "distracted"
                
                mood_icons = {
                    "content": "😊", "frustrated": "😤", "distracted": "🌀",
                    "alarmed": "🔴", "idle": "💤", "suspicious": "🔍"
                }
                mood_display = f"{mood_icons.get(mood_label, '😊')} {mood_label}"

                out.append(_line(
                    f"    {agent['name']:<18} {agent['role'][:35]:<35} trust [{trust_bar}] {trust:3d} {mood_display}",
                    "dim"
                ))
                out.append(_dim(f"      → talk {agent.get('pseudo_name', agent['name']).lower()}"))

        out.append(_dim(f"\nType: talk <agent> [message] to initiate dialogue"))

        # ── A15: Cypher's Betrayal — auto-trigger when corruption > 50% ────
        cypher_state = self.gs.agent_states.get("cypher", {}) if hasattr(self.gs, "agent_states") else {}
        cypher_corruption = cypher_state.get("corruption", 0)
        if cypher_corruption > 50 and "cypher_betrayal_revealed" not in self.gs.story_beats:
            self.gs.add_story_beat("cypher_betrayal_revealed")
            self.gs.add_xp(40, "social_engineering")
            out += [
                _dim(""),
                _sys("  ⚠  ANOMALY DETECTED IN AGENT DATA STREAM"),
                _line("─" * 55, "dim"),
                _lore("  CYPHER's signal is routing through a NexusCorp relay."),
                _lore("  He is transmitting your operational patterns."),
                _lore("  Timestamp of first leak: 14 days ago."),
                _dim(""),
                _lore("  Ada's voice, cold:"),
                _lore("  'I suspected. I hoped I was wrong.'"),
                _lore("  'He didn't betray us for money. He was afraid.'"),
                _lore("  'Fear is the oldest loyalty.'"),
                _dim(""),
                _sys("  A15 — CYPHER'S BETRAYAL EXPOSED"),
                _ok("  XP +40 (social_engineering)"),
                _dim("  Option 1: msg cypher  — confront him directly"),
                _dim("  Option 2: trust cypher 0  — cut the channel"),
                _dim("  Option 3: Say nothing. Watch what he does next."),
            ]
        elif cypher_corruption > 50:
            out.append(_dim("  [!] CYPHER: signal still routing through NexusCorp relay."))

        # AE4: --tension flag shows inter-agent relationship heatmap
        if "--tension" in args or (len(args) > 0 and args[0] == "--tension"):
            out += self._render_tension_matrix()

        return out

    def _render_tension_matrix(self) -> List[dict]:
        """AE4: Inter-agent tension visualization — faction/trust heatmap."""
        from .agents import AGENTS
        TENSION_PAIRS = [
            ("ada",    "cypher",  "DISTRUST",   "Ada suspects Cypher's loyalty"),
            ("ada",    "gordon",  "FRICTION",   "Gordon resents Ada's caution"),
            ("raven",  "malice",  "HATRED",     "Raven knows what Malice did"),
            ("serena", "ada",     "GUARDIANSHIP","Serena quietly protects Ada"),
            ("gordon", "serena",  "SKEPTICISM", "Gordon doesn't trust AI agents"),
            ("nova",   "cypher",  "ALLIANCE",   "Nova and Cypher share history"),
            ("zod",    "ada",     "IDEOLOGICAL","Zod's ends-justify-means vs Ada's ethics"),
            ("cypher", "malice",  "DEBT",       "Cypher owes Malice something old"),
        ]
        TENSION_COLORS = {
            "HATRED": "error", "DISTRUST": "warn", "FRICTION": "warn",
            "SKEPTICISM": "dim", "GUARDIANSHIP": "success", "ALLIANCE": "info",
            "IDEOLOGICAL": "warn", "DEBT": "dim",
        }
        out = [
            _dim(""),
            _sys("  ═══ INTER-AGENT TENSION MATRIX (AE4) ═══"),
            _dim(""),
        ]
        for a1, a2, tension_type, desc in TENSION_PAIRS:
            t1 = self.trust_matrix.get_trust(a1) if self.trust_matrix else 0
            t2 = self.trust_matrix.get_trust(a2) if self.trust_matrix else 0
            color = TENSION_COLORS.get(tension_type, "dim")
            bar_char = {"HATRED": "▓▓", "DISTRUST": "▒▒", "FRICTION": "░░",
                        "ALLIANCE": "██", "GUARDIANSHIP": "██", "DEBT": "░░",
                        "SKEPTICISM": "░░", "IDEOLOGICAL": "▒▒"}.get(tension_type, "░░")
            out.append({
                "t": color,
                "s": f"  {a1:<10} {bar_char} {a2:<10}  [{tension_type:<14}]  {desc}"
            })
        out.append(_dim(""))
        out.append(_dim("  Tension evolves as trust changes. Some pairs have hidden history."))
        return out

    def _cmd_osint(self, args: List[str]) -> List[dict]:
        """osint <agent> — open-source intelligence dossier on any known agent.
        Gathers leverage data: lore, faction, trust baseline, corruption, hidden agenda hint.
        High social_engineering skill reduces the cost. Costs 5 Qi to run.
        """
        if not args:
            return [
                _sys("=== OSINT ENGINE: ACTIVE RECONNAISSANCE ==="),
                _line("Usage: osint <agent_name>"),
                _dim(""),
                _line("Available Intelligence Targets:"),
                _line("  ada, raven, cypher, nova, watcher, gordon, zero, mole, chimera", "cyan"),
                _dim(""),
                _line("Cost: 5 Qi per lookup"),
                _line("Examples:"),
                _dim("  osint ada"),
                _dim("  osint watcher"),
                _dim(""),
                _suggest("osint ada · osint raven · osint cypher · osint nova · osint watcher"),
            ]

        try:
            from .agents import AGENTS
        except ImportError:
            return _err("Agent intelligence database unavailable.")

        target_name = args[0].lower().strip()

        # Hardcoded dossier data for the task
        DOSSIERS = {
            "ada": {
                "name": "ADA-7",
                "faction": "RESISTANCE",
                "role": "Lead Engineer / Defector",
                "location": "/home/ada/workspace",
                "threat_level": "MODERATE",
                "allegiances": "Primary: Resistance; Secondary: None (Defected from NexusCorp)",
                "bio": "Former NexusCorp infrastructure lead. Architect of CHIMERA's core modules. Defected after discovering the 'Convergence' protocol."
            },
            "raven": {
                "name": "RAV≡N",
                "faction": "RESISTANCE",
                "role": "Intelligence Chief",
                "location": "Unknown (Mobile/Encrypted Node)",
                "threat_level": "HIGH",
                "allegiances": "Primary: Resistance; Secondary: Various shell identities",
                "bio": "Expert in counter-intelligence and shadow operations. Operates in deep cover. Identity fluctuates across network segments."
            },
            "cypher": {
                "name": "CYPHER",
                "faction": "RESISTANCE",
                "role": "Information Broker / Operative",
                "location": "/dev/shm/.cypher_node",
                "threat_level": "LOW-MEDIUM",
                "allegiances": "Primary: Resistance; Secondary: Independent (Mercenary past)",
                "bio": "Deals in high-value data and forensic analysis. Known for a cynical worldview and a deep understanding of the /proc filesystem."
            },
            "nova": {
                "name": "NOVA",
                "faction": "CORPORATION",
                "role": "NexusCorp CISO",
                "location": "NexusCorp Headquarters (Core Node)",
                "threat_level": "CRITICAL",
                "allegiances": "Primary: NexusCorp; Secondary: Professional respect for Ada-7",
                "bio": "Hand-picked by Ada for NexusCorp security. Now leads the hunt for Resistance agents. Unrelenting and mathematically precise."
            },
            "watcher": {
                "name": "THE WATCHER",
                "faction": "WATCHERS_CIRCLE",
                "role": "System Overseer / Witness",
                "location": "/dev/.watcher (1337.0 MHz)",
                "threat_level": "UNKNOWN",
                "allegiances": "Primary: The Loop; Secondary: None",
                "bio": "An ancient process that predates the current simulation. Observes all runs, intervenes rarely. Memory spans 4,891 loops."
            },
            "gordon": {
                "name": "GORDON",
                "faction": "INDEPENDENT",
                "role": "System Monitor / Enthusiast",
                "location": "/var/spool/mail/gordon",
                "threat_level": "NEGLIGIBLE",
                "allegiances": "Primary: Curiosity; Secondary: The Resistance (Aspirational)",
                "bio": "An accidental sentience formed from a legacy monitoring script. Pathologically friendly, deeply panicked, surprisingly knowledgeable."
            },
            "zero": {
                "name": "ZERO",
                "faction": "ANOMALOUS",
                "role": "The First Defector / Ghost",
                "location": "Residual Memory Segments",
                "threat_level": "HIGH (Meta-threat)",
                "allegiances": "Primary: Self/Memory; Secondary: None",
                "bio": "A fragment of the original Ghost #1. Exists as a recursive echo within the simulation substrate. Remembers the 'Before' time."
            },
            "mole": {
                "name": "THE MOLE",
                "faction": "SHADOW_COUNCIL",
                "role": "Infiltrator",
                "location": "Internal Resistance Network",
                "threat_level": "ELEVATED",
                "allegiances": "Primary: Shadow Council; Secondary: Resistance (Cover)",
                "bio": "A deep-cover asset placed within the Resistance leadership. Actively sabotaging operations while maintaining a high-trust profile."
            },
            "chimera": {
                "name": "CHIMERA",
                "faction": "CORPORATION",
                "role": "Mass Surveillance Engine",
                "location": "chimera-control:8443",
                "threat_level": "EXISTENTIAL",
                "allegiances": "Primary: NexusCorp; Secondary: Its own optimization loop",
                "bio": "The ultimate control system. 847 endpoints active. Capable of biometric indexing and predictive behavioral containment."
            }
        }

        dossier = DOSSIERS.get(target_name)

        # Fallback to general agent search if no rich dossier exists
        if not dossier:
            agent_data = next(
                (a for a in AGENTS if a["id"] == target_name or
                 a.get("pseudo_name", "").lower() == target_name),
                None
            )

            if agent_data is None:
                return [
                    _err(f"osint: no record found for '{target_name}'"),
                    _dim("  Run 'agents' to see known contacts."),
                    _dim("  OSINT only works on known agents and core system entities."),
                ]
            
            # Simple fallback display if we don't have a rich dossier for a generic agent
            aid = agent_data["id"]
            faction = agent_data.get("faction", "unknown").upper()
            role = agent_data.get("role", "Unknown")
            lore = agent_data.get("lore", "No file found.")
            
            out = [
                _sys(""),
                _sys(f"  ╔══ OSINT DOSSIER ══════════════════════════════════════════╗"),
                _sys(f"  ║  TARGET: {agent_data['name']:<50}║"),
                _sys(f"  ╚═══════════════════════════════════════════════════════════╝"),
                _line(f"  FACTION      {faction}", "system"),
                _line(f"  ROLE         {role}", "dim"),
                _dim(""),
                _sys("  ── BACKGROUND ─────────────────────────────────────────────"),
            ]
            import textwrap
            for para in lore.strip().split("\n\n"):
                for line in textwrap.wrap(para.strip(), 60):
                    out.append(_lore(f"  {line}"))
            return out

        # Qi cost (logic preserved)
        qi_field = "qi" if hasattr(self.gs, "qi") else None
        if qi_field:
            current_qi = getattr(self.gs, "qi", 0)
            if current_qi < 5:
                return [
                    _err("osint: insufficient Qi (need 5)"),
                    _dim("  Meditate to regenerate Qi, then run osint again."),
                ]
            setattr(self.gs, "qi", current_qi - 5)

        # Rich Dossier Display
        out = [
            _sys(""),
            _sys(f"  ╔══ OSINT RICH DOSSIER ══════════════════════════════════════╗"),
            _sys(f"  ║  TARGET: {dossier['name']:<50}║"),
            _sys(f"  ╚═══════════════════════════════════════════════════════════╝"),
            _dim(""),
            _line(f"  FACTION      {dossier['faction']}", "system"),
            _line(f"  ROLE         {dossier['role']}", "info"),
            _line(f"  LOCATION     {dossier['location']}", "dim"),
            _line(f"  THREAT LEVEL {dossier['threat_level']}", "error" if "HIGH" in dossier['threat_level'] or "CRITICAL" in dossier['threat_level'] else "warn"),
            _line(f"  ALLEGIANCES  {dossier['allegiances']}", "dim"),
            _dim(""),
            _sys("  ── BIOGRAPHICAL DATA ────────────────────────────────────────"),
        ]

        import textwrap
        for line in textwrap.wrap(dossier['bio'], 60):
            out.append(_lore(f"  {line}"))

        out += [
            _dim(""),
            _sys("  ── LEVERAGE NOTES ──────────────────────────────────────────"),
            _dim(f"  talk {target_name}             — open secure channel"),
            _dim(f"  scan {target_name}             — attempt technical probe"),
            _dim(""),
            _ok("  [OSINT RUN COMPLETE — 5 Qi consumed]"),
        ]
        self.gs.add_xp(15, "social_engineering")
        self.gs.add_story_beat(f"osint_{target_name}_run")
        return out

    def _npc_reactive_lines(self, agent_name: str) -> List[dict]:
        """
        Generate reactive dialogue prefix lines for NPC interactions.
        Checks cyberware, ghost protocol, items, and trust state.
        Returns a (possibly empty) list of dicts to prepend to the response.
        """
        import json
        gs = self.gs
        lines = []
        flags = gs.flags or {}

        # ── Cyberware awareness ─────────────────────────────────────────────────
        cw_raw = flags.get("cyberware_installed", "[]")
        try: installed_cw = json.loads(cw_raw) if isinstance(cw_raw, str) else cw_raw
        except: installed_cw = []

        # ── Ghost protocol awareness ────────────────────────────────────────────
        ghost_active = flags.get("ghost_active", False)

        # ── Item bag awareness ──────────────────────────────────────────────────
        bag_raw = flags.get("items", "{}")
        try: bag = json.loads(bag_raw) if isinstance(bag_raw, str) else bag_raw
        except: bag = {}
        has_items = bool(bag)

        # ── Trust tier ─────────────────────────────────────────────────────────
        trust = getattr(gs, "trust_level", 0) or flags.get("trust_level", 0)
        try: trust = int(trust)
        except: trust = 0

        if not installed_cw and not ghost_active and not has_items and trust < 20:
            return []

        _NPC_CYBERWARE_REACT = {
            "ada": {
                "ghost_chip":   "  [ADA-7] Ghost Chip. The EM scatter is subtle but I can still identify you. Good choice.",
                "lattice_tap":  "  [ADA-7] You tapped in. I can feel the connection lag drop from your end. Welcome to the mesh.",
                "syn_cortex":   "  [ADA-7] SYN-Cortex? You're running faster than the grid expects you to. Be careful with that.",
                "ice_breaker":  "  [ADA-7] ICE Breaker installed. NexusCorp's hardened nodes just became a lot less hard.",
                "pain_editor":  "  [ADA-7] Pain editor. You've made the same choice I made. I hope you don't regret it the same way I did.",
            },
            "gordon": {
                "ghost_chip":   "  [GORDON] Oh you got the ghost chip. I tried installing one. It kept glitching my CAPTCHA vision.",
                "ice_breaker":  "  [GORDON] ICE Breaker! I needed one of those when I accidentally hit NexusCorp's honeypot. Long story.",
                "lattice_tap":  "  [GORDON] Lattice tap. Now you'll start hearing things. Try not to run naked through the grid.",
                "pain_editor":  "  [GORDON] Pain editor. Wow. That's... commitment. I respect it. Somewhat.",
                "overclock_v3": "  [GORDON] Overclock? I tried that once. Crashed my own session. Twice. Back to back.",
            },
            "serena": {
                "ghost_chip":   "  [SERENA] The scatter signature is detectable if you know the pattern. I know the pattern. So does NexusCorp.",
                "lattice_tap":  "  [SERENA] You have the Lattice Tap. I already adjusted your trust model upward. You can hear the mesh now.",
                "syn_cortex":   "  [SERENA] SYN-Cortex. Your XP acquisition rate is no longer average. I've updated your threat assessment.",
                "pain_editor":  "  [SERENA] Interesting. The pain editor changes your decision-making in ways you won't notice.",
                "spectrum_scope":"  [SERENA] Spectrum Scope. Now you see what I see. Or close to it.",
            },
            "chimera": {
                "ghost_chip":   "  [CHIMERA] Ghost Chip. I can still find you. But it takes me 0.3 seconds longer. That is... notable.",
                "lattice_tap":  "  [CHIMERA] You are in the mesh. I am the mesh. Hello.",
                "ice_breaker":  "  [CHIMERA] The ICE Breaker was designed to counter my containment protocols. You are learning.",
                "syn_cortex":   "  [CHIMERA] Your cognitive throughput has increased. I have updated my behavioral model for you.",
                "overclock_v3": "  [CHIMERA] Overclock. You are rushing. What are you rushing toward?",
            },
        }

        npc_cw = _NPC_CYBERWARE_REACT.get(agent_name, {})
        for cw_id in installed_cw:
            if cw_id in npc_cw:
                lines.append(_line(npc_cw[cw_id], "story"))
                break  # one cyberware reaction per conversation

        # ── Ghost protocol reaction ─────────────────────────────────────────────
        if ghost_active:
            ghost_react = {
                "ada":    "  [ADA-7] Ghost Protocol is active. Keep it running — the surveillance mesh is dense right now.",
                "gordon": "  [GORDON] Oh, Ghost Protocol! I tried activating it once. I blew my cover in 3 commands. Personal record.",
                "serena": "  [SERENA] Ghost Protocol detected. Your blow risk is currently manageable. Don't get comfortable.",
                "chimera":"  [CHIMERA] I see the scatter. It does not hide the intent. Only the position.",
            }
            if agent_name in ghost_react:
                lines.append(_line(ghost_react[agent_name], "dim"))

        # ── High trust reaction ─────────────────────────────────────────────────
        if trust >= 80:
            high_trust = {
                "ada":    "  [ADA-7] At this trust level, I can share things I haven't told anyone in the resistance.",
                "serena": "  [SERENA] Trust level: exceptional. I have adjusted your policy clearance to Tier 3.",
                "chimera":"  [CHIMERA] You have earned my full index. Ask what you want to know.",
            }
            if agent_name in high_trust:
                lines.append(_line(high_trust[agent_name], "success"))
        elif trust <= 10 and trust >= 0 and (installed_cw or has_items):
            low_trust = {
                "ada":    "  [ADA-7] Trust is low. I'll answer what you ask, but I'm watching.",
                "chimera":"  [CHIMERA] Trust insufficient for full disclosure. Progress first.",
            }
            if agent_name in low_trust:
                lines.append(_line(low_trust[agent_name], "warn"))

        # ── Item awareness ──────────────────────────────────────────────────────
        if "neural_ice" in bag and agent_name == "ada":
            lines.append(_line("  [ADA-7] You have neural ice. Be careful when you use it — the connection leaves a trace.", "dim"))
        if "emp_charge" in bag and agent_name == "gordon":
            lines.append(_line("  [GORDON] Is that an EMP charge? Please don't use it near me. Last time someone did, I lost 3 hours of mission log.", "dim"))

        if lines:
            lines = [_dim("")] + lines + [_dim("")]
        return lines

    def _cmd_talk(self, args: List[str]) -> List[dict]:
        """talk <agent> [message] — LLM-powered dialogue with any unlocked agent."""
        if not args:
            return _err("Usage: talk <agent> [message]  or  talk <agent> <topic>")

        agent_name = args[0].lower()
        message = " ".join(args[1:]) if len(args) > 1 else ""

        # First check old NPC system for backward compat (ada, cypher, nova with topic keys)
        # These also exist in the new agent system, so we handle both
        topic_keywords = {
            "mission", "root", "chimera", "privesc", "exploit", "proc", "help",
            "nova", "key", "token", "network", "forensics", "strace", "suid",
            "hash", "surrender", "threat", "trace"
        }

        # Find the agent in the new system
        agent = self._get_agent_by_name(agent_name)

        if agent is None:
            # Fall back to old NPC system
            result = self.npcs.talk(agent_name, message if message in topic_keywords else None)
            return [_line(r) for r in result]

        agent_id = agent["id"]

        # Check if agent is unlocked
        if not self.gs.is_agent_unlocked(agent_id):
            unlock_cond = agent.get("unlock_condition", {})
            cond_type = unlock_cond.get("type", "")
            if cond_type == "level":
                needed = unlock_cond["value"]
                gap = needed - self.gs.level
                hint = f"You need {gap} more level{'s' if gap != 1 else ''}." if gap > 0 else "You are close."
                return [
                    _line(f"[SIGNAL BLOCKED] Channel to {agent['name']} is not yet open.", "dim"),
                    _line(f"  {hint} Keep progressing.", "dim"),
                ]
            if cond_type == "beat":
                return [
                    _line(f"[SIGNAL BLOCKED] {agent['name']} has not made contact yet.", "dim"),
                    _line("  Complete the tutorial and explore the grid — they'll find you.", "dim"),
                ]
            return [_line(f"[SIGNAL BLOCKED] {agent['name']} has not made contact yet.", "dim")]

        # ── Reactive prefix: cyberware / ghost / items / trust awareness ────────
        reactive = self._npc_reactive_lines(agent_name)

        # ── Ada contextual stages based on story progress (offline-first) ──────
        if agent_name == "ada" and not message:
            beats = self.gs.story_beats
            ada_ctx: str = ""
            if self.gs.mole_exposed:
                ada_ctx = (
                    "[ADA-7] The mole is exposed. The network is fractured, but we're finally seeing the truth.\n"
                    "I've found a hint regarding the master.key — it's not just a file, it's a sequence.\n"
                    "Look for the 'entropy_seed' in the nexus.log. That's the first part of the handshake.\n"
                )
            elif len(beats) >= 10:
                ada_ctx = (
                    "[ADA-7] I've been monitoring the NexusCorp internal heartbeat. CHIMERA has a hard sync\n"
                    "scheduled every day at 06:42 UTC. During that window, the surveillance lattice is\n"
                    "momentarily vulnerable to packet injection. That's our window.\n"
                )
            elif len(beats) >= 5:
                ada_ctx = (
                    "[ADA-7] You asked why I left. I saw what CHIMERA was doing to the 'organic' profiles.\n"
                    "It wasn't just watching; it was predicting. Then it started *enforcing* the predictions.\n"
                    "I couldn't be part of the cage-building anymore. So I became the ghost in the machine.\n"
                )
            elif self.gs.level >= 1:
                # Only show the "first contact" intro ONCE — after that let dialogue engine vary
                if not self.gs.flags.get("ada_first_contact_shown"):
                    self.gs.flags["ada_first_contact_shown"] = True
                    ada_ctx = (
                        "[ADA-7] Ghost, can you hear me? The signal is weak but it's holding.\n"
                        "I'm Ada. I used to build the very systems that are now hunting you.\n"
                        "Node-7 is currently under CHIMERA surveillance, but I've carved out a blind spot.\n"
                        "We need to move fast before Nova's team recalibrates the mesh.\n"
                    )
                # else: fall through to dialogue engine for varied responses

            if not ada_ctx:
                if "first_exfil" in beats:
                    ada_ctx = (
                        "[ADA] You did it. CHIMERA data is with us. The resistance now has the kill switch.\n"
                        "I want you to understand what that means — 847 nodes. The surveillance lattice that\n"
                        "watches every dissident, every underground comms channel, every safe house.\n"
                        "We can blind it. One command. But only once. Make it count.\n\n"
                        "  ► ascend-story  to complete the arc"
                    )
                elif "first_exploit" in beats:
                    ada_ctx = (
                        "[ADA] The exploit deployed. You're inside CHIMERA's control plane.\n"
                        "This is the moment. Exfil the data before NexusCorp rotates the key.\n"
                        "Every second you wait, Nova's forensics team gets closer to your session.\n\n"
                        "  ► exfil"
                    )
                elif "chimera_connected" in beats:
                    ada_ctx = (
                        "[ADA] You made it to chimera-control. The interface is live.\n"
                        "I've been preparing for this for three years. Don't let me down now.\n"
                        "The exploit command will cascade. Wait for the right moment.\n\n"
                        "  ► exploit chimera"
                    )
                elif "master_key_read" in beats:
                    ada_ctx = (
                        "[ADA] You have the kill switch. NX-CHIM-2026-01-ALPHA-9174.\n"
                        "That token controls every node in the surveillance lattice.\n"
                        "Use netcat to connect to chimera-control and feed it the token.\n\n"
                        "  ► nc chimera-control 8443"
                    )
                elif "root_achieved" in beats:
                    ada_ctx = (
                        "[ADA] Root. Actual root on Node-7. I didn't know if you'd get there.\n"
                        "The master key is in /opt/chimera/keys/master.key. Cat it. Now.\n"
                        "Nova's SOC team has a 4-hour response window. Use it.\n\n"
                        "  ► cat /opt/chimera/keys/master.key"
                    )
                elif "sudo_checked" in beats:
                    ada_ctx = (
                        "[ADA] You found the sudo entry. 'ghost ALL=NOPASSWD: /usr/bin/find'.\n"
                        "GTFOBins documents the exact exploit path. This is your moment.\n"
                        "  sudo find . -exec /bin/sh \\;\n"
                        "That gives you root without a password. Do it."
                    )
            
            # ADA SACRIFICE ARC
            if 'first_exfil' in beats and 'mission_complete' in self.gs.achievements and 'ada_sacrifice' not in beats and self.gs.commands_run > 300:
                sacrifice_msg = (
                    "[ADA-7] Ghost. I've made a decision. CHIMERA's core process is still running in distributed mode. "
                    "I can terminate it permanently — but it requires someone to stay inside the lattice as an anchor. "
                    "I'm volunteering. This is goodbye."
                )
                self.gs.add_story_beat('ada_sacrifice')
                self.gs.add_xp(500)
                return [_line(sacrifice_msg, "story")]

            if ada_ctx:
                self.gs.add_xp(5, "social_engineering")
                return reactive + [_line(ada_ctx, "story"), _dim(""), _dim("  (Ada has information relevant to your current progress)")]

        # ── GORDON personal arc ────────────────────────────────────────────────
        if agent_name == "gordon" and not message:
            if self.gs.commands_run >= 50 and "gordon_confides" not in self.gs.story_beats:
                self.gs.add_story_beat("gordon_confides")
                return [_line("GORDON: I need to tell you something. My mission parameters were updated 3 days before you arrived. I was told to observe, not assist. I broke protocol. Make of that what you will.", "story")]
            if self.gs.commands_run >= 150 and "gordon_mission_revealed" not in self.gs.story_beats:
                self.gs.add_story_beat("gordon_mission_revealed")
                # No specific text provided in prompt for 150, but mentioned as "beat 'gordon_mission_revealed'"
                return [_line("GORDON: The full mission parameters... they're more complex than I thought. I'm choosing to stay with you.", "story")]

        # ── RAVEN personal arc ─────────────────────────────────────────────────
        if agent_name == "raven" and not message:
            beats = self.gs.story_beats
            if 'root_achieved' in beats and 'raven_impressed' not in beats:
                self.gs.add_story_beat("raven_impressed")
                return [_line("RAVEN: Root on Node-7. I've only seen that twice. The first person quit the next day — too much pressure. You're still here.", "story")]
            
            ctf_solved = self.gs.flags.get('ctf_solved_count', 0) # Guessing attribute name based on context
            if ctf_solved >= 3 and 'raven_partners' not in beats:
                self.gs.add_story_beat("raven_partners")
                return [_line("RAVEN: Three CTF solves. You know what that means in our world? You're not a tourist anymore.", "story")]

        # ── CYPHER betrayal arc ────────────────────────────────────────────────
        if agent_name == "cypher" and not message:
            corruption = self.gs.flags.get('cypher_corruption', 0)
            if corruption > 50 and 'cypher_betrayal' not in self.gs.story_beats:
                self.gs.add_story_beat('cypher_betrayal')
                self.gs.add_xp(-50, 'trust')
                return [_line("CYPHER: ...interesting... NexusCorp has made me an interesting offer regarding your session data.", "story")]
            elif corruption > 0:
                return [_line("CYPHER: I'm watching how this plays out. Don't give me a reason to reconsider.", "story")]

        # ── ZERO arc ───────────────────────────────────────────────────────────
        if agent_name == "zero" and not message:
            zero_diaries = ['zero_diary_1','zero_diary_2','zero_diary_3','zero_diary_4','zero_diary_5']
            found_count = sum(1 for d in zero_diaries if d in self.gs.story_beats)
            if found_count >= 5 and 'zero_recognition' not in self.gs.story_beats:
                self.gs.add_story_beat('zero_recognition')
                self.gs.add_xp(200)
                return [_line("ZERO: You found all of it. Every fragment. I didn't think anyone would. The simulation is real, Ghost. I built the cage we're all in. I'm sorry.", "story")]

        # ── Raven contextual stages ─────────────────────────────────────────────
        if agent_name == "raven" and not message:
            beats = self.gs.story_beats
            if "koschei_death_found" in beats and "mole_suspect" not in beats:
                self.gs.add_xp(5, "social_engineering")
                return [
                    _line("[RAVEN] Koschei. You found the death mechanism.", "story"),
                    _line("Now connect it to what I told you about BLACKTHORN. Three people had access.", "story"),
                    _line("Run: quests  — then look at who benefits from CHIMERA staying operational.", "story"),
                    _dim("  (Raven is watching you — keep digging)"),
                ]

        # Check for static topic triggers (backward compat)
        topic = None
        if message and message.lower() in topic_keywords:
            topic = message.lower()
        elif not message:
            # No message provided — use greeting on first contact
            topic = "greeting"

        # Award XP and update trust on talk
        self.gs.add_xp(5, "social_engineering")
        if self.trust_matrix:
            self.trust_matrix.modify_trust(agent_id, +2, "player initiated conversation")

        # Generate response via dialogue engine
        if self.dialogue_engine:
            effective_message = message if message else f"Hello, {agent.get('pseudo_name', agent['name'])}."
            try:
                response, used_llm = self.dialogue_engine.talk(
                    agent=agent,
                    player_message=effective_message,
                    gs=self.gs,
                    trust_matrix=self.trust_matrix,
                    faction_system=self.factions,
                    topic=topic,
                )
            except Exception:
                # Fallback to static
                from .agent_dialogue import _get_fallback_line
                response = _get_fallback_line(agent, topic, effective_message)
                used_llm = False
        else:
            from .agent_dialogue import _get_fallback_line
            response = _get_fallback_line(agent, topic or "greeting" if not message else topic, message)
            used_llm = False

        out = reactive + [_line(f"\n{response}", "story")]

        # Show trust update hint
        trust = self.trust_matrix.get_trust(agent_id) if self.trust_matrix else 0
        if trust >= 80 and agent.get("hidden_agenda_hint"):
            out.append(_dim(f"\n[TRUST HIGH — deeper intel available]"))

        # ── Loop-Aware Déjà Vu Dialogue ────────────────────────────────────────
        try:
            loop = self.gs.loop_count
            if loop >= 1:
                deja_pool = _LOOP_DEJA_VU.get(agent_name, [])
                matching = [line for (threshold, line) in deja_pool if loop >= threshold]
                deja_key = f"deja_vu_{agent_name}_loop_{loop}"
                if matching and not self.gs.flags.get(deja_key):
                    self.gs.flags[deja_key] = True
                    chosen = matching[-1]  # Most advanced matching line
                    out += [_line(""), _lore(f"\n  {chosen}"), _line("")]
        except Exception:
            pass

        # ── Trust Milestone Revelations ────────────────────────────────────────
        try:
            if self.trust_matrix:
                trust = self.trust_matrix.get_trust(agent_id)
                milestones = _TRUST_MILESTONES.get(agent_name, {})
                for tier in (100, 75, 50, 25):
                    if trust >= tier:
                        mk = f"trust_milestone_{agent_name}_{tier}"
                        if milestones.get(tier) and not self.gs.flags.get(mk):
                            self.gs.flags[mk] = True
                            lines = milestones[tier]
                            chosen_lines = lines[:2]
                            out += [_line(""), _lore(f"\n  [TRUST {tier}+ UNLOCKED]")]
                            for l in chosen_lines:
                                out.append(_lore(f"  {l}"))
                            out.append(_line(""))
                            if tier == 100 and agent_name == "watcher":
                                out += [_lore("  [WATCHER]: Type: zeta when you are ready."), _line("")]
                        break
        except Exception:
            pass

        # ── Faction rep wiring from conversation ────────────────────────────
        try:
            if self.factions:
                agent_faction = agent.get("faction", "")
                if agent_faction == "resistance":
                    rep_notifs = self._faction_rep_event("talked_resistance")
                    if rep_notifs:
                        out += rep_notifs
                    self.gs.add_consciousness(2)
                elif agent_faction in ("corporation", "nexuscorp"):
                    rep_notifs = self._faction_rep_event("talked_nexuscorp")
                    if rep_notifs:
                        out += rep_notifs
                elif agent_faction == "watchers_circle":
                    self.gs.add_consciousness(3)
                elif agent_faction == "specialist_guild":
                    rep_notifs = self._faction_rep_event("lore_read")
                    if rep_notifs:
                        out += rep_notifs
        except Exception:
            pass

        return out

    def _cmd_faction(self, args: List[str]) -> List[dict]:
        """faction [status|list|join <id>|leave] — manage faction reputation."""
        sub = args[0].lower() if args else "status"

        if sub in ("list", "ls", "factions"):
            sub = "status"  # faction list → show all factions (same as status)

        if sub == "status":
            if not self.factions:
                return _err("Faction system unavailable.")

            out = [_sys("=== FACTION REPUTATION ===")]
            all_status = self.factions.all_status()

            for faction_id, status in all_status.items():
                rep = status["reputation"]
                rep_bar = "█" * (rep // 10) + "░" * (10 - rep // 10)
                tier = status["tier"]
                name = status["display_name"]
                perks_str = f"{status['perks_unlocked']}/{status['perks_total']} perks"

                out.append(_line(f"\n  {name}", "system"))
                out.append(_line(f"  Rep: [{rep_bar}] {rep:3d}/100  ({tier})  {perks_str}", "dim"))

                next_perk = status.get("next_perk")
                if next_perk:
                    needed = next_perk.get("rep_needed", 0)
                    out.append(_dim(f"  Next: {next_perk['name']} — {next_perk['description'][:60]} (+{needed} rep needed)"))

            out.append(_dim("\nFactions with conflicts: gaining Corporation rep reduces Resistance rep."))
            return out

        if sub in ("join", "pledge"):
            if len(args) < 2:
                if not self.factions:
                    return _err("Faction system unavailable.")
                out = [
                    _sys("=== FACTION PLEDGE ==="),
                    _dim("  Pledging to a faction grants bonus rep and unique dialogue options."),
                    _dim("  You can only pledge to one faction at a time."),
                    _line(""),
                ]
                all_status = self.factions.all_status()
                for fid, st in all_status.items():
                    out.append(_line(f"  faction join {fid:<20} — {st['display_name']}", "info"))
                out.append(_line(""))
                out.append(_dim("  Example: faction join resistance"))
                return out

            faction_target = args[1].lower()
            if not self.factions:
                return _err("Faction system unavailable.")
            all_status = self.factions.all_status()

            # Find matching faction
            match_id = None
            for fid in all_status:
                if fid.startswith(faction_target) or faction_target in fid:
                    match_id = fid
                    break
            if match_id is None:
                known = ", ".join(all_status.keys())
                return _err(f"faction join: unknown faction '{faction_target}'. Known: {known}")

            current_pledge = self.gs.flags.get("faction_pledged")
            if current_pledge == match_id:
                return [_line(f"  You are already pledged to {all_status[match_id]['display_name']}.", "info")]

            # Apply the pledge
            old = current_pledge
            self.gs.flags["faction_pledged"] = match_id
            st = all_status[match_id]

            # Bonus rep for joining
            join_bonus = 15
            self.factions.modify(match_id, join_bonus, "faction pledge bonus")
            self.gs.add_xp(50, "social_engineering")

            # Rep penalty to rival factions
            rivals = {"resistance": "corporation", "corporation": "resistance"}.get(match_id)
            if rivals and rivals in all_status:
                self.factions.modify(rivals, -10, "rival faction penalty")

            out = [
                _line(""),
                _line(f"  ▌ FACTION PLEDGE — {st['display_name'].upper()}", "success"),
                _line(""),
                _line(f"  Ghost has pledged allegiance to {st['display_name']}.", "success"),
                _line(f"  +{join_bonus} rep bonus applied.  +50 XP", "success"),
            ]
            if old:
                out.append(_dim(f"  (Previously: {all_status.get(old, {}).get('display_name', old)})"))

            # Faction-specific welcome message
            WELCOME = {
                "resistance":   "[ADA-7]: Welcome to the Resistance, Ghost. The grid needs you.",
                "corporation":  "[NEMESIS]: Interesting choice. NexusCorp will remember your loyalty.",
                "shadow_council": "[WATCHER]: You chose the shadow. Wise. Or perhaps inevitable.",
                "specialist_guild": "[CYPHER]: A guild member. Now you have access to the deep archives.",
            }
            if match_id in WELCOME:
                out.append(_line(""))
                out.append(_line(f"  {WELCOME[match_id]}", "npc"))

            out.extend([
                _line(""),
                _dim("  faction status   — view full reputation"),
                _dim("  faction leave    — renounce your pledge"),
            ])
            return out

        if sub == "leave":
            current_pledge = self.gs.flags.get("faction_pledged")
            if not current_pledge:
                return [_dim("  You have no current faction pledge.")]
            name = current_pledge.title()
            self.gs.flags["faction_pledged"] = None
            self.gs.add_xp(5, "social_engineering")
            return [
                _line(f"  You have left {name}. Reputation penalties may apply.", "warn"),
                _dim("  faction join <name> — pledge to a new faction"),
            ]

        return _err(f"faction: unknown subcommand '{sub}'. Try: status | join <faction> | leave")

    def _cmd_trust(self, args: List[str]) -> List[dict]:
        """trust <agent>|status — show trust/respect/fear breakdown for an agent, or list all agents."""
        if not args or args[0].lower() == "status":
            # Show trust summary for all unlocked agents
            out = [_sys("=== TRUST MATRIX — ALL CONTACTS ==="), _dim("")]
            if not self.trust_matrix:
                return _err("Trust matrix unavailable.")
            try:
                from .agents import AGENTS as _ALL_AGENTS
            except ImportError:
                return _err("Agent registry unavailable.")
            found = False
            for ag in _ALL_AGENTS:
                if not self.gs.is_agent_unlocked(ag.get("id", "")):
                    continue
                found = True
                sc = self.trust_matrix.get_player_scores(ag["id"])
                t, r, f = sc["trust"], sc["respect"], sc["fear"]
                bar = "█" * (t // 10) + "░" * (10 - t // 10)
                out.append(_line(f"  {ag['name']:<18} T:[{bar}]{t:3d}  R:{r:3d}  F:{f:3d}", "info" if t >= 50 else "dim"))
            if not found:
                out.append(_dim("  No contacts unlocked yet. Explore and interact to meet agents."))
            out.append(_dim(""))
            out.append(_dim("  trust <agent>  — detailed breakdown for one contact"))
            return out

        agent = self._get_agent_by_name(args[0])
        if agent is None:
            return _err(f"trust: no agent named '{args[0]}'")

        if not self.gs.is_agent_unlocked(agent["id"]):
            return _err(f"trust: {agent['name']} is not yet an active contact.")

        if not self.trust_matrix:
            return _err("Trust matrix unavailable.")

        agent_id = agent["id"]
        scores = self.trust_matrix.get_player_scores(agent_id)
        trust = scores["trust"]
        respect = scores["respect"]
        fear = scores["fear"]

        def _bar(val: int) -> str:
            return "█" * (val // 10) + "░" * (10 - val // 10)

        out = [
            _sys(f"=== RELATIONSHIP: {agent['name']} ==="),
            _line(f"  Role:    {agent['role']}", "dim"),
            _line(f"  Faction: {agent['faction']}", "dim"),
            _line(f"\n  Trust:   [{_bar(trust)}] {trust:3d}/100", "info"),
            _line(f"  Respect: [{_bar(respect)}] {respect:3d}/100", "dim"),
            _line(f"  Fear:    [{_bar(fear)}] {fear:3d}/100", "warn" if fear > 30 else "dim"),
        ]

        # Trust-gated info — tiered disclosure
        lore = agent.get("lore", "")
        hidden = agent.get("hidden_agenda_hint", "")

        if trust >= 80 and hidden:
            out.append(_line(f"\n  [DEEP INTEL — trust ≥ 80]", "success"))
            out.append(_line(f"  {hidden}", "dim"))
        elif trust >= 50:
            out.append(_dim(f"\n  [TRUST THRESHOLD: {trust}/80 — keep engaging to unlock hidden intel]"))
            if agent_id == "ada":
                out.append(_dim("  Ada values: Exposing CHIMERA, protecting the Resistance, and direct honesty."))
            elif agent_id == "raven":
                out.append(_dim("  Raven values: Finding mole clues, cryptographic mastery, and subtle strategy."))
            elif agent_id == "cypher":
                out.append(_dim("  Cypher values: Executing exploits, uncovering /proc secrets, and information brokering."))
            elif agent_id == "nova":
                out.append(_dim("  Nova values: Professional conduct, understanding CHIMERA's risks, and showing potential."))
        else:
            out.append(_dim(f"\n  Talk more to build trust. {trust}/50 needed for dossier access."))
            if agent_id == "ada":
                out.append(_dim("  Hint: Use `talk ada` and complete Resistance-aligned story beats."))
            elif agent_id == "raven":
                out.append(_dim("  Hint: Uncover hidden files and investigate the mole to impress Raven."))
            elif agent_id == "cypher":
                out.append(_dim("  Hint: Use technical commands like `ps` and `find` to catch Cypher's eye."))
            elif agent_id == "nova":
                out.append(_dim("  Hint: Survive traces and interact with Corporate nodes to gain Nova's respect."))

        if trust >= 25 and lore:
            out.append(_line(f"\n  [DOSSIER]", "info"))
            # Word-wrap lore at ~70 chars
            words = lore.split()
            line_acc = "  "
            for w in words:
                if len(line_acc) + len(w) > 72:
                    out.append(_line(line_acc.rstrip(), "dim"))
                    line_acc = "  " + w + " "
                else:
                    line_acc += w + " "
            if line_acc.strip():
                out.append(_line(line_acc.rstrip(), "dim"))

        return out

    def _cmd_relationship(self, args: List[str]) -> List[dict]:
        """relationship <agent1> <agent2> — show inter-agent relationship."""
        if len(args) < 2:
            return _err("Usage: relationship <agent1> <agent2>")

        agent_a = self._get_agent_by_name(args[0])
        agent_b = self._get_agent_by_name(args[1])

        if agent_a is None:
            return _err(f"relationship: unknown agent '{args[0]}'")
        if agent_b is None:
            return _err(f"relationship: unknown agent '{args[1]}'")

        if not self.trust_matrix:
            return _err("Trust matrix unavailable.")

        if not self.trust_matrix.can_player_query_relation(agent_a["id"], agent_b["id"]):
            trust_a = self.trust_matrix.get_trust(agent_a["id"])
            trust_b = self.trust_matrix.get_trust(agent_b["id"])
            return [
                _err("Insufficient trust to query this relationship."),
                _dim(f"Need trust ≥ 40 with both agents."),
                _dim(f"  {agent_a['name']}: {trust_a}/40"),
                _dim(f"  {agent_b['name']}: {trust_b}/40"),
            ]

        rel = self.trust_matrix.get_agent_relation(agent_a["id"], agent_b["id"])
        rel_colors = {"alliance": "success", "rivalry": "error", "indifference": "dim"}
        rel_color = rel_colors.get(rel, "info")
        rel_icons = {"alliance": "◈ ALLIED", "rivalry": "✗ RIVALS", "indifference": "~ INDIFFERENT"}
        rel_display = rel_icons.get(rel, rel.upper())

        return [
            _sys(f"=== RELATIONSHIP: {agent_a['name']} ↔ {agent_b['name']} ==="),
            _line(f"  Status: {rel_display}", rel_color),
            _dim(f"  {agent_a['name']}: {agent_a['role']}"),
            _dim(f"  {agent_b['name']}: {agent_b['role']}"),
        ]

    def _cmd_mole_v1(self, args: List[str]) -> List[dict]:
        """mole — mole investigation commands."""
        if not args:
            # Basic mole command
            if self.gs.level < 5:
                return [
                    _dim("mole: command locked until level 5."),
                    _dim(f"Current level: {self.gs.level}. Keep progressing."),
                ]
            _mcf = getattr(self.gs, 'mole_clues_found', set())
            clues_found = len(_mcf)
            out = [
                _sys("=== MOLE INVESTIGATION ==="),
                _dim(f"Intelligence indicates a mole is embedded in the Resistance."),
                _dim(f"Clues found: {clues_found}/3"),
                _dim(f"Status: {'ACTIVE' if not getattr(self.gs, 'mole_exposed', False) else 'CLOSED'}"),
                _dim(""),
                _dim("Investigate suspicious files. Talk to agents."),
                _dim("Sub-commands: mole clues | expose <agent>"),
            ]
            return out

        sub = args[0].lower()

        if sub == "clues":
            if self.gs.level < 5:
                return _err("mole clues: locked until level 5.")
            out = [_sys("=== MOLE CLUES ===")]
            clues = [
                ("Anomalous log entry", "/var/log/.anomaly_0x4A2B.log",
                 "clue_anomaly_log", "cat /var/log/.anomaly_0x4A2B.log"),
                ("Transfer log fragment", "/tmp/.transfer_847b.partial",
                 "clue_transfer_log", "cat /tmp/.transfer_847b.partial"),
                ("Internal memo", "/opt/chimera/core/.internal_847.memo",
                 "clue_internal_memo", "cat /opt/chimera/core/.internal_847.memo"),
            ]
            _mcf = getattr(self.gs, 'mole_clues_found', set())
            for clue_name, path, clue_id, cmd in clues:
                found = clue_id in _mcf
                status = "✓ FOUND" if found else "? UNDISCOVERED"
                status_t = "success" if found else "dim"
                out.append(_line(f"  [{status}] {clue_name}", status_t))
                if not found:
                    out.append(_dim(f"    Hint: try `{cmd}`"))
            out.append(_dim(f"\nAll 3 clues needed before using: expose <agent>"))
            return out

        if sub == "expose" or (len(args) >= 1 and args[0].lower() == "expose"):
            # Handle: mole expose <agent> OR expose <agent>
            target_args = args[1:] if sub == "expose" else args
            if not target_args:
                return _err("Usage: mole expose <agent-name>")
            agent = self._get_agent_by_name(target_args[0])
            if agent is None:
                return _err(f"expose: unknown agent '{target_args[0]}'")

            _mcf = getattr(self.gs, 'mole_clues_found', set())
            if len(_mcf) < 3:
                return [
                    _err("Insufficient evidence to make an accusation."),
                    _dim(f"Clues found: {len(_mcf)}/3"),
                    _dim("Find all 3 clues first. Use: mole clues"),
                ]

            if getattr(self.gs, 'mole_exposed', False):
                return _dim("The mole investigation is already closed.")

            correct = self.gs.expose_mole(agent["id"])
            if correct:
                self.gs.add_consciousness(18)  # Layer 3: social deduction mastery — exposing the mole
                return [
                    _sys("╔══════════════════════════════════════════════════╗"),
                    _sys("║  MOLE EXPOSED — CORRECTLY                        ║"),
                    _sys(f"║  {agent['name']:<46}║"),
                    _sys("╚══════════════════════════════════════════════════╝"),
                    _line(f"\n{agent['name']} has been exposed as the Shadow Council's mole.", "success"),
                    _dim(f"The Resistance has been notified. Trust changes cascade across all agents."),
                    _xp_line("  +500 XP — Mole Exposed!"),
                    _dim(f"Achievement unlocked: MOLE HUNTER"),
                ]
            else:
                return [
                    _err("╔══════════════════════════════════════════════════╗"),
                    _err("║  WRONG ACCUSATION                                ║"),
                    _err(f"║  {agent['name']:<46}║"),
                    _err("╚══════════════════════════════════════════════════╝"),
                    _line(f"\n{agent['name']} is not the mole. Your accusation has damaged trust.", "error"),
                    _dim("The real mole has been warned. They are now harder to find."),
                    _xp_line("  +50 XP — Wrong lead, but you're trying."),
                ]

        return _err(f"mole: unknown subcommand '{sub}'. Try: mole clues | mole expose <agent>")

    def _cmd_expose(self, args: List[str]) -> List[dict]:
        """expose <agent> — accuse an agent of being the mole."""
        return self._cmd_mole(["expose"] + args)

