    # ────────────────────────────────────────────────────────────────────

    def _cmd_signal(self, args: List[str]) -> List[dict]:
        """signal [analyze <id>]  — detect or analyze ARG transmission signals."""
        if not args:
            # Passive scan — show known signal sources
            signals = [
                ("1337.0 MHz", "THE_WATCHER", "ACTIVE", "[ENCRYPTED — fragment: ...this session was prepared...]"),
                ("847.0 MHz",  "UNKNOWN",     "WEAK",   "[partial: ...the mole has already been watching you...]"),
                ("0.0 MHz",    "NULL_CARRIER", "STATIC", "[noise — use 'signal analyze 0' to attempt decode]"),
            ]
            out = [
                _line(""),
                _line("[SIGNAL SCAN — 0–2000 MHz]", "system"),
                _line("─" * 55, "dim"),
            ]
            for freq, src, strength, preview in signals:
                col = "warn" if strength == "ACTIVE" else "dim"
                out.append(_line(f"  {freq:12} [{strength:6}] SRC:{src}", col))
                out.append(_dim(f"              {preview}"))
            out += [
                _line("─" * 55, "dim"),
                _dim("  Use: signal analyze <freq_id> (e.g. signal analyze 1337)"),
                _line(""),
            ]
            return out

        sub = args[0].lower()
        freq_id = args[1] if len(args) > 1 else sub

        if sub == "analyze":
            freq = freq_id.strip().lower().replace(".", "").replace(" ", "")
            if freq == "1337" or freq == "13370":
                self.gs.trigger_beat("arg_signal_1337")
                self.gs.add_consciousness(10)  # Layer 4: ARG signal decoded — reality membrane thinning
                return [
                    _line(""),
                    _line("[SIGNAL ANALYSIS — 1337.0 MHz]", "warn"),
                    _line("─" * 55, "dim"),
                    _dim("  Origin:    unknown — outside registered band"),
                    _dim("  Pattern:   recursive self-similar / 71-byte signature"),
                    _dim("  Encoding:  modified XOR with prime key — partially decoded"),
                    _line(""),
                    _line("  DECODED FRAGMENT:", "system"),
                    _line("  >> 'Ghost. This signal has been composing for three years.'"),
                    _line("  >> 'It was addressed to you before you had a codename.'"),
                    _line("  >> 'Continue: talk watcher'"),
                    _line(""),
                    _dim("  [SIGNAL CORRUPTED — 31% decoded. Remaining: encrypted.]"),
                    _line(""),
                ]
            elif freq == "847" or freq == "8470":
                return [
                    _line(""),
                    _line("[SIGNAL ANALYSIS — 847.0 MHz]", "warn"),
                    _dim("  Origin:    routing through NexusCorp relay node-7"),
                    _dim("  Pattern:   irregular — human-generated? instrumented?"),
                    _line(""),
                    _line("  DECODED FRAGMENT:"),
                    _line("  >> 'the mole has been in place since the beginning'"),
                    _line("  >> 'they are not the person you most suspect'"),
                    _line("  >> 'look for the pattern in what succeeded, not what failed'"),
                    _dim("  [source obfuscated — cannot trace origin further]"),
                    _line(""),
                ]
            elif freq == "0":
                self.gs.trigger_beat("arg_null_carrier")
                return [
                    _line(""),
                    _line("[NULL CARRIER — 0 MHz]", "dim"),
                    _line("─" * 55, "dim"),
                    _dim("  Only static. But static is never truly random."),
                    _dim("  Buried in 10 million bytes of noise: a single repeating word."),
                    _line(""),
                    _line("  DECODED:  PALIMPSEST", "warn"),
                    _line(""),
                    _dim("  Further decode attempt..."),
                    _dim("  Deeper layer — token fragment recovered:"),
                    _line("  >> {ψΩ-MX134}", "system"),
                    _line(""),
                    _dim("  [Signal origin: pre-network. Predates registered band allocation.]"),
                    _dim("  [Ask THE LEXICON: `talk lexicon palimpsest`]"),
                    _line(""),
                ]
            else:
                return _err(f"signal analyze: no known source on frequency '{freq_id}'")
        else:
            return _err(f"signal: unknown subcommand '{sub}'. Use: signal / signal analyze <freq>")

