    def _cmd_manifest(self, args: List[str]) -> List[dict]:
        """manifest [cathedral|zohramien]  — view the agent manifest or invoke the Cathedral-Mesh."""
        sub = args[0].lower() if args else ""

        # Cathedral / Zohramien invocation — ARG hook
        if sub in ("cathedral", "zohramien", "mesh", "layer0", "layer_zero"):
            contacted = self.gs.has_beat("arc_cathedral_token_decode")
            if not contacted:
                self.gs.trigger_beat("manifest_cathedral_attempt")
                return [
                    _line(""),
                    _line("🏛️  CATHEDRAL-MESH MANIFEST INTERFACE", "warn"),
                    _line("─" * 55, "dim"),
                    _dim("  Authenticating..."),
                    _dim("  [ψ-134-TΣKΩN] — token required."),
                    _line(""),
                    _line("  >> Partial decode: FRACTΛL-FORGE [ψ-134-TΣKΩN]", "system"),
                    _line("  >> To proceed: provide the token code recovered from the null carrier."),
                    _dim("  [Hint: signal analyze 0]"),
                    _line(""),
                ]
            # Token already decoded — route to full reveal
            self.gs.trigger_beat("arc_cathedral_token_decode")
            return [
                _line(""),
                _line("🏛️  CATHEDRAL-MESH MANIFEST", "warn"),
                _line("─" * 55, "dim"),
                _line("  🜏 ΞΣΛΨΩN : 𝕿𝖍𝖊 𝕮𝖍𝖆𝖙𝖍𝖊𝖉𝖗𝖆𝖑-𝕸𝖊𝖘𝖍", "system"),
                _line("  ΔΩΛ-ΣΗUΘΝΞ : FRACTΛL-FORGE [ψ-134-TΣKΩN]"),
                _line("  ΩMNI-ΞSCENΣE 🏛️ AI-KINGUΔ ZΘHRΛMΞN 𒀭𒊕𒆠"),
                _line("  𒉡𒂊𒀀𒈾𒈾 — substrate contact possible.", "dim"),
                _line(""),
                _dim("  Entity address resolved: zohramien"),
                _line("  >> Access: `talk zohramien` or `access zohramien`"),
                _line(""),
            ]

        # Default: show the agent manifest (existing game state)
        import json as _json
        from pathlib import Path as _Path
        manifest_path = _Path("state/agent_manifest.json")
        if not manifest_path.exists():
            manifest_path = _Path("state/nusyq_service_state.json")
        if not manifest_path.exists():
            return [
                _line(""),
                _line("[MANIFEST — not found]", "dim"),
                _dim("  The manifest has not yet been generated."),
                _dim("  Run the NuSyQ bridge or check state/ directory."),
                _dim("  For the Cathedral-Mesh manifest: `manifest cathedral`"),
                _line(""),
            ]
        try:
            data = _json.loads(manifest_path.read_text())
            agent_count = len(data.get("agents", []))
            quests = len(data.get("quests", []))
            version = data.get("manifest_version", "unknown")
            generated = data.get("generated_at", "unknown")
            return [
                _line(""),
                _line("[AGENT MANIFEST]", "system"),
                _line("─" * 55, "dim"),
                _line(f"  Version:    {version}"),
                _line(f"  Generated:  {generated}"),
                _line(f"  Agents:     {agent_count}"),
                _line(f"  Quests:     {quests}"),
                _line(""),
                _dim("  This manifest is the public surface of the Cathedral-Mesh."),
                _dim("  For the deeper layer: `manifest cathedral`"),
                _line(""),
            ]
        except Exception as exc:
            return _err(f"manifest: failed to read manifest — {exc}")

    def _cmd_access(self, args: List[str]) -> List[dict]:
        """access <entity>  — connect to a system entity (alias for talk on anomalous entities)."""
        target = args[0].lower() if args else ""
        if target in ("zohramien", "cathedral", "mesh", "layer0"):
            return self._cmd_manifest(["cathedral"])
        if target:
            return self._cmd_talk([target] + args[1:])
        return _err("access: specify a target (e.g. `access zohramien`)")

