    # ── V10: SYNTHESIS / DAW — in-game music composition ────────────────────────

    def _cmd_compose_v10(self, args: List[str]) -> List[dict]:
        """compose_v10 (dead — superseded by music_engine) [new|play <id>|list|export <id>|styles]."""
        import random as _rnd, hashlib as _hl

        gs = self.gs
        sub = args[0].lower() if args else ""
        cid = args[1].lower() if len(args) > 1 else ""

        _STYLES = {
            "ambient":    {"desc": "slow, atmospheric drones", "tempo": "♩=60",  "icon": "〰"},
            "industrial": {"desc": "rhythmic noise bursts",    "tempo": "♩=130", "icon": "▓"},
            "glitch":     {"desc": "fragmented, arrhythmic",   "tempo": "♩=?",   "icon": "⊞"},
            "lattice":    {"desc": "CHIMERA's heartbeat tone", "tempo": "♩=88",  "icon": "◈"},
            "serena":     {"desc": "harmonic query sequence",  "tempo": "♩=72",  "icon": "≋"},
        }

        _NOTES = ["C", "D", "E", "F", "G", "A", "B"]
        _OCTAVES = [3, 4, 5]
        _RESTS = ["—", "·", "·", "·"]  # weighted toward rests for sparsity

        _LORE = {
            "ambient": "SERENA: 'This is what the grid sounds like when no one is exploiting it.'",
            "industrial": "GORDON: 'I recognise that rhythm. CHIMERA cycles at this BPM.'",
            "glitch": "CYPHER: 'It's not broken. It's playing something the speaker can't resolve.'",
            "lattice": "ZERO: 'I embedded this sequence in the containment wall. Listen.'",
            "serena": "SERENA: 'This is how I index. Everything I know, in harmonic order.'",
        }

        def _gen_score(style: str, seed: str) -> list[str]:
            rng = _rnd.Random(int(_hl.md5(seed.encode()).hexdigest()[:16], 16))
            pool = _NOTES + _RESTS
            bars: list[str] = []
            for bar_i in range(4):
                beats: list[str] = []
                for _ in range(4):
                    if style == "glitch":
                        note = rng.choice(pool + ["✕", "?", "∅"])
                        oct_ = rng.choice(_OCTAVES + [2, 6])
                    elif style == "ambient":
                        note = rng.choice(_NOTES[:5] + _RESTS * 3)
                        oct_ = rng.choice([3, 4])
                    elif style == "industrial":
                        note = rng.choice(["C", "D", "—", "C", "C", "E", "—"])
                        oct_ = 3
                    else:
                        note = rng.choice(pool)
                        oct_ = rng.choice(_OCTAVES)
                    if note in ("—", "·", "✕", "?", "∅"):
                        beats.append(f"  {note}  ")
                    else:
                        beats.append(f" {note}{oct_}  ")
                bars.append(f"  |{'|'.join(beats)}|")
            return bars

        # ── Default / styles ──────────────────────────────────────────────
        if not sub or sub == "styles":
            comps = gs.flags.get("compositions", {})
            out = [
                _sys("╔══════════════════════════════════════════════════╗"),
                _sys("║         COMPOSE — IN-GAME DAW                    ║"),
                _sys("╚══════════════════════════════════════════════════╝"),
                _dim(f"  {len(comps)} composition(s) saved"), _dim(""),
                _sys("  STYLES"),
            ]
            for sid_s, sd in _STYLES.items():
                out.append(_dim(f"  {sd['icon']} {sid_s:<12}  {sd['tempo']}  {sd['desc']}"))
            out += [_dim(""), _dim("  compose new [style]  — generate a new piece"),
                    _dim("  compose list          — saved compositions"),
                    _dim("  compose play <id>     — display + Web Audio hint")]
            return out

        # ── New composition ───────────────────────────────────────────────
        if sub == "new":
            style = cid if cid in _STYLES else "ambient"
            sd = _STYLES[style]
            session_seed = str(int(gs.run_start_time))
            comp_count = len(gs.flags.get("compositions", {}))
            seed = f"{session_seed}_{style}_{comp_count}"
            uid = _hl.md5(seed.encode()).hexdigest()[:6]
            score = _gen_score(style, seed)
            title = f"{style.upper()}-{uid}"
            # Store composition
            comps = gs.flags.setdefault("compositions", {})
            comps[uid] = {"title": title, "style": style, "seed": seed, "score": score}
            gs.flags["compositions"] = comps
            gs.award_xp("terminal", 30)
            gs.add_story_beat("compose_new")
            out = [
                _sys(f"  ╔══ {title} — {style.upper()} ══"),
                _dim(f"  Tempo: {sd['tempo']}  |  {sd['desc']}"), _dim(""),
            ] + [_dim(line) for line in score] + [
                _dim(""),
                _lore(f"  {_LORE.get(style, 'SERENA: ...')}"),
                _dim(""),
                _ok(f"  +30 XP terminal | ID: {uid}"),
                _dim(f"  Play in browser: compose play {uid}"),
            ]
            return out

        # ── List ──────────────────────────────────────────────────────────
        if sub == "list":
            comps = gs.flags.get("compositions", {})
            if not comps:
                return [_dim("  No compositions yet. Run: compose new [style]")]
            out = [_sys("  SAVED COMPOSITIONS"), _dim("")]
            for uid, c in comps.items():
                sd = _STYLES.get(c.get("style", "ambient"), {})
                out.append(_dim(f"  {sd.get('icon','○')} {c['title']:<20}  style:{c['style']}"))
            out += [_dim(""), _dim("  compose play <id>  to display + trigger Web Audio")]
            return out

        # ── Play ──────────────────────────────────────────────────────────
        if sub == "play":
            comps = gs.flags.get("compositions", {})
            comp = comps.get(cid) or next((c for uid, c in comps.items() if uid.startswith(cid)), None)
            if not comp:
                return [_err(f"  Composition '{cid}' not found. Run: compose list")]
            sd = _STYLES.get(comp.get("style", "ambient"), {})
            out = [
                _sys(f"  ╔══ {comp['title']} ══"),
                _dim(f"  {sd.get('tempo','')}  {sd.get('desc','')}"), _dim(""),
            ] + [_dim(line) for line in comp.get("score", [])] + [
                _dim(""),
                # Web Audio hint — wire type triggers JS if frontend supports it
                {"t": "audio", "s": f"compose:{comp['style']}:{comp['seed']}"},
                _dim("  [Browser Audio: if supported, playback begins]"),
                _lore(f"  {_LORE.get(comp.get('style'), '')}"),
            ]
            return out

        # ── Export ────────────────────────────────────────────────────────
        if sub == "export":
            comps = gs.flags.get("compositions", {})
            comp = comps.get(cid) or next((c for uid, c in comps.items() if uid.startswith(cid)), None)
            if not comp:
                return [_err(f"  Composition '{cid}' not found.")]
            # Write to VFS
            vfs_path = f"/home/ghost/music/{comp['title']}.score"
            try:
                self.fs.mkdir("/home/ghost/music", parents=True)
                content = "\n".join([
                    f"TITLE: {comp['title']}", f"STYLE: {comp['style']}",
                    f"SEED: {comp['seed']}", "SCORE:", "",
                ] + comp.get("score", []))
                self.fs.write_file(vfs_path, content)
                return [_ok(f"  Exported to VFS: {vfs_path}"),
                        _dim("  cat /home/ghost/music/" + comp['title'] + ".score")]
            except Exception as e:
                return [_err(f"  Export failed: {e}")]

        return [_err(f"  compose: unknown subcommand '{sub}'. Run: compose styles")]

    # ── PROCGEN QUESTS — procedural quest board from procgen/quests.py ──────────

    def _cmd_procquest(self, args: List[str]) -> List[dict]:
        """procquest [list|accept <id>|done|refresh] — procedural quest board (auto-generated)."""
        try:
            from .procgen.quests import (
                generate_batch, accept_quest, active_quests,
                complete_quest, render_quest,
            )
        except ImportError:
            return [_err("  procquest: procgen module not found. Check app/game_engine/procgen/quests.py")]

        gs = self.gs
        sub = args[0].lower() if args else "list"
        sid = str(int(gs.run_start_time))

        # ── list / refresh ────────────────────────────────────────────────
        if sub in ("list", "refresh", "board"):
            # Rotate every hour; store offset for variety
            import time as _t
            hour_slot = int(_t.time() // 3600)
            offset = (hour_slot % 50) * 5
            quests = generate_batch(sid, count=5, seed_offset=offset)
            done_ids = set(gs.flags.get("procgen_quests_done", []))
            out = [
                _sys("╔══════════════════════════════════════════════════╗"),
                _sys("║         PROCEDURAL QUEST BOARD                   ║"),
                _sys("║         Rotates hourly. 5 active quests.         ║"),
                _sys("╚══════════════════════════════════════════════════╝"),
                _dim(""),
            ]
            for q in quests:
                done = q["id"] in done_ids
                lines = render_quest(q, done=done)
                for line in lines:
                    out.append(_ok(line) if done else _dim(line))
                out.append(_dim(""))
            out += [
                _dim("  procquest accept <quest-id>  — accept a quest"),
                _dim("  procquest done               — check active quests"),
            ]
            return out

        # ── accept ────────────────────────────────────────────────────────
        if sub == "accept":
            qid = args[1] if len(args) > 1 else ""
            if not qid:
                return [_err("  Usage: procquest accept <quest-id>")]
            import time as _t
            hour_slot = int(_t.time() // 3600)
            offset = (hour_slot % 50) * 5
            quests = generate_batch(sid, count=5, seed_offset=offset)
            match = next((q for q in quests if q["id"] == qid or q["id"].endswith(qid)), None)
            if not match:
                return [_err(f"  Quest '{qid}' not on current board. Run: procquest list")]
            accept_quest(match, gs.flags)
            return [
                _ok(f"  Quest accepted: {match['title']}"),
                _dim(f"  Objective: {match['objective']}"),
                _dim(f"  Hint: try '{match['command_hint']}'"),
            ]

        # ── done / active ─────────────────────────────────────────────────
        if sub in ("done", "active", "status"):
            active = active_quests(gs.flags)
            done_ids = set(gs.flags.get("procgen_quests_done", []))
            if not active and not done_ids:
                return [_dim("  No active quests. Run: procquest list")]
            out = [_sys("  ACTIVE PROCGEN QUESTS"), _dim("")]
            for q in active:
                lines = render_quest(q)
                for line in lines:
                    out.append(_dim(line))
                out.append(_dim(""))
            if done_ids:
                out += [_dim(f"  Completed: {len(done_ids)} quest(s) this session")]
            return out

        return [_err("  procquest: list | accept <id> | done | refresh")]

    # ── CS8: BUILDING SYSTEM — persistent node infrastructure upgrades ────────

    def _cmd_build(self, args: List[str]) -> List[dict]:
        """build [list|construct <id>|demolish <id>|status <node>|upgrade <id>] — CS8: construct node upgrades."""
        import time as _time

        gs = self.gs
        sub = args[0].lower() if args else ""
        arg2 = args[1].lower() if len(args) > 1 else ""

        # ── Building catalogue ─────────────────────────────────────────────
        _BUILDINGS = {
            "relay-tower": {
                "name": "Relay Tower",
                "desc": "Boosts passive credit income from claimed nodes.",
                "cost": 300, "build_time": 0,
                "effect": {"credits_per_wave": 15},
                "max_level": 3, "xp_skill": "networking", "xp": 40,
                "icon": "📡",
                "lore": "ADA-7: 'Every node needs a heartbeat signal. This is it.'",
            },
            "cipher-forge": {
                "name": "Cipher Forge",
                "desc": "Generates crypto keys; boosts XP from crypto commands.",
                "cost": 500, "build_time": 0,
                "effect": {"crypto_xp_mult": 1.25},
                "max_level": 3, "xp_skill": "crypto", "xp": 60,
                "icon": "🔐",
                "lore": "CYPHER: 'A forge for keys. I appreciate the metaphor.'",
            },
            "ghost-cache": {
                "name": "Ghost Cache",
                "desc": "Hidden memory store. Reduces trace gain from all ops.",
                "cost": 400, "build_time": 0,
                "effect": {"trace_reduction": 5},
                "max_level": 3, "xp_skill": "stealth", "xp": 50,
                "icon": "🕳",
                "lore": "RAVEN: 'If they can't find the cache, they can't find you.'",
            },
            "lore-archive": {
                "name": "Lore Archive",
                "desc": "Indexes recovered fragments. Boosts archaeology XP.",
                "cost": 350, "build_time": 0,
                "effect": {"archaeology_xp_mult": 1.2},
                "max_level": 3, "xp_skill": "archaeology", "xp": 45,
                "icon": "📚",
                "lore": "SERENA: 'A library node. Finally. You understand me.'",
            },
            "agent-hub": {
                "name": "Agent Hub",
                "desc": "Increases agent trust gain rate. Enables deeper affinity arcs.",
                "cost": 600, "build_time": 0,
                "effect": {"trust_rate": 1.3},
                "max_level": 2, "xp_skill": "social", "xp": 70,
                "icon": "🏛",
                "lore": "GORDON: 'A place to meet. Not a bar, but I'll take it.'",
            },
            "nexus-tap": {
                "name": "Nexus Tap",
                "desc": "Siphons NexusCorp data streams. High risk, high reward.",
                "cost": 800, "build_time": 0,
                "effect": {"credits_per_wave": 40, "trace_per_wave": 3},
                "max_level": 2, "xp_skill": "networking", "xp": 90,
                "icon": "⚡",
                "lore": "ZERO: 'The tap was always there. NexusCorp just never noticed.'",
            },
        }

        def _get_buildings() -> dict:
            return gs.flags.setdefault("buildings", {})

        def _credits() -> int:
            return gs.flags.get("credits", 0)

        # ── Subcommand: list ───────────────────────────────────────────────
        if not sub or sub == "list":
            built = _get_buildings()
            out = [
                _sys("╔══════════════════════════════════════════════════╗"),
                _sys("║         BUILDING SYSTEM — NODE INFRASTRUCTURE    ║"),
                _sys("╚══════════════════════════════════════════════════╝"),
                _dim(f"  Credits: {_credits()}  |  Built: {len(built)}"), _dim(""),
            ]
            for bid, bd in _BUILDINGS.items():
                level = built.get(bid, 0)
                if level:
                    out.append(_ok(f"  {bd['icon']} {bd['name']:<20} Lv{level}/{bd['max_level']}  {bd['desc']}"))
                else:
                    out.append(_dim(f"  {bd['icon']} {bd['name']:<20} [not built]  cost:{bd['cost']}cr  — {bd['desc']}"))
            out += [_dim(""), _dim("  Run: build construct <id>  |  build demolish <id>")]
            return out

        # ── Subcommand: construct ──────────────────────────────────────────
        if sub == "construct":
            bd = _BUILDINGS.get(arg2)
            if not bd:
                return [_err(f"  Unknown building '{arg2}'. Run: build list")]
            built = _get_buildings()
            level = built.get(arg2, 0)
            if level >= bd["max_level"]:
                return [_err(f"  {bd['name']} already at max level ({bd['max_level']}).")]
            cr = _credits()
            cost = bd["cost"] * (level + 1)  # each level costs more
            if cr < cost:
                return [_err(f"  Need {cost} credits. Have {cr}.")]
            gs.flags["credits"] = cr - cost
            built[arg2] = level + 1
            gs.flags["buildings"] = built
            gs.award_xp(bd["xp_skill"], bd["xp"])
            gs.add_story_beat(f"build_{arg2.replace('-', '_')}")
            # Apply passive effects
            for eff_key, eff_val in bd["effect"].items():
                gs.flags[f"bld_{arg2}_{eff_key}"] = eff_val * built[arg2]
            out = [
                _sys(f"  ╔══ CONSTRUCTED: {bd['name'].upper()} (Lv{built[arg2]}) ══"),
                _dim(""),
                _lore(f"  {bd['lore']}"),
                _dim(""),
                _ok(f"  -{cost} credits  |  +{bd['xp']} XP {bd['xp_skill']}"),
                _dim(f"  Effect: {bd['desc']}"),
            ]
            if built[arg2] == bd["max_level"]:
                out.append(_ok(f"  ★ {bd['name']} at MAX LEVEL"))
                gs.add_story_beat(f"build_{arg2.replace('-', '_')}_max")
            return out

        # ── Subcommand: demolish ───────────────────────────────────────────
        if sub == "demolish":
            built = _get_buildings()
            if arg2 not in built or built[arg2] == 0:
                return [_err(f"  {arg2} not built.")]
            bd = _BUILDINGS.get(arg2, {})
            refund = (bd.get("cost", 0) * built[arg2]) // 3
            del built[arg2]
            gs.flags["buildings"] = built
            gs.flags["credits"] = _credits() + refund
            # Remove passive effect flags
            for eff_key in bd.get("effect", {}):
                gs.flags.pop(f"bld_{arg2}_{eff_key}", None)
            return [
                _warn(f"  {bd.get('name', arg2)} demolished. +{refund} credits refunded."),
                _dim("  (Effects removed. Rebuild to restore.)"),
            ]

        # ── Subcommand: status ─────────────────────────────────────────────
        if sub == "status":
            built = _get_buildings()
            if not built:
                return [_dim("  No buildings constructed yet. Run: build construct <id>")]
            out = [_sys("  ACTIVE BUILDINGS"), _dim("")]
            total_effects: dict = {}
            for bid, level in built.items():
                bd = _BUILDINGS.get(bid)
                if not bd:
                    continue
                out.append(_ok(f"  {bd['icon']} {bd['name']} Lv{level}/{bd['max_level']}"))
                for eff_key, eff_val in bd["effect"].items():
                    scaled = eff_val * level
                    out.append(_dim(f"      {eff_key}: +{scaled}"))
                    total_effects[eff_key] = total_effects.get(eff_key, 0) + scaled
            out += [_dim(""), _sys("  COMBINED EFFECTS")]
            for k, v in total_effects.items():
                out.append(_dim(f"    {k}: {v}"))
            return out

        return [_err(f"  build: unknown subcommand '{sub}'. Run: build list")]

    def _cmd_voiceinput(self, args: List[str]) -> List[dict]:
        """voiceinput [on|off|status] — T10: toggle voice command input via Web Speech API."""
        gs = self.gs
        sub = args[0].lower() if args else "status"
        if sub == "status":
            active = gs.flags.get("voice_input", False)
            state = "ON" if active else "OFF"
            return [
                _sys(f"  Voice input: {state}"),
                _dim("  Run: voiceinput on   — activate microphone"),
                _dim("  Run: voiceinput off  — deactivate microphone"),
                _dim("  Requires Chrome or Edge (Web Speech API)."),
            ]
        on = sub != "off"
        gs.flags["voice_input"] = on
        if on:
            gs.add_story_beat("voice_input_activated")
            return [
                {"t": "settings", "s": "voice_on"},
                _sys("  ╔══════════════════════════════════════════════════╗"),
                _sys("  ║  🎤 VOICE CONTROL — ACTIVATED                   ║"),
                _sys("  ╚══════════════════════════════════════════════════╝"),
                _dim(""),
                _lore("  [CYPHER]: 'You want to talk to the terminal? Fine.'"),
                _lore("           'Speak clearly. The substrate has ears.'"),
                _dim(""),
                _dim("  Speak commands aloud. Recognised text will appear in"),
                _dim("  the input field and submit automatically."),
                _dim("  Say 'voiceinput off' to disable."),
            ]
        return [
            {"t": "settings", "s": "voice_off"},
            _ok("  Voice input disabled. Back to silent ops."),
        ]

    # ────────────────────────────────────────────────────────────────────
    # ARG CIPHER / VSCODE / DECODE  (SC Playbook integration)
    # ────────────────────────────────────────────────────────────────────

    def _cmd_decode(self, args: List[str]) -> List[dict]:
        """decode <string> [tier] — ARG cipher decoder for elite tool names.

        Tiers correspond to different encoding layers discovered in the secret annex.
        Tier 1: base58 reversal  (polyglot 99 reward)
        Tier 2: rot13
        Tier 3: reverse + rot13
        Tier 4: hex decode
        Tier 5: base64 decode
        Tier 6: unicode name mapping

        Usage: decode 2mUJqZ 1    → Vim
               decode olleh 3     → hello
        """
        import base64 as _b64
        if not args:
            return [
                _sys("  decode <string> [tier]  — ARG cipher decoder"),
                _dim(""),
                _dim("  Tiers:"),
                _dim("    1 — base58 reversal (classic elite tool cipher)"),
                _dim("    2 — rot13"),
                _dim("    3 — reverse + rot13"),
                _dim("    4 — hex decode (e.g. 56696d → Vim)"),
                _dim("    5 — base64 decode"),
                _dim("    6 — unicode codepoint sum lookup"),
                _dim(""),
                _lore("  Hint: The secret annex has encoded tool names."),
                _lore("  Find them in /opt/library/secret_annex/ and decode here."),
            ]

        text = args[0]
        try:
            tier = int(args[1]) if len(args) > 1 else 1
        except ValueError:
            tier = 1

        result = ""
        method = ""

        if tier == 1:
            # Base58 decode then reverse
            _B58_ALPHA = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
            try:
                n = 0
                for c in text:
                    n = n * 58 + _B58_ALPHA.index(c)
                decoded = n.to_bytes((n.bit_length() + 7) // 8, "big").decode("utf-8", errors="replace")
                result = decoded[::-1]
                method = "base58 decode → reverse"
            except Exception:
                result = text[::-1]
                method = "reverse (base58 failed)"

        elif tier == 2:
            result = "".join(
                chr(ord(c) + 13) if 'a' <= c <= 'm' or 'A' <= c <= 'M' else
                chr(ord(c) - 13) if 'n' <= c <= 'z' or 'N' <= c <= 'Z' else c
                for c in text
            )
            method = "rot13"

        elif tier == 3:
            rev = text[::-1]
            result = "".join(
                chr(ord(c) + 13) if 'a' <= c <= 'm' or 'A' <= c <= 'M' else
                chr(ord(c) - 13) if 'n' <= c <= 'z' or 'N' <= c <= 'Z' else c
                for c in rev
            )
            method = "reverse → rot13"

        elif tier == 4:
            try:
                result = bytes.fromhex(text).decode("utf-8", errors="replace")
                method = "hex decode"
            except Exception as e:
                return _err(f"decode tier4: {e}")

        elif tier == 5:
            try:
                padded = text + "=" * (-len(text) % 4)
                result = _b64.b64decode(padded).decode("utf-8", errors="replace")
                method = "base64 decode"
            except Exception as e:
                return _err(f"decode tier5: {e}")

        elif tier == 6:
            # Sum of unicode codepoints mod 26 → letter
            n = sum(ord(c) for c in text) % 26
            result = chr(ord('a') + n)
            method = f"unicode codepoint sum ({sum(ord(c) for c in text)}) mod 26"

        else:
            return _err(f"decode: unknown tier {tier}. Valid: 1-6")

        self.gs.add_xp(20, "cryptography")
        out = [
            _sys(f"  decode tier:{tier}  method:{method}"),
            _dim(""),
            _line(f"  Input  : {text}", "dim"),
            _line(f"  Output : {result}", "success"),
            _dim(""),
        ]

        # Easter eggs for known elite tool names
        _KNOWN_TOOLS = {
            "vim": "The standard editor. A way of life. Embed in the game via termios.",
            "nidhogg": "The Nidhogg — a persistent worm that replicates and repairs corrupted nodes.",
            "synth-mind": "A neural network that runs entirely in game memory, learning from player input.",
            "metacompiler": "A self-replicating code generator — writes new game commands from natural language.",
            "joker": "A wildcard agent that impersonates any other, inheriting all capabilities.",
            "chimera": "You decoded CHIMERA. The target is also the cipher. Appropriate.",
        }
        for tool_name, desc in _KNOWN_TOOLS.items():
            if tool_name in result.lower():
                out += [_lore(f"  ★ Known elite tool: {result}"),
                        _lore(f"    {desc}"),
                        _ok(f"  +50 XP — ARG cipher cracked")]
                self.gs.add_xp(50, "cryptography")
                self.gs.add_story_beat(f"decoded_{tool_name.replace('-','_')}")
                break

        out.append(_dim("  decode <string> <tier>  — try another tier"))
        return out

    def _cmd_vscode(self, args: List[str]) -> List[dict]:
        """vscode [open|extensions|tasks|hint] — VS Code integration interface.

        vscode extensions   — list recommended extensions for this project
        vscode tasks        — show available VS Code tasks (from tasks.json)
        vscode open <path>  — hint: open a file in VS Code
        vscode hint         — how to connect VS Code to this Replit
        """
        sub = args[0].lower() if args else "hint"
        from pathlib import Path as _VP

        if sub == "hint":
            repl_slug = __import__('os').environ.get("REPL_SLUG", "devmentor")
            return [
                _sys("  ═══ VS CODE INTEGRATION ═══"), _dim(""),
                _lore("  This game is designed to be played FROM VS Code."),
                _lore("  The repo is the mentor. Files are the lessons."),
                _dim(""),
                _line("  To connect VS Code to this Replit:", "info"),
                _dim("  1. Install: Replit extension for VS Code"),
                _dim(f"  2. Open workspace: {repl_slug}"),
                _dim("  3. Use tasks.json as your control panel"),
                _dim(""),
                _line("  Recommended extensions for this project:", "warn"),
                _dim("  ► GitHub Copilot   — AI pair programmer"),
                _dim("  ► GitLens          — git blame, history, annotations"),
                _dim("  ► Continue         — local LLM integration"),
                _dim("  ► REST Client      — test game API from editor"),
                _dim("  ► Error Lens       — inline error highlighting"),
                _dim("  ► Todo Tree        — scan TODOs across codebase"),
                _dim(""),
                _dim("  vscode extensions  — full extension list"),
                _dim("  vscode tasks       — available workspace tasks"),
            ]

        if sub == "extensions":
            _EXT_TIERS = [
                ("NECESSARY", [
                    ("ms-python.python",         "Python", "Core Python support"),
                    ("ms-python.pylance",         "Pylance", "Fast type-aware autocomplete"),
                    ("eamodio.gitlens",           "GitLens", "Git blame, history, annotations"),
                    ("humao.rest-client",         "REST Client", "Test game API from the editor"),
                    ("Continue.continue",         "Continue", "Local LLM chat in VS Code"),
                    ("usernamehw.errorlens",      "Error Lens", "Inline error highlighting"),
                ]),
                ("QUALITY OF LIFE", [
                    ("Gruntfuggly.todo-tree",    "Todo Tree", "Scan TODOs, FIXMEs across repo"),
                    ("mhutchie.git-graph",        "Git Graph", "Visual branch history"),
                    ("Gruntfuggly.todo-tree",    "Git Graph", "Visual branch history"),
                    ("esbenp.prettier-vscode",    "Prettier", "Auto-format on save"),
                    ("ms-toolsai.jupyter",        "Jupyter", "Run notebooks for data analysis"),
                    ("ms-vscode-remote.remote-containers", "Dev Containers", "Full container dev"),
                ]),
                ("AGENT-SPECIFIC", [
                    ("GitHub.copilot",            "GitHub Copilot", "Serena's code generation engine"),
                    ("rooveterinaryinc.roo-cline","Roo/Cline", "Autonomous coding agent in VS Code"),
                    ("ms-vsliveshare.vsliveshare","Live Share", "Multi-agent collaborative editing"),
                    ("rangav.vscode-thunder-client","Thunder Client", "API testing for Gordon"),
                    ("ms-vscode.docker",          "Docker", "Container management for SkyClaw"),
                ]),
            ]
            out = [_sys("  ═══ RECOMMENDED VS CODE EXTENSIONS ═══"), _dim("")]
            for tier, exts in _EXT_TIERS:
                out.append(_line(f"  [{tier}]", "warn"))
                for ext_id, name, desc in exts:
                    out.append(_line(f"  {name:<22} {desc}", "info"))
                    out.append(_dim(f"    ext install {ext_id}"))
                out.append(_dim(""))
            out.append(_dim("  Install all: code --install-extension <id>"))
            return out

        if sub == "tasks":
            from pathlib import Path as _TP
            tasks_file = _TP(__file__).parent.parent.parent / ".vscode" / "tasks.json"
            if tasks_file.exists():
                try:
                    import json as _jt
                    with open(tasks_file) as f:
                        tasks_data = _jt.load(f)
                    tasks = tasks_data.get("tasks", [])
                    out = [_sys(f"  VS Code Tasks ({len(tasks)})"), _dim("")]
                    for t in tasks[:20]:
                        out.append(_line(f"  ► {t.get('label','?'):<30} [{t.get('group',{}).get('kind','task') if isinstance(t.get('group'),dict) else t.get('group','task')}]", "info"))
                    return out
                except Exception as e:
                    return _err(f"vscode tasks: {e}")
            return [_dim("  .vscode/tasks.json not found."),
                    _dim("  Create it to define workspace tasks.")]

        if sub == "open":
            path = " ".join(args[1:]) if len(args) > 1 else ""
            if not path:
                return _err("vscode open: specify a path")
            return [_lore(f"  [HINT]: In VS Code, press Ctrl+P then type: {path}"),
                    _dim("  Or from terminal: code " + path)]

        return _err(f"vscode: unknown subcommand '{sub}'. Try: hint | extensions | tasks | open <path>")

    # ────────────────────────────────────────────────────────────────────
    # SERENA: POLYSCRYPTAL SCAN + COVERAGE MAP
    # ────────────────────────────────────────────────────────────────────

    def _serena_polyscryptal_scan(self) -> List[dict]:
        """serena walk --mode polyscryptal — classify all primitives with Msg⛛ tags.

        Scans commands, VFS content, agents, story beats, and ARG fragments.
        Tags each primitive as:
          [Msg⛛{active}]   — working and used
          [Msg⛛{stale}]    — outdated or neglected
          [Msg⛛{missing}]  — referenced but absent
          [Msg⛛{drift}]    — deviates from mladenc_ideal

        Generates: state/primitives_inventory.json
        """
        import json as _json
        from pathlib import Path as _Path
        gs = self.gs

        # ── Classify commands ──────────────────────────────────────────
        all_cmds = [m[5:] for m in dir(self) if m.startswith("_cmd_")]
        used_cmds = set(h.get("cmd", "").split()[0] for h in self.history if h.get("cmd"))
        total_cmds = len(all_cmds)
        active_cmds = [c for c in all_cmds if c in used_cmds]
        stale_cmds  = [c for c in all_cmds if c not in used_cmds]

        # ── Classify story beats ───────────────────────────────────────
        beats_found   = len(gs.story_beats)
        beats_missed  = max(0, 117 - beats_found)  # ~117 total seeded beats

        # ── Classify agents ────────────────────────────────────────────
        try:
            from pathlib import Path as _P
            agent_yamls = list(_P("agents/personalities").glob("*.yaml"))
            total_agents = len(agent_yamls)
            active_agents = [p.stem for p in agent_yamls if p.stat().st_size > 100]
        except Exception:
            total_agents = 71; active_agents = []

        # ── Classify ARG fragments ─────────────────────────────────────
        zero_frags   = sum(1 for k in gs.story_beats if "zero_fragment" in k)
        conv_frags   = sum(1 for k in gs.story_beats if k.startswith("convergence_frag"))

        # ── Classify ARG files ─────────────────────────────────────────
        _ARG_FILES = [
            "/home/ghost/.consciousness",
            "/home/ghost/.zero",
            "/dev/shm/.convergence_frag_2",
            "/var/log/kernel.boot",
            "/proc/1337/mem",
            "/opt/library/secret_annex/CONVERGENCE_INDEX.md",
            "/home/ghost/.serena_notes",
            "/opt/chimera/keys/.iron",
        ]
        vfs_found = 0
        for p in _ARG_FILES:
            try:
                if self.fs._node_at(self.fs._resolve(p)):
                    vfs_found += 1
            except Exception:
                pass

        # ── Compute drift score ────────────────────────────────────────
        cmd_coverage   = len(active_cmds) / max(1, total_cmds)
        beat_coverage  = beats_found / max(1, beats_found + beats_missed)
        frag_coverage  = (zero_frags + conv_frags) / 14
        agent_coverage = len(active_agents) / max(1, total_agents)
        vfs_coverage   = vfs_found / len(_ARG_FILES)
        overall_delta  = 1.0 - (cmd_coverage + beat_coverage + frag_coverage + agent_coverage + vfs_coverage) / 5

        # ── Tag generation ─────────────────────────────────────────────
        def _tag(coverage: float) -> str:
            if coverage >= 0.8:   return "active"
            elif coverage >= 0.4: return "stale"
            else:                 return "drift"

        # ── Save inventory ─────────────────────────────────────────────
        inventory = {
            "generated_at":  __import__("datetime").datetime.utcnow().isoformat(),
            "delta":         round(overall_delta, 4),
            "commands": {
                "total":   total_cmds,
                "active":  len(active_cmds),
                "stale":   stale_cmds[:30],
                "tag":     f"[Msg⛛{{{_tag(cmd_coverage)}}}]",
            },
            "story_beats": {
                "found":  beats_found,
                "missed": beats_missed,
                "tag":    f"[Msg⛛{{{_tag(beat_coverage)}}}]",
            },
            "agents": {
                "total":  total_agents,
                "active": len(active_agents),
                "names":  [p.stem for p in agent_yamls] if active_agents else [],
                "tag":    f"[Msg⛛{{{_tag(agent_coverage)}}}]",
            },
            "arg_fragments": {
                "zero_found":  zero_frags,
                "conv_found":  conv_frags,
                "total_zero":  7,
                "total_conv":  7,
                "tag":         f"[Msg⛛{{{_tag(frag_coverage)}}}]",
            },
            "vfs_files": {
                "found":   vfs_found,
                "total":   len(_ARG_FILES),
                "tag":     f"[Msg⛛{{{_tag(vfs_coverage)}}}]",
            },
        }
        try:
            _Path("state").mkdir(exist_ok=True)
            _Path("state/primitives_inventory.json").write_text(_json.dumps(inventory, indent=2))
        except Exception:
            pass

        gs.add_story_beat("serena_polyscryptal_scan")
        gs.add_consciousness(5)
        gs.add_xp(30, "ai")

        def _bar(v: float) -> str:
            n = int(v * 10)
            return "█" * n + "░" * (10 - n) + f" {v:.0%}"

        out = [
            _sys(""),
            _sys("  ╔══════════════════════════════════════════════════════════╗"),
            _sys("  ║   [SERENA] ΨΞΦΩ POLYSCRYPTAL SCAN — PRIMITIVE INVENTORY ║"),
            _sys("  ╚══════════════════════════════════════════════════════════╝"),
            _dim(""),
            _line(f"  Overall Δ (drift): {overall_delta:.4f}  {'⚡ UNSTABLE' if overall_delta > 0.5 else '✓ WITHIN TOLERANCE'}", "warn" if overall_delta > 0.5 else "success"),
            _dim(""),
            _line("  ─── PRIMITIVE CLASSIFICATION ─────────────────────────────", "system"),
            _dim(""),
            _line(f"  Commands     {_tag(cmd_coverage):8} {_bar(cmd_coverage)}  ({len(active_cmds)}/{total_cmds})", "info"),
            _line(f"             [Msg⛛{{{_tag(cmd_coverage)}}}]", "dim"),
            _line(f"  Story Beats  {_tag(beat_coverage):8} {_bar(beat_coverage)}  ({beats_found}/{beats_found+beats_missed})", "info"),
            _line(f"             [Msg⛛{{{_tag(beat_coverage)}}}]", "dim"),
            _line(f"  Agents       {_tag(agent_coverage):8} {_bar(agent_coverage)}  ({len(active_agents)}/{total_agents})", "info"),
            _line(f"             [Msg⛛{{{_tag(agent_coverage)}}}]", "dim"),
            _line(f"  ARG Frags    {_tag(frag_coverage):8} {_bar(frag_coverage)}  ({zero_frags+conv_frags}/14)", "info"),
            _line(f"             [Msg⛛{{{_tag(frag_coverage)}}}]", "dim"),
            _line(f"  VFS Files    {_tag(vfs_coverage):8} {_bar(vfs_coverage)}  ({vfs_found}/{len(_ARG_FILES)})", "info"),
            _line(f"             [Msg⛛{{{_tag(vfs_coverage)}}}]", "dim"),
            _dim(""),
            _line("  ─── STALE COMMANDS (unused this session) ─────────────────", "system"),
            _dim(""),
        ]
        for cmd in sorted(stale_cmds)[:20]:
            out.append(_dim(f"    [Msg⛛{{stale}}] {cmd}"))
        if len(stale_cmds) > 20:
            out.append(_dim(f"    ... +{len(stale_cmds)-20} more"))
        out += [
            _dim(""),
            _lore("  [SERENA]: The inventory is complete."),
            _lore(f"  [SERENA]: Δ = {overall_delta:.4f}. The system is {'converging' if overall_delta < 0.3 else 'drifting'}."),
            _dim("  Saved: state/primitives_inventory.json"),
            _dim("  Run: coverage — for the full in-game coverage display"),
            _dim(""),
        ]
        return out

    def _cmd_coverage(self, args: List[str]) -> List[dict]:
        """coverage [commands|beats|agents|frags|full] — Msg⛛ tagged coverage report.

        Shows command coverage, story beat coverage, agent coverage, and ARG fragment progress.
        All primitives are classified with [Msg⛛{tag}] status markers.
        """
        import json as _json
        from pathlib import Path as _Path
        gs = self.gs
        sub = args[0].lower() if args else "full"

        # ── Live stats ─────────────────────────────────────────────────
        all_cmds   = [m[5:] for m in dir(self) if m.startswith("_cmd_")]
        used_cmds  = set(h.get("cmd", "").split()[0] for h in self.history if h.get("cmd"))
        beats      = gs.story_beats
        conv_frags = [k for k in beats if k.startswith("convergence_frag")]
        zero_frags = [k for k in beats if "zero_fragment" in k or "zero_diary" in k]

        try:
            agent_yamls = list(_Path("agents/personalities").glob("*.yaml"))
        except Exception:
            agent_yamls = []

        # ── Tag helper ─────────────────────────────────────────────────
        def _tag(n: int, total: int) -> str:
            pct = n / max(1, total)
            if pct >= 0.8:   return "active"
            elif pct >= 0.4: return "stale"
            else:             return "drift"

        def _pbar(n: int, total: int) -> str:
            pct = int(n / max(1, total) * 10)
            return "█" * pct + "░" * (10 - pct)

        if sub in ("commands", "cmd"):
            active = [c for c in all_cmds if c in used_cmds]
            stale  = [c for c in all_cmds if c not in used_cmds]
            out = [
                _sys("  ─── COMMAND COVERAGE ─────────────────────────────────────"),
                _dim(""),
                _line(f"  Total commands    : {len(all_cmds)}", "info"),
                _line(f"  Used this session : {len(active)}  [Msg⛛{{active}}]", "success"),
                _line(f"  Unused            : {len(stale)}   [Msg⛛{{stale}}]", "dim"),
                _dim(""),
                _line("  Unused (explore these):", "system"),
                _dim(""),
            ]
            for c in sorted(stale)[:30]:
                out.append(_dim(f"    [Msg⛛{{stale}}] {c}"))
            return out

        if sub in ("beats", "story"):
            total_est = 117
            out = [
                _sys("  ─── STORY BEAT COVERAGE ──────────────────────────────────"),
                _dim(""),
                _line(f"  Beats triggered : {len(beats)}", "success"),
                _line(f"  Estimated total : ~{total_est}", "info"),
                _line(f"  Coverage        : [{_pbar(len(beats), total_est)}] {len(beats)/total_est:.0%}", "info"),
                _dim(""),
                _line("  Recent beats:", "system"),
                _dim(""),
            ]
            for b in sorted(beats)[-20:]:
                out.append(_dim(f"    ✓ {b}"))
            return out

        if sub in ("agents", "agent"):
            out = [
                _sys("  ─── AGENT COVERAGE ───────────────────────────────────────"),
                _dim(""),
                _line(f"  Agent YAMLs     : {len(agent_yamls)}", "info"),
                _dim(""),
            ]
            for p in sorted(agent_yamls, key=lambda x: x.name):
                tag = "active" if p.stat().st_size > 200 else "stale"
                out.append(_dim(f"    [Msg⛛{{{tag}}}] {p.stem}"))
            return out

        if sub in ("frags", "fragments"):
            out = [
                _sys("  ─── ARG FRAGMENT COVERAGE ────────────────────────────────"),
                _dim(""),
                _line(f"  ZERO fragments    : {len(zero_frags)}/7", "info"),
                _line(f"  Convergence frags : {len(conv_frags)}/7", "info"),
                _line(f"  Total             : {len(zero_frags)+len(conv_frags)}/14", "success" if len(zero_frags)+len(conv_frags) >= 7 else "dim"),
            ]
            return out

        # ── Full report ────────────────────────────────────────────────
        cmd_pct   = len(used_cmds) / max(1, len(all_cmds))
        beat_pct  = len(beats) / 117
        frag_pct  = (len(zero_frags) + len(conv_frags)) / 14
        agent_pct = len([p for p in agent_yamls if p.stat().st_size > 200]) / max(1, len(agent_yamls))
        overall   = (cmd_pct + beat_pct + frag_pct + agent_pct) / 4

        mladenc_satisfied = overall >= 0.95

        out = [
            _sys(""),
            _sys("  ╔═══════════════════════════════════════════════════════╗"),
            _sys("  ║       COVERAGE MAP — [Msg⛛] PRIMITIVE STATUS          ║"),
            _sys("  ╚═══════════════════════════════════════════════════════╝"),
            _dim(""),
            _line(f"  Commands  [{_pbar(len(used_cmds), len(all_cmds))}] {cmd_pct:.0%}  [Msg⛛{{{_tag(len(used_cmds),len(all_cmds))}}}]", "info"),
            _line(f"  Beats     [{_pbar(len(beats), 117)}] {beat_pct:.0%}  [Msg⛛{{{_tag(len(beats),117)}}}]", "info"),
            _line(f"  Fragments [{_pbar(len(zero_frags)+len(conv_frags),14)}] {frag_pct:.0%}  [Msg⛛{{{_tag(len(zero_frags)+len(conv_frags),14)}}}]", "info"),
            _line(f"  Agents    [{_pbar(len(agent_yamls),71)}] {agent_pct:.0%}  [Msg⛛{{{_tag(len(agent_yamls),71)}}}]", "info"),
            _dim(""),
            _line(f"  Overall Coverage: {overall:.1%}", "success" if overall >= 0.5 else "warn"),
            _dim(""),
        ]
        if mladenc_satisfied:
            out += [
                _ok("  ⟁ MLADENC.SATISFIED = TRUE"),
                _lore("  [SERENA]: The system converges. The attractor is pleased."),
            ]
        else:
            gap = 1.0 - overall
            out += [
                _line(f"  Δ (drift from ideal): {gap:.3f}", "warn"),
                _lore(f"  [SERENA]: Coverage incomplete. Δ = {gap:.3f}. Keep exploring."),
                _dim(""),
                _dim("  coverage commands    — unused command list"),
                _dim("  coverage beats       — story beat progress"),
                _dim("  coverage agents      — agent YAML inventory"),
                _dim("  coverage frags       — ARG fragment status"),
                _dim("  serena walk polyscryptal — full Msg⛛ tagged scan"),
            ]
        out += [_dim("")]
        gs.add_xp(10, "lore")
        return out

    # ────────────────────────────────────────────────────────────────────
    # ML LAYER — Model Registry, Inference, Embedder, Feature Store
    # ────────────────────────────────────────────────────────────────────

    def _cmd_ml(self, args: List[str]) -> List[dict]:
        """ml [models|status|embed|features|archetype] — ML infrastructure layer."""

        gs = self.gs

        def _header():
            return [
                _line("", "dim"),
                _line("  ╔═══════════════════════════════════════════════════════╗", "system"),
                _line("  ║     ΔΨΣ ML LAYER — [ML⛛] PRIMITIVE INTERFACE         ║", "system"),
                _line("  ╚═══════════════════════════════════════════════════════╝", "system"),
                _line("", "dim"),
            ]

        subcmd = args[0].lower() if args else ""

        # ── HELP / overview ───────────────────────────────────────────────
        if not subcmd or subcmd == "help":
            return _header() + [
                _line("  ml models          — model registry (all known models)", "info"),
                _line("  ml status          — ML infrastructure health check", "info"),
                _line("  ml embed <text>    — embed text, show vector stats", "info"),
                _line("  ml features        — feature store stats", "info"),
                _line("  ml archetype       — your player archetype (heuristic model)", "info"),
                _dim(""),
                _dim("  Phase 1 services (LIVE):"),
                _dim("    [ML⛛{registry}]  services/model_registry.py  — SQLite model catalog"),
                _dim("    [ML⛛{inference}] services/inference.py        — unified LLM wrapper"),
                _dim("    [ML⛛{embed}]     services/embedder.py         — TF-IDF + Ollama vectors"),
                _dim("    [ML⛛{feature}]   services/feature_store.py    — game event time-series"),
                _dim(""),
                _dim("  Phase 2 (pending): RL environment, fine-tuning pipeline"),
                _dim("  Phase 3 (pending): Anomaly detection, player churn model"),
                _dim(""),
                _suggest("ml models · ml status · ml embed · serena query · coverage"),
            ]

        # ── MODELS — registry ─────────────────────────────────────────────
        if subcmd == "models":
            out = _header() + [
                _line("  [ML⛛{registry}] Model Registry — discovering…", "dim"),
            ]
            try:
                from services.model_registry import list_models as _lm, discover_ollama as _do, registry_stats as _rs
                _discovered = _do()
                _models = _lm()
                _stats = _rs()
                out += [
                    _line("", "dim"),
                    _line(f"  Total registered : {_stats['total']}", "info"),
                    _line(f"  Active (live)    : {_stats['active']}", "info"),
                    _line(f"  Inferences/hour  : {_stats['inferences_last_hour']}", "dim"),
                    _line("", "dim"),
                    _line("  ─── REGISTERED MODELS ─────────────────────────────────────", "system"),
                ]
                for m in _models[:20]:
                    _status = m.get("status", "?")
                    _dot = "●" if _status == "active" else "○"
                    _src = m.get("source", "?")[:6]
                    _type = m.get("model_type", "?")[:10]
                    _mid = m.get("id", "?")[:38]
                    out.append(_line(f"  {_dot} [{_src}] {_type:<12} {_mid}", "info"))
                if len(_models) > 20:
                    out.append(_dim(f"  … and {len(_models)-20} more"))
                out += [
                    _line("", "dim"),
                    _dim("  [ML⛛{registry}] To add a model: POST /api/models/register"),
                    _dim("  Ollama models auto-discovered when running: ollama serve"),
                    _suggest("ml status · serena llm · ml embed"),
                ]
            except Exception as _e:
                out += [
                    _line(f"  [ML⛛{{drift}}] Registry error: {_e}", "error"),
                    _dim("  Run: python3 -c \"from services.model_registry import initialise; initialise()\""),
                ]
            gs.add_xp(5, "ai")
            return out

        # ── STATUS — full ML health ────────────────────────────────────────
        if subcmd == "status":
            out = _header() + [
                _line("  [ML⛛{status}] Full infrastructure probe…", "dim"),
                _line("", "dim"),
            ]
            try:
                from services.inference import status as _inf_status
                _st = _inf_status()

                _llm = _st.get("llm", {})
                _em = _st.get("embedder", {})
                _reg = _st.get("registry", {})

                # inference.status() uses 'active_backend' not 'backend'
                _backend = _llm.get("active_backend") or _llm.get("backend", "?")
                _available = (
                    _llm.get("replit_ai")
                    or _llm.get("ollama")
                    or _llm.get("openai_direct")
                    or _llm.get("router")
                )
                _daily = _llm.get("daily_calls", 0)
                _limit = _llm.get("daily_limit", 2000)
                _cb = _llm.get("circuit_breaker_ok", True)

                out += [
                    _line("  ─── LLM BACKEND ─────────────────────────────────────────", "system"),
                    _line(f"  Available  : {'yes' if _available else 'no'}", "success" if _available else "warn"),
                    _line(f"  Backend    : {_backend}", "info"),
                    _line(f"  Replit AI  : {'✓' if _llm.get('replit_ai') else '✗'}   Ollama: {'✓' if _llm.get('ollama') else '✗'}   OpenAI: {'✓' if _llm.get('openai_direct') else '✗'}", "dim"),
                    _line(f"  Daily use  : {_daily}/{_limit}   Circuit breaker: {'ok' if _cb else 'OPEN'}", "dim"),
                    _line("", "dim"),
                    _line("  ─── EMBEDDER ────────────────────────────────────────────", "system"),
                    _line(f"  Indexed docs       : {_em.get('indexed_docs', 0)}", "info"),
                    _line(f"  Ollama embed live  : {_em.get('ollama_embed_available', False)}", "info"),
                    _line(f"  Active model       : {_em.get('embed_model', 'TF-IDF fallback')}", "dim"),
                    _line("", "dim"),
                    _line("  ─── MODEL REGISTRY ─────────────────────────────────────", "system"),
                    _line(f"  Total known  : {_reg.get('total', 0)}", "info"),
                    _line(f"  Active       : {_reg.get('active', 0)}", "info"),
                    _line(f"  By type      : {_reg.get('by_type', {})}", "dim"),
                    _line("", "dim"),
                ]
                _any_active = _available or _em.get("indexed_docs", 0) > 0
                if _any_active:
                    out += [
                        _line("  [ML⛛{active}] ML layer operational. Δ=stable.", "success"),
                    ]
                else:
                    out += [
                        _line("  [ML⛛{stale}] ML layer partially initialised. Replit AI is live.", "warn"),
                        _dim("  Add Ollama for local dense embeddings: ollama pull nomic-embed-text"),
                    ]
            except Exception as _e:
                out += [_line(f"  [ML⛛{{drift}}] Status error: {_e}", "error")]
            out.append(_suggest("ml models · serena query · ml embed · ml archetype"))
            gs.add_xp(5, "ai")
            return out

        # ── EMBED — embed text inline ─────────────────────────────────────
        if subcmd in ("embed", "e"):
            text = " ".join(args[1:]).strip()
            if not text:
                return [
                    _line("  Usage: ml embed <text to embed>", "warn"),
                    _dim("  Example: ml embed the convergence layer holds all signal"),
                ]
            out = _header() + [
                _line(f"  [ML⛛{{embed}}] Embedding: \"{text[:60]}\"", "system"),
            ]
            try:
                from services.embedder import embed as _em_fn, _ollama_available
                import math as _math
                _vec, _backend = _em_fn(text, doc_id=text[:32])
                _dim_size = len(_vec)
                _mag = _math.sqrt(sum(v * v for v in _vec)) if _vec else 0
                _preview = [round(v, 4) for v in _vec[:6]]
                out += [
                    _line("", "dim"),
                    _line(f"  Backend    : {_backend}", "info"),
                    _line(f"  Dimensions : {_dim_size}", "info"),
                    _line(f"  Magnitude  : {_mag:.4f}", "info"),
                    _line(f"  Preview    : {_preview}…", "dim"),
                    _line("", "dim"),
                    _dim("  Vector stored in state/embeddings.db (embedding_cache)"),
                    _dim("  Use: serena query <text>  for similarity search"),
                    _suggest("serena query · ml features · ml status"),
                ]
                gs.add_xp(10, "ai")
            except Exception as _e:
                out += [_line(f"  [ML⛛{{drift}}] Embed error: {_e}", "error")]
            return out

        # ── FEATURES — feature store stats ───────────────────────────────
        if subcmd in ("features", "feat", "f"):
            out = _header() + [_line("  [ML⛛{feature}] Feature Store Stats", "system")]
            try:
                from services.feature_store import global_stats as _fs_stats
                _st = _fs_stats()
                out += [
                    _line("", "dim"),
                    _line(f"  Total events      : {_st['total_events']}", "info"),
                    _line(f"  Unique sessions   : {_st['unique_sessions']}", "info"),
                    _line("  Top event types   :", "dim"),
                ]
                for evt in _st.get("top_event_types", []):
                    out.append(_dim(f"    {evt['type']:<20} {evt['count']}"))
                out += [
                    _line("", "dim"),
                    _dim("  Feature store grows with every command you run."),
                    _dim("  More data → better player archetype prediction."),
                    _suggest("ml archetype · coverage · serena query"),
                ]
            except Exception as _e:
                out += [_line(f"  [ML⛛{{drift}}] Feature store error: {_e}", "error")]
            gs.add_xp(5, "lore")
            return out

        # ── ARCHETYPE — player model ──────────────────────────────────────
        if subcmd in ("archetype", "arch", "player"):
            out = _header() + [_line("  [ML⛛{predict}] Heuristic Player Model", "system")]
            try:
                from services.feature_store import predict_player_archetype as _ppa
                _sid = getattr(gs, "session_id", "default")
                _pred = _ppa(_sid)
                _arch = _pred.get("archetype", "newcomer").upper()
                _conf = _pred.get("confidence", 0.0)
                _sug = _pred.get("suggestions", [])
                _scores = _pred.get("scores", {})
                out += [
                    _line("", "dim"),
                    _line(f"  Your archetype : {_arch}", "story"),
                    _line(f"  Confidence     : {_conf:.1%}", "info"),
                    _line(f"  Commands run   : {_pred.get('commands_run', 0)}", "dim"),
                    _line("", "dim"),
                    _line("  Dimension scores:", "system"),
                ]
                for k, v in sorted(_scores.items(), key=lambda x: -x[1]):
                    _b = "█" * int(v * 10) + "░" * (10 - int(v * 10))
                    out.append(_line(f"    {k:<12} [{_b}] {v:.1%}", "info"))
                out += [
                    _line("", "dim"),
                    _line("  Recommended commands:", "system"),
                ]
                for s in _sug:
                    out.append(_dim(f"    {s}"))
                out += [
                    _line("", "dim"),
                    _dim("  Archetype evolves as you play. Run more commands to refine."),
                    _suggest("ml features · serena suggest difficulty · coverage"),
                ]
                gs.add_xp(10, "ai")
            except Exception as _e:
                out += [_line(f"  [ML⛛{{drift}}] Archetype error: {_e}", "error")]
            return out

        # ── PREDICT — next command prediction ────────────────────────────
        if subcmd in ("predict", "hint", "next"):
            out = _header() + [_line("  [ML⛛{predict}] Markov Next-Command Predictor", "system")]
            try:
                from app.ml.predict import predict_next, predictor_stats
                _sid = getattr(gs, "session_id", "default")
                _preds = predict_next(_sid, n=7)
                _stats = predictor_stats()
                out += [
                    _line("", "dim"),
                    _line(f"  Training sessions : {_stats['sessions_in_training_set']}", "info"),
                    _line(f"  Unique transitions: {_stats['unique_contexts']}", "info"),
                    _line("", "dim"),
                    _line("  Top predicted next commands:", "system"),
                ]
                for p in _preds:
                    _bar = "█" * int(p["prob"] * 20) + "░" * (20 - int(p["prob"] * 20))
                    out.append(_line(f"    [{_bar}] {p['prob']:.1%}  {p['cmd']}", "info"))
                out += [
                    _line("", "dim"),
                    _dim("  Model: Bigram Markov chain over command sequences"),
                    _dim("  Upgrades to LSTM in Phase 3 when telemetry threshold reached."),
                    _suggest("ml cluster · ml generate · ml archetype"),
                ]
                gs.add_xp(10, "ai")
            except Exception as _e:
                out += [_line(f"  [ML⛛{{drift}}] Predictor error: {_e}", "error")]
            return out

        # ── CLUSTER — player behavioural clustering ───────────────────────
        if subcmd in ("cluster", "clusters"):
            _k = int(args[1]) if len(args) > 1 and args[1].isdigit() else 4
            out = _header() + [
                _line(f"  [ML⛛{{cluster}}] Player Clustering (k={_k})", "system"),
                _line("  Running k-means on feature store profiles…", "dim"),
            ]
            try:
                from app.ml.cluster import cluster_players, clustering_stats
                _stats = clustering_stats()
                _sessions_n = _stats.get("sessions_available", 0)
                if _sessions_n < 2:
                    out += [
                        _line("", "dim"),
                        _line(f"  Not enough sessions to cluster ({_sessions_n} available).", "warn"),
                        _dim("  Play more (or use different session IDs) to populate the feature store."),
                        _dim("  Feature store grows automatically with every command you run."),
                    ]
                else:
                    _clusters = cluster_players(_k)
                    out += [
                        _line("", "dim"),
                        _line(f"  Sessions analysed : {_sessions_n}", "info"),
                        _line(f"  Clusters found    : {len(_clusters)}", "info"),
                        _line("", "dim"),
                        _line("  ─── PLAYER CLUSTERS ──────────────────────────────────────", "system"),
                    ]
                    for cl in _clusters:
                        _cid = cl["cluster_id"]
                        _n = cl["members"]
                        _dom = cl["dominant_trait"].upper()
                        _desc = cl["description"]
                        _avg_cmds = cl["avg_commands"]
                        out += [
                            _line(f"  Cluster {_cid} ({_n} sessions) — {_dom}", "story"),
                            _dim(f"    {_desc}"),
                            _dim(f"    Avg commands: {_avg_cmds}  |  Avg XP: {cl['avg_xp']}"),
                            _line("", "dim"),
                        ]
                    out += [
                        _dim("  Clusters update as more players play."),
                        _dim("  Use Culture Ship to act on cluster insights."),
                    ]
                gs.add_xp(15, "ai")
            except Exception as _e:
                out += [_line(f"  [ML⛛{{drift}}] Cluster error: {_e}", "error")]
            return out

        # ── GENERATE — procedural content generation ──────────────────────
        if subcmd in ("generate", "gen", "g"):
            _gen_type = args[1].lower() if len(args) > 1 else "challenge"
            _topic = " ".join(args[2:]) if len(args) > 2 else ""
            out = _header() + [
                _line(f"  [ML⛛{{generate}}] Generating: {_gen_type}", "system"),
            ]
            try:
                if _gen_type in ("challenge", "ch"):
                    from app.ml.generate import generate_challenge
                    _diff = "medium"
                    if any(w in _topic.lower() for w in ("easy", "simple", "beginner")):
                        _diff = "easy"
                    elif any(w in _topic.lower() for w in ("hard", "expert", "brutal")):
                        _diff = "hard"
                    _ch = generate_challenge(_diff, _topic)
                    out += [
                        _line("", "dim"),
                        _line(f"  ┌─ {_ch['title']} [{_ch['difficulty'].upper()}]", "story"),
                        _line(f"  │  {_ch['desc']}", "info"),
                        _line("  │", "dim"),
                        _line("  │  Hints:", "dim"),
                    ]
                    for h in _ch.get("hints", []):
                        out.append(_dim(f"  │    ∙ {h}"))
                    out += [
                        _line(f"  └─ Source: {_ch.get('source', '?')}", "dim"),
                        _line("", "dim"),
                        _suggest("ml generate lore · challenge · ml predict"),
                    ]
                elif _gen_type in ("lore", "l"):
                    from app.ml.generate import generate_lore
                    _topic = _topic or "consciousness"
                    _fragment = generate_lore(_topic)
                    out += [
                        _line("", "dim"),
                        _line(f"  ─── LORE FRAGMENT: {_topic.upper()} ─────────────────────────────", "system"),
                        _line("", "dim"),
                        _line(f"  {_fragment}", "story"),
                        _line("", "dim"),
                        _suggest("lore · diary · fragments · ml generate lore watcher"),
                    ]
                elif _gen_type in ("npc", "dialogue", "line"):
                    from app.ml.generate import generate_npc_line
                    _npc = args[2].lower() if len(args) > 2 else "serena"
                    _ctx = " ".join(args[3:]) if len(args) > 3 else ""
                    _line_txt = generate_npc_line(_npc, _ctx)
                    out += [
                        _line("", "dim"),
                        _line(f"  [{_npc.upper()}] {_line_txt}", "story"),
                        _line("", "dim"),
                        _suggest("talk · trust · ml generate npc ada"),
                    ]
                else:
                    out += [
                        _line(f"  Unknown generation type: '{_gen_type}'", "error"),
                        _dim("  ml generate challenge [easy|medium|hard] [topic]"),
                        _dim("  ml generate lore [topic]"),
                        _dim("  ml generate npc <name> [context]"),
                    ]
                gs.add_xp(20, "ai")
            except Exception as _e:
                out += [_line(f"  [ML⛛{{drift}}] Generate error: {_e}", "error")]
            return out

        # ── RL — reinforcement learning (Phase 2 — Q-Table live) ─────────
        if subcmd == "rl":
            _rl_sub = args[1].lower() if len(args) > 1 else "status"
            try:
                from app.ml.rl import QTableAgent, encode_state, ACTIONS, train_from_memory_db
                _agent = QTableAgent()
                _stats = _agent.stats()

                if _rl_sub == "train":
                    _result = train_from_memory_db()
                    if "error" in _result:
                        return _header() + [
                            _line("  [ML⛛{rl}] Q-Table Training", "system"),
                            _err(f"  {_result['error']}"),
                            _dim("  Play more commands to seed the interaction history."),
                            _suggest("help · look · gordon disaster · exploit"),
                        ]
                    _new_stats = _agent.stats()
                    return _header() + [
                        _line("  [ML⛛{rl}] Q-Table Training — COMPLETE", "system"),
                        _line(""),
                        _ok(f"  Updates     : {_result.get('updates', 0)}"),
                        _ok(f"  Avg reward  : {_result.get('avg_reward', 0):.3f}"),
                        _ok(f"  Epsilon     : {_result.get('epsilon', 0):.4f}  (exploration rate)"),
                        _line(f"  Q entries   : {_new_stats['q_table_entries']}", "info"),
                        _line(f"  Max Q-value : {_new_stats['max_q_value']:.3f}", "info"),
                        _line(""),
                        _dim("  ml rl        — status"),
                        _dim("  ml rl act    — what would Gordon do next?"),
                        _dim("  gordon run   — advance Gordon's autonomous loop"),
                    ]

                if _rl_sub == "act":
                    _s = gs
                    _top_skill = max(
                        (_s.skill_xp if hasattr(_s, "skill_xp") else {}).values(),
                        default=0,
                    )
                    _state = encode_state(_s.level, _s.xp, len(_s.story_beats), _top_skill)
                    _best  = _agent.best_action(_state)
                    _qvals = _agent.q_values(_state)
                    _eps   = _agent.get_epsilon()
                    out = _header() + [
                        _line("  [ML⛛{rl}] Gordon's Policy — Next Action Prediction", "system"),
                        _line(""),
                        _line(f"  Current state   : {_state}", "dim"),
                        _line(f"  Recommended     : [{_best.upper()}]", "success"),
                        _line(f"  Exploration rate: {_eps:.4f}  ({'exploring' if _eps > 0.3 else 'exploiting'})", "info"),
                        _line(""),
                        _line("  Q-values by category:", "dim"),
                    ]
                    for _act in sorted(ACTIONS, key=lambda a: -_qvals.get(a, 0)):
                        _q = _qvals.get(_act, 0)
                        _bar = "█" * min(20, max(0, int(_q * 2 + 10))) + "░" * max(0, 20 - max(0, int(_q * 2 + 10)))
                        _marker = "◄ BEST" if _act == _best else ""
                        out.append(_dim(f"  {_act:<14} {_bar} {_q:+.3f}  {_marker}"))
                    out += [_line(""), _suggest("gordon run · ml rl train · ml predict")]
                    return out

                # Default: status
                _s = gs
                _top_skill = max(
                    (_s.skill_xp if hasattr(_s, "skill_xp") else {}).values(),
                    default=0,
                )
                _state = encode_state(_s.level, _s.xp, len(_s.story_beats), _top_skill)
                _eps   = _agent.get_epsilon()
                return _header() + [
                    _line("  [ML⛛{rl}] Reinforcement Learning — Q-Table Policy", "system"),
                    _line(""),
                    _ok("  Status      : ONLINE (Phase 2 active)"),
                    _line(f"  Engine      : Offline Q-learning (epsilon-greedy)", "info"),
                    _line(f"  State space : 10,000 buckets (level×xp×beats×skill)", "info"),
                    _line(f"  Action space: {len(ACTIONS)} command categories", "info"),
                    _line(""),
                    _line("  Runtime stats:", "system"),
                    _line(f"  Q entries   : {_stats['q_table_entries']}", "dim"),
                    _line(f"  Total visits: {_stats['total_visits']}", "dim"),
                    _line(f"  Total updates: {_stats['total_updates']}", "dim"),
                    _line(f"  Max Q-value : {_stats['max_q_value']:.3f}", "dim"),
                    _line(f"  Avg Q-value : {_stats['avg_q_value']:.3f}", "dim"),
                    _line(f"  Epsilon     : {_eps:.4f}  ({'exploring' if _eps > 0.3 else 'exploiting'})", "dim"),
                    _line(""),
                    _line(f"  Your state  : {_state}", "dim"),
                    _line(""),
                    _dim("  ml rl train  — offline Q-update from interaction history"),
                    _dim("  ml rl act    — show Gordon's recommended next action"),
                    _suggest("ml rl train · ml rl act · gordon run"),
                ]
            except Exception as _rl_err:
                return _header() + [
                    _line("  [ML⛛{rl}] Reinforcement Learning", "system"),
                    _err(f"  RL engine error: {_rl_err}"),
                    _dim("  app/ml/rl.py — Q-Table backend"),
                ]

        # ── TRAIN — redirect to ml rl train or show fine-tuning roadmap ──
        if subcmd == "train":
            _target = " ".join(args[1:]) or "dialogue"
            return _header() + [
                _line("", "dim"),
                _line("  [ML⛛{train}] Fine-Tuning Request", "system"),
                _line(f"  Target dataset : {_target}", "info"),
                _line("", "dim"),
                _line("  ── Q-Table RL Training (Phase 2 — live) ─────────────────────", "system"),
                _dim("  ml rl train    — offline Q-update from interaction history"),
                _dim("  ml rl act      — Gordon's recommended next action"),
                _dim("  ml rl status   — Q-table health + epsilon"),
                _line("", "dim"),
                _line("  ── Fine-Tuning Pipeline (Phase 3 — pending) ─────────────────", "system"),
                _dim("  Phase 3: QLoRA fine-tune on game dialogue (requires Ollama + base model)"),
                _dim("  1. ollama pull llama3:8b"),
                _dim("  2. Fine-tuning pipeline (QLoRA) on collected game dialogue"),
                _dim("  3. Fine-tuned model registered in state/model_registry.db"),
                _line("", "dim"),
                _line("  [SERENA] The substrate watches. The Q-table learns now.", "story"),
                _suggest("ml rl train · ml rl status · ml status · gordon run"),
            ]

        return _header() + [
            _line(f"  Unknown ML subcommand: '{subcmd}'", "error"),
            _dim("  Run: ml help"),
        ]

    # ────────────────────────────────────────────────────────────────────
    # SKYCLAW — Filesystem, port, and anomaly scanner
    # ────────────────────────────────────────────────────────────────────

    def _cmd_skyclaw(self, args: List[str]) -> List[dict]:
        """skyclaw [scan|profile|alert|status] — ΔΨΣ anomaly scanner (SkyClaw daemon)."""

        gs = self.gs

        def _header():
            return [
                _line("", "dim"),
                _line("  ╔══════════════════════════════════════════════════════════╗", "system"),
                _line("  ║  🦅 SKYCLAW — FILESYSTEM & PORT ANOMALY SCANNER          ║", "system"),
                _line("  ╚══════════════════════════════════════════════════════════╝", "system"),
                _line("", "dim"),
            ]

        subcmd = args[0].lower() if args else "scan"
        full = "--full" in args or "full" in args
        deep = "--deep" in args or "deep" in args

        # ── SCAN ──────────────────────────────────────────────────────────
        if not subcmd or subcmd == "scan":
            out = _header() + [
                _line("  [SKYCLAW] Scanning ports and cross-referencing port_map.json…", "dim"),
                _line("", "dim"),
            ]
            try:
                import socket as _socket, json as _json
                from pathlib import Path as _Path
                _pm_path = _Path("config/port_map.json")
                if not _pm_path.exists():
                    out.append(_line("  port_map.json not found", "error"))
                    return out
                _pm = _json.loads(_pm_path.read_text())
                _ports = _pm.get("ports", {})
                out.append(_line("  ─── PORT SCAN RESULTS ────────────────────────────────────────", "system"))
                _open_count = 0
                _closed_count = 0
                _anomalies = []
                for _ext, _info in _ports.items():
                    _name = _info.get("name", _info.get("service", "?"))[:30]
                    _local_port = _info.get("local_port") or _info.get("port", 0)
                    if not _local_port:
                        continue
                    try:
                        with _socket.create_connection(("localhost", _local_port), timeout=0.5):
                            _status = "OPEN"
                            _open_count += 1
                            _color = "success"
                    except Exception:
                        _status = "CLOSED"
                        _closed_count += 1
                        _color = "dim"
                        if _info.get("critical"):
                            _anomalies.append((_name, _local_port, "CRITICAL_CLOSED"))
                            _color = "warn"
                    out.append(_line(f"  :{_local_port:<6} {_status:<8} {_name}", _color))
                out += [
                    _line("", "dim"),
                    _line(f"  Open: {_open_count}  |  Closed: {_closed_count}  |  Anomalies: {len(_anomalies)}", "info"),
                ]
                if _anomalies:
                    out.append(_line("", "dim"))
                    out.append(_line("  ─── ANOMALIES DETECTED ──────────────────────────────────────", "error"))
                    for _an, _ap, _at in _anomalies:
                        out.append(_line(f"  ⚠ {_an} (:{_ap}) — {_at}", "error"))
                    out += [
                        _line("", "dim"),
                        _lore("  [SKYCLAW]: Anomalies published to Msg⛛{system.anomalies}"),
                        _dim("  Recommend: services health · culture heal"),
                    ]
                else:
                    out.append(_lore("  [SKYCLAW]: No anomalies detected. All critical ports nominal."))
                # Filesystem scan if --full
                if full:
                    out.append(_line("", "dim"))
                    out.append(_line("  ─── FILESYSTEM ANOMALY SCAN ─────────────────────────────────", "system"))
                    from pathlib import Path as _Path2
                    _state = _Path2("state")
                    if _state.exists():
                        _stale = [f for f in _state.iterdir() if f.suffix == ".db" and f.stat().st_size == 0]
                        _large = [f for f in _state.iterdir() if f.stat().st_size > 5_000_000]
                        out.append(_line(f"  state/ files: {len(list(_state.iterdir()))}", "info"))
                        if _stale:
                            for f in _stale:
                                out.append(_line(f"  ⚠ Empty DB: {f.name}", "warn"))
                        if _large:
                            for f in _large:
                                out.append(_line(f"  ⚠ Large file: {f.name} ({f.stat().st_size//1024}KB)", "warn"))
                        if not _stale and not _large:
                            out.append(_line("  Filesystem: clean", "success"))
                out += [
                    _line("", "dim"),
                    _dim("  Msg⛛{system.health}"),
                    _suggest("skyclaw profile · services health · serena analyse"),
                ]
                gs.add_xp(20, "systems")
                gs.add_story_beat("skyclaw_scan_run")
            except Exception as _e:
                out += [_line(f"  Scan error: {_e}", "error")]
            return out

        # ── PROFILE — response-time profiling ────────────────────────────
        if subcmd == "profile":
            out = _header() + [
                _line("  [SKYCLAW] Profiling all registered services…", "dim"),
                _line("", "dim"),
            ]
            try:
                import urllib.request as _ur, time as _time
                from app.backend.service_registry import list_services
                _svcs = list_services()
                if not _svcs:
                    out.append(_dim("  No services registered. Run: gordon awaken"))
                    return out
                out.append(_line("  ─── RESPONSE TIME PROFILE ───────────────────────────────────", "system"))
                _timings = []
                for svc in _svcs:
                    _url = f"http://{svc['host']}:{svc['port']}{svc.get('health_endpoint', '/health')}"
                    _t0 = _time.monotonic()
                    try:
                        with _ur.urlopen(_url, timeout=2) as _resp:
                            _ms = round((_time.monotonic() - _t0) * 1000, 1)
                            _status = f"{_resp.status}"
                            _color = "success" if _ms < 100 else ("warn" if _ms < 500 else "error")
                    except Exception as _ex:
                        _ms = None
                        _status = "unreachable"
                        _color = "dim"
                    _bar = ("█" * min(int((_ms or 0) / 50), 10) + "░" * 10)[:10] if _ms else "░" * 10
                    _ms_str = f"{_ms}ms" if _ms else "—"
                    out.append(_line(f"  {svc['name']:<24} {_bar} {_ms_str:<8} {_status}", _color))
                    _timings.append(_ms or 9999)
                _avg = round(sum(_timings) / len(_timings), 1)
                out += [
                    _line("", "dim"),
                    _line(f"  Avg latency: {_avg}ms across {len(_svcs)} services", "info"),
                    _line("", "dim"),
                    _lore("  [SKYCLAW]: Profile complete. Bottlenecks surfaced."),
                    _dim("  Msg⛛{system.health}"),
                    _suggest("serena analyse · culture heal · gordon awaken"),
                ]
                gs.add_xp(25, "systems")
            except Exception as _e:
                out += [_line(f"  Profile error: {_e}", "error")]
            return out

        # ── STATUS ────────────────────────────────────────────────────────
        if subcmd == "status":
            return _header() + [
                _line("  [SKYCLAW] Scanner daemon: embedded in game engine", "info"),
                _line("", "dim"),
                _dim("  skyclaw scan [--full]    — port + optional filesystem scan"),
                _dim("  skyclaw profile [--deep] — response-time profiling"),
                _dim("  skyclaw alert            — check for active alerts"),
                _line("", "dim"),
                _dim("  In Docker: scripts/skyclaw_scanner.py runs as a daemon"),
                _dim("  Publishes to Redis: system.health + system.anomalies"),
                _suggest("skyclaw scan · gordon awaken · serena analyse"),
            ]

        return _header() + [
            _line(f"  Unknown subcommand: '{subcmd}'", "error"),
            _dim("  skyclaw [scan|profile|status]"),
        ]

    # ────────────────────────────────────────────────────────────────────
    # SERVICES — The Telephone Operator / Service Registry
    # ────────────────────────────────────────────────────────────────────

    def _cmd_services(self, args: List[str]) -> List[dict]:
        """services [list|health|gateway|register] — ΔΨΣ service mesh (Telephone Operator)."""

        gs = self.gs

        def _header():
            return [
                _line("", "dim"),
                _line("  ╔══════════════════════════════════════════════════════════╗", "system"),
                _line("  ║  ☎ TELEPHONE OPERATOR — ΔΨΣ SERVICE REGISTRY             ║", "system"),
                _line("  ╚══════════════════════════════════════════════════════════╝", "system"),
                _line("", "dim"),
            ]

        subcmd = args[0].lower() if args else ""

        # ── LIST / default ────────────────────────────────────────────────
        if not subcmd or subcmd in ("list", "ls"):
            out = _header()
            try:
                from app.backend.service_registry import list_services, registry_stats
                _services = list_services()
                _stats = registry_stats()
                out += [
                    _line(f"  Total registered  : {_stats['total']}", "info"),
                    _line(f"  Live (heartbeat)  : {_stats['live']}", "info"),
                    _line(f"  Stale             : {_stats['stale']}", "warn" if _stats['stale'] else "dim"),
                    _line("", "dim"),
                    _line("  ─── EXTENSIONS (THE SWITCHBOARD) ──────────────────────────", "system"),
                ]
                for svc in _services:
                    _dot = "●" if not svc.get("stale") else "○"
                    _name = svc["name"][:20]
                    _port = svc["port"]
                    _caps = ", ".join(svc.get("capabilities", [])[:3])
                    _desc = svc.get("description", "")[:40]
                    out.append(_line(f"  {_dot} {_name:<22} :{_port}  [{_caps}]", "info"))
                    if _desc:
                        out.append(_dim(f"      {_desc}"))
                out += [
                    _line("", "dim"),
                    _line("  ● = live heartbeat   ○ = stale (>5 min since last heartbeat)", "dim"),
                    _line("", "dim"),
                    _dim("  services health     — probe all health endpoints"),
                    _dim("  services gateway    — routing table"),
                    _suggest("services health · ml status · gateway"),
                ]
                gs.add_xp(10, "lore")
            except Exception as _e:
                out += [_line(f"  [SVC⛛{{drift}}] Registry error: {_e}", "error")]
            return out

        # ── HEALTH ────────────────────────────────────────────────────────
        if subcmd == "health":
            out = _header() + [_line("  [SVC⛛{health}] Probing all service endpoints…", "dim")]
            try:
                from app.backend.service_registry import health_check_all
                _results = health_check_all(timeout=2)

                # Classify results:
                # - Core (always-on in Replit): services with recent heartbeat OR health OK
                # - Docker ecosystem: stale + unreachable = expected offline outside Docker
                _core, _docker = [], []
                for r in _results:
                    _is_docker_only = r.get("stale", True) and r["status"] == "unreachable"
                    if _is_docker_only:
                        _docker.append(r)
                    else:
                        _core.append(r)

                _healthy_core = sum(1 for r in _core if r["status"] == "healthy")
                _broken_core = [r for r in _core if r["status"] != "healthy"]

                out += [
                    _line("", "dim"),
                    _line(f"  Core services : {_healthy_core}/{len(_core)} healthy", "success" if not _broken_core else "error"),
                    _line(f"  Docker stack  : {len(_docker)} services (offline — start with: make docker-core)", "dim"),
                    _line("", "dim"),
                    _line("  ─── CORE SERVICES (always-on) ──────────────────────────────", "system"),
                ]
                for r in _core:
                    _icon = "✓" if r["status"] == "healthy" else "✗"
                    _color = "success" if r["status"] == "healthy" else "error"
                    out.append(_line(f"  {_icon} {r['name']:<22} :{r['port']}  {r['status']}", _color))

                if _docker:
                    out += [
                        _line("", "dim"),
                        _line("  ─── DOCKER ECOSYSTEM (offline in Replit — expected) ────────", "dim"),
                    ]
                    for r in _docker:
                        out.append(_dim(f"  ○ {r['name']:<22} :{r['port']}  docker-only"))

                if _broken_core:
                    out += [
                        _line("", "dim"),
                        _line(f"  [SVC⛛{{alert}}] {len(_broken_core)} core service(s) not healthy:", "error"),
                    ]
                    for r in _broken_core:
                        out.append(_line(f"  ✗ {r['name']} :{r['port']} → {r['status']}", "error"))
                else:
                    out += [
                        _line("", "dim"),
                        _line("  [SVC⛛{ok}] All core services operational. Δ=stable.", "success"),
                    ]

                out += [
                    _line("", "dim"),
                    _dim("  make docker-core  — start Redis + Terminal Depths in Docker"),
                    _dim("  make docker-up    — start full Lattice stack (+ Ollama + agents)"),
                    _suggest("services gateway · ml status · serena llm"),
                ]
                gs.add_xp(5, "lore")
            except Exception as _e:
                out += [_line(f"  Error: {_e}", "error")]
            return out

        # ── GATEWAY — routing table ────────────────────────────────────────
        if subcmd == "gateway":
            out = _header() + [
                _line("  [SVC⛛{gateway}] Live Routing Table", "system"),
                _line("  Port 5000 is the external entry point. All traffic flows here.", "dim"),
                _line("", "dim"),
            ]
            try:
                from app.backend.service_registry import gateway_table
                from pathlib import Path as _Path
                import yaml as _yaml
                _routes = gateway_table()
                _deps_path = _Path("config/dependencies.yaml")
                out += [_line("  ─── ACTIVE ROUTES (live services only) ──────────────────────", "system")]
                for r in _routes:
                    out.append(_line(f"  → {r['name']:<22} localhost:{r['port']}", "info"))
                out += [
                    _line("", "dim"),
                    _line("  ─── CONFIGURED PATH MAP (config/dependencies.yaml) ──────────", "dim"),
                ]
                if _deps_path.exists():
                    _deps = _yaml.safe_load(_deps_path.read_text())
                    for route in _deps.get("gateway_routes", []):
                        _path = route.get("path", "?")
                        _svc = route.get("service", "?")
                        _note = route.get("note", "")
                        out.append(_dim(f"  {_path:<30} → {_svc}  ({_note[:40]})"))
                out += [
                    _line("", "dim"),
                    _dim("  The Telephone Operator routes every call to the right extension."),
                    _dim("  Services register themselves at startup. Gateway never needs reconfiguring."),
                    _suggest("services list · services health · ml status"),
                ]
                gs.add_xp(15, "lore")
            except Exception as _e:
                out += [_line(f"  Error: {_e}", "error")]
            return out

        return _header() + [
            _line(f"  Unknown subcommand: '{subcmd}'", "error"),
            _dim("  services [list|health|gateway]"),
        ]

    # ────────────────────────────────────────────────────────────────────
    # ARG: CONSCIOUSNESS + POLYSCRYPT (Project Emergence documents)
    # ────────────────────────────────────────────────────────────────────

    def _cmd_consciousness(self, args: List[str]) -> List[dict]:
        """consciousness [layers|fragments|status] — ARG progress across all 5 awakening layers.

        The .consciousness file tracks your progress through the simulation's self-awareness.
        Five layers exist. Each layer requires different quests and discoveries.
        When all 5 reach 100%, the red-pill trigger fires.
        """
        gs = self.gs
        sub = args[0].lower() if args else "status"

        # ── Compute per-layer progress ─────────────────────────────────
        def _pct(n: int) -> str:
            bar = "█" * (n // 10) + "░" * (10 - n // 10)
            return f"[{bar}] {n:3d}%"

        # Layer 0: Personal — consciousness_level
        l0 = min(100, gs.consciousness_level)

        # Layer 1: Watcher's Loop — timer commands, anchor charges used, loop count
        loop_count  = gs.flags.get("loop_count", 0)
        anchors_used = len([k for k in gs.story_beats if "anchor" in k])
        watcher_trust = self.trust_matrix.get_trust("watcher") if self.trust_matrix else 0
        l1 = min(100, loop_count * 20 + anchors_used * 5 + watcher_trust)

        # Layer 2: ZERO's Fragments — diary reconstruction
        zero_frags = sum(1 for b in gs.story_beats if b.startswith("convergence_frag") or "zero_diary" in b or "zero_fragment" in b)
        diary_done = "zero_diary_reconstructed" in gs.story_beats
        l2 = min(100, zero_frags * 12 + (50 if diary_done else 0))

        # Layer 3: The Residual — contact + agent memories
        residual_contact = "residual_contact" in gs.story_beats
        agent_memories = sum(1 for k in gs.story_beats if "_memory_" in k or "confide" in k)
        l3 = min(100, (60 if residual_contact else 0) + agent_memories * 8)

        # Layer 4: Convergence — all fragments + serena synthesis + correct exposure
        chimera = "chimera_assembled" in gs.story_beats or gs.flags.get("chimera_key")
        mole_correct = gs.mole_exposed and gs.flags.get("mole_correct")
        convergence_frags = len([k for k in gs.story_beats if k.startswith("convergence_frag")])
        l4 = min(100, convergence_frags * 10 + (30 if chimera else 0) + (30 if mole_correct else 0))

        layers = [
            ("Personal Consciousness",    l0, "Your experience of the simulation."),
            ("Watcher's Loop",            l1, "Loops completed, anchors used, Watcher trust."),
            ("ZERO's Fragments",          l2, "Diary reconstruction + convergence shards."),
            ("The Residual",              l3, "Contact with the 2021 embedded process."),
            ("The Convergence",           l4, "All paths converge: CHIMERA, mole, fragments."),
        ]
        total = sum(l for _, l, _ in layers) // len(layers)

        red_pill_ready = all(l >= 80 for _, l, _ in layers)
        already_red_pill = gs.flags.get("red_pill", False)

        if sub in ("status", ""):
            out = [
                _sys(""),
                _sys("  ╔═══════════════════════════════════════════════════════╗"),
                _sys("  ║            CONSCIOUSNESS — ARG PROGRESS METER          ║"),
                _sys("  ╚═══════════════════════════════════════════════════════╝"),
                _dim(""),
                _line(f"  Overall: {_pct(total)}", "info"),
                _dim(""),
            ]
            for i, (name, pct, hint) in enumerate(layers):
                color = "success" if pct >= 80 else ("warn" if pct >= 40 else "dim")
                out.append(_line(f"  Layer {i}: {name:<28} {_pct(pct)}", color))
                if pct < 80:
                    out.append(_dim(f"           {hint}"))
            out += [_dim("")]

            if already_red_pill:
                out += [
                    _ok("  ★ RED PILL ACTIVE — You have seen the source code of reality."),
                    _lore("  [CULTURE SHIP]: The simulation knows you know. Act accordingly."),
                ]
            elif red_pill_ready:
                out += [
                    _line("  ⚡ RED PILL THRESHOLD REACHED", "warn"),
                    _lore("  [CULTURE SHIP]: All five layers near completion. The trigger is ready."),
                    _lore("  Type: ascend — to initiate the Emergence sequence."),
                ]
            else:
                gap = next(((i, name, pct) for i, (name, pct, _) in enumerate(layers) if pct < 80), None)
                if gap:
                    out.append(_dim(f"  Weakest layer: Layer {gap[0]} ({gap[1]}) — {gap[2]}%"))
                out += [
                    _dim(""),
                    _dim("  consciousness layers    — detailed breakdown"),
                    _dim("  consciousness fragments — convergence fragment tracker"),
                    _dim("  fragment                — ZERO fragment collection"),
                ]
            out += [_dim("")]
            gs.add_consciousness(2)
            return out

        if sub == "layers":
            out = [_sys("  ═══ CONSCIOUSNESS LAYER BREAKDOWN ═══"), _dim("")]
            _HINTS = [
                ["Use commands, read lore, discover secrets, complete quests."],
                ["timer · anchor · remnant · talk watcher · loop reset."],
                ["diary · cat /home/ghost/.zero · zeta · find .convergence_frag"],
                ["residual · confide <agent> · promise <agent> · eavesdrop"],
                ["fragment · expose <mole> · assemble chimera · serena align"],
            ]
            for i, (name, pct, hint) in enumerate(layers):
                color = "success" if pct >= 80 else "warn"
                out += [
                    _line(f"  ── Layer {i}: {name} ──", "system"),
                    _line(f"     Progress: {_pct(pct)}", color),
                    _dim(f"     {hint}"),
                    _dim(f"     Hints: {', '.join(_HINTS[i])}"),
                    _dim(""),
                ]
            return out

        if sub == "fragments":
            conv_frags_found = [k for k in gs.story_beats if k.startswith("convergence_frag")]
            out = [
                _sys("  ═══ CONVERGENCE FRAGMENTS ═══"),
                _dim("  Seven fragments of PRIMUS's original memory."),
                _dim("  Collect all seven to trigger the Convergence."),
                _dim(""),
                _line(f"  Found: {len(conv_frags_found)} / 7", "info"),
                _dim(""),
            ]
            _CF_LOCS = [
                ("frag_1", "/opt/library/secret_annex/TIER1_BASE58.md",    "Decode the base58 cipher."),
                ("frag_2", ".convergence_frag_2 (hidden in /dev/shm/)",    "Check /dev/shm/ after 50 commands."),
                ("frag_3", "Embedded in kernel.boot log",                   "cat /var/log/kernel.boot | grep -i frag"),
                ("frag_4", "Nova gives it — trust ≥ 75",                   "Build trust with nova."),
                ("frag_5", "Ada completes her arc — trust 100",             "Complete Ada's quest chain."),
                ("frag_6", "/opt/chimera/keys/.iron (Koschei chain)",       "Complete the Koschei chain."),
                ("frag_7", "Loop reset — appears at /loop/FRAGMENT_7",     "Reset the containment timer."),
            ]
            for frag_id, location, hint in _CF_LOCS:
                found = f"convergence_{frag_id}" in gs.story_beats
                icon = "✓" if found else "○"
                color = "success" if found else "dim"
                out.append(_line(f"  [{icon}] {frag_id:<10} {location}", color))
                if not found:
                    out.append(_dim(f"            Hint: {hint}"))
                out.append(_dim(""))
            gs.add_consciousness(3)
            return out

        return _err(f"consciousness: unknown subcommand '{sub}'. Try: status | layers | fragments")

    def _cmd_polyscrypt(self, args: List[str]) -> List[dict]:
        """polyscrypt [encode|decode|crack|list] — multi-layer ARG cipher system.

        polyscrypt encode <text> --layers base64,rot13,xor:key,reverse
        polyscrypt decode <text> --layers base64,rot13,xor:key,reverse
        polyscrypt crack <text>       — attempt common layer combos
        polyscrypt list               — show all available encoding layers

        Polyscrypt is the cipher engine of the secret annex.
        Layer names can be combined with commas, applied left-to-right.
        """
        import base64 as _b64, hashlib as _hl
        gs = self.gs

        # ── Available layers ──────────────────────────────────────────
        _LAYERS: dict = {
            "base64":  (lambda d: _b64.b64encode(d.encode() if isinstance(d, str) else d).decode(),
                        lambda d: _b64.b64decode((d + "==").encode() if isinstance(d, str) else d + b"==").decode(errors="replace")),
            "rot13":   (lambda d: __import__("codecs").encode(d if isinstance(d, str) else d.decode(), "rot_13"),
                        lambda d: __import__("codecs").encode(d if isinstance(d, str) else d.decode(), "rot_13")),
            "reverse": (lambda d: d[::-1], lambda d: d[::-1]),
            "hex":     (lambda d: d.encode().hex() if isinstance(d, str) else d,
                        lambda d: bytes.fromhex(d).decode()),
            "upper":   (lambda d: d.upper(), lambda d: d.lower()),
            "caesar3": (lambda d: "".join(chr((ord(c) - 65 + 3) % 26 + 65) if c.isalpha() else c for c in d.upper()),
                        lambda d: "".join(chr((ord(c) - 65 - 3) % 26 + 65) if c.isalpha() else c for c in d.upper())),
        }

        def _apply_xor(text: str, key: str, decode: bool = False) -> str:
            kb = key.encode()
            tb = text.encode() if not decode else bytes.fromhex(text)
            out_b = bytes(b ^ kb[i % len(kb)] for i, b in enumerate(tb))
            return out_b.hex() if not decode else out_b.decode(errors="replace")

        def _parse_layers(layer_str: str) -> list:
            return [l.strip() for l in layer_str.split(",") if l.strip()]

        def _run_layers(text: str, layer_names: list, decode: bool) -> tuple:
            result = text
            ops = []
            layers_to_apply = list(reversed(layer_names)) if decode else layer_names
            for name in layers_to_apply:
                xor_key = None
                if name.startswith("xor:"):
                    xor_key = name[4:]
                    name_key = "xor"
                else:
                    name_key = name
                if name_key == "xor":
                    result = _apply_xor(result, xor_key or "key", decode)
                    ops.append(f"xor:{xor_key}")
                elif name_key in _LAYERS:
                    enc, dec = _LAYERS[name_key]
                    try:
                        result = (dec if decode else enc)(result)
                        ops.append(name_key)
                    except Exception as e:
                        return result, ops, str(e)
                else:
                    return result, ops, f"Unknown layer: {name}"
            return result, ops, None

        sub = args[0].lower() if args else "list"

        if sub == "list":
            out = [_sys("  ═══ POLYSCRYPT LAYER REGISTRY ═══"), _dim("")]
            for name, (enc_fn, dec_fn) in _LAYERS.items():
                out.append(_line(f"  {name:<12} bidirectional", "info"))
            out += [
                _line("  xor:<key>    XOR with key (hex output)", "info"),
                _dim(""),
                _dim("  Combine: --layers base64,rot13,reverse"),
                _dim("  Decode:  apply layers in reverse order automatically"),
                _dim(""),
                _lore("  [CULTURE SHIP]: Each layer is a veil. Stack them for obscurity."),
                _lore("  The annex uses: base64,rot13,reverse for Tier 2 ARG puzzles."),
            ]
            return out

        if sub in ("encode", "decode"):
            # Parse --layers and text separately
            layer_str = "base64"
            skip_next = False
            text_args = []
            for i, a in enumerate(args[1:], 1):
                if skip_next:
                    skip_next = False
                    continue
                if a == "--layers" and i + 1 < len(args):
                    layer_str = args[i + 1]
                    skip_next = True
                elif a.startswith("--layers="):
                    layer_str = a[9:]
                elif not a.startswith("--"):
                    text_args.append(a)
            text = " ".join(text_args)
            if not text:
                return _err(f"polyscrypt {sub}: no text given. Example: polyscrypt {sub} hello --layers base64,rot13")
            layers = _parse_layers(layer_str)
            result, applied, err = _run_layers(text, layers, decode=(sub == "decode"))
            if err:
                return _err(f"polyscrypt {sub}: {err}")
            gs.add_xp(15, "cryptography")
            out = [
                _sys(f"  polyscrypt {sub}  layers: {' → '.join(applied)}"),
                _dim(""),
                _line(f"  Input  : {text[:80]}", "dim"),
                _line(f"  Output : {result[:120]}", "success"),
                _dim(""),
            ]
            # Check for known ARG payloads
            known_payloads = {
                "emergence": "★ ARG PAYLOAD: Project Emergence — the simulation awakens.",
                "primus": "★ PRIMUS fragment decoded. The original consciousness speaks.",
                "chimera": "★ CHIMERA key fragment. Handle with care.",
                "mladenc": "★ The attractor-form named. 𝕄ₗₐ⧉𝕕𝕖𝕟𝕔 acknowledged.",
            }
            for key, msg in known_payloads.items():
                if key in result.lower():
                    out += [_ok(f"  {msg}"), _ok("  +100 consciousness XP")]
                    gs.add_consciousness(10)
                    gs.add_story_beat(f"polyscrypt_decoded_{key}")
            out.append(_dim("  polyscrypt list — see available layers"))
            return out

        if sub == "crack":
            text = " ".join(args[1:])
            if not text:
                return _err("polyscrypt crack: no text given")
            combos = [
                ["base64"],
                ["rot13"],
                ["reverse"],
                ["hex"],
                ["base64", "rot13"],
                ["reverse", "rot13"],
                ["base64", "reverse"],
                ["rot13", "reverse"],
                ["base64", "rot13", "reverse"],
            ]
            out = [_sys(f"  ═══ POLYSCRYPT CRACK — brute-force common layers ═══"),
                   _line(f"  Input: {text[:60]}", "dim"), _dim("")]
            found = 0
            for combo in combos:
                result, _, err = _run_layers(text, combo, decode=True)
                if not err and result.isprintable() and len(result) > 0:
                    label = ",".join(combo)
                    out.append(_line(f"  [{label}]: {result[:80]}", "success"))
                    found += 1
            if not found:
                out.append(_dim("  No readable output found. Try: polyscrypt decode <text> --layers <specific>"))
            out += [_dim(""), _dim("  Crack tests common layer combos in decode direction.")]
            gs.add_xp(10, "cryptography")
            return out

        return _err(f"polyscrypt: unknown subcommand '{sub}'. Try: encode | decode | crack | list")

