    def _cmd_workspace(self, args: List[str]) -> List[dict]:
        """workspace [sync|open <repo>] — show adjacent repos detected by workspace bridge."""
        import json as _json
        from pathlib import Path as _Path

        manifest_path = _Path(__file__).parent.parent.parent / "state" / "workspace_manifest.json"

        sub = args[0].lower() if args else ""

        if sub == "sync":
            try:
                import subprocess as _sp
                bridge = _Path(__file__).parent.parent.parent / "scripts" / "workspace_bridge.py"
                _sp.Popen(["python", str(bridge)], stdout=_sp.DEVNULL, stderr=_sp.DEVNULL)
                return [
                    _sys("WORKSPACE BRIDGE — SYNC"),
                    _line("Scanning adjacent repositories...", "dim"),
                    _ok("Scan launched in background. Re-run `workspace` in a moment."),
                ]
            except Exception as exc:
                return [_err(f"Bridge error: {exc}")]

        if sub == "open" and len(args) >= 2:
            repo_name = args[1]
            return [
                _sys(f"WORKSPACE — CONNECT TO {repo_name.upper()}"),
                _lore(f"Establishing cross-repo link to {repo_name}..."),
                _line(""),
                _line(f"  [*] Probing {repo_name} manifest endpoint...", "dim"),
                _line(f"  [*] Checking for DevMentor surface in {repo_name}...", "dim"),
                _ok(f"Link established. {repo_name} visible at /opt/workspace/{repo_name}/"),
                _line("  Use: ls /opt/workspace/ to see connected repos", "dim"),
                _line("  Use: cat /opt/workspace/{repo_name}/README to read their manifest".format(repo_name=repo_name), "dim"),
            ]

        # Default: show workspace map
        out = [_sys("WORKSPACE BRIDGE — ADJACENT REPO MAP")]

        if not manifest_path.exists():
            out += [
                _line("No workspace scan found.", "dim"),
                _line("Run: workspace sync"),
                _line(""),
                _line("Known integration targets:", "dim"),
                _line("  NuSyQ-Hub      SimulatedVerse   ChatDev", "dim"),
                _line("  prime_anchor   rimworld         skyclaw", "dim"),
                _line("  openclaw       serena           metaclaw", "dim"),
            ]
            return out

        try:
            manifest = _json.loads(manifest_path.read_text())
        except Exception:
            return [_err("Could not read workspace manifest. Try: workspace sync")]

        found = manifest.get("found", [])
        unknown = manifest.get("unknown_repos", [])
        scan_time = manifest.get("scan_time", "unknown")[:19].replace("T", " ")

        if not found and not unknown:
            out += [
                _line(f"Scan: {scan_time}", "dim"),
                _line("No adjacent repos detected.", "dim"),
                _line("Run: workspace sync — to re-scan"),
            ]
            return out

        out.append(_line(f"Scan: {scan_time}  |  {len(found)} known  {len(unknown)} unknown", "dim"))
        out.append(_line(""))

        if found:
            out.append(_line("  KNOWN INTEGRATIONS:", "dim"))
            out.append(_line("  ─────────────────────────────────────────────────────", "dim"))
            for r in found:
                badge = {"native": "[NATIVE]", "api_bridge": "[API]",
                         "workspace_mount": "[MOUNT]", "ide_surface": "[IDE]",
                         "passive": "[passive]"}.get(r.get("td_integration", ""), "[?]")
                out.append(_line(f"  {badge:<10} {r['name']:<20} {r.get('description', '')[:40]}"))
            out.append(_line(""))

        if unknown:
            out.append(_line("  OTHER REPOS:", "dim"))
            for r in unknown[:5]:
                out.append(_line(f"             {r['name']}", "dim"))
            out.append(_line(""))

        out += [
            _line("Commands:", "dim"),
            _line("  workspace sync          — re-scan for new repos", "dim"),
            _line("  workspace open <repo>   — connect to a repo surface", "dim"),
            _line("  cat /opt/workspace/     — browse mounted repos", "dim"),
        ]
        self.gs.add_xp(5, "terminal")
        return out

