    def _cmd_scan(self, args: List[str]) -> List[dict]:
        """scan [target] — active network scan returning connected nodes."""
        target = next((a for a in args if not a.startswith("-")), "local")
        self.gs.add_xp(10, "networking")
        nodes = [
            ("node-1",          "10.0.1.1",   "22, 80",    "ACCESSIBLE"),
            ("chimera-control",  "10.0.1.254", "8443",      "RESTRICTED"),
            ("nexus-gateway",    "10.0.1.2",   "80, 443",   "ACCESSIBLE"),
            ("nexus-db",         "10.0.1.50",  "5432",      "FILTERED"),
            ("watcher-relay",    "10.0.1.77",  "???",       "UNKNOWN"),
        ]
        out = [
            _line(f"[*] Scanning network from {target}...", "system"),
            _line(""),
            _line("  NODE              IP            PORTS       STATUS", "dim"),
        ]
        for name, ip, ports, status in nodes:
            color = "success" if status == "ACCESSIBLE" else ("warn" if status == "RESTRICTED" else "dim")
            out.append(_line(f"  {name:<18} {ip:<14} {ports:<12} {status}", color))
        out.append(_line(""))
