    def _cmd_stocks(self, args: List[str]) -> List[dict]:
        """stocks [ticker|list|portfolio|events] — simulated stock market."""
        if not self._stock_market:
            return _err("Market subsystem unavailable.")

        market = self._stock_market
        market.tick()  # Advance one tick on each visit

        if not args or args[0].lower() == "list":
            from .stock_market import COMPANIES
            out = [
                _sys("╔══════════════════════════════════════════════════════════════════╗"),
                _sys("║  NEXUS EXCHANGE — DARK MARKET TERMINAL                          ║"),
                _sys("╚══════════════════════════════════════════════════════════════════╝"),
                _line(f"  {'TICKER':<6} {'COMPANY':<30} {'PRICE':>10} {'CHG%':>7}  {'GRAPH':<12}", "dim"),
                _dim("  " + "─" * 65),
            ]
            for c in COMPANIES:
                q = market.get_quote(c["ticker"])
                if not q:
                    continue
                chg_t = "success" if q["change"] >= 0 else "error"
                arrow = "▲" if q["change"] >= 0 else "▼"
                graph = market.price_graph(c["ticker"])
                held = f" [{q['held']}sh]" if q["held"] else ""
                out.append(_line(
                    f"  {q['ticker']:<6} {q['name'][:28]:<30} ${q['price']:>9,.2f} "
                    f"{arrow}{abs(q['change_pct']):>5.1f}%  {graph}{held}", chg_t))
            cash = market._cash
            pv = market.portfolio_value()
            out.append(_dim(f"\n  Cash: ${cash:,.2f}   Portfolio Value: ${pv:,.2f}"))
            out.append(_dim("  stocks <TICKER>  buy <TICKER> <n>  sell <TICKER> <n>  stocks events"))
            return out

        sub = args[0].upper()
        if sub == "PORTFOLIO":
            out = [_sys("═══ YOUR PORTFOLIO ═══")]
            from .stock_market import COMPANIES
            if not market._holdings:
                out.append(_dim("  No holdings. Buy shares with: buy <TICKER> <shares>"))
            else:
                for ticker, shares in market._holdings.items():
                    q = market.get_quote(ticker)
                    if q:
                        val = round(q["price"] * shares, 2)
                        out.append(_line(f"  {ticker:<6}  {shares:>5} shares  @ ${q['price']:,.2f}  = ${val:,.2f}"))
            out.append(_line(f"\n  Cash:  ${market._cash:,.2f}"))
            out.append(_line(f"  Total: ${market.portfolio_value():,.2f}"))
            return out

        if sub == "EVENTS":
            out = [_sys("═══ RECENT MARKET EVENTS ═══")]
            if not market._events_log:
                out.append(_dim("  No events yet. The market is calm..."))
            else:
                for ev in reversed(market._events_log[-10:]):
                    out.append(_line(f"  • {ev}"))
            return out

        # Quote for specific ticker
        q = market.get_quote(sub)
        if not q:
            return _err(f"stocks: unknown ticker '{sub}'. Use: stocks list")
        graph = market.price_graph(sub, 20)
        direction = "▲" if q["change"] >= 0 else "▼"
        chg_t = "success" if q["change"] >= 0 else "error"
        return [
            _sys(f"══ {q['ticker']} — {q['name']} ══"),
            _line(f"  Sector:   {q['sector']}"),
            _line(f"  Desc:     {q['description']}"),
            _line(f"  Price:    ${q['price']:,.2f}  {direction}{abs(q['change_pct']):.2f}%", chg_t),
            _line(f"  Held:     {q['held']} shares"),
            _line(f"  History:  {graph}"),
            _dim(f"\n  buy {sub} <shares>  sell {sub} <shares>"),
        ]

    def _cmd_buy(self, args: List[str]) -> List[dict]:
        """buy <TICKER> <shares> — buy shares in the dark market."""
        if not self._stock_market:
            return _err("Market subsystem unavailable.")
        if len(args) < 2:
            return _err("Usage: buy <TICKER> <shares>")
        ticker = args[0].upper()
        try:
            shares = int(args[1])
            if shares <= 0:
                raise ValueError
        except ValueError:
            return _err("buy: shares must be a positive integer")
        self._stock_market.tick()
        result = self._stock_market.buy(ticker, shares)
        if result.get("error"):
            return _err(f"buy: {result['error']}")
        return [
            _line(f"  ✓ Bought {result['shares']} shares of {result['ticker']} @ ${result['price']:,.2f}", "success"),
            _line(f"    Cost: ${result['cost']:,.2f}", "dim"),
            _line(f"    Cash remaining: ${result['cash_remaining']:,.2f}", "dim"),
        ]

    def _cmd_sell(self, args: List[str]) -> List[dict]:
        """sell <TICKER> <shares> — sell shares on the dark market."""
        if not self._stock_market:
            return _err("Market subsystem unavailable.")
        if len(args) < 2:
            return _err("Usage: sell <TICKER> <shares>")
        ticker = args[0].upper()
        try:
            shares = int(args[1])
            if shares <= 0:
                raise ValueError
        except ValueError:
            return _err("sell: shares must be a positive integer")
        self._stock_market.tick()
        result = self._stock_market.sell(ticker, shares)
        if result.get("error"):
            return _err(f"sell: {result['error']}")
        return [
            _line(f"  ✓ Sold {result['shares']} shares of {result['ticker']} @ ${result['price']:,.2f}", "success"),
            _line(f"    Proceeds: ${result['proceeds']:,.2f}", "dim"),
            _line(f"    Cash: ${result['cash_remaining']:,.2f}", "dim"),
        ]

