    def _cmd_augment(self, args: List[str]) -> List[dict]:
        """augment [list|info|buy|owned] — permanent augmentation shop."""
        if not self._augmentations or not self._prestige:
            return _err("Augmentation subsystem unavailable.")
        from .augmentations import AUGMENTATION_CATALOGUE, AUG_MAP

        aug_sys = self._augmentations
        prestige = self._prestige
        currency = prestige.prestige_currency

        if not args or args[0].lower() == "list":
            out = [
                _sys("╔══════════════════════════════════════════════════════╗"),
                _sys("║  AUGMENTATION SHOP — PERMANENT UPGRADES             ║"),
                _sys("╚══════════════════════════════════════════════════════╝"),
                _line(f"  Balance: {currency} ΨP (prestige currency)", "success"),
                _dim("  " + "─" * 54),
            ]
            for aug in AUGMENTATION_CATALOGUE:
                owned = aug_sys.has(aug["id"])
                status = "✓ INSTALLED" if owned else f"{aug['cost']} ΨP"
                t = "dim" if owned else ("success" if currency >= aug["cost"] else "error")
                tier_tag = f"[T{aug['tier']}]"
                out.append(_line(
                    f"  {aug['icon']} {tier_tag} {aug['name']:<28} {status:>12}", t))
                out.append(_dim(f"       {aug['description']}"))
            out.append(_dim("\n  augment info <id>   augment buy <id>   augment owned"))
            return out

        sub = args[0].lower()

        if sub == "owned":
            owned = aug_sys.get_owned()
            if not owned:
                return [_dim("  No augmentations installed yet. Buy with: augment buy <id>")]
            out = [_sys("═══ INSTALLED AUGMENTATIONS ═══")]
            for aug in owned:
                out.append(_line(f"  {aug['icon']} {aug['name']}", "success"))
                out.append(_dim(f"       {aug['description']}"))
            return out

        if sub == "info":
            if len(args) < 2:
                return _err("augment info: missing augmentation ID")
            aug = AUG_MAP.get(args[1])
            if not aug:
                return _err(f"augment info: unknown ID '{args[1]}'")
            owned = aug_sys.has(aug["id"])
            return [
                _sys(f"══ {aug['icon']} {aug['name']} ══"),
                _line(f"  ID:          {aug['id']}"),
                _line(f"  Tier:        {aug['tier']}"),
                _line(f"  Cost:        {aug['cost']} ΨP"),
                _line(f"  Status:      {'✓ INSTALLED' if owned else '○ Not installed'}", "success" if owned else "dim"),
                _line(f"  Description: {aug['description']}"),
                _line(f"  Effect:      {aug['effect']}"),
            ]

        if sub == "buy":
            if len(args) < 2:
                return _err("augment buy: missing augmentation ID")
            result = aug_sys.purchase(args[1], currency)
            if result.get("error"):
                return _err(f"augment: {result['error']}")
            aug = result["aug"]
            prestige.prestige_currency = result["remaining"]
            return [
                _sys(f"╔══════════════════════════════════════╗"),
                _sys(f"║  AUGMENTATION INSTALLED              ║"),
                _sys(f"║  {aug['icon']} {aug['name']:<34}║"),
                _sys(f"╚══════════════════════════════════════╝"),
                _line(f"  Cost: {result['cost']} ΨP", "dim"),
                _line(f"  Remaining balance: {result['remaining']} ΨP", "success"),
                _line(f"  Effect: {aug['description']}", "dim"),
            ]

        return _err(f"augment: unknown subcommand '{sub}'. Try: augment list | info <id> | buy <id> | owned")

    # ────────────────────────────────────────────────────────────────────
    # SECTION: PRESTIGE / ASCENSION
    # ────────────────────────────────────────────────────────────────────

    def _cmd_prestige_status(self, args: List[str]) -> List[dict]:
        """prestige — display prestige status, currency, and ascension history."""
        if not self._prestige:
            return _err("Prestige subsystem unavailable.")
        p = self._prestige
        out = [
            _sys("╔══════════════════════════════════════════════╗"),
            _sys("║  PRESTIGE TERMINAL — ASCENSION RECORDS       ║"),
            _sys("╚══════════════════════════════════════════════╝"),
            _line(f"  Current Layer:     {p.layer_name}"),
            _line(f"  Ascension Count:   {p.ascension_count}"),
            _line(f"  Prestige Currency: {p.prestige_currency} ΨP", "success"),
            _line(f"  Total Earned:      {p.total_prestige_earned} ΨP", "dim"),
            _line(f"  Story Complete:    {'YES — ready to ascend' if p.main_story_complete else 'No (complete main story first)'}", "success" if p.main_story_complete else "dim"),
        ]
        if p.layer_modifiers:
            out.append(_line("\n  Layer Modifiers:", "system"))
            for k, v in p.layer_modifiers.items():
                out.append(_dim(f"    {k}: {v}"))
        if p.ascension_log:
            out.append(_line("\n  Ascension History:", "system"))
            for rec in p.ascension_log[-5:]:
                out.append(_dim(f"    #{rec['ascension_number']} — Level {rec['level_reached']} — +{rec['prestige_earned']} ΨP — {rec['layer']}"))
        out.append(_dim("\n  ascend — trigger ascension (requires story completion)"))
        out.append(_dim("  augment — spend ΨP on permanent upgrades"))
        return out

    def _cmd_ascend(self, args: List[str]) -> List[dict]:
        """ascend — reset progress, earn prestige currency, enter next layer."""
        if not self._prestige or not self._augmentations:
            return _err("Ascension subsystem unavailable.")

        prestige = self._prestige

        if not prestige.can_ascend():
            beats = self.gs.story_beats
            arc_steps = [
                ("root_achieved",   "Obtain root shell",          "sudo find . -exec /bin/sh \\;"),
                ("master_key_read", "Read CHIMERA master key",    "cat /opt/chimera/keys/master.key"),
                ("chimera_connected","Connect to chimera-control","nc chimera-control 8443"),
                ("first_exploit",   "Deploy exploit",             "exploit chimera"),
                ("first_exfil",     "Exfiltrate data to Ada",     "exfil"),
            ]
            mission_done = "mission_complete" in self.gs.achievements
            out = [
                _err("╔══════════════════════════════════════════════════════╗"),
                _err("║  ▲ ASCENSION LOCKED — COMPLETE THE ARC FIRST        ║"),
                _err("╚══════════════════════════════════════════════════════╝"),
                _line(""),
                _line("  To ascend, you must complete the main mission arc:", "dim"),
                _line(""),
            ]
            all_done = True
            for beat_id, desc, cmd_hint in arc_steps:
                done = beat_id in beats
                if not done:
                    all_done = False
                mark = "✓" if done else "·"
                color = "success" if done else "warn"
                out.append(_line(f"    [{mark}] {desc}", color))
                if not done:
                    out.append(_line(f"         → {cmd_hint}", "dim"))
                    break
            if all_done and not mission_done:
                out.extend([
                    _line("    [·] Complete the arc", "warn"),
                    _line("         → ascend-story", "dim"),
                ])
            out.extend([
                _line(""),
                _line("  TYPE: story   for the full arc checklist with side quests.", "info"),
                _line("  TYPE: status  for your complete game dashboard.", "info"),
            ])
            return out

        if "--confirm" not in args and "-y" not in args:
            return [
                _sys("╔══════════════════════════════════════════════════════╗"),
                _sys("║  ASCENSION WARNING                                   ║"),
                _sys("╚══════════════════════════════════════════════════════╝"),
                _line("  Ascending will reset your progress:"),
                _line("    • Level reset to 1"),
                _line("    • XP reset to 0"),
                _line("    • Completed challenges cleared"),
                _line("    • Story beats cleared"),
                _line("    • Stock market reset"),
                _line("  PRESERVED ACROSS RESET:"),
                _line("    • Augmentations (permanent bonuses)", "success"),
                _line("    • Prestige currency", "success"),
                _line("    • Ascension count", "success"),
                _dim(f"\n  Estimated prestige earned: see your stats above"),
                _dim("  Type: ascend --confirm  to proceed"),
            ]

        gs_snap = self.gs.to_dict()
        result = prestige.ascend(gs_snap, self._augmentations)
        if result.get("error"):
            return _err(f"ascend: {result['error']}")

        # Reset game state
        from .gamestate import GameState
        old_augs = self._augmentations
        old_prestige = self._prestige
        new_gs = GameState()
        new_gs.ascension_count = result["ascension_count"]

        # Apply augmentation bonuses to new run — fully reset stock market
        bonus_cash = old_augs.stock_bonus_cash()
        if self._stock_market:
            self._stock_market.reset(bonus_cash=bonus_cash)

        # Rebuild game state reference
        self.gs.level = new_gs.level
        self.gs.xp = new_gs.xp
        self.gs.xp_to_next = new_gs.xp_to_next
        self.gs.skills = dict(new_gs.skills)
        self.gs.commands_run = 0
        self.gs.completed_challenges = set()
        self.gs.achievements = set()
        self.gs.story_beats = set()
        self.gs.lore = []
        self.gs.unlocked_agents = set()
        self.gs.mole_id = None
        self.gs.mole_clues_found = set()
        self.gs.mole_exposed = False
        self.gs.active_challenge_id = None
        self.gs.ascension_count = result["ascension_count"]

        rec = result["record"]
        mods = result["layer_modifiers"]
        out = [
            _sys("╔══════════════════════════════════════════════════════════╗"),
            _sys("║  ▲  ASCENSION COMPLETE                                   ║"),
            _sys(f"║  Layer: {result['new_layer']:<50}║"),
            _sys("╚══════════════════════════════════════════════════════════╝"),
            _line(""),
            _line(f"  Ghost has ascended to {result['new_layer']}.", "success"),
            _line(f"  Prestige Earned: +{rec['prestige_earned']} ΨP", "success"),
            _line(f"  Total Prestige:  {result['prestige_total']} ΨP", "success"),
            _line(""),
            _line(f"  Previous run summary:", "dim"),
            _line(f"    Level reached:        {rec['level_reached']}", "dim"),
            _line(f"    Challenges completed: {rec['challenges_completed']}", "dim"),
            _line(f"    Commands run:         {rec['commands_run']}", "dim"),
        ]
        if mods:
            out.append(_line("\n  New layer modifiers:", "system"))
            for k, v in mods.items():
                out.append(_dim(f"    {k}: {v}"))
        out.append(_line(""))
        out.append(_line("  Your augmentations persist. Level 1 again — but stronger.", "success"))
        out.append(_dim("  augment — spend your prestige currency on upgrades"))
        return out

    # For dev mode: force story completion to test ascend
    def _cmd_ghost_exec(self, args: List[str]) -> List[dict]:
        """ghost_exec — hidden command (augmentation: Ghost Protocol Alpha)."""
        if not self._augmentations or "ghost_exec" not in self._augmentations.hidden_commands():
            return _err("ghost_exec: command not found")
        if not args:
            return [_sys("ghost_exec: available sub-operations: force_story_complete")]
        if args[0] == "force_story_complete":
            if self._prestige:
                self._prestige.main_story_complete = True
            return _ok("Story arc flagged complete. You may now ascend.")
        return _err(f"ghost_exec: unknown operation '{args[0]}'")

    def _cmd_shadow_mode(self, args: List[str]) -> List[dict]:
        """shadow_mode — hidden command (augmentation: Ghost Protocol Alpha)."""
        if not self._augmentations or "shadow_mode" not in self._augmentations.hidden_commands():
            return _err("shadow_mode: command not found")
        return [
            _sys("╔══════════════════════════════════════╗"),
            _sys("║  SHADOW MODE ACTIVE                  ║"),
            _sys("╚══════════════════════════════════════╝"),
            _line("  All command output is ghost-routed.", "dim"),
            _dim("  (flavor only — no mechanical effect in this version)"),
        ]

    def _cmd_map(self, args: List[str]) -> List[dict]:
        """map [<node>] — display the network node graph or node detail."""
        NODES = {
            "home":          ("residential", "ghost",    "10",  ["node-1", "nexus-gateway"]),
            "node-1":        ("corporate",   "nexus",    "15",  ["home", "nexus-gateway"]),
            "nexus-gateway": ("corporate",   "nexus",    "30",  ["node-1", "nexus-db", "chimera-control"]),
            "nexus-db":      ("corporate",   "nexus",    "50",  ["nexus-gateway"]),
            "chimera-control":("corporate",  "root",     "80",  ["nexus-gateway", "watcher-relay"]),
            "watcher-relay": ("darknet",     "unknown",  "90",  ["chimera-control", "darknet-relay-7"]),
            "darknet-relay-7":("darknet",    "unknown",  "70",  ["watcher-relay", "collector-node"]),
            "collector-node":("darknet",     "collector","85",  ["darknet-relay-7"]),
            "resistance-cell":("underground","resistance","20", ["home", "darknet-relay-7"]),
        }
        
        HIDDEN_NODES = {
            "signal-echo": "A faint pulse in the noise. Originates from outside the local cluster.",
            "dead-drop-7": "A secure storage node used by the early Resistance. Contains encrypted fragments.",
            "null-route": "A routing table anomaly. Packets sent here disappear into a recursive loop.",
            "ghost-cache": "A hidden cache of ghost-class exploits. Protected by a rotating cipher.",
            "cold-storage-4": "Old server bank, disconnected from the main grid. Contains legacy logs.",
            "proxy-chain-3": "A series of compromised IoT devices used to mask trace signatures.",
            "deep-scan-alpha": "Advanced sensor node. Monitors traffic across the entire backbone.",
            "black-hole-9": "Data gravity anomaly. High-density information storage.",
            "void-buffer": "A temporary storage area that shouldn't exist according to the official spec.",
            "echo-chamber": "A node that replicates every packet it receives. Useful for stress testing.",
            "silent-bridge": "A stealthy connection between two disparate network segments.",
            "shadow-port": "An undocumented port on a corporate switch. Leads to the backplane.",
            "glitch-nexus": "A point where the simulation substrate is particularly thin.",
            "omega-point": "A theoretical terminal node in the network graph.",
            "spectral-relay": "Uses quantum entanglement to bypass standard firewalls.",
            "phantom-disk": "A virtual disk drive mapped to unallocated memory space.",
            "logic-vault": "A highly secure node requiring complex SAT solutions to access.",
            "nebula-route": "A randomized routing protocol that defies standard mapping.",
            "cipher-core": "The heart of the network's encryption layer.",
            "zero-point": "The very first node created in this simulation segment.",
        }

        if args:
            sub = args[0].lower()
            if sub == "discover":
                if len(args) < 2: return _err("map discover: specify a node name")
                node = args[1].lower()
                discovered = self.gs.flags.setdefault("discovered_nodes", [])
                
                if node in HIDDEN_NODES:
                    if node not in discovered:
                        discovered.append(node)
                        count = len(discovered)
                        self.gs.add_xp(5, "meta")
                        out = [_ok(f"  NODE DISCOVERED: {node}"),
                               _lore(f"  {HIDDEN_NODES[node]}"),
                               _dim(f"  Progress: {count} hidden nodes found.")]
                        
                        if count == 10: self.gs.add_story_beat("map_10_nodes")
                        if count == 25: self.gs.add_story_beat("map_25_nodes")
                        if count == 50: self.gs.add_story_beat("map_50_nodes")
                        
                        return out
                    else:
                        return [_dim(f"  Node '{node}' already discovered.")]
                elif node in NODES:
                    return [_dim(f"  Node '{node}' is a known public node. No discovery XP awarded.")]
                else:
                    return _err(f"map discover: '{node}' is not a valid discoverable node.")
            
            if sub == "discovered":
                discovered = self.gs.flags.get("discovered_nodes", [])
                if not discovered: return [_dim("  No hidden nodes discovered yet.")]
                out = [_sys("  ═══ DISCOVERED HIDDEN NODES ═══")]
                for d in discovered:
                    out.append(_line(f"  • {d}", "success"))
                out.append(_dim(f"\n  Total: {len(discovered)} / 50 for exploration quest."))
                return out

            target = args[0].lower().rstrip("/")
            node = NODES.get(target)
            if not node:
                return _err(f"map: unknown node '{target}'. Run `map` for the full topology.")
            category, owner, difficulty, connections = node
            out = [
                _sys(f"=== NODE: {target.upper()} ==="),
                _line(f"  Category:    {category}", "dim"),
                _line(f"  Owner:       {owner}", "dim"),
                _line(f"  Difficulty:  {difficulty}", "warn" if int(difficulty) > 50 else "info"),
                _line(f"  Connections: {', '.join(connections)}", "dim"),
                _line(f"\n  Commands: ssh {target} | warp {target} | scan {target}", "dim"),
            ]
            return out

        out = [
            _sys("=== NETWORK TOPOLOGY MAP ==="),
            _line("", "dim"),
            _line("  [home] ──── [node-1] ──── [nexus-gateway] ──── [nexus-db]", "info"),
            _line("    │                              │", "dim"),
            _line("    │                        [chimera-control] ─── [watcher-relay]", "warn"),
            _line("    │                                                     │", "dim"),
            _line("  [resistance-cell]          [collector-node] ─── [darknet-relay-7]", "success"),
            _line("", "dim"),
            _line("  Legend:  info=residential  warn=corporate  dim=darknet  success=underground", "dim"),
            _line("  Run: map <node>  for detail  |  warp <node>  to travel", "dim"),
        ]
        return out

    def _cmd_warp(self, args: List[str]) -> List[dict]:
        """warp <node> — instantly travel to a discovered network node."""
        ALIASES = {
            "home": "/home/ghost",
            "last": None,
            "safe": "resistance-cell",
        }
        KNOWN_NODES = {
            "home", "node-1", "nexus-gateway", "nexus-db",
            "chimera-control", "watcher-relay", "darknet-relay-7",
            "collector-node", "resistance-cell",
        }

        if not args:
            return _err("Usage: warp <node>  (or: warp home | warp last | warp safe)")

        target = args[0].lower()

        if target == "last":
            return [_line("  warp: no previous destination recorded.", "dim")]

        if target in ALIASES:
            resolved = ALIASES[target]
            if resolved is None:
                return [_line("  warp: no previous destination.", "dim")]
            target = resolved

        if target not in KNOWN_NODES and not target.startswith("/"):
            return [
                _err(f"warp: '{target}' not in discovered node list."),
                _dim("  Discover nodes with: scan, nmap, map"),
            ]

        out = [
            _sys(f"WARP INITIATED — {target.upper()}"),
            _line(f"  Tunneling through resistance relay...", "dim"),
            _line(f"  Spoofing origin packet — TTL mismatch injected.", "dim"),
            _line(f"  Connected. Current context: {target}", "success"),
        ]

        if target == "chimera-control" and not self._chimera_connected:
            out.append(_line("\n  WARN: CHIMERA control node requires authenticated session.", "warn"))
            out.append(_line("  Hint: nc chimera-control 8443 first, then warp.", "dim"))
        elif target == "watcher-relay":
            if not self.gs.has_beat("watcher_contact"):
                out.append(_line("\n  STATIC. The relay is active but not responding to your signature.", "dim"))
            else:
                out.append(_line("\n  [WATCHER RELAY]: You've been expected.", "warn"))

        return out

    def _cmd_phase(self, args: List[str]) -> List[dict]:
        """phase [<layer>] — shift to an alternate simulation layer."""
        current = self.gs.get_flag("simulation_layer", 1)

        LAYERS = {
            1: ("Standard Operative View", "default environment"),
            2: ("ARG Observer Layer", "Watcher transmissions and myth database"),
            3: ("CHIMERA v0 Substrate", "identity revelation — requires discovery arc"),
        }

        if not args:
            out = [
                _sys("=== SIMULATION LAYER STATUS ==="),
                _line(f"  Current layer: {current} — {LAYERS[current][0]}", "info"),
                _line(f"  Description:   {LAYERS[current][1]}", "dim"),
                _line("", "dim"),
            ]
            for n, (name, desc) in LAYERS.items():
                marker = "▶" if n == current else "·"
                lock = ""
                if n == 3 and not self.gs.has_beat("arc_discovery_complete"):
                    lock = "  [LOCKED — complete Discovery arc]"
                color = "success" if n == current else "dim"
                out.append(_line(f"  {marker} phase-{n}: {name}{lock}", color))
            out.append(_line("\n  Use: phase <1|2|3> to shift layers", "dim"))
            return out

        try:
            target = int(args[0])
        except ValueError:
            return _err(f"phase: invalid layer '{args[0]}'. Use: phase 1 | phase 2 | phase 3")

        if target not in LAYERS:
            return _err(f"phase: layer {target} does not exist. Valid: 1, 2, 3")

        if target == 3 and not self.gs.has_beat("arc_discovery_complete"):
            return [
                _err("phase 3: CHIMERA v0 substrate locked."),
                _dim("  Complete the Discovery arc first: `arcs discovery`"),
            ]

        if target == current:
            return [_line(f"  Already in phase-{target}.", "dim")]

        self.gs.set_flag("simulation_layer", target)
        name, desc = LAYERS[target]
        out = [
            _sys(f"PHASE SHIFT — LAYER {target}"),
            _line(f"  Entering: {name}", "success"),
            _line(f"  Context:  {desc}", "dim"),
        ]
        if target == 2:
            out += [
                _line("", "dim"),
                _line("  Watcher channel active. Run: watcher | myth | signal analyze 1337", "warn"),
            ]
        elif target == 3:
            out += [
                _line("", "dim"),
                _line("  CHIMERA v0 substrate accessible. Run: introspect chimera | rebuild chimera", "warn"),
            ]
        return out

    def _cmd_phases(self, args: List[str]) -> List[dict]:
        """phases — alias for 'phase'; list all simulation layers."""
        return self._cmd_phase(args)

