    # SCP / ANOMALY SYSTEM
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_anomaly(self, args: List[str]) -> List[dict]:
        """anomaly — View and interact with active SCP-style anomalies."""
        _ANOMALIES = [
            {
                "id": "SCP-7734",
                "class": "Safe",
                "description": "A text file that rewrites its own content between readings. Content appears to be contextually relevant to the reader.",
                "location": "/var/anomalies/SCP-7734.txt",
                "status": "CONTAINED",
                "note": "Do not read twice without documentation. Effect appears benign but mechanism unknown.",
            },
            {
                "id": "SCP-7735",
                "class": "Euclid",
                "description": "A directory that increases in size with each `ls` call without new files being added. Subdirectories appear on subsequent reads.",
                "location": "/opt/library/",
                "status": "MONITORING",
                "note": "Believed to be related to the 'Library' phenomenon. The Librarian claims ownership.",
            },
            {
                "id": "SCP-7736",
                "class": "Keter",
                "description": "A process that appears in `ps aux` but cannot be killed. Named 'watcher_eternal'. CPU usage: 0.0%. Has been running since before this node was initialized.",
                "location": "PID: unknown",
                "status": "UNCONTAINED",
                "note": "The Watcher denies involvement. The Watcher is lying.",
            },
            {
                "id": "SCP-7737",
                "class": "Thaumiel",
                "description": "An agent communication channel that predates the Resistance network. Messages arrive before they are sent.",
                "location": "/dev/hive_prelisten",
                "status": "UTILIZED",
                "note": "Serena uses this for 'drift detection.' Classification: asset.",
            },
        ]

        if not args:
            out: List[dict] = [
                _sys(""),
                _sys("  ╔═══════════════════════════════════════════════════╗"),
                _sys("  ║    SCIENTIFIC DIVISION — ANOMALY REGISTRY           ║"),
                _sys("  ╚═══════════════════════════════════════════════════╝"),
                _dim(""),
            ]
            for a in _ANOMALIES:
                cls_color = "error" if a["class"] == "Keter" else "warn" if a["class"] == "Euclid" else "dim"
                out.append(_line(f"  {a['id']}  [{a['class']}]  {a['status']}", cls_color))
                out.append(_dim(f"    Location: {a['location']}"))
                out.append(_dim(f"    {a['description'][:80]}..."))
                out.append(_dim(""))
            out.append(_dim("  'anomaly <id>' for full report · 'cat /var/anomalies/*' for raw files"))
            return out

        target = args[0].upper()
        for a in _ANOMALIES:
            if target in a["id"]:
                out = [
                    _sys(""),
                    _sys(f"  ── ANOMALY REPORT: {a['id']} ──────────────────────────"),
                    _line(f"  Classification:  {a['class']}"),
                    _line(f"  Status:          {a['status']}"),
                    _line(f"  Location:        {a['location']}"),
                    _dim(""),
                    _line(f"  Description: {a['description']}"),
                    _dim(""),
                    _warn(f"  ⚠ Note: {a['note']}"),
                    _dim(""),
                ]
                self.gs.add_xp(15, "security")
                return out
        return [_err(f"anomaly: '{args[0]}' not found in registry. Known: SCP-7734 through SCP-7737")]

