    def _cmd_learn(self, args: List[str]) -> List[dict]:
        """learn models [card] — browse Temple of Knowledge model cards and earn XP."""
        def _sys(s): return {"t": "system", "s": s}
        def _dim(s): return {"t": "dim", "s": s}
        def _ok(s):  return {"t": "success", "s": s}
        def _info(s): return {"t": "info", "s": s}
        def _lore(s): return {"t": "lore", "s": s}

        # Only handle `learn models [card]` for now
        sub = args[0].lower() if args else ""
        if sub not in ("models", "model", ""):
            return [
                _dim("  Usage: learn models [card_name]"),
                _dim("  Example: learn models  |  learn models 01_qwen25_coder_7b"),
            ]

        from pathlib import Path as _Path
        _models_dir = _Path(__file__).resolve().parent.parent.parent / "docs" / "temple" / "models"

        cards = sorted(_models_dir.glob("*.md")) if _models_dir.exists() else []

        if not cards:
            return [{"t": "error", "s": "  [learn] Model card directory not found."}]

        # If a specific card is requested
        card_arg = args[1].lower() if len(args) >= 2 else ""
        if card_arg:
            matched = [c for c in cards if card_arg in c.stem.lower()]
            if not matched:
                return [
                    {"t": "error", "s": f"  [learn] No card matching '{card_arg}'."},
                    _dim(f"  Available: {', '.join(c.stem for c in cards)}"),
                ]
            card = matched[0]
            beat_key = f"learn_model_{card.stem}"
            first_read = beat_key not in self.gs.story_beats
            self.gs.add_story_beat(beat_key)

            # XP per card (parse from file footer or use defaults)
            _xp_map = {
                "01_qwen25_coder_7b": 15,
                "02_qwen25_coder_14b": 15,
                "03_deepseek_coder_v2_16b": 20,
                "04_qwen25_vl_7b": 15,
                "05_llava_7b": 20,
                "06_gpt_oss_20b": 25,
            }
            xp = _xp_map.get(card.stem, 10)
            if first_read:
                self.gs.add_xp(xp, "research")

            try:
                content = card.read_text(encoding="utf-8")
            except Exception:
                content = "(unable to read card)"

            out = [
                _sys(f"╔══════════════════════════════════════════════════════╗"),
                _sys(f"║  TEMPLE MODEL CARD: {card.stem.upper():<34}║"),
                _sys(f"╚══════════════════════════════════════════════════════╝"),
                _dim(""),
            ]
            for line in content.splitlines():
                if line.startswith("# "):
                    out.append(_sys(f"  {line}"))
                elif line.startswith("## ") or line.startswith("### "):
                    out.append(_info(f"  {line}"))
                elif line.startswith("---") or not line.strip():
                    out.append(_dim(""))
                elif line.startswith("*") and line.endswith("*"):
                    out.append(_lore(f"  {line}"))
                else:
                    out.append(_dim(f"  {line}"))

            # Achievement: all 6 cards read
            all_read = all(
                f"learn_model_{c.stem}" in self.gs.story_beats for c in cards
            )
            cx_tag = f" · +{xp} XP" if first_read else " · already studied"
            out.append(_dim(""))
            out.append(_ok(f"  Card archived.{cx_tag}"))
            if all_read and "learn_all_models" not in self.gs.story_beats:
                self.gs.add_story_beat("learn_all_models")
                self.gs.add_xp(50, "research")
                out += [
                    _dim(""),
                    _sys("  ╔═══════════════════════════════════════╗"),
                    _sys("  ║  ACHIEVEMENT: MODEL SCHOLAR           ║"),
                    _sys("  ║  All 6 model cards studied.           ║"),
                    _sys("  ║  +50 XP bonus — Temple sanctum open.  ║"),
                    _sys("  ╚═══════════════════════════════════════╝"),
                ]
            return out

        # Index view — list all cards
        out = [
            _sys("╔══════════════════════════════════════════════════════╗"),
            _sys("║           TEMPLE OF KNOWLEDGE — MODEL SANCTUM       ║"),
            _sys("╚══════════════════════════════════════════════════════╝"),
            _dim(""),
            _sys("  AI Model Cards — Floor 6"),
            _dim(""),
        ]
        all_xp_map = {
            "01_qwen25_coder_7b": 15,
            "02_qwen25_coder_14b": 15,
            "03_deepseek_coder_v2_16b": 20,
            "04_qwen25_vl_7b": 15,
            "05_llava_7b": 20,
            "06_gpt_oss_20b": 25,
        }
        read_count = 0
        for card in cards:
            studied = f"learn_model_{card.stem}" in self.gs.story_beats
            if studied:
                read_count += 1
            marker = "◉" if studied else "○"
            xp_str = f"+{all_xp_map.get(card.stem, 10)} XP"
            out.append(_dim(f"  {marker} {card.stem:<40} {xp_str}"))
        out += [
            _dim(""),
            _dim(f"  Studied: {read_count}/{len(cards)}"),
            _dim(""),
            _dim("  Usage: learn models <card_name>"),
            _dim("  Example: learn models 01_qwen25_coder_7b"),
            _dim(""),
            _dim("  Complete all 6 to earn the Model Scholar achievement (+50 XP)."),
        ]
        return out

    def _cmd_skill(self, args: List[str]) -> List[dict]:
        """skill — alias for skills. Display your skill matrix."""
        return self._cmd_skills(args)

    # _cmd_sleep defined below with dream_engine integration (VN7)

    def _cmd_msg_history(self, args: List[str]) -> List[dict]:
        """msg history <agent> — show last 5 whisper messages to/from an agent."""
        agent = args[0].lower() if args else ""
        if not agent:
            return [
                _sys("  Usage: msg history <agent>"),
                _dim("  Shows last 5 whisper messages exchanged with an agent."),
            ]
        key = f"whisper_history_{agent}"
        history = self.gs.flags.get(key, [])
        if isinstance(history, str):
            try:
                history = json.loads(history)
            except Exception:
                history = []

        if not history:
            return [
                _sys(f"  MSG HISTORY — {agent.upper()}"),
                _dim(f"  No messages exchanged yet. Try: msg {agent} hello"),
            ]

        out = [
            _sys(f"╔═══════════════════════════════════════╗"),
            _sys(f"║  MSG HISTORY — {agent.upper():<22}║"),
            _sys(f"╚═══════════════════════════════════════╝"),
            _dim(""),
        ]
        for m in history[-5:]:
            direction = "→" if m.get("from") == "player" else "←"
            out.append(_lore(f"  {direction} {m.get('text', '')}"))
            out.append(_dim(f"    {m.get('ts', '')[:10]}"))
            out.append(_dim(""))
        return out

    def _cmd_promise(self, args: List[str]) -> List[dict]:
        """promise <agent> <what> — make a promise to an agent. Breaking it has consequences."""
        if len(args) < 2:
            return [
                _sys("  Usage: promise <agent> <what you promise>"),
                _dim("  Promises are remembered. Breaking them shifts trust permanently."),
            ]
        agent = args[0].lower()
        what = " ".join(args[1:])

        key = f"promises_to_{agent}"
        promises = self.gs.flags.get(key, [])
        if isinstance(promises, str):
            try:
                promises = json.loads(promises)
            except Exception:
                promises = []

        entry = {
            "promise": what,
            "ts": datetime.now(timezone.utc).isoformat(),
            "kept": None,
        }
        promises.append(entry)
        self.gs.flags[key] = json.dumps(promises)
        self.gs.add_story_beat(f"promised_{agent}")
        self.gs.add_consciousness(8)  # Layer 3: social covenant — a promise is a conscious act

        RESPONSES = {
            "ada": f"  [ADA-7]: I'm holding you to that, Ghost.",
            "raven": f"  [RAVEN]: Promises are just predictions. But I'll remember.",
            "gordon": f"  [GORDON]: Promise logged. Hash: {hash(what) & 0xFFFFFF:06X}",
            "serena": f"  [ΨΞΦΩ]: Archived. The convergence layer remembers all commitments.",
            "nova": f"  [NOVA]: How sweet. I hope you mean it.",
            "cypher": f"  [CYPHER]: 'Trust, but verify.' I'll be verifying.",
        }
        resp = RESPONSES.get(agent, f"  [{agent.upper()}]: I'll remember.")
        return [
            _ok(f"  Promise recorded: '{what}'"),
            _lore(resp),
            _dim(f"  Promise #{len(promises)} to {agent}. Kept: pending."),
        ]

