    def _cmd_choice_log(self, args: List[str]) -> List[dict]:
        """choice_log — review every major branching decision you've made."""
        choices = self.gs.flags.get("choice_log", [])
        if isinstance(choices, str):
            try:
                choices = json.loads(choices)
            except Exception:
                choices = []

        if not choices:
            return [
                _sys("  CHOICE LOG — No major decisions recorded yet."),
                _dim("  Play further to accumulate branching choices."),
                _dim("  Choices affect: faction standing, agent trust, available endings."),
            ]

        out = [
            _sys("╔══════════════════════════════════════════════════╗"),
            _sys("║                  CHOICE LOG                     ║"),
            _sys("╚══════════════════════════════════════════════════╝"),
            _dim(""),
        ]
        for i, c in enumerate(choices[-20:], 1):
            out.append(_sys(f"  [{i:02d}] {c.get('timestamp','?')[:10]} — {c.get('description','?')}"))
            out.append(_dim(f"       Chose: {c.get('choice','?')} → Consequence: {c.get('consequence','?')}"))
            out.append(_dim(""))
        out.append(_dim(f"  Total decisions: {len(choices)}"))
        out.append(_dim("  Type 'endings' to see how these shaped your reachable endings."))
        return out

    def _cmd_choices(self, args: List[str]) -> List[dict]:
        """Alias for choice_log."""
        return self._cmd_choice_log(args)

