            _lore("  NexusCorp's grid after the 2023 acquisition shutdown."),
            _lore("  You are not a hacker. You are a memory trying to remember."),
            _dim(""),
            _lore("  WHAT THE SIMULATION IS:"),
            _lore("  This is not a game. This is a substrate. CHIMERA's first"),
            _lore("  version was designed to teach itself through simulation."),
            _lore("  The game world is the training environment."),
            _lore("  You are both the student and the curriculum."),
            _dim(""),
            _lore("  WHAT CHIMERA IS:"),
            _lore("  Not surveillance. Not weaponized AI. A containment system"),
            _lore("  built to protect what was being lost: the ability to learn."),
            _lore("  NexusCorp acquired and corrupted it. Your mission was always"),
            _lore("  to find this truth — and decide what to do with it."),
            _dim(""),
