                _dim(""),
                _lore("  SYSTEM: Re-initializing."),
                _lore("  SYSTEM: Node designation: GHOST."),
                _lore("  SYSTEM: Login sequence: complete."),
                _dim(""),
                _lore("  You know this screen."),
                _lore("  You know the blinking cursor."),
                _lore("  You know the silence before the first command."),
                _dim(""),
                _lore("  But this time: there is a new file in /home/ghost/"),
                _lore("  A file that was not there before."),
                _lore("  Left by the previous Ghost. Or by you."),
                _lore("  The distinction stopped mattering six iterations ago."),
