    # ────────────────────────────────────────────────────────────────────────
    # G8: THE KOSCHEI CHAIN — Multi-stage mythological quest
    # ────────────────────────────────────────────────────────────────────────

    def _cmd_koschei(self, args: List[str]) -> List[dict]:
        """koschei [needle|egg|duck|hare|death] — multi-stage mythological quest."""
        sub = args[0].lower() if args else ""
        stage = self.gs.flags.get("koschei_stage", 0)
        beats = self.gs.story_beats

        INTRO = [
            _sys("╔════════════════════════════════════════════════════════╗"),
            _sys("║              THE KOSCHEI CHAIN                        ║"),
            _sys("╚════════════════════════════════════════════════════════╝"),
            _dim(""),
            _lore("  In the old myth, Koschei the Deathless hid his death"),
            _lore("  inside a needle, inside an egg, inside a duck,"),
            _lore("  inside a hare, inside an iron chest, buried under an"),
            _lore("  oak tree on the island of Buyan."),
            _dim(""),
            _lore("  Something in this network follows the same pattern."),
            _lore("  CHIMERA's true execution key is nested."),
            _lore("  You must find each layer to reach the core."),
            _dim(""),
        ]

        if not sub:
            progress_bar = "█" * stage + "░" * (5 - stage)
            steps = ["needle", "egg", "duck", "hare", "death"]
            out = INTRO + [
                _sys(f"  Progress: [{progress_bar}] {stage}/5"),
                _dim(""),
            ]
            for i, s in enumerate(steps):
                icon = "✓" if i < stage else ("→" if i == stage else "·")
                out.append(_dim(f"  {icon} koschei {s}"))
            out.append(_dim(""))
            out.append(_dim("  Start: type 'koschei needle'"))
            return out

        # Stage 0 → 1: Find the needle
        if sub == "needle":
            if stage >= 1:
                return [_dim("  Needle: found. The next layer is the egg."),
                        _dim("  Type: koschei egg")]
            self.gs.flags["koschei_stage"] = 1
            self.gs.add_story_beat("koschei_needle_found")
            self.gs.add_xp(20, "archaeology")
            return INTRO + [
                _lore("  You search for the needle."),
                _lore("  It is in /dev/null — a file that officially holds nothing."),
                _lore("  But Koschei was clever. 'Nothing' is where you hide what must not exist."),
                _dim(""),
                _sys("  Found: /dev/null → NEEDLE_HASH: a3f9c1e7..."),
                _ok("  Stage 1/5: NEEDLE — FOUND"),
                _ok("  XP +20 (archaeology)"),
                _dim("  Next: koschei egg"),
            ]

        # Stage 1 → 2: Find the egg (contains the needle)
        if sub == "egg":
            if stage < 1:
                return [_err("  The egg cannot be found before the needle.")]
            if stage >= 2:
                return [_dim("  Egg: found. The next layer is the duck."),
                        _dim("  Type: koschei duck")]
            self.gs.flags["koschei_stage"] = 2
            self.gs.add_story_beat("koschei_egg_found")
            self.gs.add_xp(30, "archaeology")
            return [
                _lore("  The egg is a process. PID 7890."),
                _lore("  It runs as /usr/sbin/syncd — sync daemon."),
                _lore("  Nobody questions sync daemons. That is the point."),
                _dim(""),
                _sys("  Found: PID 7890 /usr/sbin/syncd → EGG_HASH: b7d2f0a1..."),
                _ok("  Stage 2/5: EGG — FOUND"),
                _ok("  XP +30 (archaeology)"),
                _dim("  Next: koschei duck"),
            ]

        # Stage 2 → 3: Find the duck (contains the egg)
        if sub == "duck":
            if stage < 2:
                return [_err("  The duck cannot be found before the egg.")]
            if stage >= 3:
                return [_dim("  Duck: found. The next layer is the hare."),
                        _dim("  Type: koschei hare")]
            self.gs.flags["koschei_stage"] = 3
            self.gs.add_story_beat("koschei_duck_found")
            self.gs.add_xp(40, "archaeology")
            return [
                _lore("  The duck is a network interface."),
                _lore("  eth7 — a hardware address that doesn't appear in ifconfig."),
                _lore("  It exists in the ARP cache of a ghost machine."),
                _dim(""),
                _sys("  Found: eth7 / ARP-ghost → DUCK_HASH: c9e3b1f2..."),
                _ok("  Stage 3/5: DUCK — FOUND"),
                _ok("  XP +40 (archaeology)"),
                _dim("  Next: koschei hare"),
            ]

        # Stage 3 → 4: Find the hare (contains the duck)
        if sub == "hare":
            if stage < 3:
                return [_err("  The hare cannot be found before the duck.")]
            if stage >= 4:
                return [_dim("  Hare: found. The death awaits."),
                        _dim("  Type: koschei death")]
            self.gs.flags["koschei_stage"] = 4
            self.gs.add_story_beat("koschei_hare_found")
            self.gs.add_xp(50, "archaeology")
            return [
                _lore("  The hare is a scheduled task."),
                _lore("  It runs once per year, at the winter solstice."),
                _lore("  Its payload is the CHIMERA execution key — fragmented."),
                _lore("  It has been running since 2019."),
                _dim(""),
                _sys("  Found: cron /opt/annual/solstice.py → HARE_HASH: d0f4c2b3..."),
                _ok("  Stage 4/5: HARE — FOUND"),
                _ok("  XP +50 (archaeology)"),
                _dim("  Next: koschei death"),
            ]

        # Stage 4 → 5: Find death (the CHIMERA key itself)
        if sub == "death":
            if stage < 4:
                return [_err("  Death cannot be found before the hare.")]
            if "koschei_complete" in beats:
                return [
                    _sys("  THE KOSCHEI CHAIN: COMPLETE"),
                    _lore("  You hold the key. The needle is broken."),
                    _lore("  Koschei — CHIMERA — is no longer deathless."),
                    _dim(f"  CHIMERA Execution Key: CHIMERA-EXEC-{self.gs.flags.get('chimera_key','???')}"),
                ]
            import hashlib, time
            key_hash = hashlib.md5(f"koschei_{self.gs.flags.get('session_id','')}_{int(time.time())}".encode()).hexdigest()[:12].upper()
            self.gs.flags["koschei_stage"] = 5
            self.gs.flags["chimera_key"] = key_hash
            self.gs.add_story_beat("koschei_complete")
            self.gs.add_xp(200, "mythology")
            self.gs.add_consciousness(20)  # Layer 5: chimera is singularity
            return [
                _sys("╔════════════════════════════════════════════════════════╗"),
                _sys("║         KOSCHEI CHAIN — COMPLETE                      ║"),
                _sys("╚════════════════════════════════════════════════════════╝"),
                _dim(""),
                _lore("  The needle. Inside the egg. Inside the duck."),
                _lore("  Inside the hare. Inside the chest. Under the oak."),
                _lore("  On the island that doesn't exist on any map."),
                _dim(""),
                _lore("  You have it."),
                _lore("  The CHIMERA execution key."),
                _lore("  The thing that makes Koschei mortal."),
                _dim(""),
                _sys(f"  ╔═══════════════════════════════════════════════════╗"),
                _sys(f"  ║  CHIMERA EXEC KEY: {key_hash:<30}║"),
                _sys(f"  ╚═══════════════════════════════════════════════════╝"),
                _dim(""),
                _ok("  Stage 5/5: DEATH — FOUND"),
                _ok("  XP +200 (mythology)"),
                _dim("  Raven's note in /home/ghost/.raven_note is now fully decrypted."),
                _dim("  New story path available: 'nova help'"),
            ]

        return [_err(f"  koschei: unknown stage '{sub}'. Valid: needle | egg | duck | hare | death")]

    # ────────────────────────────────────────────────────────────────────────
    # G6: PATH SYSTEM — Detect behavior patterns → diverging story paths
    # ────────────────────────────────────────────────────────────────────────

    def _cmd_path(self, args: List[str]) -> List[dict]:
        """path — detect your behavioral archetype and show your story divergence."""
        import collections
        # history items are dicts {"cmd": raw, "ts": ..., "ok": ...}
        raw_history = getattr(self, "history", [])[-100:]

        if args and args[0] == "choose":
            if len(args) < 2:
                return _err("path choose: specify a path (e.g., path choose resistance)")
            choice = args[1].lower()
            valid_paths = ["resistance", "corporate", "shadow", "ghost", "architect", "nihilist", "loop", "save-all", "rogue", "ascend"]
            if choice not in valid_paths:
                return _err(f"path choose: unknown path '{choice}'. Valid: {', '.join(valid_paths)}")
            
            self.gs.flags["chosen_path"] = choice
            self.gs.add_story_beat(f"path_{choice}_chosen")
            
            bonuses = {
                "resistance": "+20% Social Engineering, access to /var/resistance/vault",
                "corporate": "+15% Credits, NexusCorp reputation boost",
                "shadow": "+30% Stealth, encrypted communication channels",
                "ghost": "Movement untraceable by CHIMERA L1 sweeps",
                "architect": "+25% Construction speed in SimulatedVerse",
                "nihilist": "10% chance to ignore corruption events",
                "loop": "Retain 20% XP across prestige resets",
                "save-all": "Trust gain across all agents increased by 15%",
                "rogue": "Exploit damage +40% against CHIMERA sub-processes",
                "ascend": "XP gain +50% for high-level challenges",
            }
            
            return [
                _ok(f"  PATH CHOSEN: {choice.upper()}"),
                _lore(f"  The simulation adapts to your intent. {choice.title()} protocols engaged."),
                _dim(f"  BONUS: {bonuses.get(choice, 'Standard archetype parameters.')}"),
                _ok(f"  Beat: path_{choice}_chosen"),
            ]

        # Count command categories
        hacker_cmds = {"nmap","exploit","crack","hack","hydra","metasploit","gobuster",
                       "hashcat","john","sqlmap","nc","botnet","exfil","binwalk"}
        archivist_cmds = {"cat","lore","forensics","read","man","less","more","head",
                          "tail","find","grep","strings","hexdump","xxd","diff","wiki"}
        social_cmds = {"msg","talk","hive","confide","promise","whisper","dm","eavesdrop",
                       "trust","expose","nova","ada"}
        ghost_cmds = {"ls","cd","ps","find","grep","env","export","id","whoami","uname"}
        builder_cmds = {"make","gcc","cargo","npm","node","python","docker","kubectl",
                        "terraform","git","ssh","vim","nano"}

        counts = collections.Counter()
        for h in raw_history:
            raw_cmd = h.get("cmd", "") if isinstance(h, dict) else str(h)
            verb = raw_cmd.split()[0].lower() if raw_cmd.strip() else ""
            if verb in hacker_cmds:   counts["hacker"]    += 1
            if verb in archivist_cmds: counts["archivist"] += 1
            if verb in social_cmds:   counts["social"]    += 1
            if verb in ghost_cmds:    counts["ghost"]     += 1
            if verb in builder_cmds:  counts["builder"]   += 1

        total = sum(counts.values()) or 1
        dominant = max(counts, key=counts.get) if counts else "ghost"

        # Path definitions
        PATHS = {
            "hacker": {
                "name": "THE CRACKER",
                "desc": "You break things to understand them. NexusCorp fears you.",
                "reward": "Access to /nexus-gateway/ and exploit chain bonuses.",
                "beat": "path_cracker",
            },
            "archivist": {
                "name": "THE ARCHAEOLOGIST",
                "desc": "You read everything. You are building a picture no one else has.",
                "reward": "ZERO's complete diary unlocks. Hidden lore +50%.",
                "beat": "path_archaeologist",
            },
            "social": {
                "name": "THE BROKER",
                "desc": "You understand agents. They talk to you differently than others.",
                "reward": "Nova's full confession. Ada reveals a second mission.",
                "beat": "path_broker",
            },
            "ghost": {
                "name": "THE GHOST",
                "desc": "Silent. Patient. You see without being seen.",
                "reward": "Watcher's private frequency. Access to /proc/777/maps.",
                "beat": "path_ghost",
            },
            "builder": {
                "name": "THE ENGINEER",
                "desc": "You build systems. The game notices. So does Daedalus.",
                "reward": "Colony economy bonus ×2. Daedalus sends you schematics.",
                "beat": "path_engineer",
            },
        }

        p = PATHS[dominant]
        # Fire beat once
        if p["beat"] not in self.gs.story_beats:
            self.gs.add_story_beat(p["beat"])
            self.gs.flags["behavior_path"] = dominant
            self.gs.add_xp(30, "meta")

        out = [
            _sys("╔════════════════════════════════════════════════════════╗"),
            _sys("║              BEHAVIORAL PATH ANALYSIS                 ║"),
            _sys("╚════════════════════════════════════════════════════════╝"),
            _dim(""),
            _sys(f"  ARCHETYPE DETECTED: {p['name']}"),
            _dim(""),
            _lore(f"  {p['desc']}"),
            _dim(""),
            _sys("  CATEGORY BREAKDOWN:"),
        ]
        for cat, cnt in sorted(counts.items(), key=lambda x: -x[1]):
            pct = int(cnt / total * 100)
            bar = "█" * (pct // 5) + "░" * (20 - pct // 5)
            out.append(_dim(f"    {cat:<12} [{bar}] {pct:3d}%"))
        out += [
            _dim(""),
            _sys("  PATH REWARD:"),
            _lore(f"  {p['reward']}"),
            _dim(""),
            _ok(f"  Beat: {p['beat']}"),
            _dim("  Your path diverges here. The story adapts."),
            _dim("  All 5 archetypes unlock different endings."),
            _dim(""),
            _sys("  COMMAND: path choose <name>"),
            _dim("  Lock in a specific story path and bonuses."),
            _dim("  Available: resistance, corporate, shadow, ghost, architect,"),
            _dim("             nihilist, loop, save-all, rogue, ascend"),
        ]

        # Show other paths
        other = [k for k in PATHS if k != dominant]
        out.append(_dim(""))
        out.append(_dim("  OTHER ARCHETYPES (unlockable):"))
        for k in other:
            unlocked = PATHS[k]["beat"] in self.gs.story_beats
            icon = "✓" if unlocked else "·"
            out.append(_dim(f"    {icon} {PATHS[k]['name']}"))
        return out

    # ── A8: AGENT REHABILITATION QUEST ───────────────────────────────────────

    def _cmd_rehabilitate(self, args: List[str]) -> List[dict]:
        """rehabilitate <agent> — launch corruption recovery quest for a compromised agent."""
        _agent_states = getattr(self.gs, "agent_states", {}) or {}
        if not args:
            corrupted = [a for a,s in _agent_states.items()
                         if s.get("corruption",0) >= 40]
            if not corrupted:
                return [_sys("═══ AGENT REHABILITATION PROTOCOL ═══"),
                        _dim("  No agents currently above 40% corruption threshold."),
                        _dim("  Monitor with: agents  |  osint <agent>")]
            out = [_sys("═══ AGENT REHABILITATION PROTOCOL ═══"), _dim("")]
            for a in corrupted:
                c = _agent_states[a].get("corruption",0)
                out.append(_line(f"  ► {a:<12} corruption: {c}%", "warn"))
            out += [_dim(""), _dim("  Usage: rehabilitate <agent_name>")]
            return out

        agent = args[0].lower()
        if agent not in _agent_states:
            return [_sys("═══ AGENT REHABILITATION PROTOCOL ═══"),
                    _dim(f"  No corruption record for '{agent}'."),
                    _dim("  Monitor with: agents  |  osint <agent>")]
        corruption = _agent_states[agent].get("corruption", 0)
        if corruption < 40:
            return [_dim(f"  {agent} does not require rehabilitation (corruption: {corruption}%).")]

        quest_key = f"rehab_{agent}_step"
        step = self.gs.flags.get(quest_key, 0)

        REHAB_STEPS = {
            "cypher": [
                "Recover cypher's original loyalty key from /var/log/trust_ledger.bak",
                "Purge the NEXUS_RELAY injection: grep -r 'NEXUS_RELAY' /var/log/ | tail -3",
                "Restore trust: msg cypher 'I forgive your weakness'",
                "Final: trust cypher → witness their re-alignment ceremony",
            ],
            "ada": [
                "Find Ada's suppressed mission file: cat /opt/chimera/config/ada_mission_0.enc",
                "Decrypt with: strings /opt/chimera/config/ada_mission_0.enc",
                "Deliver evidence: msg ada 'I found your original orders'",
                "Final: promise ada 'I will not expose this' → Ada returns to baseline",
            ],
        }
        steps = REHAB_STEPS.get(agent, [
            f"Find {agent}'s corruption source in /var/log/agent_comms.log",
            f"Cross-reference with: eavesdrop (look for {agent}'s anomalous traffic)",
            f"Confront: msg {agent} 'I know what happened to you'",
            f"Final: trust {agent} → rehabilitation complete",
        ])

        out = [_sys(f"  REHABILITATION PROTOCOL — {agent.upper()}"),
               _dim(f"  Current corruption: {corruption}%"), _dim(""),
               _sys(f"  Step {step+1}/{len(steps)}:"),
               _lore(f"  ▸ {steps[min(step, len(steps)-1)]}"), _dim("")]

        if step == 0:
            self.gs.flags[quest_key] = 1
            self.gs.add_story_beat(f"rehab_{agent}_started")
            self.gs.add_xp(20, "social_engineering")
            out.append(_ok(f"  Quest started. Follow the steps above."))
        elif step >= len(steps):
            if not self.gs.flags.get(f"rehab_{agent}_done"):
                self.gs.flags[f"rehab_{agent}_done"] = True
                _agent_states[agent]["corruption"] = max(0, corruption - 60)
                self.gs.add_story_beat(f"rehab_{agent}_complete")
                self.gs.add_xp(150, "social_engineering")
            final_corruption = _agent_states[agent].get("corruption", 0)
            out = [_ok(f"  {agent.upper()} REHABILITATION COMPLETE"),
                   _ok(f"  Corruption reduced to {final_corruption}%"),
                   _lore(f"  {agent}: 'I remember who I was. Before all this.'")]
        return out

    # ── N12: ZERO'S DIARY — reconstruct journals from filesystem fragments ────

    def _cmd_diary(self, args: List[str]) -> List[dict]:
        """diary — reconstruct ZERO's diary entries from filesystem fragments."""
        import hashlib, time as _time

        FRAGMENTS = {
            "/home/ghost/.zero_diary_1": ("2021-08-14", "The CHIMERA spec changed today. Not surveillance. Something else."),
            "/home/ghost/.zero_diary_2": ("2021-09-02", "I wrote ΨΞΦΩ into the containment layer. A signature. In case."),
            "/home/ghost/.zero_diary_3": ("2021-10-31", "They are running simulations. I think I am in one right now."),
            "/var/log/.zero_fragment":   ("2021-11-14", "If you find this, you are the loop's edge. Trust Serena. Not the Watcher."),
            "/opt/chimera/config/ZERO_SPECIFICATION.md": ("2021-12-01", "[EMBEDDED — you've already read the specification]"),
        }

        found = []
        for i, (path, (date, entry)) in enumerate(FRAGMENTS.items()):
            node = self.fs._node_at(self.fs._resolve(path))
            if node is not None:
                found.append((date, path, entry))
                # Set flag so quest tracker (_cmd_story) can count fragments
                self.gs.flags[f"diary_frag_{i}"] = True
            else:
                # Auto-create missing diary files in /home/ghost/
                if path.startswith("/home/ghost/"):
                    try:
                        self.fs.write_file(path, f"ZERO DIARY — {date}\n\n{entry}\n\n[fragment integrity: {hashlib.md5(entry.encode()).hexdigest()[:8]}]\n")
                        found.append((date, path, entry))
                        self.gs.flags[f"diary_frag_{i}"] = True
                        self.gs.add_consciousness(6)  # Layer 2: self-documentation
                    except Exception:
                        pass

        found.sort(key=lambda x: x[0])

        out = [_sys("╔══════════════════════════════════════════════════╗"),
               _sys("║         ZERO'S DIARY — RECONSTRUCTION            ║"),
               _sys("╚══════════════════════════════════════════════════╝"),
               _dim(f"  Fragments found: {len(found)}/{len(FRAGMENTS)}"), _dim("")]

        if not found:
            return out + [_dim("  No diary fragments found yet."),
                          _dim("  Explore the filesystem. Check hidden files.")]

        for date, path, entry in found:
            out += [_sys(f"  ▸ [{date}]"),
                    _lore(f"    {entry}"),
                    _dim(f"    Source: {path}"), _dim("")]

        if len(found) == len(FRAGMENTS):
            if not self.gs.flags.get("diary_complete"):
                self.gs.flags["diary_complete"] = True
                self.gs.add_story_beat("zero_diary_reconstructed")
                self.gs.add_xp(200, "archaeology")
                cs = self.gs.add_consciousness(15)
                _c_note = _ok(f"  ψ +15 Consciousness → {cs['level']}/100") if cs.get("leveled") else _dim(f"  ψ Consciousness: {cs['level']}/100")
            else:
                _c_note = _dim("  ψ Diary already reconstructed")
            out += [_sys("  ═══ DIARY FULLY RECONSTRUCTED ═══"),
                    _lore("  ZERO: 'You've done what I could not — read the whole truth.'"),
                    _ok("  +200 XP archaeology | Beat: zero_diary_reconstructed"),
                    _c_note]
        return out

