        # ── Helper: inject a fragment's VFS file if missing ──────────────────
        def _ensure_vfs(frag: dict) -> None:
            path = frag["vfs_path"]
            try:
                node = self.fs._node_at(self.fs._resolve(path))
                if node is not None:
                    return
                parent = "/".join(path.split("/")[:-1])
                self.fs.mkdir(parent, parents=True)
                content_lines = [
                    f"ZERO ARCHIVE — FRAGMENT {frag['id']:02d}",
                    f"DATE: {frag['date']}",
                    f"TITLE: {frag['title']}",
                    "━" * 52,
                    "",
                ] + frag["text"] + [
                    "",
                    "━" * 52,
                    f"[integrity: {_hl.sha256(frag['title'].encode()).hexdigest()[:12]}]",
                ]
                self.fs.write_file(path, "\n".join(content_lines))
            except Exception:
                pass

        # ── Subcommand: status ────────────────────────────────────────────────
        if sub == "status":
            found = sum(1 for f in _FRAGS if gs.flags.get(f"flashback_frag_{f['id']}"))
