            if total_new_xp:
                out += [_ok(f"  +{total_new_xp} XP total (archaeology + consciousness)")]
            if not gs.flags.get("flashback_arc_complete"):
                gs.flags["flashback_arc_complete"] = True
                gs.add_story_beat("flashback_arc_complete")
                con = gs.add_consciousness(20)
                c_note = _ok(f"  ψ +20 Consciousness → {con['level']}/100") if con.get("leveled") \
                    else _dim(f"  ψ Consciousness: {con['level']}/100")
