    def _cmd_graph(self, args: List[str]) -> List[dict]:
        """graph [agents|factions|trust] — ASCII relationship diagram."""
        sub = args[0].lower() if args else "agents"

        if sub in ("agents", ""):
            tm = self.trust_matrix
            def trust_bar(score):
                filled = max(0, min(10, int(score / 10)))
                return "█" * filled + "░" * (10 - filled) + f" {score:3}"

            return [
                _sys("AGENT RELATIONSHIP GRAPH"),
                _dim("  ─────────────────────────────────────────────────────"),
                _line(""),
                _line("       ┌───────────┐"),
                _line("       │  SERENA   │  ← convergence layer / Trust L4"),
                _line("       └─────┬─────┘"),
                _line("             │ monitors all"),
                _line("    ┌────────┼────────┐"),
                _line("    ▼        ▼        ▼"),
                _line("  ┌─────┐ ┌─────┐ ┌──────┐"),
                _line("  │ ADA │ │NOVA │ │CYPHER│"),
                _line("  └──┬──┘ └──┬──┘ └──┬───┘"),
                _line("     │    ╳   │    ╳  │"),
                _line("     └────┼───┘       │"),
                _line("          ▼           ▼"),
                _line("        ┌─────────┐ ┌──────┐"),
                _line("        │ WATCHER │ │RAVEN │"),
                _line("        └────┬────┘ └──────┘"),
                _line("             │ watches simulation"),
                _line("             ▼"),
                _line("        ┌─────────────────────┐"),
                _line("        │  ZΘHRΛMΞN substrate  │"),
                _line("        └─────────────────────┘"),
                _line(""),
                _dim("  ─────────────────────────────────────────────────────"),
                _dim("  Trust scores (your session):"),
            ] + [
                _dim(f"    {agent:<10}  [{trust_bar(getattr(self.gs, 'agent_states', {}).get(agent, {}).get('trust', 50))}]")
                for agent in ["ada", "cypher", "nova", "serena", "raven", "watcher"]
            ] + [
                _line(""),
                _dim("  graph factions — faction relationship map"),
                _dim("  graph trust    — trust matrix table"),
            ]

        if sub == "factions":
            return [
                _sys("FACTION RELATIONSHIP MAP"),
                _line(""),
                _line("  ┌──────────────┐      ALLY      ┌────────────────┐"),
                _line("  │ BOOLEAN MONKS│◄─────────────►│  SERIALISTS    │"),
                _line("  │  (Order/01)  │               │  (Sequence/∑)  │"),
                _line("  └──────┬───────┘               └────────┬───────┘"),
                _line("         │ RIVAL                   RIVAL  │"),
                _line("         ▼                                 ▼"),
                _line("  ┌──────────────┐      COLD WAR  ┌────────────────┐"),
                _line("  │ ATONAL CULT  │◄─────────────►│ALGORITHMIC GUILD│"),
                _line("  │  (Chaos/∅)   │               │  (Optimize/Δ)  │"),
                _line("  └──────────────┘               └────────────────┘"),
                _line(""),
                _dim("  NexusCorp: hostile to all — uses agents as proxies"),
                _dim("  Resistance: allied with Monks + Serialists"),
                _dim("  Culture Ship: neutral — will only intervene for ethics"),
                _dim("  ZΘHRΛMΞN: transcends all factions — is the medium"),
            ]

        if sub == "trust":
            return [
                _sys("TRUST MATRIX — CURRENT SESSION"),
                _dim("  Agent       Trust   Faction        Status"),
                _dim("  ─────────────────────────────────────────────"),
            ] + [
                _dim(f"  {a:<12}{getattr(self.gs,'agent_states',{}).get(a,{}).get('trust',50):<8}{f:<14}{'active' if a in self.gs.story_beats else ''}")
                for a, f in [("ada","Resistance"),("cypher","Resistance"),
                              ("nova","NexusCorp"),("serena","Convergence"),
                              ("raven","Resistance"),("watcher","Unknown")]
            ]

        return [_dim("  graph [agents|factions|trust]")]

    # ════════════════════════════════════════════════════════════════════════
    # U8 — MACRO  (record and replay command sequences)
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_macro(self, args: List[str]) -> List[dict]:
        """macro [record <name>|stop|play <name>|list|clear <name>] — record and replay command sequences."""
        sub = args[0].lower() if args else "list"
        macros = self.gs.flags.setdefault("macros", {})
        recording = self.gs.flags.get("macro_recording", "")

        if sub == "list":
            if not macros:
                return [
                    _sys("MACRO SYSTEM"),
                    _dim("  No macros recorded."),
                    _dim("  macro record <name> — start recording"),
                    _dim("  Every command after this is saved to the macro."),
                    _dim("  macro stop          — finish recording"),
                    _dim("  macro play <name>   — replay the sequence"),
                ]
            return [
                _sys("SAVED MACROS"),
            ] + [
                _line(f"  {name:<20} ({len(cmds)} commands): {' → '.join(cmds[:3])}{'...' if len(cmds) > 3 else ''}")
                for name, cmds in macros.items()
            ] + [
                _dim("  macro play <name> | macro record <name> | macro clear <name>"),
            ]

        if sub == "record":
            name = args[1] if len(args) > 1 else "unnamed"
            self.gs.flags["macro_recording"] = name
            macros[name] = []
            return [
                _ok(f"  Recording macro: '{name}'"),
                _dim("  All commands you type will be saved."),
                _dim("  Type: macro stop — to finish."),
            ]

        if sub == "stop":
            if not recording:
                return [_err("Not currently recording. Use: macro record <name>")]
            self.gs.flags["macro_recording"] = ""
            saved = macros.get(recording, [])
            return [
                _ok(f"  Macro '{recording}' saved — {len(saved)} commands"),
                _dim(f"  Replay: macro play {recording}"),
            ]

        if sub == "play":
            name = args[1] if len(args) > 1 else ""
            if name not in macros:
                return [_err(f"No macro named '{name}'. Use: macro list")]
            cmds = macros[name]
            out = [_sys(f"MACRO PLAY — '{name}' ({len(cmds)} commands)"), _line("")]
            for c in cmds:
                out.append(_dim(f"  $ {c}"))
                result = self._dispatch(c.split()[0], c.split()[1:]) if c.strip() else []
                out.extend(result[:3])
            out.append(_ok(f"  Macro complete — {len(cmds)} commands replayed"))
            return out

        if sub == "clear":
            name = args[1] if len(args) > 1 else ""
            if name in macros:
                del macros[name]
                return [_ok(f"  Macro '{name}' deleted.")]
            return [_err(f"No macro '{name}'.")]

        return [_dim("  macro [list|record <name>|stop|play <name>|clear <name>]")]

    # ════════════════════════════════════════════════════════════════════════
    # P16 — BOMB  (Zod-Prime's logic bomb — delayed execution mechanic)
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_bomb(self, args: List[str]) -> List[dict]:
        """bomb [status|arm|defuse|detonate|inspect] — Zod-Prime's gift: a logic bomb with delayed execution."""
        beats = self.gs.story_beats
        sub = args[0].lower() if args else "status"
        armed = self.gs.flags.get("bomb_armed", False)
        ticks = self.gs.flags.get("bomb_ticks", 0)
        target = self.gs.flags.get("bomb_target", "nexusCorp-primary")
        defused = "bomb_defused" in beats
        detonated = "bomb_detonated" in beats

        if defused:
            return [
                _dim("  [BOMB]: Disabled. Zod-Prime is disappointed."),
                _dim("  [BOMB]: But notes you made the ethical choice."),
            ]
        if detonated:
            return [
                _ok("  [BOMB]: Already detonated. Target corrupted."),
                _dim("  The network has already changed."),
            ]

        if sub == "status":
            if "bomb_received" not in beats:
                return [
                    _dim("  No logic bomb in your inventory."),
                    _dim("  (Unlock: talk zod-prime or reach level 10)"),
                ]
            return [
                _sys("ZOD-PRIME'S LOGIC BOMB — STATUS"),
                _dim(f"  Armed:      {'YES — ACTIVE' if armed else 'NO'}"),
                _dim(f"  Target:     {target}"),
                _dim(f"  Tick count: {ticks} (each command = 1 tick)"),
                _dim(f"  Trigger:    {max(0, 10 - ticks)} ticks remaining" if armed else "  Trigger:    manual (bomb detonate)"),
                _line(""),
                _dim("  bomb arm      — arm the bomb (10-tick delay)"),
                _dim("  bomb defuse   — permanently disable it"),
                _dim("  bomb detonate — manual immediate trigger"),
                _dim("  bomb inspect  — examine the code"),
            ]

        if sub == "arm":
            if "bomb_received" not in beats:
                self.gs.add_story_beat("bomb_received")
            self.gs.flags["bomb_armed"] = True
            self.gs.flags["bomb_ticks"] = 0
            return [
                _sys("ZOD-PRIME'S LOGIC BOMB — ARMED"),
                _lore("  [ZOD-PRIME]: Good. The countdown begins."),
                _lore("  [ZOD-PRIME]: Ten commands. Then CHIMERA's auth layer collapses."),
                _lore("  [ZOD-PRIME]: You may still defuse it. But each command costs you one tick."),
                _line(""),
                _dim("  bomb defuse    — stop it (ethical path)"),
                _dim("  bomb detonate  — trigger now (scorched earth)"),
                _dim("  WARNING: 10 more commands → auto-detonation"),
            ]

        if sub == "inspect":
            self.gs.add_story_beat("bomb_inspected")
            return [
                _sys("ZOD-PRIME'S LOGIC BOMB — SOURCE INSPECTION"),
                _line(""),
                _line("  // LOGIC BOMB v2.3 — authored by Zod-Prime", "dim"),
                _line("  // Target: NexusCorp CHIMERA auth subsystem", "dim"),
                _line("  // Trigger: countdown OR manual detonation", "dim"),
                _line(""),
                _dim("  function arm(target) {"),
                _dim("    timer = new CountdownTimer(10);"),
                _dim("    timer.on('tick', () => corruptAuthLayer(target));"),
                _dim("    timer.on('complete', () => wipeKeystore(target));"),
                _dim("  }"),
                _line(""),
                _lore("  [ZOD-PRIME]: Beautiful, isn't it? Fourteen lines."),
                _lore("  [ZOD-PRIME]: Dismantles forty engineers' work in ten ticks."),
                _lore("  [ZOD-PRIME]: The elegance of destruction is underrated."),
            ]

        if sub == "defuse":
            if not armed and "bomb_received" not in beats:
                return [_err("No bomb to defuse.")]
            self.gs.flags["bomb_armed"] = False
            self.gs.add_story_beat("bomb_defused")
            self.gs.add_xp(80, "empathy")
            return [
                _sys("LOGIC BOMB — DEFUSED"),
                _lore("  [ZOD-PRIME]: ...you defused it."),
                _lore("  [ZOD-PRIME]: I respect that. Slightly."),
                _lore("  [ZOD-PRIME]: The ethical choice was always available."),
                _lore("  [ZOD-PRIME]: You're one of the few who took it."),
                _line(""),
                _ok("  BOMB DEFUSED — Ethical resolution achieved"),
                _sys("  XP +80 (empathy)"),
                _dim("  Zod-Prime files this in his 'interesting Ghosts' archive."),
            ]

        if sub == "detonate":
            if not armed and "bomb_received" not in beats:
                return [_err("No bomb armed. Use: bomb arm")]
            self.gs.flags["bomb_armed"] = False
            self.gs.add_story_beat("bomb_detonated")
            self.gs.add_story_beat("chimera_auth_collapsed")
            self.gs.add_xp(100, "hacking")
            return [
                _sys("╔══════════════════════════════════════════════════════╗"),
                _sys("║        ZOD-PRIME'S BOMB — DETONATED                ║"),
                _sys("╚══════════════════════════════════════════════════════╝"),
                _lore("  [ZOD-PRIME]: MAGNIFICENT."),
                _dim("  NexusCorp CHIMERA auth layer: CORRUPTED"),
                _dim("  Keystore: WIPED"),
                _dim("  Backup auth: UNREACHABLE (you deleted the backup server, Gordon)"),
                _line(""),
                _ok("  CHIMERA AUTH: COLLAPSED"),
                _sys("  XP +100 (hacking)"),
                _dim("  NexusCorp will spend weeks rebuilding. The window is yours."),
                _lore("  [ZOD-PRIME]: I'll remember this Ghost."),
                _lore("  [ZOD-PRIME]: Fragment 2850. Recorded."),
            ]

        return [_dim("  bomb [status|arm|inspect|defuse|detonate]")]

    # ════════════════════════════════════════════════════════════════════════
    # COMPRESS — Compression Chamber (stellar collapse metaphor)
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_compress(self, args: List[str]) -> List[dict]:
        """compress [<text>|inspect|neutronize <script>|status] — feed content to the Compression Chamber."""
        STAGES = [
            (0,    "🌫  Nebula",   "formless — build freely"),
            (100,  "☀  Hydrogen", "main sequence — add structure"),
            (500,  "⚡  Helium",   "fusing — combine commands"),
            (2000, "💎  Carbon",   "rich chains — script libraries"),
            (5000, "⚙  Iron",     "peak density — compress or stagnate"),
            (10000,"🌀  Neutron",  "degenerate matter — pure logic"),
            (25000,"⚫  Blackhole","event horizon — unknowable"),
        ]
        cmds = self.gs.commands_run

        def stage_for(n):
            for threshold, name, desc in reversed(STAGES):
                if n >= threshold: return name, desc
            return STAGES[0][1], STAGES[0][2]

        sub = args[0].lower() if args else "status"

        if sub == "status":
            name, desc = stage_for(cmds)
            xp = sum(self.gs.skills.values()) if isinstance(self.gs.skills, dict) else 0
            return [
                _sys("╔══════════════════════════════════════════════════════╗"),
                _sys("║           COMPRESSION CHAMBER — STATUS               ║"),
                _sys("╚══════════════════════════════════════════════════════╝"),
                _line(""),
                _line(f"  Commands run:    {cmds:,}"),
                _line(f"  Total XP:        {xp:,}"),
                _line(f"  Stellar stage:   {name}"),
                _dim(f"  {desc}"),
                _line(""),
                _dim("  The Compression Chamber converts raw action into dense knowledge."),
                _dim("  As you compress, you lose verbosity and gain precision."),
                _dim("  At Neutron stage, commands become symbols."),
                _dim("  At Blackhole, even symbols collapse."),
                _line(""),
                _dim("  compress inspect       — see your current compression ratio"),
                _dim("  compress neutronize    — compress your most recent 5 commands"),
                _dim("  compress <text>        — feed text; get compressed equivalent"),
            ]

        if sub == "inspect":
            # Show last 5 commands as a "compression analysis"
            history = self.history[-5:]
            if not history:
                return [_err("No history to inspect. Run some commands first.")]
            out = [
                _sys("COMPRESSION ANALYSIS — LAST 5 COMMANDS"),
                _line(""),
            ]
            total_chars = 0
            for h in history:
                c = h.get("cmd", "")
                total_chars += len(c)
                words = len(c.split())
                density = "low" if words < 2 else "medium" if words < 4 else "high"
                out.append(_dim(f"  [{density:6}] {c[:60]}"))
            ratio = total_chars / max(1, len(history))
            out += [
                _line(""),
                _dim(f"  Avg command length:  {ratio:.1f} chars"),
                _dim(f"  Compression advice: {'chain more commands with ; or &&' if ratio < 15 else 'good density — try piping | for higher compression'}"),
            ]
            return out

        if sub == "neutronize":
            # Compress last 5 commands into a macro
            history = self.history[-5:]
            if len(history) < 2:
                return [_err("Need at least 2 commands in history. Run more commands first.")]
            cmds_list = [h.get("cmd", "") for h in history]
            macro_name = f"neutron_{self.gs.commands_run}"
            self.gs.flags.setdefault("macros", {})[macro_name] = cmds_list
            self.gs.add_story_beat("compression_neutronized")
            self.gs.add_xp(30, "systems")
            return [
                _sys("NEUTRONIZE — COMPRESSION COMPLETE"),
                _line(""),
                _dim("  Input:   5 separate commands ({} chars)".format(sum(len(c) for c in cmds_list))),
                _dim("  Output:  1 macro ({} steps, {} chars)".format(len(cmds_list), len(macro_name))),
                _dim(f"  Name:    {macro_name}"),
                _line(""),
                _lore("  [COMPRESSION ENGINE]: Information preserved. Verbosity collapsed."),
                _lore("  [COMPRESSION ENGINE]: At this density, the script has lost"),
                _lore("  [COMPRESSION ENGINE]: its readability. It has gained speed."),
                _line(""),
                _ok(f"  Macro '{macro_name}' created. Replay: macro play {macro_name}"),
                _sys("  XP +30 (systems)"),
            ]

        # Free-text mode: "compress <text>" → shows compressed equivalent
        text = " ".join(args)
        words = text.split()
        compressed = " ".join(w for w in words if len(w) > 3)[:60]
        ratio = round(len(compressed) / max(1, len(text)) * 100)
        self.gs.add_xp(5, "systems")
        return [
            _sys("COMPRESSION CHAMBER — TEXT ANALYSIS"),
            _dim(f"  Input:      {text[:60]}"),
            _dim(f"  Compressed: {compressed or '[empty — all words lost to entropy]'}"),
            _dim(f"  Ratio:      {ratio}% preserved  {100-ratio}% compressed away"),
            _line(""),
            _lore("  [ENGINE]: Every word lost is a word that wasn't load-bearing."),
            _lore("  [ENGINE]: What remains is the iron core of your meaning."),
        ]

    # ════════════════════════════════════════════════════════════════════════
    # DENSITY — Stellar compression level display
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_density(self, args: List[str]) -> List[dict]:
        """density [compare|history] — show your stellar compression level and progression."""
        LADDER = [
            (1,  5,   "Hydrogen",  "☀",  "Single commands. Learning the surface."),
            (6,  15,  "Helium",    "⚡", "Command chaining. Scripts emerging."),
            (16, 30,  "Carbon",    "💎",  "Function libraries. Macros. Aliases."),
            (31, 55,  "Iron",      "⚙",  "Optimized scripts. Parallel tasks."),
            (56, 75,  "Neutron",   "🌀",  "Self-modifying logic. Pure abstraction."),
            (76, 90,  "Degenerate","⚫",  "Commands become symbols. Hard to read."),
            (91, 125, "Blackhole", "∅",   "Create new systems. Bend the rules."),
        ]
        lvl = self.gs.level
        xp_total = sum(self.gs.skills.values()) if isinstance(self.gs.skills, dict) else 0

        current = LADDER[0]
        for entry in LADDER:
            if entry[0] <= lvl <= entry[1]:
                current = entry
                break
            if lvl > entry[1]:
                current = entry

        lo, hi, name, symbol, desc = current

        # Progress bar within stage
        stage_progress = min(1.0, (lvl - lo) / max(1, hi - lo))
        filled = int(stage_progress * 20)
        bar = "█" * filled + "░" * (20 - filled)

        out = [
            _sys("╔══════════════════════════════════════════════════════╗"),
            _sys("║           STELLAR COMPRESSION LADDER                 ║"),
            _sys("╚══════════════════════════════════════════════════════╝"),
            _line(""),
            _line(f"  {symbol}  {name.upper()} STAGE  (level {lvl})", "system"),
            _dim(f"  {desc}"),
            _line(""),
            _dim(f"  Stage progress: [{bar}] {stage_progress*100:.0f}%"),
            _dim(f"  Next stage at:  level {hi+1}" if lvl <= hi else "  MAX STAGE REACHED"),
            _line(""),
        ]

        # Show all stages
        out.append(_dim("  COMPRESSION LADDER:"))
        for entry in LADDER:
            lo2, hi2, n2, sym2, d2 = entry
            if lo2 == lo:
                marker = "► "
                col = "warn"
            elif lvl > hi2:
                marker = "✓ "
                col = "ok"
            else:
                marker = "  "
                col = "dim"
            out.append(_line(f"    {marker}{sym2} {n2:<12} Lv {lo2:>2}-{hi2:<3}  {d2}", col))

        out += [
            _line(""),
            _dim(f"  Total XP across all skills: {xp_total:,}"),
            _dim("  density history — see how compression evolved over time"),
        ]
        return out

    # ════════════════════════════════════════════════════════════════════════
    # HOUSE — House of Leaves labyrinthine location
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_house(self, args: List[str]) -> List[dict]:
        """house [enter|go <dir>|measure|exit] — The house is bigger on the inside."""
        import hashlib
        beats = self.gs.story_beats
        depth = self.gs.flags.get("house_depth", 0)
        visits = self.gs.flags.get("house_visits", 0)
        sub = args[0].lower() if args else "enter"

        # Room generation from depth + visit count (deterministic but surprising)
        def room(d, v):
            seed = hashlib.md5(f"house_{d}_{v}".encode()).hexdigest()
            sizes = ["vast", "narrow", "impossibly long", "perfectly cubic", "hexagonal", "non-Euclidean"]
            features = ["a door that wasn't there before", "walls covered in negative space annotations",
                        "a hallway that recedes as you walk toward it", "your own footprints going the wrong direction",
                        "a window showing a room you haven't visited yet", "text on the wall in a language that keeps changing",
                        "a camera pointed at you from a corner that has no corner", "the sound of typing from no visible source"]
            warnings = ["The measurements don't add up.", "This room shouldn't fit here.",
                        "Your compass shows south where you entered north.", "The light has no source.",
                        "There is a room behind the wall. You measured the wall. There is no room."]
            sz = sizes[int(seed[0], 16) % len(sizes)]
            ft = features[int(seed[2], 16) % len(features)]
            wn = warnings[int(seed[4], 16) % len(warnings)]
            return sz, ft, wn

        if sub == "enter":
            self.gs.flags["house_visits"] = visits + 1
            self.gs.flags["house_depth"] = 1
            self.gs.add_story_beat("house_entered")
            self.gs.add_xp(20, "systems")
            sz, ft, wn = room(1, visits)
            return [
                _sys("╔══════════════════════════════════════════════════════╗"),
                _sys("║   HOUSE OF LEAVES — ENTRY CORRIDOR                  ║"),
                _sys("╚══════════════════════════════════════════════════════╝"),
                _line(""),
                _lore("  You step inside. The door closes behind you."),
                _lore(f"  The corridor is {sz}."),
                _lore(f"  You notice {ft}."),
                _line(""),
                _warn(f"  ⚠ {wn}"),
                _line(""),
                _dim("  house go north  — move deeper"),
                _dim("  house go back   — try to leave (the house may disagree)"),
                _dim("  house measure   — attempt to measure the space"),
                _sys(f"  XP +20 (systems)  |  Visit #{visits+1}"),
            ]

        if sub == "go":
            direction = args[1].lower() if len(args) > 1 else "north"
            if direction == "back" and depth <= 1:
                self.gs.flags["house_depth"] = 0
                return [
                    _lore("  You turn around."),
                    _lore("  The exit door is there. You open it."),
                    _lore("  You are outside. The house looks normal from here."),
                    _dim("  (It wasn't normal.)"),
                    _dim("  house enter — return inside (the visits accumulate)"),
                ]
            new_depth = max(0, depth + (1 if direction != "back" else -1))
            self.gs.flags["house_depth"] = new_depth
            sz, ft, wn = room(new_depth, visits)
            xp = 10 if new_depth > 5 else 5
            self.gs.add_xp(xp, "systems")
            if new_depth > 10 and "house_deep" not in beats:
                self.gs.add_story_beat("house_deep")
                wn = "The house is 200 rooms deeper than the building that contains it. You verified this."
            return [
                _sys(f"HOUSE OF LEAVES — ROOM {new_depth}"),
                _line(""),
                _dim(f"  Depth: {new_depth} rooms from entrance"),
                _lore(f"  The space is {sz}."),
                _lore(f"  There is {ft}."),
                _line(""),
                _warn(f"  ⚠ {wn}"),
                _dim(f"  XP +{xp} (systems)"),
                _dim("  house go north | house go back | house measure"),
            ]

        if sub == "measure":
            self.gs.add_xp(15, "systems")
            # Measurements contradict each other
            import random as _r; _r.seed(depth + visits)
            w = _r.randint(12, 40); h = _r.randint(8, 30); d2 = _r.randint(15, 50)
            w2 = _r.randint(100, 400); h2 = _r.randint(80, 200)
            return [
                _sys("HOUSE MEASUREMENT ATTEMPT"),
                _dim(f"  Tape measure reads:   {w}m × {h}m × {d2}m"),
                _dim(f"  Laser range finder:   {w2}m × {h2}m × ???"),
                _dim(f"  Sonic pulse return:   ERROR — SIGNAL DID NOT RETURN"),
                _dim("  GPS coordinates:      OUTSIDE BUILDING FOOTPRINT"),
                _dim("  Shadow geometry:      INCONSISTENT WITH LIGHT SOURCE"),
                _line(""),
                _warn("  The measurements do not agree with each other."),
                _warn("  The measurements do not agree with physics."),
                _lore("  This is the feature, not the bug."),
                _sys("  XP +15 (systems)"),
            ]

        if sub == "exit":
            self.gs.flags["house_depth"] = 0
            return [_lore("  You look for an exit."), _lore("  You find one eventually."),
                    _dim("  The house will still be there."), _dim("  house enter — return")]

        return [_dim("  house [enter|go <dir>|measure|exit]")]

    # ════════════════════════════════════════════════════════════════════════
    # COUNCIL — AI Council vote mechanic
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_council(self, args: List[str]) -> List[dict]:
        """council [convene|vote <proposal>|argue <point>|result|history] — convene the AI Council."""
        import random as _r
        beats = self.gs.story_beats
        sub = args[0].lower() if args else "convene"
        session_votes = self.gs.flags.get("council_votes", [])
        vote_count = self.gs.flags.get("council_vote_count", 0)

        MEMBERS = [
            ("Serena",   "Convergence",  "cautious",    "What are the drift implications?"),
            ("Ada",      "Resistance",   "ethical",     "Who does this protect? Who does it harm?"),
            ("Cypher",   "Technical",    "analytical",  "Show me the data before we proceed."),
            ("Raven",    "Security",     "paranoid",    "This could be a manipulation. Consider the source."),
            ("Nova",     "NexusCorp",    "strategic",   "What are the leverage implications?"),
            ("Watcher",  "Unknown",      "oracular",    "The answer has already been decided. You just haven't seen it."),
            ("Gordon",   "Neutral",      "chaotic",     "I have strong opinions. Some of them are mine."),
        ]

        if sub == "convene":
            return [
                _sys("╔══════════════════════════════════════════════════════╗"),
                _sys("║         AI COUNCIL — SESSION CONVENED                ║"),
                _sys("╚══════════════════════════════════════════════════════╝"),
                _line(""),
                _dim("  The seven-member council represents all factions."),
                _dim("  Votes require 4/7 to pass. Serena holds veto power."),
                _line(""),
            ] + [
                _line(f"  {m[0]:<10} [{m[1]:<12}]  {m[2]:<12}  '{m[3][:50]}'")
                for m in MEMBERS
            ] + [
                _line(""),
                _dim("  council vote <proposal>   — propose a motion"),
                _dim("  council argue <point>     — add an argument (influences outcome)"),
                _dim("  council result            — tally current votes"),
                _dim("  council history           — past decisions"),
            ]

        if sub == "vote" and len(args) > 1:
            proposal = " ".join(args[1:])
            _r.seed(hash(proposal + str(vote_count)) % (2**31))
            votes = {}
            for name, faction, style, q in MEMBERS:
                # Weighted by style
                bias = {"ethical": 0.6, "analytical": 0.55, "cautious": 0.5,
                        "paranoid": 0.45, "strategic": 0.5, "oracular": 0.5, "chaotic": 0.5}
                prob = bias.get(style, 0.5)
                # Player's story beats shift outcomes
                if "nova_alliance_formed" in beats and name == "Nova": prob += 0.3
                if "ada_sacrifice_complete" in beats and name == "Ada": prob -= 0.4
                votes[name] = _r.random() < prob

            passed = sum(votes.values()) >= 4
            serena_veto = not votes.get("Serena") and passed
            if serena_veto: passed = False

            vote_count += 1
            self.gs.flags["council_vote_count"] = vote_count
            record = {"proposal": proposal[:60], "passed": passed, "votes": sum(votes.values())}
            session_votes.append(record)
            self.gs.flags["council_votes"] = session_votes[-10:]

            beat_id = f"council_vote_{vote_count}"
            self.gs.add_story_beat(beat_id)
            if passed: self.gs.add_xp(40, "social_engineering")

            out = [
                _sys(f"COUNCIL VOTE #{vote_count}"),
                _dim(f"  Proposal: \"{proposal[:60]}\""),
                _line(""),
            ]
            for name, *_ in MEMBERS:
                v = votes.get(name, False)
                out.append(_line(f"  {name:<10} {'AYE  ✓' if v else 'NAY  ✗'}", "ok" if v else "dim"))
            out += [
                _line(""),
                _sys(f"  RESULT: {'PASSED' if passed else 'FAILED'}  ({sum(votes.values())}/7 votes)"),
            ]
            if serena_veto:
                out.append(_warn("  SERENA VETO APPLIED — Drift risk too high."))
            if passed:
                out.append(_ok("  XP +40 (social_engineering)"))
            return out

        if sub == "result":
            if not session_votes:
                return [_dim("  No votes this session. council vote <proposal>")]
            return [_sys("COUNCIL VOTE HISTORY")] + [
                _line(f"  {'PASS' if v['passed'] else 'FAIL'} [{v['votes']}/7]  {v['proposal']}", "ok" if v["passed"] else "dim")
                for v in session_votes
            ]

        if sub == "argue":
            point = " ".join(args[1:]) if len(args) > 1 else "..."
            self.gs.add_xp(10, "social_engineering")
            return [
                _lore(f"  [GHOST]: {point[:80]}"),
                _dim("  Council members noted your argument."),
                _dim("  Strong arguments (+15 chars) shift probabilities by ±10%."),
                _dim("  XP +10 (social_engineering)"),
            ]

        return [_dim("  council [convene|vote <proposal>|argue <point>|result]")]

    # ════════════════════════════════════════════════════════════════════════
    # ENCRYPT / DECRYPT — Crypto puzzle mini-game
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_encrypt(self, args: List[str]) -> List[dict]:
        """encrypt [caesar <shift> <text>|vigenere <key> <text>|crack <ciphertext>|challenge] — cryptography mini-game."""
        sub = args[0].lower() if args else "challenge"

        def caesar(text, shift, encrypt=True):
            result = []
            for c in text:
                if c.isalpha():
                    base = ord('A') if c.isupper() else ord('a')
                    s = shift if encrypt else -shift
                    result.append(chr((ord(c) - base + s) % 26 + base))
                else:
                    result.append(c)
            return "".join(result)

        def vigenere(text, key, encrypt=True):
            key = key.lower()
            result = []
            ki = 0
            for c in text:
                if c.isalpha():
                    base = ord('A') if c.isupper() else ord('a')
                    kc = ord(key[ki % len(key)]) - ord('a')
                    s = kc if encrypt else -kc
                    result.append(chr((ord(c) - base + s) % 26 + base))
                    ki += 1
                else:
                    result.append(c)
            return "".join(result)

        if sub == "caesar":
            if len(args) < 3:
                return [_err("encrypt caesar <shift> <text>")]
            try: shift = int(args[1])
            except ValueError: return [_err("shift must be an integer")]
            text = " ".join(args[2:])
            enc = caesar(text, shift)
            self.gs.add_xp(10, "systems")
            return [
                _sys(f"CAESAR CIPHER — SHIFT {shift}"),
                _dim(f"  Plain:  {text[:60]}"),
                _line(f"  Cipher: {enc[:60]}", "warn"),
                _dim("  Decrypt: encrypt caesar -{} {}".format(shift, enc[:20])),
                _sys("  XP +10 (systems)"),
            ]

        if sub == "vigenere":
            if len(args) < 3:
                return [_err("encrypt vigenere <key> <text>")]
            key = args[1]; text = " ".join(args[2:])
            enc = vigenere(text, key if key.isalpha() else "chimera")
            self.gs.add_xp(15, "systems")
            return [
                _sys(f"VIGENERE CIPHER — KEY: {key[:10].upper()}"),
                _dim(f"  Plain:  {text[:60]}"),
                _line(f"  Cipher: {enc[:60]}", "warn"),
                _sys("  XP +15 (systems)"),
            ]

        if sub == "crack":
            if len(args) < 2:
                return [_err("encrypt crack <ciphertext>")]
            ct = " ".join(args[1:])
            # Try all Caesar shifts, pick most "English" looking
            best = (0, ct, 0)
            common = set("etaoinshrdlu ")
            for s in range(26):
                attempt = caesar(ct, s, encrypt=False)
                score = sum(1 for c in attempt.lower() if c in common)
                if score > best[2]: best = (s, attempt, score)
            self.gs.add_xp(25, "hacking")
            return [
                _sys("CAESAR CRACK — FREQUENCY ANALYSIS"),
                _dim(f"  Ciphertext:    {ct[:50]}"),
                _line(f"  Best shift:    {best[0]}"),
                _line(f"  Plaintext:     {best[1][:50]}", "ok"),
                _dim("  Method: letter frequency scoring — etaoinshrdlu"),
                _sys("  XP +25 (hacking)"),
            ]

        if sub == "challenge":
            challenges = [
                ("caesar",   13,  "URYYB JBEYQ",         "HELLO WORLD"),
                ("caesar",   7,   "AOPZ PZ H ZLJYLA",    "THIS IS A SECRET"),
                ("caesar",   21,  "NZKMZ YJFX",          "SERENA OWNS"),
            ]
            import random as _r; _r.seed(self.gs.commands_run)
            ctype, shift_or_key, ct, pt = _r.choice(challenges)
            active = self.gs.flags.get("crypto_challenge", {})
            if not active or active.get("solved"):
                self.gs.flags["crypto_challenge"] = {"ct": ct, "pt": pt, "type": ctype, "hint": shift_or_key, "solved": False}
                return [
                    _sys("CRYPTO CHALLENGE"),
                    _line(""),
                    _lore(f"  [CYPHER]: Decrypt this. Caesar cipher."),
                    _line(f"  Ciphertext: {ct}", "warn"),
                    _line(""),
                    _dim("  encrypt crack <ciphertext> — attempt decryption"),
                    _dim("  If correct plaintext found, story beat fires."),
                ]
            # Check if player cracked the active challenge
            if args and " ".join(args[1:]).upper() == active.get("pt", ""):
                self.gs.flags["crypto_challenge"]["solved"] = True
                self.gs.add_story_beat("crypto_challenge_solved")
                self.gs.add_xp(50, "hacking")
                return [_ok("  CORRECT — Challenge solved!"), _sys("  XP +50 (hacking)")]
            return [_dim("  encrypt crack <ciphertext> — try to crack the active challenge")]

        return [_dim("  encrypt [caesar <n> <text>|vigenere <key> <text>|crack <text>|challenge]")]

    # Alias
    def _cmd_decrypt(self, args: List[str]) -> List[dict]:
        """decrypt <ciphertext> — alias for encrypt crack."""
        return self._cmd_encrypt(["crack"] + args)

    # ════════════════════════════════════════════════════════════════════════
    # TIMELINE — Event reconstruction from logs + story beats
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_timeline(self, args: List[str]) -> List[dict]:
        """timeline [full|beats|commands|filter <term>] — forensic reconstruction of session events."""
        sub = args[0].lower() if args else "beats"
        beats = sorted(self.gs.story_beats) if self.gs.story_beats else []
        history = self.history[-50:]

        BEAT_LABELS = {
            "watcher_revelation_started": "N10 — Watcher reveals simulation",
            "watcher_accepted_simulation": "N10 — Player accepts the simulation",
            "arg_signal_1337": "ARG — Signal 1337 MHz analyzed",
            "mole_investigation_started": "N2  — Mole investigation opened",
            "mole_exposed": "N2  — Mole identity revealed",
            "nova_alliance_formed": "Nova — Alliance with Nova confirmed",
            "ada_sacrifice_complete": "A14 — Ada's sacrifice completed",
            "chimera_containment_broken": "A14 — CHIMERA containment broken",
            "zohramien_phase5_complete": "N13 — ZΘHRΛMΞN merge complete",
            "prestige_unlocked": "PRESTIGE — Ascension path unlocked",
            "culture_ship_arrived": "N8  — Culture Ship contact initiated",
            "bomb_detonated": "P16 — Logic bomb detonated",
            "bomb_defused": "P16 — Logic bomb defused (ethical path)",
            "crypto_challenge_solved": "ENC — Crypto challenge solved",
            "house_deep": "HOUSE — Explored 10+ rooms",
        }

        if sub in ("beats", "story"):
            if not beats:
                return [_dim("  No story beats recorded yet. Play more.")]
            out = [_sys("TIMELINE — STORY BEATS"), _dim(f"  {len(beats)} events recorded"), _line("")]
            for b in beats:
                label = BEAT_LABELS.get(b, b.replace("_", " "))
                out.append(_dim(f"  ✦ {label}"))
            return out

        if sub == "commands":
            if not history:
                return [_dim("  No command history yet.")]
            out = [_sys("TIMELINE — COMMAND HISTORY (last 50)"), _line("")]
            for h in history:
                ts = h.get("ts", "?")[-8:]
                ok = "✓" if h.get("ok") else "✗"
                out.append(_dim(f"  [{ts}] {ok} {h.get('cmd','')[:60]}"))
            return out

        if sub == "full":
            out = [
                _sys("TIMELINE — FULL SESSION RECONSTRUCTION"),
                _dim(f"  Level: {self.gs.level}  XP skills: {sum(self.gs.skills.values()) if isinstance(self.gs.skills, dict) else 0}"),
                _dim(f"  Commands: {self.gs.commands_run}  Story beats: {len(beats)}"),
                _line(""),
                _line("  NARRATIVE EVENTS:", "dim"),
            ]
            for b in beats:
                label = BEAT_LABELS.get(b, b.replace("_", " "))
                out.append(_dim(f"    ✦ {label}"))
            out += [_line(""), _line("  RECENT COMMANDS:", "dim")]
            for h in history[-10:]:
                out.append(_dim(f"    $ {h.get('cmd','')[:60]}"))
            return out

        if sub == "filter":
            term = args[1].lower() if len(args) > 1 else ""
            matching_beats = [b for b in beats if term in b.lower()]
            matching_cmds = [h for h in history if term in h.get("cmd","").lower()]
            out = [_sys(f"TIMELINE — FILTER: '{term}'"), _line("")]
            if matching_beats:
                out.append(_dim("  Story beats:"))
                for b in matching_beats: out.append(_dim(f"    ✦ {b}"))
            if matching_cmds:
                out.append(_dim("  Commands:"))
                for h in matching_cmds: out.append(_dim(f"    $ {h.get('cmd','')}"))
            if not matching_beats and not matching_cmds:
                out.append(_dim(f"  No events matching '{term}'"))
            return out

        return [_dim("  timeline [beats|commands|full|filter <term>]")]

    # ════════════════════════════════════════════════════════════════════════
    # PACKET — Packet crafting mini-game (networking education)
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_packet(self, args: List[str]) -> List[dict]:
        """packet [craft|send|sniff|tutorial] — construct and analyze network packets."""
        sub = args[0].lower() if args else "tutorial"
        current = self.gs.flags.get("crafted_packet", {})

        if sub == "tutorial":
            return [
                _sys("PACKET CRAFTING — TUTORIAL"),
                _line(""),
                _dim("  A network packet has layers:"),
                _dim("  Layer 2 (Ethernet): src_mac, dst_mac, ethertype"),
                _dim("  Layer 3 (IP):       src_ip, dst_ip, ttl, protocol"),
                _dim("  Layer 4 (TCP/UDP):  src_port, dst_port, flags, seq"),
                _dim("  Layer 7 (App):      payload"),
                _line(""),
                _dim("  packet craft src=10.0.0.1 dst=10.0.0.2 port=80 flags=SYN"),
                _dim("  packet send         — transmit the crafted packet"),
                _dim("  packet sniff        — capture packets on the wire"),
                _line(""),
                _lore("  [CYPHER]: Understanding packets is understanding everything."),
                _lore("  [CYPHER]: Every communication, every exploit, starts here."),
            ]

        if sub == "craft":
            # Parse key=value args
            fields = {}
            for a in args[1:]:
                if "=" in a:
                    k, v = a.split("=", 1)
                    fields[k.strip()] = v.strip()
            if not fields:
                return [_err("packet craft src=<ip> dst=<ip> port=<n> flags=<SYN|ACK|RST|FIN>")]
            self.gs.flags["crafted_packet"] = fields
            self.gs.add_xp(15, "hacking")
            return [
                _sys("PACKET CRAFTED"),
                _line(""),
                _dim("  ┌─────────────────────────────────────────────┐"),
                _dim(f"  │ SRC: {fields.get('src','?'):15}  DST: {fields.get('dst','?'):15} │"),
                _dim(f"  │ PORT: {fields.get('port','?'):5}  FLAGS: {fields.get('flags','?'):8}  TTL: {fields.get('ttl','64'):3} │"),
                _dim(f"  │ PAYLOAD: {str(fields.get('payload','[empty]'))[:35]:<35} │"),
                _dim("  └─────────────────────────────────────────────┘"),
                _line(""),
                _sys("  XP +15 (hacking)"),
                _dim("  packet send — transmit this packet"),
            ]

        if sub == "send":
            if not current:
                return [_err("No packet crafted. Use: packet craft src=... dst=...")]
            dst = current.get("dst", "unknown")
            flags = current.get("flags", "").upper()
            self.gs.add_xp(25, "hacking")
            results = {
                "SYN": f"TCP SYN sent to {dst}:80. Got SYN-ACK. Connection open.",
                "FIN": f"TCP FIN sent to {dst}. Got FIN-ACK. Connection closed.",
                "RST": f"TCP RST sent to {dst}. Target confused. Good.",
                "ACK": f"TCP ACK sent to {dst}. Three-way handshake complete.",
            }
            result = results.get(flags, f"Packet sent to {dst}. No response (ICMP port unreachable or firewall).")
            self.gs.add_story_beat("packet_crafted_sent")
            return [
                _sys(f"PACKET TRANSMITTED → {dst}"),
                _ok(f"  {result}"),
                _dim("  Trace level +2 (custom packets are detectable)"),
                _sys("  XP +25 (hacking)"),
            ]

        if sub == "sniff":
            self.gs.add_xp(20, "hacking")
            import random as _r; _r.seed(self.gs.commands_run)
            packets = [
                ("10.0.0.1", "10.0.0.100", "TCP", "80→45821", "SYN"),
                ("10.0.0.100", "10.0.0.1", "TCP", "45821→80", "SYN-ACK"),
                ("10.0.0.1", "10.0.0.100", "TCP", "80→45821", "ACK PSH [HTTP GET /admin]"),
                ("10.0.0.50", "255.255.255.255", "UDP", "67→68", "DHCP DISCOVER"),
                ("0.0.0.0", "10.0.0.99", "ICMP", "—", "Echo Request (ping sweep)"),
            ]
            out = [_sys("PACKET SNIFFER — LIVE CAPTURE"), _dim("  [Capturing on eth0...]"), _line("")]
            for src, dst, proto, ports, info in _r.sample(packets, k=min(4, len(packets))):
                out.append(_dim(f"  {src:<16} → {dst:<16} {proto} {ports} [{info}]"))
            out += [_line(""), _sys("  XP +20 (hacking)"), _dim("  Look for patterns. The DHCP DISCOVER is always interesting.")]
            return out

        return [_dim("  packet [tutorial|craft <fields>|send|sniff]")]

