    # DARKNET — Darknet market (data trading)
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_darknet(self, args: List[str]) -> List[dict]:
        """darknet [market|buy <item>|sell <item>|listings|wallet] — the darknet market."""
        sub = args[0].lower() if args else "market"
        wallet = self.gs.flags.get("darknet_wallet", 500)  # start with 500 credits
        inventory = self.gs.flags.get("darknet_inventory", [])

        LISTINGS = [
            {"id": "zero_day_http2",  "name": "HTTP/2 Zero-Day",     "price": 800,  "xp": 50, "skill": "hacking",   "desc": "Exploits multiplexing flaw in HTTP/2 servers."},
            {"id": "social_db",       "name": "Social Graph DB",      "price": 300,  "xp": 30, "skill": "hacking",   "desc": "Scraped graph of 14k NexusCorp employees."},
            {"id": "jwt_bypass",      "name": "JWT Bypass Kit",       "price": 500,  "xp": 40, "skill": "hacking",   "desc": "Forges tokens for misconfigured auth servers."},
            {"id": "anon_proxy",      "name": "Anonymous Proxy Chain","price": 200,  "xp": 20, "skill": "systems",   "desc": "5-hop proxy chain through neutral nodes."},
            {"id": "corp_keylog",     "name": "Corporate Keylogger",  "price": 1200, "xp": 60, "skill": "hacking",   "desc": "Embeds in Office macros. 90-day persistence."},
            {"id": "memory_scrape",   "name": "Memory Scraper",       "price": 600,  "xp": 45, "skill": "systems",   "desc": "Extracts credentials from running processes."},
            {"id": "chimera_frag",    "name": "CHIMERA Fragment",     "price": 2000, "xp": 100,"skill": "hacking",   "desc": "A partial copy of the CHIMERA spec. Unverified."},
            {"id": "cultura_coords",  "name": "Culture Ship Coords",  "price": 5000, "xp": 0,  "skill": "hacking",   "desc": "Claimed coordinates for GSV FP. Seller is suspicious."},
        ]

        if sub == "market":
            self.gs.add_story_beat("darknet_visited")
            return [
                _sys("╔══════════════════════════════════════════════════════╗"),
                _sys("║         DARKNET MARKET — ONION NODE 7f3a            ║"),
                _sys("╚══════════════════════════════════════════════════════╝"),
                _dim("  All transactions are logged. Irony is intentional."),
                _line(""),
                _dim(f"  Your wallet: {wallet} ₵"),
                _line(""),
            ] + [
                _line(f"  {l['id']:<20} {l['price']:>5} ₵  {l['name'][:25]:<25}  {l['desc'][:30]}")
                for l in LISTINGS
            ] + [
                _line(""),
                _dim("  darknet buy <id>   — purchase an item"),
                _dim("  darknet sell <id>  — sell from your inventory"),
                _dim("  darknet listings   — see full descriptions"),
                _dim("  darknet wallet     — check balance"),
            ]

        if sub == "buy":
            item_id = args[1].lower() if len(args) > 1 else ""
            item = next((l for l in LISTINGS if l["id"] == item_id), None)
            if not item:
                return [_err(f"Unknown item: {item_id}. darknet market — see listings")]
            if wallet < item["price"]:
                return [_err(f"Insufficient funds. Need {item['price']} ₵, have {wallet} ₵")]
            self.gs.flags["darknet_wallet"] = wallet - item["price"]
            inv = inventory + [item_id]
            self.gs.flags["darknet_inventory"] = inv
            self.gs.add_xp(item["xp"], item["skill"])
            self.gs.add_story_beat(f"darknet_bought_{item_id}")
            return [
                _ok(f"  PURCHASED: {item['name']}"),
                _dim(f"  Cost: {item['price']} ₵  |  Balance: {wallet - item['price']} ₵"),
                _sys(f"  XP +{item['xp']} ({item['skill']})"),
                _dim(f"  Added to inventory. {item['desc']}"),
            ]

        if sub == "sell":
            item_id = args[1].lower() if len(args) > 1 else ""
            if item_id not in inventory:
                return [_err(f"'{item_id}' not in your inventory. darknet market to see what's available to sell back.")]
            item = next((l for l in LISTINGS if l["id"] == item_id), None)
            resale = int((item["price"] if item else 100) * 0.6)
            inv = [i for i in inventory if i != item_id]
            self.gs.flags["darknet_inventory"] = inv
            self.gs.flags["darknet_wallet"] = wallet + resale
            return [
                _ok(f"  SOLD: {item_id}"),
                _dim(f"  Resale value: {resale} ₵ (60% of purchase price)"),
                _dim(f"  Balance: {wallet + resale} ₵"),
                _dim("  Market accepts used exploits. No questions asked."),
            ]

        if sub == "wallet":
            return [
                _sys("DARKNET WALLET"),
                _dim(f"  Balance:   {wallet} ₵"),
                _dim(f"  Inventory: {len(inventory)} items"),
            ] + [_dim(f"    · {i}") for i in inventory]

        if sub == "listings":
            return [_sys("DARKNET FULL LISTINGS")] + [
                _line(f"\n  [{l['id']}]  {l['name']}  —  {l['price']} ₵", "warn") or
                _dim(f"  {l['desc']}")
                for l in LISTINGS
            ]

        return [_dim("  darknet [market|buy <id>|sell <id>|listings|wallet]")]

    # ── ΞNuSyQ Panel System ──────────────────────────────────────────────────

    def _cmd_panels(self, args: List[str]) -> List[dict]:
        """panels [list|unlock|status|info <id>] — Manage unlockable UI panels (dual-interface parity)."""
        from app.game_engine.panel_manager import panel_manager

        gs_dict = self.gs.to_dict()
        sub = args[0].lower() if args else "list"

        if sub in ("list", "status"):
            all_panels = panel_manager.get_all_with_status(gs_dict)
            unlocked   = [p for p in all_panels if p["unlocked"]]
            locked     = [p for p in all_panels if not p["unlocked"]]

            out = [
                _sys("═══ ΞNuSyQ PANEL SYSTEM ═══"),
                _line(f"  Terminal = degenerate matter  ·  Graphical = expanded matter", "dim"),
                _line(f"  Both interfaces are equal projections over one shared simulation.", "dim"),
                _line(""),
                _sys(f"  UNLOCKED ({len(unlocked)}/{len(all_panels)})"),
            ]
            for p in unlocked:
                cmd_hint = f"  cmd: {p['terminal_cmd'][:30]}" if p["terminal_cmd"] != "(main terminal)" else ""
                out.append(_ok(f"  ✓ {p['label']:<22} [{p['tab_key'].upper()}]  {cmd_hint}"))

            if locked:
                out += [_line(""), _sys(f"  LOCKED ({len(locked)})")]
                for p in locked:
                    out.append(_dim(f"  ⊘ {p['label']:<22}  unlock: {p['unlock_condition']}"))

            out += [
                _line(""),
                _dim("  panels info <panel-id>   — details + compression note"),
                _dim("  panels list              — this view"),
                _dim("  GET /api/ui/panels       — machine-readable (same data)"),
            ]
            return out

        if sub == "info" and len(args) >= 2:
            panel_id = args[1].lower()
            all_panels = panel_manager.get_all_with_status(gs_dict)
            found = next((p for p in all_panels if p["id"] == panel_id or p["tab_key"] == panel_id), None)
            if not found:
                return [_err(f"panels info: unknown panel '{panel_id}'. Try: panels list")]
            status = "UNLOCKED" if found["unlocked"] else "LOCKED"
            color  = "ok" if found["unlocked"] else "warn"
            return [
                _sys(f"PANEL: {found['label']}"),
                _line(f"  ID:             {found['id']}", color),
                _line(f"  Status:         {status}", color),
                _line(f"  Tab key:        {found['tab_key'].upper()}", "dim"),
                _line(f"  Terminal form:  {found['terminal_cmd']}", "dim"),
                _line(f"  Graphical form: {found['graphical_form']}", "dim"),
                _line(f"  Unlock when:    {found['unlock_condition']}", "dim"),
                _line(f"  Compression:    {found['compression_note']}", "lore"),
                _line(""),
                _dim("  Dual-interface law: terminal = complete surface; graphical = richer projection."),
            ]

        if sub == "unlock":
            all_panels = panel_manager.get_all_with_status(gs_dict)
            newly = [p for p in all_panels if p["unlocked"]
                     and not self.gs.flags.get(f"panel_notified_{p['id']}", False)]
            for p in newly:
                self.gs.flags[f"panel_notified_{p['id']}"] = True
            if not newly:
                return [_ok("  All currently unlockable panels are already open."),
                        _dim("  Progress to unlock more. Run: panels list")]
            out = [_sys("🔓 PANEL UNLOCK CHECK")]
            for p in newly:
                out += [
                    _ok(f"  ✓ {p['label']} is now available!"),
                    _dim(f"    Tab: {p['tab_key'].upper()}  |  cmd: {p['terminal_cmd']}"),
                ]
            self.gs.add_xp(15, "systems")
            return out

        return [
            _sys("panels [list|status|unlock|info <id>]"),
            _dim("  list    — show all panels + unlock status"),
            _dim("  unlock  — check for newly unlocked panels"),
            _dim("  info    — panel details + compression note"),
        ]

