    # ════════════════════════════════════════════════════════════════════
    # SECTION: CONTAINMENT TIMER SYSTEM
    # ════════════════════════════════════════════════════════════════════

    def _cmd_timer(self, args):
        """timer — Display the 72-hour containment countdown and loop status."""
        gs = self.gs
        new_events = gs.check_timer_events()
        remaining = gs.containment_remaining()
        pct = gs.containment_pct_elapsed()
        h = int(remaining // 3600)
        m = int((remaining % 3600) // 60)
        s = int(remaining % 60)
        if remaining <= 0:
            urgency_t, urgency_label = "error", "CONTAINMENT FAILED"
        elif remaining <= 3600:
            urgency_t, urgency_label = "error", "CRITICAL — LOOP RESET IMMINENT"
        elif remaining <= 6 * 3600:
            urgency_t, urgency_label = "warn", "FATAL — BREACH IMMINENT"
        elif remaining <= 12 * 3600:
            urgency_t, urgency_label = "warn", "CRITICAL — PERIMETER FAILING"
        elif remaining <= 24 * 3600:
            urgency_t, urgency_label = "warn", "WARNING — DEGRADED"
        elif remaining <= 48 * 3600:
            urgency_t, urgency_label = "system", "LAYER 1 DEGRADED"
        else:
            urgency_t, urgency_label = "success", "STABLE"
        filled = int(pct * 40)
        bar = "\u2588" * filled + "\u2591" * (40 - filled)
        out = [
            _sys("\u2550\u2550\u2550 CONTAINMENT TIMER \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550"),
            _dim("  Protocol: 72-Hour Roguelike Containment Loop"),
            _dim("  Classification: ULTRAVIOLET"),
            _line(""),
            _line(f"  Remaining  : {h:02d}:{m:02d}:{s:02d}", urgency_t),
            _line(f"  Status     : {urgency_label}", urgency_t),
            _line(f"  Loop       : #{gs.loop_count}  Echo Level: {gs.echo_level}", "dim"),
            _line(f"  Paused     : {'YES (Temporal Anchor active)' if gs.timer_paused else 'No'}", "warn" if gs.timer_paused else "dim"),
            _line(""),
            _line(f"  [{bar}] {int(pct*100):3d}%", urgency_t),
            _line(""),
        ]
        threshold_data = [
            ("48h", 48 * 3600, "Layer 1 degraded"),
            ("24h", 24 * 3600, "Perimeter failing"),
            ("12h", 12 * 3600, "Critical breach"),
            ("6h",  6 * 3600,  "Fatal breach"),
            ("1h",  3600,      "Loop reset imminent"),
            ("expired", 0.0,   "Loop reset triggered"),
        ]
        out.append(_sys("  THRESHOLD EVENTS:"))
        for tid, threshold_s, desc in threshold_data:
            fired = tid in gs.timer_events_fired
            sym = "\u2713" if fired else "\u00b7"
            ttype = "success" if fired else "dim"
            out.append(_line(f"    {sym} {tid:<10} [{desc}]", ttype))
        out += [
            _line(""),
            _sys("  PERSISTENT STATE (survives loops):"),
            _line(f"    Remnant Shards : {gs.remnant_shards}", "warn"),
            _line(f"    Echo Level     : {gs.echo_level} / 10", "warn"),
            _line(f"    Anchor Charges : {gs.anchor_charges}", "warn"),
            _line(f"    Upgrades       : {len(gs.remnant_upgrades)}", "warn"),
            _line(""),
            _dim("  Commands: remnant · anchor · timer"),
            _dim("  Lore:     lore containment · lore echo-loop"),
            _suggest("timer · remnant · anchor · proficiency"),
        ]
        event_out = []
        for (tid, msg) in new_events:
            if tid == "expired":
                reset = gs.trigger_loop_reset()
                event_out += [
                    _line(""),
                    _lore("  CONTAINMENT FAILED — Loop reset initiated. Echoes persist."),
                    _lore(f"  Shards gained: {reset['shards_gained']}  Echo: {reset['echo_level']}  Loop: #{reset['loop']}"),
                    _dim("  Your memories fragment. Something remains. Something always remains."),
                ]
            else:
                event_out += [
                    _line(""),
                    _lore(f"  CONTAINMENT EVENT [{tid.upper()}]: {msg}"),
                ]
        return out + event_out

    def _cmd_remnant(self, args):
        """remnant [status|upgrades|spend <id>] — Manage cross-loop remnant shards."""
        gs = self.gs
        sub = args[0].lower() if args else "status"
        _UPGRADES = [
            {"id": "anchor_perm",  "name": "Temporal Anchor (Permanent)",  "cost": 10, "desc": "Anchor persists across loop resets. Echo Level >= 1 required."},
            {"id": "echo_voice",   "name": "Echo Voice",                   "cost": 8,  "desc": "Unlock NPC echo-dialogues -- ghosts of prior loop agents."},
            {"id": "shard_magnet", "name": "Shard Magnet",                 "cost": 15, "desc": "Gain +2 extra shards per threshold event crossed."},
            {"id": "loop_memory",  "name": "Loop Memory Fragment",         "cost": 20, "desc": "Retain 25% of XP after loop reset instead of 0%."},
            {"id": "ghost_skills", "name": "Ghost Skill Imprint",          "cost": 25, "desc": "Carry forward the highest skill point from previous run."},
            {"id": "chimera_scar", "name": "CHIMERA Scar",                 "cost": 50, "desc": "Unlock CHIMERA endgame path fragments across loops."},
        ]
        if sub in ("status", "list"):
            out = [
                _sys("REMNANT SHARDS"),
                _line(f"  Balance  : {gs.remnant_shards} shards", "warn"),
                _line(f"  Echo Lvl : {gs.echo_level} / 10", "warn"),
                _line(f"  Loop     : #{gs.loop_count}", "dim"),
                _line(""),
                _sys("  PURCHASED UPGRADES:"),
            ]
            if gs.remnant_upgrades:
                for uid in gs.remnant_upgrades:
                    u = next((x for x in _UPGRADES if x["id"] == uid), None)
                    name = u["name"] if u else uid
                    out.append(_ok(f"  + {name}"))
            else:
                out.append(_dim("  None yet. Survive a loop reset to earn shards."))
            out += [
                _line(""),
                _dim("  remnant upgrades   -- browse available upgrades"),
                _dim("  remnant spend <id> -- purchase an upgrade"),
                _suggest("remnant upgrades · remnant spend anchor_perm · timer"),
            ]
            return out
        if sub == "upgrades":
            out = [_sys("UPGRADE CATALOGUE"), _line(f"  Balance: {gs.remnant_shards} shards", "warn"), _line("")]
            for u in _UPGRADES:
                owned = u["id"] in gs.remnant_upgrades
                status = "+ OWNED" if owned else f"{u['cost']} shards"
                ttype = "success" if owned else "warn"
                out += [_line(f"  [{u['id']}]  {u['name']:<35} {status}", ttype), _dim(f"    {u['desc']}")]
            out += [_line(""), _dim("  remnant spend <id>   -- purchase an upgrade")]
            return out
        if sub == "spend":
            if len(args) < 2:
                return [_err("Usage: remnant spend <upgrade-id>")]
            uid = args[1].lower()
            u = next((x for x in _UPGRADES if x["id"] == uid), None)
            if not u:
                ids = ", ".join(x["id"] for x in _UPGRADES)
                return [_err(f"Unknown upgrade: {uid}"), _dim(f"  Available: {ids}")]
            if uid in gs.remnant_upgrades:
                return [_ok(f"  Already purchased: {u['name']}")]
            if gs.echo_level < 1 and uid == "anchor_perm":
                return [_err("  Requires Echo Level >= 1. Complete a loop reset first.")]
            if gs.remnant_shards < u["cost"]:
                return [_err(f"  Insufficient shards: {gs.remnant_shards} / {u['cost']} required")]
            gs.remnant_shards -= u["cost"]
            gs.remnant_upgrades.add(uid)
            gs.add_consciousness(5)  # Layer 1: temporal mastery — spending remnant shards across loops
            return [_ok(f"  PURCHASED: {u['name']}"), _dim(f"  Cost: {u['cost']}  Balance: {gs.remnant_shards}"), _dim(f"  {u['desc']}")]
        return [_dim("  remnant [status|upgrades|spend <id>]")]

    def _cmd_anchor(self, args):
        """anchor [activate|release|status] -- Temporal Anchor: freeze the containment timer."""
        gs = self.gs
        sub = args[0].lower() if args else "status"
        def _can_anchor():
            if gs.anchor_charges > 0:
                return True, f"Anchor charge available ({gs.anchor_charges} remaining)"
            if gs.echo_level >= 2:
                return True, "Echo Level 2+ grants passive anchor access"
            watcher_trust = gs.flags.get("watcher_trust", 0)
            if watcher_trust >= 50:
                return True, f"Watcher trust {watcher_trust}/100 grants anchor access"
            if "anchor_perm" in gs.remnant_upgrades:
                return True, "Permanent Anchor upgrade active"
            return False, ("Temporal Anchor requires:\n"
                "  anchor_charges > 0 (earn by surviving threshold events)\n"
                "  Echo Level >= 2 (survive 2 loop resets)\n"
                "  Watcher trust >= 50 (talk to Watcher)\n"
                "  Or: remnant spend anchor_perm (10 shards)")
        if sub == "status":
            allowed, reason = _can_anchor()
            return [
                _sys("TEMPORAL ANCHOR"),
                _line(f"  Timer status  : {'PAUSED' if gs.timer_paused else 'RUNNING'}", "warn" if gs.timer_paused else "dim"),
                _line(f"  Charges       : {gs.anchor_charges}", "warn"),
                _line(f"  Access        : {'GRANTED' if allowed else 'DENIED'}", "success" if allowed else "error"),
                _dim(f"  Reason        : {reason}"),
                _line(""),
                _dim("  anchor activate  -- pause the containment timer"),
                _dim("  anchor release   -- resume the timer"),
            ]
        if sub == "activate":
            if gs.timer_paused:
                return [_warn("  Timer is already paused. anchor release to resume.")]
            allowed, reason = _can_anchor()
            if not allowed:
                return [_err("  ACCESS DENIED"), _dim(reason)]
            gs.paused_timer_remaining = gs.containment_remaining()
            gs.timer_paused = True
            gs.add_consciousness(12)  # Layer 1: temporal mastery — bending the containment clock
            if gs.anchor_charges > 0 and gs.echo_level < 2 and gs.flags.get("watcher_trust", 0) < 50 and "anchor_perm" not in gs.remnant_upgrades:
                gs.anchor_charges -= 1
            remaining = gs.paused_timer_remaining
            h2 = int(remaining // 3600)
            m2 = int((remaining % 3600) // 60)
            s2 = int(remaining % 60)
            return [
                _ok(f"  TEMPORAL ANCHOR ACTIVATED"),
                _dim(f"  Timer frozen at {h2:02d}:{m2:02d}:{s2:02d}"),
                _dim(f"  Charges remaining: {gs.anchor_charges}"),
                _dim("  anchor release   -- resume the timer"),
            ]
        if sub == "release":
            if not gs.timer_paused:
                return [_dim("  Timer is not paused.")]
            import time as _t2
            gs.run_start_time = _t2.time() - (gs.CONTAINMENT_SECONDS - gs.paused_timer_remaining)
            gs.timer_paused = False
            gs.paused_timer_remaining = 0.0
            remaining = gs.containment_remaining()
            h2 = int(remaining // 3600)
            m2 = int((remaining % 3600) // 60)
            s2 = int(remaining % 60)
            return [
                _ok("  TEMPORAL ANCHOR RELEASED"),
                _dim(f"  Timer resumed at {h2:02d}:{m2:02d}:{s2:02d}"),
                _dim("  Containment clock is running."),
            ]
        return [_dim("  anchor [activate|release|status]")]

    # ════════════════════════════════════════════════════════════════════
    # SECTION: LANGUAGE PROFICIENCY MATRIX
    # ════════════════════════════════════════════════════════════════════

    def _cmd_proficiency(self, args):
        """proficiency [<lang>|matrix|abilities] -- Language proficiency dashboard."""
        gs = self.gs
        sub = args[0].lower().replace("-", "_") if args else "matrix"
        lang_keys = set(gs.lang_proficiency.keys())
        if sub in lang_keys:
            return self._proficiency_detail(sub)
        if sub in ("mat", "matrix", "grid", "all", "list"):
            return self._proficiency_matrix()
        if sub in ("abilities", "ability", "skills", "unlock"):
            return self._proficiency_abilities()
        return [
            _sys("proficiency -- Language Mastery Matrix"),
            _dim("  proficiency matrix       -- full grid of all 51 languages"),
            _dim("  proficiency abilities    -- unlocked language abilities"),
            _dim("  proficiency <lang>       -- detailed view for one language"),
            _suggest("proficiency matrix · proficiency abilities · proficiency python"),
        ]

    def _proficiency_matrix(self):
        gs = self.gs
        prof = gs.lang_proficiency
        def _bar(val, width=20):
            filled = int(val / 100 * width)
            return "\u2588" * filled + "\u2591" * (width - filled)
        def _tier(val):
            if val >= 80: return "MASTER"
            if val >= 60: return "ADEPT"
            if val >= 40: return "JOURNEYMAN"
            if val >= 20: return "INITIATE"
            if val > 0: return "NOVICE"
            return "LOCKED"
        tiers = {"MASTER": [], "ADEPT": [], "JOURNEYMAN": [], "INITIATE": [], "NOVICE": [], "LOCKED": []}
        for lang, val in sorted(prof.items()):
            tiers[_tier(val)].append((lang, val))
        total = len(prof)
        mastered = sum(1 for v in prof.values() if v >= 80)
        avg = sum(prof.values()) // total if total else 0
        out = [
            _sys("LANGUAGE PROFICIENCY MATRIX"),
            _dim("  The Lattice measures fluency across 51 languages."),
            _dim("  Proficiency grows through polyglot runs, file reads, and usage."),
            _line(""),
            _line(f"  Total: {total} languages  Mastered: {mastered}  Avg: {avg}/100", "system"),
            _line(""),
        ]
        tier_order = ["MASTER", "ADEPT", "JOURNEYMAN", "INITIATE", "NOVICE", "LOCKED"]
        tier_colors = {"MASTER": "success", "ADEPT": "success", "JOURNEYMAN": "warn",
                       "INITIATE": "warn", "NOVICE": "dim", "LOCKED": "dim"}
        for tier in tier_order:
            langs = tiers[tier]
            if not langs: continue
            out.append(_line(f"  -- {tier} ({len(langs)}) --", tier_colors[tier]))
            for lang, val in langs:
                bar = _bar(val, 16)
                out.append(_line(f"  {lang:<16} [{bar}] {val:3d}", tier_colors[tier]))
        all_mastered = all(v >= 80 for v in prof.values())
        if all_mastered:
            out += [_line(""), _lore("  ALL LANGUAGES MASTERED. The CHIMERA master key crystallizes."), _lore("  Type: chimera unlock")]
        else:
            needed = sum(1 for v in prof.values() if v < 80)
            out += [_line(""), _dim(f"  CHIMERA master key: {needed} language(s) below 80.")]
        out.append(_suggest("proficiency python · proficiency abilities · polyglot run python"))
        return out

    def _proficiency_detail(self, lang):
        gs = self.gs
        val = gs.lang_proficiency.get(lang, 0)
        def _bar(v, w=30):
            f = int(v / 100 * w)
            return "\u2588" * f + "\u2591" * (w - f)
        abilities = _LANG_ABILITIES.get(lang, [])
        unlocked = [a for a in abilities if val >= a["req"]]
        locked = [a for a in abilities if val < a["req"]]
        out = [
            _sys(f"{lang.upper()} PROFICIENCY"),
            _line(f"  [{_bar(val)}] {val}/100", "warn" if val < 40 else "success"),
            _line(""),
        ]
        if abilities:
            out.append(_sys("  ABILITIES:"))
            for a in unlocked:
                out.append(_ok(f"  + [{a['cmd']:<18}] req: {a['req']:3d}   {a['desc']}"))
            for a in locked:
                out.append(_dim(f"  o [{a['cmd']:<18}] req: {a['req']:3d}   {a['desc']}"))
        out += [
            _line(""),
            _dim(f"  Gain: polyglot run {lang} · read {lang} files"),
            _suggest(f"polyglot run {lang} · proficiency matrix"),
        ]
        return out

    def _proficiency_abilities(self):
        gs = self.gs
        prof = gs.lang_proficiency
        out = [_sys("LANGUAGE ABILITIES"), _dim("  Abilities unlock when proficiency reaches threshold."), _line("")]
        for lang, abilities in sorted(_LANG_ABILITIES.items()):
            val = prof.get(lang, 0)
            for a in abilities:
                unlocked = val >= a["req"]
                sym = "+" if unlocked else "o"
                t = "success" if unlocked else "dim"
                out.append(_line(f"  {sym} {a['cmd']:<20} [{lang} {a['req']}+]   {a['desc']}", t))
        out += [_line(""), _dim("  polyglot run <lang>  -- improve proficiency"), _suggest("scrape · memdump · safe_exploit · chain · inject")]
        return out

    def _cmd_scrape(self, args):
        """scrape [<target>] -- Python 30+: Extract synthetic data from web nodes."""
        gs = self.gs
        if gs.lang_proficiency.get("python", 0) < 30:
            return [_err("  ABILITY LOCKED: scrape requires Python >= 30"), _dim(f"  Current: {gs.lang_proficiency.get('python', 0)}/100"), _dim("  polyglot run python")]
        target = args[0] if args else "nexuscorp-intranet.local"
        import random, hashlib
        rng = random.Random(target + str(gs.loop_count))
        rows = [{"user": f"user_{rng.randint(1000,9999)}", "hash": hashlib.md5(f"{rng.random()}".encode()).hexdigest()[:12],
                 "role": rng.choice(["operator", "analyst", "admin", "ghost"]),
                 "last_seen": f"20{rng.randint(21,25)}-{rng.randint(1,12):02d}-{rng.randint(1,28):02d}"}
                for _ in range(rng.randint(4, 8))]
        new_val = gs.gain_proficiency("python", 4)
        gs.add_xp(10, "programming")
        out = [_sys(f"SCRAPE: {target}"), _dim("  [python] Executing web scraper..."), _line(""), _sys(f"  {'USER':<14} {'HASH':<14} {'ROLE':<12} LAST SEEN"), _line("  " + "-" * 60, "dim")]
        for r in rows:
            out.append(_ok(f"  {r['user']:<14} {r['hash']:<14} {r['role']:<12} {r['last_seen']}"))
        out += [_line(""), _sys(f"  Extracted {len(rows)} records"), _dim(f"  Python: {new_val}/100 (+4)"), _suggest("scrape darknode-7.internal · memdump · inject")]
        return out

    def _cmd_memdump(self, args):
        """memdump [<pid>] -- C 50+: Read raw memory segments of a running process."""
        gs = self.gs
        if gs.lang_proficiency.get("c", 0) < 50:
            return [_err("  ABILITY LOCKED: memdump requires C >= 50"), _dim(f"  Current: {gs.lang_proficiency.get('c', 0)}/100"), _dim("  polyglot run c")]
        pid = args[0] if args else "1337"
        import random, hashlib
        rng = random.Random(f"memdump_{pid}_{gs.loop_count}")
        hex_lines = []
        base = rng.randint(0x7fff0000, 0x7fffffff)
        for i in range(8):
            addr = base + i * 16
            raw_bytes = bytes([rng.randint(0, 255) for _ in range(16)])
            hex_part = " ".join(f"{b:02x}" for b in raw_bytes)
            ascii_part = "".join(chr(b) if 32 <= b < 127 else "." for b in raw_bytes)
            hex_lines.append(f"  0x{addr:08x}  {hex_part}  |{ascii_part}|")
        new_val = gs.gain_proficiency("c", 5)
        gs.add_xp(15, "programming")
        lore_idx = rng.randint(0, len(hex_lines) - 1)
        lore_insert = "  [FRAGMENT] " + rng.choice(["process 1 was never here", "chimera_key: 0xDEADBEEFCAFE",
            f"echo_loop: iteration_{gs.loop_count}", "GHOST_SIGNAL: RESIDUAL DETECTED", "SERENA_CORE: trust_level_overflow"])
        out = [_sys(f"MEMDUMP pid:{pid}"), _dim("  [c] Attaching to process memory..."), _line("")]
        out += [_line(l, "system") for l in hex_lines[:lore_idx]]
        out.append(_lore(lore_insert))
        out += [_line(l, "system") for l in hex_lines[lore_idx:]]
        out += [_line(""), _dim(f"  C proficiency: {new_val}/100 (+5)"), _suggest("memdump 1 · safe_exploit · scrape")]
        return out

    def _cmd_safe_exploit(self, args):
        """safe_exploit [<target>] -- Rust 40+: Exploit system safely without crashing."""
        gs = self.gs
        if gs.lang_proficiency.get("rust", 0) < 40:
            return [_err("  ABILITY LOCKED: safe_exploit requires Rust >= 40"), _dim(f"  Current: {gs.lang_proficiency.get('rust', 0)}/100"), _dim("  polyglot run rust")]
        target = (args[0] if args else "kernel.nexus").replace("..", ".")
        import random, hashlib
        rng = random.Random(f"safe_exploit_{target}_{gs.loop_count}")
        success_chance = min(0.95, 0.4 + gs.lang_proficiency.get("rust", 0) / 200)
        success = rng.random() < success_chance
        token = hashlib.sha256(f"{target}{gs.loop_count}{rng.random()}".encode()).hexdigest()[:24]
        new_val = gs.gain_proficiency("rust", 5)
        gs.add_xp(20 if success else 5, "security")
        out = [_sys(f"SAFE_EXPLOIT: {target}"), _dim("  [rust] Memory-safe exploit harness..."), _dim("  [*] Fuzzing target interface..."), _line("")]
        if success:
            out += [_ok(f"  EXPLOIT SUCCEEDED -- Token: {token}"), _dim(f"  Rust: {new_val}/100 (+5)")]
            gs.add_story_beat("safe_exploit_success")
        else:
            out += [_warn("  Exploit blocked. Increase Rust proficiency for better odds."), _dim(f"  Rust: {new_val}/100 (+5)")]
        out.append(_suggest("safe_exploit chimera-proxy.net · memdump · scrape"))
        return out

    def _cmd_chain(self, args):
        """chain <cmd1> | <cmd2> | ... -- Bash 30+: Multi-step automation pipeline."""
        gs = self.gs
        if gs.lang_proficiency.get("bash", 0) < 30:
            return [_err("  ABILITY LOCKED: chain requires Bash >= 30"), _dim(f"  Current: {gs.lang_proficiency.get('bash', 0)}/100"), _dim("  polyglot run bash")]
        if not args:
            return [_sys("chain <cmd1> | <cmd2> | ..."), _dim("  Example: chain ls /var/log | grep kernel | sort"), _suggest("chain ls /var/log | grep nexus | sort")]
        pipeline_str = " ".join(args)
        steps = [s.strip() for s in pipeline_str.split("|") if s.strip()]
        if len(steps) < 2:
            return [_dim("  chain requires at least 2 pipe stages.")]
        new_val = gs.gain_proficiency("bash", 4)
        gs.add_xp(10, "scripting")
        out = [_sys(f"CHAIN PIPELINE ({len(steps)} stages)"), _line("")]
        for i, step in enumerate(steps):
            result_count = max(1, 10 - i * 2)
            out += [_dim(f"  [{i+1}] {step}"), _line(f"      -> {result_count} records", "system")]
        out += [_line(""), _ok(f"  Pipeline complete."), _dim(f"  Bash: {new_val}/100 (+4)"), _suggest("safe_exploit · inject · scrape")]
        return out

    def _cmd_inject(self, args):
        """inject [<target>] -- JavaScript 40+: Manipulate the web interface layer."""
        gs = self.gs
        if gs.lang_proficiency.get("javascript", 0) < 40:
            return [_err("  ABILITY LOCKED: inject requires JavaScript >= 40"), _dim(f"  Current: {gs.lang_proficiency.get('javascript', 0)}/100"), _dim("  polyglot run javascript")]
