        gs.add_xp(15, "programming")
        gs.add_story_beat("inject_used")
        out = [
            _sys(f"INJECT: #{target}"),
            _dim("  [javascript] Locating DOM surface in browser client..."),
            _dim(f"  [*] Payload: {payload_id}"),
            _line(""),
            _lore(f"  > document.getElementById(\'{target}\').setAttribute(\'data-injected\', \'{payload_id}\')"),
            _line(""),
            _ok("  Injection delivered. Effect propagated to graphical panel."),
            _dim(f"  Valid targets: {chr(32).join(valid_targets)}"),
            _dim(f"  JavaScript: {new_val}/100 (+5)"),
            _suggest("inject output · inject header · safe_exploit · scrape"),
        ]
        return out


