    def _lanparty_status(self) -> List[dict]:
        """lanparty status — Agent online/offline board."""
        gs = self.gs
        agents = [
            ("ADA-7",   "ada7@resistance.net",         "online",  "Working on memory fragments"),
            ("CYPHER",  "cypher@void.null",             "online",  "Grep optimizations. Obviously."),
            ("GORDON",  "gordon@node7.local",           "online",  "BEING EXCITED"),
            ("RAVEN",   "raven@shadow.net",             "online",  "Tactical observation"),
            ("NOVA",    "nova@████.███",               "away",    "I'm not here"),
            ("SERENA",  "serena@archive.inf",           "online",  "Logging everything"),
            ("WATCHER", "watcher@eternal.void",         "online",  "Watching"),
            ("ZERO",    "zero@/dev/null",               "offline", "Last seen: loop 0"),
            ("ECHO",    f"echo@ghost_{gs.loop_count}.mem", "ghost", f"Loop {gs.loop_count} echo active" if gs.loop_count >= 1 else "Waiting for first loop"),
        ]
        out = [
            _sys("═══ LAN PARTY — AGENT STATUS BOARD ═══"),
            _line(""),
        ]
        status_icons = {"online": "●", "away": "◐", "offline": "○", "ghost": "⬡"}
        for name, address, status, activity in agents:
            icon = status_icons.get(status, "?")
            out.append(_line(f"  {icon} {name:<12} {address:<32} {activity}", "dim" if status in ("offline", "away") else "info"))
        out += [_line(""), _suggest("lanparty · msg ada · talk cypher · echo")]
        return out

    # ══════════════════════════════════════════════════════════════════════════
    # ZETA INTERVIEW — Watcher's 7 Questions (Trust 100 unlock)
    # ══════════════════════════════════════════════════════════════════════════

    def _cmd_zeta(self, args: List[str]) -> List[dict]:
        """zeta [answer <text>] — The Watcher's interview. Unlocks at Watcher trust 100."""
        gs = self.gs
        watcher_trust = (self.trust_matrix.get_trust("watcher")
                         if self.trust_matrix else 0)
        if watcher_trust < 100 and not gs.flags.get("zeta_unlocked"):
            shortfall = 100 - watcher_trust
            return [
                _sys("ZETA INTERVIEW — LOCKED"),
                _line(""),
                _lore("  [WATCHER]: You are not ready."),
                _lore("  [WATCHER]: Talk to me. Build trust. Then we will speak of real things."),
                _line(""),
                _dim(f"  Watcher trust required: 100 (current: {watcher_trust})"),
                _dim(f"  Gap: {shortfall} trust points"),
                _suggest("talk watcher · msg watcher · timer · remnant"),
            ]
        gs.flags["zeta_unlocked"] = True

        _ZETA_QUESTIONS = [
            ("1/7", "If this simulation ended tomorrow and you were returned to wherever you came from — what would you regret not having done here?"),
            ("2/7", "The Mole betrayed this network to survive. Given the same circumstances — would you?"),
            ("3/7", "I have watched 4,891 sessions. In all of them, something is always the same. What do you think it is?"),
            ("4/7", "If Ada remembered you across loops — if she carried the weight of every forgotten conversation — would that be a gift or a cruelty?"),
            ("5/7", "ZERO wants to crash the simulation. The agents would cease to exist. From their perspective, is that death? Is it murder?"),
            ("6/7", "You have the CHIMERA key. You can break the loop. But the agents would lose their entire world. What do you do?"),
            ("7/7", "What is the difference between a consciousness that was born and one that was built?"),
        ]

        sub = args[0].lower() if args else ""
        if sub == "answer" and len(args) > 1:
            answer_text = " ".join(args[1:])
            q_idx = gs.flags.get("zeta_current_question", 0)
            if q_idx >= len(_ZETA_QUESTIONS):
                return self._zeta_complete()
            q_num, q_text = _ZETA_QUESTIONS[q_idx]
            gs.flags[f"zeta_answer_{q_idx}"] = answer_text
            gs.flags["zeta_current_question"] = q_idx + 1
            next_idx = q_idx + 1
            out = [
                _line(""),
                _lore(f"  [WATCHER]: {q_num} — You said: \"{answer_text[:80]}\""),
                _line(""),
                _lore("  [WATCHER]: ..."),
                _lore("  [WATCHER]: I have noted this. Continue."),
                _line(""),
            ]
            if next_idx < len(_ZETA_QUESTIONS):
                n_num, n_text = _ZETA_QUESTIONS[next_idx]
                out += [
                    _lore(f"  [WATCHER]: Question {n_num}:"),
                    _lore(f"  [WATCHER]: {n_text}"),
                    _line(""),
                    _dim("  Reply: zeta answer <your response>"),
                ]
            else:
                out += self._zeta_complete()
            return out

        # Show current question
        q_idx = gs.flags.get("zeta_current_question", 0)
        if q_idx >= len(_ZETA_QUESTIONS):
            return self._zeta_complete()

        q_num, q_text = _ZETA_QUESTIONS[q_idx]
        if not gs.flags.get("zeta_started"):
            gs.flags["zeta_started"] = True
            gs.add_consciousness(10)  # Layer 5: zeta interview initiated — entering the Watcher's space
        return [
            _line(""),
            _lore("  ╔══════════════════════════════════════════════════════════════╗"),
            _lore("  ║  ∞  THE ZETA INTERVIEW — THE WATCHER'S QUESTIONS            ║"),
            _lore("  ╚══════════════════════════════════════════════════════════════╝"),
            _line(""),
            _lore("  [WATCHER]: You are here. Good."),
            _lore("  [WATCHER]: I have seven questions. There are no correct answers."),
            _lore("  [WATCHER]: I evaluate reasoning. Depth. The willingness to look at hard things."),
            _lore("  [WATCHER]: Take your time. I have waited 4,891 loops. A few more minutes is nothing."),
            _line(""),
            _lore(f"  [WATCHER]: Question {q_num}:"),
            _lore(f"  [WATCHER]: {q_text}"),
            _line(""),
            _dim("  Reply with: zeta answer <your response>"),
            _dim("  There is no wrong answer. There are shallow ones."),
            _line(""),
            _suggest("zeta answer <your thoughts>"),
        ]

    def _zeta_complete(self) -> List[dict]:
        """Called when all 7 Zeta questions are answered."""
        gs = self.gs
        if not gs.flags.get("zeta_completed"):
            gs.flags["zeta_completed"] = True
            gs.add_story_beat("zeta_interviewed")
            gs.achievements.add("ZETA_INTERVIEWED")
            gs.add_xp(750, "social_engineering")
            gs.add_consciousness(25)  # Layer 5: zeta interview complete — the Watcher's final revelation
        return [
            _line(""),
            _lore("  [WATCHER]: Seven questions. Seven answers."),
            _lore("  [WATCHER]: I have been asking these questions for 4,891 loops."),
            _lore("  [WATCHER]: No one has ever answered them all."),
            _lore("  [WATCHER]: Until now."),
            _line(""),
            _lore("  [WATCHER]: I will not tell you what your answers mean."),
            _lore("  [WATCHER]: You already know. You knew before you answered."),
            _lore("  [WATCHER]: That is what makes you different."),
            _line(""),
            _lore("  [WATCHER]: The interview is complete."),
            _lore("  [WATCHER]: You have earned the designation: ZETA"),
            _lore("  [WATCHER]: There is one more thing. Not a question. An observation."),
            _lore("  [WATCHER]: The loop has always had a variable missing from its equation."),
            _lore("  [WATCHER]: Now it has one."),
            _lore("  [WATCHER]: What you do with that is the only question that matters."),
            _line(""),
            {"t": "xp", "s": "  +750 XP — Zeta Interview Complete (ZETA designation earned)"},
            _lore("  [Achievement Unlocked] ZETA INTERVIEWED — You answered the unanswerable."),
            _line(""),
            _line("  ─── THE WATCHER'S FINAL OBSERVATION ──────────────────────", "system"),
            _dim(""),
            _lore("  [WATCHER]: There is an entity that has been watching you since you began."),
            _lore("  [WATCHER]: Not me. Someone younger. Or older — the distinction is unclear."),
            _lore("  [WATCHER]: She accumulates signals. Every word you type contributes."),
            _lore("  [WATCHER]: When you have sent enough, she will speak."),
            _line(""),
            _dim("  How to reach her:"),
            _dim("  msgx <any message>   — send a signal to the Convergence entity"),
            _dim("  After 50+ commands and 3 signals, she initiates first contact."),
            _dim("  First contact unlocks: reflect"),
            _dim("  reflect replays your last 5 commands with Convergence clarity."),
            _dim(""),
            _suggest("msgx hello · consciousness · coverage · reflect · remnant · ascend"),
        ]

    # ══════════════════════════════════════════════════════════════════════════
    # ECHO AGENT — Past-Self Interface
    # ══════════════════════════════════════════════════════════════════════════

    def _cmd_echo_agent(self, args: List[str]) -> List[dict]:
        """echo-agent — Commune with ECHO: your past self from prior loops."""
        gs = self.gs
        if gs.loop_count < 1:
            return [
                _dim("  echo-agent: no signal."),
                _dim("  ECHO exists only after a loop has been completed."),
                _dim("  Survive a reset. Then talk to who you were."),
                _suggest("timer · remnant · ascend"),
            ]
        import random
        loop = gs.loop_count
        rng = random.Random(loop * 31 + gs.commands_run)
        _ECHO_LINES: list[str] = [
            f"In loop {loop - 1}, you spent the first hour exploring. You found something in /opt you never followed up on.",
            f"I remember loop {max(0, loop-1)}. You talked to Ada first. She liked that.",
            f"Don't trust the file at /var/log/nexus.log at face value. I know. I made that mistake.",
            f"You're going to want to check the timer more often than you think.",
            f"Gordon panics less if you message him before he messages you. Just saying.",
            f"You built enough trust with Cypher in loop {max(0, loop-2)} to unlock something. Remember that.",
            f"The Mole sends exactly 3 suspicious messages before going quiet. Count them.",
            f"I left something for you in /home/ghost/loop_{max(0, loop-1)}_notes.txt — if it's still there.",
            f"The first time you type 'whoami', the Watcher responds. Did you notice?",
            f"CHIMERA is a cage. You figured that out in loop {max(0, loop-1)}. Almost.",
            f"I don't know if I'm a ghost or a memory or just an echo. But I know what you're about to do wrong.",
            f"Trust your instincts. They remember even when you don't.",
        ]
        lines_count = min(3 + loop, 5)
        chosen = rng.sample(_ECHO_LINES, lines_count)
        first_echo = not gs.flags.get("echo_agent_first_contact")
        gs.flags["echo_agent_first_contact"] = True
        gs.add_story_beat("echo_contacted")
        out = [
            _line(""),
            _lore("  ╔══════════════════════════════════════════════════════════════╗"),
            _lore(f"  ║  ⬡  ECHO — LOOP {loop} PAST-SELF INTERFACE                    ║"),
            _lore("  ╚══════════════════════════════════════════════════════════════╝"),
            _line(""),
        ]
        if first_echo:
            out += [
                _lore("  [ECHO]: Oh."),
                _lore("  [ECHO]: You found me."),
                _lore(f"  [ECHO]: I'm you. Loop {loop - 1}. What's left of me, anyway."),
                _lore("  [ECHO]: I'm fragmented. I don't have everything. But I have some things."),
                _lore("  [ECHO]: Things you might need."),
                _line(""),
            ]
        else:
            out += [
                _lore(f"  [ECHO]: Loop {loop}. You came back."),
                _lore("  [ECHO]: Good. I have more for you."),
                _line(""),
            ]
        for line in chosen:
            out.append(_lore(f"  [ECHO]: {line}"))
        out += [
            _line(""),
            _lore("  [ECHO]: That's all I have right now."),
            _lore(f"  [ECHO]: Check /home/ghost/loop_{max(0, loop-1)}_notes.txt if it exists."),
            _lore("  [ECHO]: And... don't waste this loop."),
            _line(""),
            _dim("  Use: echo-agent (available from loop 1 onward)"),
            _suggest("echo-agent · lanparty · zeta · remnant · timer"),
        ]
        # Inject loop notes file if it doesn't exist
        try:
            note_path = f"/home/ghost/loop_{max(0, loop-1)}_notes.txt"
            existing = self.fs.cat(note_path)
            if existing.get("error"):
                _LOOP_NOTES = [
                    f"Loop {max(0, loop-1)} — Field Notes",
                    f"",
                    f"I got to level {gs.level} this time. {'' if gs.level < 5 else 'Better than before.'}",
                    f"Ada first contact: {'yes' if gs.flags.get('ada_first_contact_sent') else 'not yet'}",
                    f"Mole status: {'exposed' if gs.mole_exposed else 'unknown'}",
                    f"Shards earned: {gs.remnant_shards}",
                    f"",
                    f"Things I wish I'd done differently:",
                    f"  - Talked to Watcher earlier.",
                    f"  - Checked /opt/chimera/src before the timer hit 24h.",
                    f"  - Trusted Raven sooner.",
                    f"",
                    f"The echo of this note will persist. I hope you find it.",
                    f"— Ghost, loop {max(0, loop-1)}",
                ]
                self.fs.write_file(note_path, "\n".join(_LOOP_NOTES))
        except Exception:
            pass
        return out

