    def _detect_class(self) -> str:
        """Detect player's current class from lang_proficiency thresholds."""
        best_class = None
        best_score = 0
        for cls_name, cls_data in self._CLASS_DEFS.items():
            langs = cls_data["langs"]
            threshold = cls_data["threshold"]
            score = sum(self.gs.lang_proficiency.get(l, 0) for l in langs if self.gs.lang_proficiency.get(l, 0) >= threshold)
            if score > best_score:
                best_score = score
                best_class = cls_name
        return best_class or "Ghost"

    def _cmd_archetype(self, args: List[str]) -> List[dict]:
        """archetype [<name>|list|abilities] — view or set your language-based archetype."""
        sub = args[0].lower() if args else "status"

        if sub == "list":
            out = [
                _sys("=== CHARACTER CLASSES — THE SEVEN ARCHETYPES ==="),
                _line(""),
            ]
            for cls_name, cls_data in self._CLASS_DEFS.items():
                langs = cls_data["langs"]
                threshold = cls_data["threshold"]
                your_best = max((self.gs.lang_proficiency.get(l, 0) for l in langs), default=0)
                unlocked = your_best >= threshold
                status = "✓ UNLOCKED" if unlocked else f"  (need {threshold}+ in {'/'.join(langs[:2])})"
                color = "success" if unlocked else "dim"
                out.append(_line(f"  {'★' if unlocked else '·'} {cls_name:<20} {status}", color))
                out.append(_dim(f"       {cls_data['flavor'][:70]}"))
            out += [_line(""), _dim("  class <name>    — adopt an archetype"), _dim("  class abilities — see all class abilities")]
            return out

        if sub == "abilities":
            out = [_sys("=== CLASS ABILITIES ==="), _line("")]
            for cls_name, cls_data in self._CLASS_DEFS.items():
                out.append(_line(f"  {cls_name}:  {', '.join(cls_data['abilities'])}", "info"))
            return out

        if sub == "status":
            detected = self._detect_class()
            stored = self.gs.flags.get("player_class", detected)
            out = [
                _sys("=== GHOST — ARCHETYPE STATUS ==="),
                _line(""),
                _line(f"  Detected class:  {detected}", "info"),
                _line(f"  Active class:    {stored}", "success"),
                _line(""),
                _dim("  Your class is determined by language proficiencies."),
                _dim("  Use 'class list' to see all archetypes."),
                _dim("  Use 'polyglot run <lang>' to train languages."),
                _dim("  Use 'class <name>' to manually adopt an archetype."),
            ]
            return out

        target = " ".join(args).title()
        if target in self._CLASS_DEFS:
            cls_data = self._CLASS_DEFS[target]
            langs = cls_data["langs"]
            threshold = cls_data["threshold"]
            your_best = max((self.gs.lang_proficiency.get(l, 0) for l in langs), default=0)
            if your_best < threshold:
                return [
                    _warn(f"  CLASS LOCKED: {target}"),
                    _dim(f"  Requires {threshold}+ proficiency in: {', '.join(langs[:2])}"),
                    _dim(f"  Your current best: {your_best}"),
                    _dim("  Use 'polyglot run <lang>' to level up."),
                ]
            prev = self.gs.flags.get("player_class", "Ghost")
            self.gs.flags["player_class"] = target
            self.gs.add_story_beat(f"class_adopted_{target.lower().replace(' ', '_')}")
            out = [
                _ok(f"  Archetype adopted: {target}"),
                _line(""),
                _lore(f"  {cls_data['flavor']}"),
                _line(""),
                _lore(f"  {cls_data['agent_line']}"),
                _line(""),
                _dim(f"  Abilities unlocked: {', '.join(cls_data['abilities'])}"),
            ]
            if prev != "Ghost" and prev != target:
                out.append(_dim(f"  (Previously: {prev})"))
            return out

        return _err(f"Unknown class '{target}'. Try: class list")

    def _cmd_archetypes(self, args: List[str]) -> List[dict]:
        """archetypes — list language-based archetypes (alias for archetype list)."""
        return self._cmd_archetype(["list"] + args)

