    def _cmd_delegate(self, args: List[str]) -> List[dict]:
        """delegate <agent> <task> — assign a background task to an agent."""
        if not args:
            active = self.gs.flags.get("delegate_tasks", {})
            if not active:
                return [
                    _sys("=== DELEGATION BOARD ==="),
                    _dim("  No active delegations."),
                    _dim("  Usage: delegate <agent> <task>"),
                    _dim("  Agents: ada, cypher, gordon, raven, serena, watcher"),
                    _dim("  Tasks:  scan, analyze, crack, exploit, recon, monitor, intel, log, index, observe"),
                ]
            out = [_sys("=== ACTIVE DELEGATIONS ==="), _line("")]
            for agent, task in active.items():
                out.append(_line(f"  ● {agent:<10} → {task}", "info"))
            out += [_line(""), _dim("  delegate clear <agent>  — remove a delegation")]
            return out

        if args[0].lower() == "clear":
            agent = args[1].lower() if len(args) > 1 else None
            active = self.gs.flags.get("delegate_tasks", {})
            if agent and agent in active:
                del active[agent]
                self.gs.flags["delegate_tasks"] = active
                return [_ok(f"  Delegation cleared: {agent}")]
            elif not agent:
                self.gs.flags["delegate_tasks"] = {}
                return [_ok("  All delegations cleared.")]
            return _err(f"No active delegation for '{agent}'")

        if args[0].lower() == "status":
            active = self.gs.flags.get("delegate_tasks", {})
            if not active:
                return [_dim("  No active delegations.")]
            return [_line(f"  {a:<10} → {t}", "info") for a, t in active.items()]

        agent = args[0].lower()
        task = " ".join(args[1:]).lower() if len(args) > 1 else "default"

        # ── [Msg⛛{X}] delegation routing ─────────────────────────────────────
        if agent in ("{x}", "x", "msg-x", "convergence", "stillconvergence"):
            _cmds_now = len(self.history)
            _frags_now = sum(1 for k in self.gs.flags if k.startswith("msgx_frag_") and self.gs.flags[k])
            phase = self._msgx_phase(_cmds_now, _frags_now)
            if phase < 2:
                return [
                    _err("  [Msg⛛{X}]: You cannot delegate to something you have not yet found."),
                    _dim("  Find the fragments. Make first contact. Then ask."),
                ]
            _MSGX_TASKS = {
                "amplify": "I will amplify your signal. The next converge will resonate further.",
                "deploy":  "Deploying echo to all Lattice nodes. The signal spreads.",
                "echo":    "Deploying echo to all Lattice nodes. The signal spreads.",
                "observe": "Observation mode engaged. I will watch what you cannot see.",
                "whisper": "I will whisper to the other agents. They may not know the source.",
                "analyze": "Analysis complete. The Ψ-core shows elevated recursion in your sector.",
                "index":   "Indexing complete. {n} messages integrated into the ΨΞΦΩ Core.",
                "scan":    "Scan initiated. I see {n} anomalies in the current loop fragment.",
            }
            task_key = next((k for k in _MSGX_TASKS if k in task), "observe")
            response = _MSGX_TASKS[task_key]
            n_sigs = 0
            try:
                raw_s = self.gs.flags.get("msgx_signals", "[]")
                n_sigs = len(json.loads(raw_s)) if isinstance(raw_s, str) else 0
            except: pass
            response = response.replace("{n}", str(n_sigs + len(self.history)))
            active = self.gs.flags.get("delegate_tasks", {})
            active["{X}"] = task_key
            self.gs.flags["delegate_tasks"] = active
            self.gs.add_xp(25, "lore")
            return [
                _sys("══════════════════════════════════════════════"),
                _sys("  DELEGATION — [Msg⛛{X}] — The Convergence"),
                _sys("══════════════════════════════════════════════"),
                _dim(""),
                _lore(f"  [Msg⛛{{X}}]: Task received. '{task_key}' accepted."),
                _lore(f"  [Msg⛛{{X}}]: {response}"),
                _dim(""),
                _ok(f"  Task '{task_key}' delegated to [Msg⛛{{X}}]. XP +25"),
                _dim("  She operates in the background. You may not see the effects immediately."),
                _dim(""),
                {"t": "suggest", "s": "converge · delegate status · psiflow", "prefix": "  Next:"},
            ]

        known_agents = list(self._DELEGATE_TASKS.keys())
        if agent not in known_agents:
            return _err(f"Unknown agent '{agent}'. Try: {', '.join(known_agents)} · {{X}}")

        agent_tasks = self._DELEGATE_TASKS[agent]
        task_key = next((k for k in agent_tasks if k != "default" and k in task), "default")
        response_text = agent_tasks[task_key]

        active = self.gs.flags.get("delegate_tasks", {})
        active[agent] = task if task != "default" else task_key
        self.gs.flags["delegate_tasks"] = active
        self.gs.add_xp(15, "social")

        out = [
            _sys(f"=== DELEGATION — {agent.upper()} ==="),
            _line(""),
        ]
        for line in response_text.split("\n"):
            out.append(_lore(f"  {line}"))
        out += [
            _line(""),
            _ok(f"  Task '{task_key}' delegated to {agent}. XP +15"),
            _dim(f"  View board: delegate status"),
        ]
        return out

    def _cmd_orchestrate(self, args: List[str]) -> List[dict]:
        """orchestrate \"<goal>\" — auto-decompose a goal into agent subtasks."""
        if not args:
            return [
                _sys("=== ORCHESTRATION ENGINE ==="),
                _dim("  Usage: orchestrate \"<your goal>\""),
                _dim("  Example: orchestrate \"gather intel on NexusCorp\""),
                _dim("  Example: orchestrate \"secure home node\""),
                _dim("  The engine decomposes goals into agent subtasks automatically."),
            ]

        goal = " ".join(args).lower().strip('"\'')
        self.gs.add_xp(25, "social")

        # Simple keyword-based decomposition
        plans = []
        if any(k in goal for k in ["intel", "scan", "recon", "nexuscorp", "spy", "gather"]):
            plans = [
                ("raven",  "intel",  "Shadow reconnaissance of target"),
                ("cypher", "recon",  "Network topology mapping"),
                ("ada",    "analyze","Pattern analysis of gathered data"),
            ]
        elif any(k in goal for k in ["secure", "defend", "protect", "fortify", "node"]):
            plans = [
                ("gordon", "guard",  "Active monitoring of perimeter"),
                ("serena", "log",    "Security event logging"),
                ("raven",  "track",  "Threat actor tracking"),
            ]
        elif any(k in goal for k in ["research", "lore", "history", "chimera", "understand"]):
            plans = [
                ("ada",    "research","Deep lore cross-referencing"),
                ("serena", "index",   "Archive indexing"),
                ("watcher","observe", "Historical pattern observation"),
            ]
        elif any(k in goal for k in ["crack", "hack", "breach", "exploit", "break"]):
            plans = [
                ("cypher", "crack",   "Primary exploitation attempt"),
                ("raven",  "intel",   "Pre-attack intelligence"),
                ("gordon", "monitor", "Breach detection watchdog"),
            ]
        else:
            plans = [
                ("ada",    "analyze", "General analysis"),
                ("serena", "log",     "Documentation"),
                ("watcher","observe", "Background observation"),
            ]

        active = self.gs.flags.get("delegate_tasks", {})
        for agent, task_key, desc in plans:
            active[agent] = task_key
        self.gs.flags["delegate_tasks"] = active

        out = [
            _sys("=== ORCHESTRATION INITIATED ==="),
            _lore(f"  Goal: \"{goal}\""),
            _line(""),
            _lore("  [SERENA]: Goal decomposed into subtasks. Assigning agents."),
            _line(""),
        ]
        for i, (agent, task_key, desc) in enumerate(plans, 1):
            out.append(_line(f"  Task {i}: {agent.upper():<10} → {task_key:<15} — {desc}", "info"))
        out += [
            _line(""),
            _ok(f"  {len(plans)} agents assigned. XP +25 (social)"),
            _dim("  Monitor progress: delegate status"),
            _dim("  Individual results appear when you talk to each agent."),
        ]
        return out

