    def _cmd_bazaar(self, args: List[str]) -> List[dict]:
        """bazaar [list [<cat>]|buy <item>|sell <item>|status] — the simulation's market node."""
        sub = args[0].lower() if args else "list"

        credits = self.gs.flags.get("credits", 500)  # Starting credits

        if sub == "status":
            inventory = self.gs.flags.get("bazaar_inventory", [])
            return [
                _sys("=== BAZAAR — YOUR ACCOUNT ==="),
                _line(f"  Credits:   {credits} ᶜ", "success"),
                _line(f"  Inventory: {len(inventory)} items", "info"),
                _dim("  bazaar list          — browse all items"),
                _dim("  bazaar list tools    — filter by category"),
                _dim("  bazaar buy <item>    — purchase an item"),
                _dim("  bazaar sell <item>   — sell an item (50% value)"),
            ]

        if sub == "list":
            cat_filter = args[1].lower() if len(args) > 1 else None
            cats = {"tools", "weapons", "armor", "consumables", "rare"}
            if cat_filter and cat_filter not in cats:
                return _err(f"Unknown category '{cat_filter}'. Try: {', '.join(sorted(cats))}")

            out = [
                _sys("=== THE BAZAAR — NODE-MARKET ==="),
                _lore("  [GORDON]: WELCOME TO THE BAZAAR!!! I DON'T WORK HERE BUT I LOVE IT!!!"),
                _line(f"  Your credits: {credits} ᶜ", "success"),
                _line(""),
            ]
            current_cat = None
            for item_id, item in self._BAZAAR_ITEMS.items():
                if cat_filter and item["cat"] != cat_filter:
                    continue
                if item["cat"] != current_cat:
                    current_cat = item["cat"]
                    out.append(_line(f"  ── {current_cat.upper()} ──", "warn"))
                owned = "✓" if item_id in self.gs.flags.get("bazaar_inventory", []) else " "
                can_afford = "✓" if credits >= item["price"] else "✗"
                price_color = "success" if credits >= item["price"] else "dim"
                out.append(_line(f"  {owned} {item_id:<22} {item['price']:>5} ᶜ  {item['desc'][:45]}", price_color))
            out += [
                _line(""),
                _dim("  bazaar buy <item-id>  — purchase"),
                _dim("  bazaar list <cat>     — filter (tools/weapons/armor/consumables/rare)"),
            ]
            return out

        if sub == "buy":
            if len(args) < 2:
                return _err("Usage: bazaar buy <item-id>")
            item_id = args[1].lower()
            item = self._BAZAAR_ITEMS.get(item_id)
            if not item:
                return _err(f"No item '{item_id}'. Run 'bazaar list' to browse.")
            if credits < item["price"]:
                return [
                    _err(f"  Insufficient credits. Need: {item['price']} ᶜ  Have: {credits} ᶜ"),
                    _dim("  Earn credits by: completing challenges, stock market, selling items."),
                ]
            inventory = self.gs.flags.get("bazaar_inventory", [])
            self.gs.flags["credits"] = credits - item["price"]
            inventory.append(item_id)
            self.gs.flags["bazaar_inventory"] = inventory
            self.gs.add_story_beat(f"bought_{item_id}")
            out = [
                _ok(f"  Purchased: {item_id}"),
                _dim(f"  {item['desc']}"),
                _line(f"  Credits remaining: {credits - item['price']} ᶜ", "info"),
            ]
            # Apply instant effects
            if item_id == "echo_fragment":
                self.gs.echo_level = getattr(self.gs, "echo_level", 0) + 1
                out.append(_ok(f"  Echo Level → {self.gs.echo_level}"))
            elif item_id == "ada_talisman":
                cur = self.gs.flags.get("trust_ada", 0)
                self.gs.flags["trust_ada"] = min(100, cur + 15)
                out.append(_ok("  Ada trust +15"))
            elif item_id == "lang_booster_py":
                old = self.gs.lang_proficiency.get("python", 0)
                self.gs.lang_proficiency["python"] = min(100, old + 10)
                out.append(_ok(f"  Python proficiency: {old} → {self.gs.lang_proficiency['python']}"))
            return out

        if sub == "sell":
            if len(args) < 2:
                return _err("Usage: bazaar sell <item-id>")
            item_id = args[1].lower()
            inventory = self.gs.flags.get("bazaar_inventory", [])
            if item_id not in inventory:
                return _err(f"'{item_id}' not in your inventory. bazaar status to see what you own.")
            item = self._BAZAAR_ITEMS.get(item_id, {"price": 100})
            sell_price = item["price"] // 2
            inventory.remove(item_id)
            self.gs.flags["bazaar_inventory"] = inventory
            self.gs.flags["credits"] = credits + sell_price
            return [
                _ok(f"  Sold: {item_id} for {sell_price} ᶜ"),
                _line(f"  Credits: {credits + sell_price} ᶜ", "success"),
            ]

        return _err("Usage: bazaar [list|buy <item>|sell <item>|status]")

