    def _cmd_protocols(self, args: List[str]) -> List[dict]:
        """protocols [list|set <name>|clear|status] — manage persistent agent behavior protocols."""
        sub = args[0].lower() if args else "status"
        active_protocol = self.gs.flags.get("active_protocol", None)
        directives = self.gs.flags.get("directives", [])

        if sub == "status":
            out = [
                _sys("=== PROTOCOL STATUS ==="),
                _line(f"  Active protocol: {active_protocol or '(none)'}", "success" if active_protocol else "dim"),
                _line(f"  Directives set:  {len(directives)}", "info"),
                _line(""),
                _dim("  protocols list          — view all available protocols"),
                _dim("  protocols set <name>    — activate a protocol"),
                _dim("  protocols clear         — deactivate current protocol"),
                _dim("  directive <text>        — set a persistent directive"),
            ]
            if active_protocol and active_protocol in self._PROTOCOL_DEFS:
                pd = self._PROTOCOL_DEFS[active_protocol]
                out += [_line(""), _lore(f"  Effect: {pd['effect']}", )]
            return out

        if sub == "list":
            out = [_sys("=== AVAILABLE PROTOCOLS ==="), _line("")]
            for name, pd in self._PROTOCOL_DEFS.items():
                is_active = name == active_protocol
                marker = "► ACTIVE" if is_active else "       "
                out.append(_line(f"  {marker}  {name:<20}  {pd['desc'][:50]}", "success" if is_active else "info"))
            out += [_line(""), _dim("  protocols set <name>  — activate")]
            return out

        if sub == "set":
            if len(args) < 2:
                return _err("Usage: protocols set <protocol-name>")
            name = args[1].lower()
            if name not in self._PROTOCOL_DEFS:
                return _err(f"Unknown protocol '{name}'. Try: protocols list")
            self.gs.flags["active_protocol"] = name
            self.gs.add_story_beat(f"protocol_{name}_activated")
            pd = self._PROTOCOL_DEFS[name]
            return [
                _ok(f"  Protocol activated: {name}"),
                _lore(f"  {pd['activation']}"),
                _dim(f"  Effect: {pd['effect']}"),
            ]

        if sub == "clear":
            self.gs.flags["active_protocol"] = None
            return [_ok("  Protocol cleared. Agents in default mode.")]

        return _err("Usage: protocols [list|set <name>|clear|status]")

    def _cmd_directive(self, args: List[str]) -> List[dict]:
        """directive <text> — set a persistent agent directive."""
        if not args:
            directives = self.gs.flags.get("directives", [])
            if not directives:
                return [
                    _sys("=== DIRECTIVES ==="),
                    _dim("  No active directives."),
                    _dim("  Usage: directive <instruction>"),
                    _dim("  Example: directive Alert me if Node-7 security changes"),
                    _dim("  Example: directive Protect Gordon at all costs"),
                ]
            out = [_sys("=== ACTIVE DIRECTIVES ==="), _line("")]
            for i, d in enumerate(directives, 1):
                out.append(_line(f"  {i:2}. {d}", "info"))
            out += [_line(""), _dim("  directive clear <n>  — remove directive by number")]
            return out

        if args[0].lower() == "clear":
            directives = self.gs.flags.get("directives", [])
            if len(args) > 1 and args[1].isdigit():
                idx = int(args[1]) - 1
                if 0 <= idx < len(directives):
                    removed = directives.pop(idx)
                    self.gs.flags["directives"] = directives
                    return [_ok(f"  Directive removed: {removed}")]
            directives.clear()
            self.gs.flags["directives"] = []
            return [_ok("  All directives cleared.")]

        text = " ".join(args)
        directives = self.gs.flags.get("directives", [])
        directives.append(text)
        self.gs.flags["directives"] = directives[-20:]  # Keep max 20

        # Agent acknowledgment based on directive content
        ack = "[SERENA]: Directive logged. I've flagged it in the operations register."
        lower_text = text.lower()
        if any(k in lower_text for k in ["alert", "notify", "watch", "monitor"]):
            ack = "[GORDON]: I'M WATCHING!!! DON'T WORRY!!!"
        elif any(k in lower_text for k in ["protect", "guard", "defend"]):
            ack = "[RAVEN]: Understood. I'll position myself accordingly."
        elif any(k in lower_text for k in ["gather", "find", "research", "intel"]):
            ack = "[ADA]: I've queued this into the research pipeline."
        elif any(k in lower_text for k in ["never", "stop", "don't"]):
            ack = "[WATCHER]: Constraint acknowledged."

        return [
            _ok(f"  Directive set: {text}"),
            _lore(f"  {ack}"),
            _dim(f"  Active directives: {len(directives)}"),
        ]

