    # FORGE — Item crafting system
    # ══════════════════════════════════════════════════════════════════════════

    _FORGE_RECIPES: Dict[str, dict] = {
        "stealth_cloak":    {"components": ["stealth_mod", "encryption_shell"], "result": "stealth_cloak",    "desc": "Renders you nearly undetectable in corporate nodes for 30 minutes."},
        "master_cracker":   {"components": ["cracker_v1", "inject_kit"],        "result": "master_cracker",   "desc": "Combines crack + inject. Bypasses 2-layer auth."},
        "siege_kit":        {"components": ["script_bomb", "hunter_repellent"],  "result": "siege_kit",        "desc": "Assault package. Clears a node of hunters, then lets you work."},
        "memory_crystal":   {"components": ["echo_fragment", "memory_elixir"],   "result": "memory_crystal",   "desc": "Crystallized cross-loop memory. Agents recall 3 past interactions."},
        "qi_amplifier":     {"components": ["qi_potion", "qi_potion"],           "result": "qi_amplifier",     "desc": "Double-strength Qi restoration. +100 Qi."},
        "watcher_lens":     {"components": ["ada_talisman", "nmap_advanced"],    "result": "watcher_lens",     "desc": "See what the Watcher sees. Reveals hidden nodes on the map."},
    }

    def _cmd_forge(self, args: List[str]) -> List[dict]:
        """forge [list|craft <recipe>|recipes] — craft new items from components."""
        sub = args[0].lower() if args else "list"

        if sub in ("list", "recipes"):
            inventory = self.gs.flags.get("bazaar_inventory", [])
            out = [
                _sys("=== THE FORGE — ITEM CRAFTING ==="),
                _lore("  [GORDON]: THE FORGE!!! FIRE AND CREATION!!!"),
                _line(""),
            ]
            for recipe_id, recipe in self._FORGE_RECIPES.items():
                comps = recipe["components"]
                can_craft = all(inventory.count(c) >= comps.count(c) for c in set(comps))
                marker = "✓" if can_craft else "✗"
                color = "success" if can_craft else "dim"
                out.append(_line(f"  {marker} {recipe_id:<20}  needs: {', '.join(comps)}", color))
                out.append(_dim(f"       → {recipe['desc'][:65]}"))
            out += [_line(""), _dim("  forge craft <recipe-id>  — craft an item")]
            return out

        if sub == "craft":
            if len(args) < 2:
                return _err("Usage: forge craft <recipe-id>")
            recipe_id = args[1].lower()
            if recipe_id not in self._FORGE_RECIPES:
                return _err(f"Unknown recipe '{recipe_id}'. Run 'forge list' to browse.")
            recipe = self._FORGE_RECIPES[recipe_id]
            inventory = self.gs.flags.get("bazaar_inventory", [])
            comps = recipe["components"]
            for c in set(comps):
                if inventory.count(c) < comps.count(c):
                    return [
                        _err(f"  Missing component: {c} (need {comps.count(c)}, have {inventory.count(c)})"),
                        _dim("  bazaar buy <item>  to acquire components"),
                    ]
            for c in comps:
                inventory.remove(c)
            result = recipe["result"]
            inventory.append(result)
            self.gs.flags["bazaar_inventory"] = inventory
            self.gs.add_story_beat(f"forged_{result}")
            self.gs.add_xp(50, "crafting")
            return [
                _ok(f"  Crafted: {result}"),
                _lore(f"  {recipe['desc']}"),
                _ok("  XP +50 (crafting)"),
                _dim("  Item added to your inventory."),
            ]

        return _err("Usage: forge [list|craft <recipe-id>]")

