    # TRAIN — Improve agent skills through delegation
    # ══════════════════════════════════════════════════════════════════════════

    _AGENT_SKILLS: Dict[str, Dict[str, int]] = {
        "ada":    {"analysis": 80, "social": 70, "hacking": 50, "stealth": 40},
        "cypher": {"hacking": 95, "stealth": 85, "analysis": 60, "social": 30},
        "gordon": {"social": 60, "analysis": 40, "hacking": 20, "stealth": 10},
        "raven":  {"stealth": 90, "analysis": 75, "social": 65, "hacking": 70},
        "serena": {"analysis": 85, "social": 55, "hacking": 30, "stealth": 45},
        "watcher":{"analysis": 100,"stealth": 100,"hacking": 80, "social": 50},
        "nova":   {"social": 90, "stealth": 75, "hacking": 65, "analysis": 70},
        "zero":   {"analysis": 70, "stealth": 80, "hacking": 60, "social": 20},
    }

    def _cmd_train(self, args: List[str]) -> List[dict]:
        """train <agent> <skill> — improve an agent's skill through focused sessions."""
        if not args:
            out = [
                _sys("=== AGENT TRAINING ==="),
                _dim("  Usage: train <agent> <skill>"),
                _dim("  Skills: hacking, analysis, social, stealth"),
                _dim("  Example: train cypher stealth"),
                _dim("  Example: train ada analysis"),
                _line(""),
            ]
            for agent, skills in self._AGENT_SKILLS.items():
                stored = self.gs.flags.get(f"trained_{agent}", {})
                combined = {k: min(100, v + stored.get(k, 0)) for k, v in skills.items()}
                skill_str = "  ".join(f"{k}:{v}" for k, v in combined.items())
                out.append(_dim(f"  {agent:<10}  {skill_str}"))
            return out

        agent = args[0].lower()
        skill = args[1].lower() if len(args) > 1 else ""
        known = list(self._AGENT_SKILLS.keys())
        valid_skills = {"hacking", "analysis", "social", "stealth"}

        if agent not in known:
            return _err(f"Unknown agent '{agent}'. Try: {', '.join(known[:6])}")
        if skill not in valid_skills:
            return _err(f"Unknown skill '{skill}'. Try: hacking, analysis, social, stealth")

        base = self._AGENT_SKILLS[agent].get(skill, 0)
        trained = self.gs.flags.get(f"trained_{agent}", {})
        bonus = trained.get(skill, 0)
        current = min(100, base + bonus)

        if current >= 100:
            return [
                _warn(f"  {agent.upper()} — {skill} is already at maximum (100)."),
                _dim("  Choose a different skill to train."),
            ]

        gain = 5
        new_bonus = bonus + gain
        trained[skill] = new_bonus
        self.gs.flags[f"trained_{agent}"] = trained
        self.gs.add_xp(20, "social")
        new_level = min(100, base + new_bonus)

        agent_reactions = {
            "ada":    f"[ADA]: The training helps. I can feel the {skill} pathways strengthening.",
            "cypher": f"[CYPHER]: I didn't need training. But I appreciate the attention.",
            "gordon": f"[GORDON]: I'M LEARNING!!! I'M GETTING BETTER AT {skill.upper()}!!!",
            "raven":  f"[RAVEN]: Noted. I'll apply the {skill} upgrade tonight.",
            "serena": f"[SERENA]: Training session logged. {skill.capitalize()} +{gain}. Efficient.",
            "watcher":f"[WATCHER]: You invest in others. Interesting.",
            "nova":   f"[NOVA]: Smart investment.",
            "zero":   f"[ZERO]: ...thank you.",
        }

        return [
            _ok(f"  {agent.upper()} — {skill} training complete"),
            _line(f"  {skill}:  {current} → {new_level}", "success"),
            _line(""),
            _lore(f"  {agent_reactions.get(agent, '[AGENT]: Training received.')}"),
            _ok("  XP +20 (social)"),
        ]

