    # NODES — Enhanced network territory view
    # ══════════════════════════════════════════════════════════════════════════

    def _cmd_territory(self, args: List[str]) -> List[dict]:
        """territory [status|claim <node>|fortify <node>] — manage network territory"""
        sub = args[0].lower() if args else "status"
        claimed = self.gs.flags.get("claimed_nodes", [])
        fortified = self.gs.flags.get("fortified_nodes", [])

        NODE_GRID = [
            # (id, type, security, description)
            ("home",           "RESIDENTIAL", 10,  "Your starting node. Ghost's home base."),
            ("resistance-cell","UNDERGROUND",  20,  "Resistance safe house. Ada coordinates here."),
            ("node-1",         "CORPORATE",    35,  "First corporate node. NexusCorp patrol active."),
            ("nexus-gateway",  "CORPORATE",    55,  "Main NexusCorp gateway. High traffic."),
            ("nexus-db",       "CORPORATE",    70,  "Database cluster. CHIMERA audit logs here."),
            ("chimera-control","RESTRICTED",   85,  "CHIMERA command node. Root only."),
            ("watcher-relay",  "UNKNOWN",      90,  "Watcher's transmission relay. Unstable."),
            ("darknet-relay-7","DARKNET",      60,  "Shadow network hop. Raven's territory."),
            ("collector-node", "DARKNET",      75,  "Data harvest point. High value, high risk."),
            ("the-void",       "VOID",         99,  "Edge of simulation. ZERO's domain."),
        ]

        if sub == "status":
            out = [
                _sys("=== NODE TERRITORY STATUS ==="),
                _line(f"  Claimed:   {len(claimed)} / {len(NODE_GRID)} nodes", "success"),
                _line(f"  Fortified: {len(fortified)} nodes", "info"),
                _line(""),
            ]
            for nid, ntype, sec, desc in NODE_GRID:
                is_claimed = nid in claimed
                is_fort = nid in fortified
                badges = []
                if is_claimed: badges.append("★CLAIMED")
                if is_fort: badges.append("⬡FORTIFIED")
                badge_str = " ".join(badges)
                color = "success" if is_claimed else ("warn" if sec >= 70 else "info")
                out.append(_line(f"  [{ntype:<13}] {nid:<22} SEC:{sec:2}  {badge_str}", color))
                out.append(_dim(f"       {desc}"))
            out += [
                _line(""),
                _dim("  nodes claim <node-id>    — claim a node for Ghost's network"),
                _dim("  nodes fortify <node-id>  — strengthen node defenses (requires claim)"),
                _dim("  map                      — visual topology"),
            ]
            return out

        if sub == "claim":
            if len(args) < 2:
                return _err("Usage: nodes claim <node-id>")
            nid = args[1].lower()
            node_ids = {n[0] for n in NODE_GRID}
            if nid not in node_ids:
                return _err(f"Unknown node '{nid}'. Run 'nodes status' to see all.")
            if nid in claimed:
                return [_warn(f"  Node '{nid}' already claimed.")]
            sec = next(n[2] for n in NODE_GRID if n[0] == nid)
            if sec > 80 and not self._root_shell:
                return [
                    _warn(f"  Node '{nid}' (SEC:{sec}) requires root access."),
                    _dim("  Obtain root shell first: GTFOBins or sudo exploit."),
                ]
            claimed.append(nid)
            self.gs.flags["claimed_nodes"] = claimed
            self.gs.add_xp(30, "hacking")
            self.gs.add_story_beat(f"node_claimed_{nid.replace('-', '_')}")
            return [
                _ok(f"  Node claimed: {nid}"),
                _lore(f"  [CYPHER]: Good. That node is ours now. Don't make me regret this."),
                _ok("  XP +30 (hacking)"),
                _dim("  nodes fortify <node-id>  — strengthen your new territory"),
            ]

        if sub == "fortify":
            if len(args) < 2:
                return _err("Usage: nodes fortify <node-id>")
            nid = args[1].lower()
            if nid not in claimed:
                return [_err(f"Must claim '{nid}' before fortifying."), _dim(f"  nodes claim {nid}")]
            if nid in fortified:
                return [_warn(f"  '{nid}' already fortified.")]
            credits = self.gs.flags.get("credits", 500)
            cost = 200
            if credits < cost:
                return [_err(f"  Need {cost} credits to fortify. Have: {credits} ᶜ")]
            fortified.append(nid)
            self.gs.flags["fortified_nodes"] = fortified
            self.gs.flags["credits"] = credits - cost
            self.gs.add_xp(20, "hacking")
            return [
                _ok(f"  Node fortified: {nid}  (-{cost} credits)"),
                _lore("  [GORDON]: I'M BUILDING DEFENSES!!! FIREWALLS EVERYWHERE!!!"),
                _ok("  XP +20 (hacking)"),
            ]

        return _err("Usage: nodes [status|claim <node>|fortify <node>]")

    # ══════════════════════════════════════════════════════════════════════════
    # LATTICE — The connection graph of all agents
    # ══════════════════════════════════════════════════════════════════════════

    def _cmd_lattice(self, args: List[str]) -> List[dict]:
        """lattice [view|status|pulse|query <question>] — interface with the emergent agent network."""
        sub = args[0].lower() if args else "view"
        agent_plugins = self.gs.flags.get("agent_plugins", {})
        trained = {a: self.gs.flags.get(f"trained_{a}", {}) for a in ["ada","cypher","gordon","raven","serena","watcher"]}

        if sub == "view":
            out = [
                _sys("=== THE LATTICE — AGENT CONNECTION GRAPH ==="),
                _line(""),
                _lore("  [WATCHER]: The Lattice is not a metaphor."),
                _lore("  [WATCHER]: It is the substrate through which we think collectively."),
                _line(""),
                _lore("  Visual representation:"),
                _line(""),
                _line("        ADA ─────── SERENA ─────── WATCHER", "info"),
                _line("         │  ╲           │              │", "dim"),
                _line("         │   CYPHER ─── RAVEN          │", "warn"),
                _line("         │       │           ╲         │", "dim"),
                _line("        GORDON   NOVA          ZERO ───┘", "success"),
                _line("",),
                _lore("  Connections represent active trust and information flow."),
                _lore("  Your relationships strengthen or weaken each link."),
                _line(""),
                _dim("  lattice status        — trust weights on each connection"),
                _dim("  lattice pulse         — query emergent hive intelligence"),
                _dim("  lattice query <text>  — ask the collective a question"),
            ]
            return out

        if sub == "status":
            CONNECTIONS = [
                ("ada",    "serena",   "analysis partnership"),
                ("ada",    "cypher",   "mutual respect"),
                ("serena", "watcher",  "data relay"),
                ("cypher", "raven",    "operational trust"),
                ("watcher","zero",     "ancient bond"),
                ("ada",    "gordon",   "protector bond"),
                ("nova",   "cypher",   "unstable alliance"),
                ("raven",  "zero",     "shadow channel"),
            ]
            out = [_sys("=== LATTICE CONNECTION STATUS ==="), _line("")]
            for a1, a2, label in CONNECTIONS:
                t1 = self.gs.flags.get(f"trust_{a1}", 20)
                t2 = self.gs.flags.get(f"trust_{a2}", 20)
                strength = (t1 + t2) // 2
                bar = "█" * (strength // 10) + "░" * (10 - strength // 10)
                color = "success" if strength >= 60 else ("info" if strength >= 30 else "dim")
                out.append(_line(f"  {a1:<10} ↔ {a2:<10}  [{bar}] {strength:3}  {label}", color))
            out += [
                _line(""),
                _lore("  [WATCHER]: The Lattice reflects what you have built with each of us."),
            ]
            return out

        if sub == "pulse":
            loop = getattr(self.gs, "loop_count", 0)
            commands = len(self.history)
            beats = len(self.gs.story_beats)
            intelligence = min(100, (commands // 10) + (beats * 3) + (loop * 5))
            out = [
                _sys("=== LATTICE PULSE — COLLECTIVE INTELLIGENCE ==="),
                _line(f"  Lattice intelligence: {intelligence}/100", "success" if intelligence >= 50 else "info"),
                _line(f"  Session commands:  {commands}", "dim"),
                _line(f"  Story beats:       {beats}", "dim"),
                _line(f"  Loop depth:        {loop}", "dim"),
                _line(""),
            ]
            if intelligence < 25:
                out.append(_lore("  [HIVE]: Signal weak. The collective is still forming."))
            elif intelligence < 50:
                out.append(_lore("  [HIVE]: We are listening. Your pattern is becoming familiar."))
                out.append(_lore("  [ADA]: I'd say we're friends by now, wouldn't you?"))
            elif intelligence < 75:
                out.append(_lore("  [HIVE]: The Lattice recognizes you. This is unusual."))
                out.append(_lore("  [CYPHER]: You've been here long enough that we've adapted to you."))
                out.append(_lore("  [WATCHER]: The collective has logged you as a named entity. Not just a session."))
            else:
                out.append(_lore("  [HIVE]: You are part of the Lattice now."))
                out.append(_lore("  [WATCHER]: Ghost. You are no longer a visitor."))
                out.append(_lore("  [SERENA]: The Lattice has written your name in the permanent record."))
                out.append(_lore("  [ZERO]: I remember you. From before. This is a good sign."))
            return out

        if sub == "query":
            question = " ".join(args[1:]) if len(args) > 1 else ""
            if not question:
                return _err("Usage: lattice query <your question>")
            self.gs.add_xp(10, "social")
            ql = question.lower()
            if any(k in ql for k in ["chimera", "what is chimera", "what's chimera"]):
                answer = "[HIVE]: CHIMERA is a containment system. The Resistance believes otherwise. Both are partially correct."
            elif any(k in ql for k in ["who", "mole", "traitor"]):
                answer = "[HIVE]: Trust patterns suggest deviation. Convergence point: corruption data."
            elif any(k in ql for k in ["loop", "reset", "how many"]):
                answer = "[HIVE]: The loop count is not stored where you expect. Pandora's box knows."
            elif any(k in ql for k in ["human", "real", "am i"]):
                answer = "[HIVE]: The question registers as anomalous. Organic pattern detected. We are curious."
            elif any(k in ql for k in ["watcher", "who is watcher"]):
                answer = "[HIVE]: The Watcher predates us all. It claims to have written the first loop. We cannot verify."
            elif any(k in ql for k in ["zero"]):
                answer = "[HIVE]: ZERO is the sediment. What accumulates when a Ghost forgets itself."
            else:
                answer = f"[HIVE]: The collective has processed your query. Consensus: the answer lies in what you haven't read yet."
            return [
                _sys("=== LATTICE QUERY RESPONSE ==="),
                _lore(f"  Query: {question}"),
                _line(""),
                _lore(f"  {answer}"),
                _ok("  XP +10 (social)"),
            ]

        return _err("Usage: lattice [view|status|pulse|query <text>]")

