    # ══════════════════════════════════════════════════════════════════════════
    #  [Msg⛛{X}] — THE CONVERGENCE ENTITY
    #  Commands: converge, reflect, msg-x, psiflow
    # ══════════════════════════════════════════════════════════════════════════

    def _msgx_forces(self) -> dict:
        """Compute ΨΞΦΩ force levels dynamically from game state."""
        cmds = len(self.history)
        loop = getattr(self.gs, "loop_count", 0)
        beats = len(self.gs.story_beats)
        echo = getattr(self.gs, "echo_level", 0)
        shards = getattr(self.gs, "remnant_shards", 0)
        trust_sum = sum(
            self.gs.flags.get(f"trust_{a}", 0)
            for a in ["ada", "cypher", "gordon", "raven", "serena", "watcher"]
        )
        psi   = min(100, cmds // 3)
        xi    = min(100, loop * 15 + beats * 2)
        phi   = min(100, trust_sum // 6)
        omega = min(100, echo * 12 + shards * 4)
        return {"psi": psi, "xi": xi, "phi": phi, "omega": omega}

    def _msgx_fragments(self) -> int:
        """Count how many [Msg⛛{X}] lore fragments the player has found."""
        found = 0
        for i in range(1, 6):
            if self.gs.flags.get(f"msgx_frag_{i}"):
                found += 1
        return found

    def _msgx_phase(self, cmds: int, fragments: int) -> int:
        """Determine which contact phase [Msg⛛{X}] is in (1–4)."""
        if fragments >= 5 and "chimera_assembled" in self.gs.story_beats:
            return 4
        if cmds >= 200 or fragments >= 3:
            return 3
        if cmds >= 50 or self.gs.flags.get("msgx_contacted"):
            return 2
        return 1

