    def _cmd_cultivator(self, args: List[str]) -> List[dict]:
        """
        cultivator [status|serena|gordon|analyze|help]
        The unified cultivation intelligence: Serena + Gordon + CHUG + LLM.
        Shows all three systems feeding the autonomous improvement loop.
        """
        sub = args[0].lower() if args else "status"
        out: List[dict] = []

        out += [
            _sys("╔══════════════════════════════════════════════════════════╗"),
            _sys("║           CULTIVATION INTELLIGENCE  — TRIPARTITE         ║"),
            _sys("║   SERENA (Convergence) + GORDON (Play) + CHUG (Build)    ║"),
            _sys("╚══════════════════════════════════════════════════════════╝"),
            _dim(""),
        ]

        if sub == "help":
            return out + [
                _sys("  Subcommands:"),
                _ok("    cultivator status    — Overview of all three systems"),
                _ok("    cultivator serena    — Serena's recent observations"),
                _ok("    cultivator gordon    — Gordon's learnings from autonomous play"),
                _ok("    cultivator analyze   — LLM synthesizes all signals into bullets"),
                _dim(""),
                _lore("  The three systems form a triangle:"),
                _lore("  SERENA watches the code. GORDON plays the game."),
                _lore("  CHUG improves the system. All feed each other."),
            ]

        if sub == "serena":
            try:
                from app.game_engine.signal_harvester import _read_serena_observations
                obs = _read_serena_observations(limit=8)
                out += [
                    _sys("  ─── SERENA MEMORY PALACE — RECENT OBSERVATIONS ────────────"),
                    _dim(f"  Total observations: {len(obs)}"),
                    _dim(""),
                ]
                if obs:
                    for o in obs[:5]:
                        sev = o.get("severity", "info")
                        icon = "⚠" if sev in ("warning", "critical") else "◈"
                        out.append(_ok(f"  {icon}  {o.get('content', '')[:70]}"))
                else:
                    out += [
                        _dim("  No observations yet."),
                        _dim("  Trigger: serena walk · omni audit · vantage all"),
                    ]
            except Exception as e:
                out.append(_err(f"  Serena unavailable: {e}"))
            return out + [
                _dim(""),
                {"t": "suggest", "s": "cultivator gordon · cultivator analyze · cultivator status", "prefix": "  Next:"},
            ]

        if sub == "gordon":
            try:
                from app.game_engine.signal_harvester import _read_gordon_learnings
                learnings = _read_gordon_learnings(limit=5)
                out += [
                    _sys("  ─── GORDON CHRONICLE — AUTONOMOUS PLAY LEARNINGS ──────────"),
                ]
                if learnings:
                    out.append(_ok(f"  {len(learnings)} recent entries:"))
                    out.append(_dim(""))
                    for e in learnings[:4]:
                        if e.get("learning"):
                            out.append(_ok(f"  ▸  {e['learning'][:72]}"))
                        elif e.get("action"):
                            out.append(_dim(f"  ·  [{e.get('outcome','?')}] {e['action'][:60]}"))
                else:
                    out += [
                        _dim("  Gordon has not played yet in this environment."),
                        _dim("  Start: python gordon_player.py --mode autonomous"),
                        _dim("  Docker: GORDON_DOCKER_HOST=host.docker.internal python gordon_player.py"),
                    ]
            except Exception as e:
                out.append(_err(f"  Gordon unavailable: {e}"))
            return out + [
                _dim(""),
                {"t": "suggest", "s": "cultivator serena · cultivator analyze · cultivator status", "prefix": "  Next:"},
            ]

        if sub == "analyze":
            if self.gs.level < 5:
                return out + [
                    _err("  CULTIVATION INTELLIGENCE requires Level 5"),
                    _dim("  The neural cultivator trusts only advanced operators."),
                ]
            out += [
                _sys("  ─── LLM CULTIVATION ANALYSIS ──────────────────────────────"),
                _dim("  Invoking synthesis: signals + Serena + Gordon → bullets..."),
                _dim(""),
            ]
            try:
                import requests as _req
                import os as _os
                dev_domain = _os.environ.get("REPLIT_DEV_DOMAIN", "")
                base = f"https://{dev_domain}" if dev_domain else "http://localhost:7337"
                r = _req.post(
                    f"{base}/api/cultivator/analyze",
                    json={"context_hint": "In-game analysis request from player"},
                    headers={"X-NuSyQ-Passkey": _os.environ.get("NUSYQ_PASSKEY", "")},
                    timeout=30,
                )
                data = r.json()
                if data.get("ok"):
                    self.gs.add_xp(75, "terminal")
                    self.gs.add_story_beat("cultivator_analyzed")
                    bullets = data.get("bullets", [])
                    for b in bullets:
                        icon = "▸"
                        if b.startswith("FIX"):
                            icon = "⚡"
                        elif b.startswith("DISCOVER"):
                            icon = "◈"
                        elif b.startswith("WIRE"):
                            icon = "⌁"
                        out.append(_ok(f"  {icon}  {b}"))
                    if not bullets:
                        out.append(_dim("  (No bullets generated — LLM response was empty)"))
                else:
                    out.append(_err(f"  Analysis failed: {data.get('error', 'unknown')}"))
            except Exception as e:
                out.append(_err(f"  Cultivator offline: {e}"))
                out.append(_dim("  (LLM backend may be unavailable — try again later)"))
            return out + [
                _dim(""),
                _lore("  The system has heard you. Improvement is non-linear."),
                {"t": "suggest", "s": "chug run · chug signals · reflect", "prefix": "  Next:"},
            ]

        # Default: status
        try:
            from app.game_engine.signal_harvester import get_stats
            stats = get_stats()
            serena_count = len(stats.get("serena_observations", []))
            gordon_count = len(stats.get("gordon_learnings", []))
            out += [
                _sys("  ─── SIGNAL SOURCES ─────────────────────────────────────────"),
                _ok(f"  Gameplay signals : {stats['total_signals']} commands across {stats['unique_cmds']} unique verbs"),
                _ok(f"  Serena           : {serena_count} recent observations in Memory Palace"),
                _ok(f"  Gordon           : {gordon_count} recent learnings from autonomous play"),
                _dim(""),
                _sys("  ─── CULTIVATION ARCHITECTURE ───────────────────────────────"),
                _dim(""),
                _ok("  SERENA  ΨΞΦΩ  Convergence Layer"),
                _dim("    Ψ-intake: walks the repository, indexes code"),
                _dim("    Ω-core:   Memory Palace (SQLite — never collapses)"),
                _dim("    Ξ-loops:  answers queries, detects drift"),
                _dim("    Φ-sync:   surfaces findings to CHUG + Gordon"),
                _dim(""),
                _ok("  GORDON  ★     Autonomous Player"),
                _dim("    Plays Terminal Depths 24/7 via REST API"),
                _dim("    Earns DP, triggers story beats, learns strategies"),
                _dim("    Chronicle feeds cultivation signals directly"),
                _dim(f"    API: {__import__('os').environ.get('GORDON_GAME_API', 'http://localhost:7337')}"),
                _dim(""),
                _ok("  CHUG    ⟳     Perpetual Improvement Engine"),
                _dim("    ASSESS → PLAN → EXECUTE → VERIFY → CONSOLIDATE → DOCUMENT → EXPORT"),
                _dim("    Reads signals + Serena + Gordon before every cycle"),
                _dim("    Auto-pushes improvements to GitHub"),
                _dim(""),
                _sys("  ─── LLM NEURAL CULTIVATOR ──────────────────────────────────"),
                _dim("  Endpoint: POST /api/cultivator/analyze"),
                _dim("  Input:    gameplay signals + Serena observations + Gordon learnings"),
                _dim("  Output:   ≤7 surgical improvement bullets via LLM"),
                _dim("  Auth:     NuSyQ passkey (X-NuSyQ-Passkey header)"),
                _dim(""),
                _lore("  Reach Level 5 to run: cultivator analyze"),
            ]
        except Exception as e:
            out.append(_err(f"  Cultivator status unavailable: {e}"))

        return out + [
            _dim(""),
            {"t": "suggest", "s": "cultivator serena · cultivator gordon · cultivator analyze", "prefix": "  Explore:"},
        ]

    def _cmd_chug(self, args: List[str]) -> List[dict]:
        """
        chug [status|signals|run|help]
        The CHUG Engine — gameplay cultivates the repository.
        Every command you type feeds the autonomous improvement loop.
        """
        sub = args[0].lower() if args else "status"
        out: List[dict] = []

        out += [
            _sys("╔══════════════════════════════════════════════════════════╗"),
            _sys("║         CHUG — CONTINUOUS HABITAT UPGRADE GENERATOR      ║"),
            _sys("║       Gameplay → Signals → Improvement → Auto-Push       ║"),
            _sys("╚══════════════════════════════════════════════════════════╝"),
            _dim(""),
        ]

        if sub in ("help", "?"):
            return out + [
                _sys("  Commands:"),
                _ok("    chug status    — CHUG engine state and cycle history"),
                _ok("    chug signals   — Gameplay signals powering the loop"),
                _ok("    chug run       — Trigger an ASSESS cycle now"),
                _dim(""),
                _lore("  Every command you type is a signal. Enough signals, and"),
                _lore("  the system wakes up and improves itself. You are not just"),
                _lore("  playing the game. You are building it."),
            ]

        if sub == "signals":
            try:
                from app.game_engine.signal_harvester import get_stats, get_cultivation_report
                stats = get_stats()
                report = get_cultivation_report()
                out += [
                    _sys("  ─── CULTIVATION SIGNALS ────────────────────────────────"),
                    _ok(f"  Total signals harvested : {stats['total_signals']}"),
                    _ok(f"  Unique commands observed: {stats['unique_cmds']}"),
                    _ok(f"  Story beats triggered   : {stats['beats']}"),
                    _dim(""),
                    _sys("  ─── MILESTONES REACHED ─────────────────────────────────"),
                ]
                if stats["milestones"]:
                    for m in stats["milestones"]:
                        out.append(_ok(f"  ✓  {m}"))
                else:
                    out.append(_dim("  (none yet — keep playing)"))
                out += [
                    _dim(""),
                    _sys("  ─── CHUG SUGGESTIONS (from your gameplay) ──────────────"),
                ]
                for s in report.get("chug_suggestions", []):
                    out.append(_ok(f"  ▸  {s}"))
                if report.get("undiscovered_features"):
                    out += [
                        _dim(""),
                        _dim(f"  Unexplored commands: {', '.join(report['undiscovered_features'][:6])}"),
                    ]
            except Exception as e:
                out.append(_err(f"  Signal harvester unavailable: {e}"))
            return out + [
                _dim(""),
                {"t": "suggest", "s": "chug run · chug status · signal <message>", "prefix": "  Next:"},
            ]

        if sub == "run":
            if self.gs.level < 3:
                return out + [
                    _err("  CHUG access denied — reach Level 3 first"),
                    _dim("  The engine trusts only those who have proven themselves."),
                ]
            out += [
                _sys("  ─── INITIATING CHUG ASSESS PHASE ──────────────────────"),
                _dim("  Scanning repository health..."),
            ]
            try:
                import subprocess as _sp
                import sys as _sys2
                from pathlib import Path as _Path
                chug_path = _Path(__file__).resolve().parent.parent.parent / "chug_engine.py"
                if chug_path.exists():
                    r = _sp.run(
                        [_sys2.executable, str(chug_path), "--phase", "1"],
                        capture_output=True, text=True, timeout=45,
                        cwd=str(chug_path.parent),
                    )
                    self.gs.add_xp(50, "terminal")
                    self.gs.add_story_beat("chug_manual_trigger")
                    out += [
                        _ok("  ASSESS phase complete."),
                        _ok("  Reports written to reports/health.json"),
                        _dim(""),
                        _ok(f"  Exit code: {r.returncode}"),
                    ]
                    for line in r.stdout.splitlines()[-5:]:
                        if line.strip():
                            out.append(_dim(f"  {line.strip()}"))
                else:
                    out.append(_err("  chug_engine.py not found"))
            except Exception as e:
                out.append(_err(f"  CHUG cycle failed: {e}"))
            return out + [
                _dim(""),
                _lore("  The engine has stirred. The repository is aware of your presence."),
                {"t": "suggest", "s": "chug signals · chug status · reflect", "prefix": "  Next:"},
            ]

        # Default: status
        try:
            import json as _json
            from pathlib import Path as _Path
            state_file = _Path(__file__).resolve().parent.parent.parent / ".devmentor" / "chug_state.json"
            if state_file.exists():
                state = _json.loads(state_file.read_text())
                out += [
                    _sys("  ─── CHUG ENGINE STATE ──────────────────────────────────"),
                    _ok(f"  Cycles completed       : {state.get('cycles_completed', 0)}"),
                    _ok(f"  Last cycle             : {state.get('last_cycle_time', 'Never')}"),
                    _ok(f"  Total issues found     : {state.get('total_issues_found', 0)}"),
                    _ok(f"  Total fixes applied    : {state.get('total_fixes_applied', 0)}"),
                    _ok(f"  Consecutive clean runs : {state.get('consecutive_clean_cycles', 0)}"),
                ]
            else:
                out += [
                    _dim("  CHUG has not run yet in this environment."),
                    _dim("  Try: chug run"),
                ]
        except Exception:
            out.append(_dim("  CHUG state unavailable."))

        out += [
            _dim(""),
            _sys("  ─── THE LOOP ───────────────────────────────────────────────"),
            _dim("  1. You play Terminal Depths. Every command is a signal."),
            _dim("  2. Signals accumulate in .devmentor/gameplay_signals.json"),
            _dim("  3. At milestone thresholds, CHUG wakes up and ASSESS runs."),
            _dim("  4. CHUG identifies improvements, applies fixes, commits."),
            _dim("  5. Auto-push sends changes to GitHub."),
            _dim("  6. VS Code pulls the update. The system grows."),
            _dim(""),
            _lore("  You are not just a player. You are a cultivation signal."),
            _lore("  The game builds itself through your engagement."),
            _dim(""),
            {"t": "suggest", "s": "chug signals · chug run · signal <message> · omni audit", "prefix": "  Explore:"},
        ]
        return out

