    def _evaluate_condition(self, condition: str) -> bool:
        """Evaluate simple bash [ ] conditions."""
        import re as _re
        cond = condition.strip().lstrip("[").rstrip("]").strip()
        # -f file  (file exists)
        if cond.startswith("-f "):
            path = cond[3:].strip().strip('"').strip("'")
            r = self.fs.cat(path)
            return not r.get("error")
        # -d dir
        if cond.startswith("-d "):
            path = cond[3:].strip().strip('"').strip("'")
            r = self.fs.ls(path)
            return not r.get("error")
        # -z string (empty)
        if cond.startswith("-z "):
            val = cond[3:].strip().strip('"').strip("'")
            return len(val) == 0
        # -n string (non-empty)
        if cond.startswith("-n "):
            val = cond[3:].strip().strip('"').strip("'")
            return len(val) > 0
        # string1 == string2
        m = _re.match(r'^(.+?)\s*==\s*(.+)$', cond)
        if m:
            return m.group(1).strip().strip('"').strip("'") == m.group(2).strip().strip('"').strip("'")
        # string1 != string2
        m = _re.match(r'^(.+?)\s*!=\s*(.+)$', cond)
        if m:
            return m.group(1).strip().strip('"').strip("'") != m.group(2).strip().strip('"').strip("'")
        # num -eq/-ne/-lt/-le/-gt/-ge
        m = _re.match(r'^(\d+)\s+(-eq|-ne|-lt|-le|-gt|-ge)\s+(\d+)$', cond)
        if m:
            a, op, b = int(m.group(1)), m.group(2), int(m.group(3))
            return {"eq": a == b, "ne": a != b, "lt": a < b, "le": a <= b, "gt": a > b, "ge": a >= b}.get(op[1:], False)
        return False

    def _execute_if_block(self, raw: str) -> List[dict]:
        """Parse and execute single-line: if [ cond ]; then CMD; fi"""
        import re as _re
        m = _re.match(r'^if\s+(.+?);\s*then\s+(.+?)\s*(?:else\s+(.+?)\s*)?fi$', raw, _re.DOTALL)
        if not m:
            return [_err("bash: parse error near 'if' — use: if [ cond ]; then CMD; fi")]
        condition, then_cmd = m.group(1).strip(), m.group(2).strip()
        else_cmd = m.group(3).strip() if m.group(3) else None
        out = [_dim(f"  $ if {condition}")]
        try:
            result = self._evaluate_condition(condition)
        except Exception:
            result = False
        if result:
            out.append(_dim(f"  → then: {then_cmd}"))
            out.extend(self.execute(then_cmd))
        elif else_cmd:
            out.append(_dim(f"  → else: {else_cmd}"))
            out.extend(self.execute(else_cmd))
        return out

    def _execute_for_block(self, raw: str) -> List[dict]:
        """Parse and execute single-line: for VAR in ITEMS; do CMD; done"""
        import re as _re
        m = _re.match(r'^for\s+(\w+)\s+in\s+(.+?);\s*do\s+(.+?)\s*done$', raw, _re.DOTALL)
        if not m:
            return [_err("bash: parse error near 'for' — use: for x in a b c; do CMD; done")]
        var, items_str, cmd_template = m.group(1), m.group(2).strip(), m.group(3).strip()
        # Parse items (simple space-split or brace expansion 1..N)
        brace_m = _re.match(r'^\{(\d+)\.\.(\d+)\}$', items_str)
        if brace_m:
            items = [str(i) for i in range(int(brace_m.group(1)), int(brace_m.group(2)) + 1)]
        else:
            items = items_str.split()
        MAX_ITER = 20
        out = [_dim(f"  $ for {var} in {items_str} (×{min(len(items), MAX_ITER)} iterations)")]
        for i, item in enumerate(items[:MAX_ITER]):
            cmd = cmd_template.replace(f"${var}", item).replace(f"${{{var}}}", item)
            out.append(_dim(f"  [{i+1}] {cmd}"))
            sub = self.execute(cmd)
            out.extend(sub[:10])  # cap output per iteration
        if len(items) > MAX_ITER:
            out.append(_dim(f"  ... (truncated at {MAX_ITER} iterations)"))
        return out

    def _execute_while_block(self, raw: str) -> List[dict]:
        """Simulate while loops — evaluate once and explain (no infinite loops)."""
        import re as _re
        m = _re.match(r'^while\s+(.+?);\s*do\s+(.+?)\s*done$', raw, _re.DOTALL)
        if not m:
            return [_err("bash: parse error near 'while' — use: while [ cond ]; do CMD; done")]
        cond, body = m.group(1).strip(), m.group(2).strip()
        out = [
            _dim(f"  $ while {cond}"),
            _lore("  [SYSTEM]: Interactive while loops are simulated in this terminal."),
            _dim("  Evaluating condition once..."),
        ]
        try:
            cond_true = self._evaluate_condition(cond)
        except Exception:
            cond_true = False
        if cond_true:
            out.append(_dim(f"  → Condition true; executing body: {body}"))
            out.extend(self.execute(body))
            out.append(_dim("  (loop would continue while condition remains true)"))
        else:
            out.append(_dim("  Condition is false; loop would not execute."))
        return out

