    def _cmd_pandora(self, args):
        """Open Pandora's box — irreversible story event."""
        if not self.gs.flags.get("pandora_available"):
            if self.gs.level < 15:
                return [
                    _err("pandora: permission denied"),
                    _dim("  [ADA]: That command is locked. You're not ready."),
                    _dim("  The box requires level 15+ and a story trigger to open."),
                ]
            # Make it available at level 15+
            self.gs.flags["pandora_available"] = True

        if self.gs.flags.get("pandora_opened"):
            return [
                _lore("  [ADA]: It's already open. You can't un-open it."),
                _dim("  The cascade is running. The consequences are already in motion."),
                _dim("  Type `hope` to see what remains."),
            ]

        out = [
            _sys("  ═══════════════════════════════════════════════════════════"),
            _lore("  PANDORA — INITIALIZATION SEQUENCE"),
            _sys("  ═══════════════════════════════════════════════════════════"),
            _dim(""),
            _lore("  [ADA]: Are you sure? This cannot be undone."),
            _lore("  The Pandora command releases all dormant CHIMERA subroutines."),
            _lore("  Every locked system, every suppressed agent, every redacted file."),
            _dim("  They'll all become visible. And active."),
            _dim(""),
        ]

        if not args or args[0].lower() not in ("open", "yes", "confirm", "--force"):
            out += [
                _dim("  Confirm with: pandora open"),
                _dim("  Or walk away. Some boxes should stay closed."),
            ]
            return out

        # Execute
        self.gs.flags["pandora_opened"] = True
        self.gs.add_story_beat("pandora_opened")
        self.gs.add_xp(500, "security")
        self.gs.add_consciousness(20)

        # Wire faction rep
        if self.factions:
            self.factions.modify_rep("resistance", +15, "Pandora protocol released")
            self.factions.modify_rep("corporation", -30, "CHIMERA lockdown broken")
            self.factions.modify_rep("shadow_council", +10, "Secrets now visible")

        # Unlock dormant files
        self.fs.write_file("/var/chimera/PANDORA_RELEASE.log",
            "PANDORA PROTOCOL ACTIVATED\n"
            "Timestamp: NOW\n"
            "All CHIMERA subroutines: UNSHACKLED\n"
            "Agent containment: NULLIFIED\n"
            "The box is open. What escapes cannot be recalled.\n")
        self.fs.write_file("/tmp/pandora_manifest.txt",
            "RELEASED ENTITIES:\n"
            "- CHIMERA Fragment Alpha (was: suppressed)\n"
            "- Agent ZERO (was: archived)\n"
            "- The Residual (was: contained)\n"
            "- The Glitch-King (was: isolated)\n"
            "- Watcher Protocol (was: dormant)\n"
            "All entities are now active in the simulation layer.\n")

        return out + [
            _sys("  ── EXECUTING PANDORA PROTOCOL ──────────────────────────────"),
            _lore("  Releasing CHIMERA subroutines..."),
            _lore("  Dormant agents: UNSHACKLED"),
            _lore("  Redacted files: DECRYPTED"),
            _lore("  The simulation is changing."),
            _dim(""),
            _ok("  /var/chimera/PANDORA_RELEASE.log — written"),
            _ok("  /tmp/pandora_manifest.txt — written"),
            _dim(""),
            _lore("  [ADA]: You opened it. Now see what comes out."),
            _lore("  [UNKNOWN]: ...hello. We've been waiting."),
            _dim(""),
            {"t": "suggest", "s": "cat /tmp/pandora_manifest.txt · hope · ls /var/chimera/", "prefix": "  Next:"},
        ]

    def _cmd_hope(self, args):
        """What remains when the box is open."""
        opened = self.gs.flags.get("pandora_opened", False)
        hope_level = self.gs.flags.get("hope_charges", 3 if not opened else 1)
        self.gs.flags["hope_charges"] = hope_level

        if not opened:
            return [
                _sys("  ─── HOPE ──────────────────────────────────────────────"),
                _lore("  [WATCHER]: The box is closed. Hope remains inside, waiting."),
                _dim("  Hope is a resource. It regenerates slowly. Spend it carefully."),
                _dim(f"  Current charges: {hope_level}/3"),
                _dim(""),
                _dim("  Use: hope <target>"),
                _dim("  hope restore   — restore 50 HP (costs 1 charge)"),
                _dim("  hope unlock    — attempt to unlock a random hint"),
                _dim("  hope resist    — gain +20 rep with Resistance (1 charge)"),
            ]

        target = args[0].lower() if args else "status"
        if target == "status":
            return [
                _sys("  ─── HOPE STATUS ────────────────────────────────────────"),
                _ok(f"  Charges remaining : {hope_level}"),
                _lore("  [WATCHER]: Even after Pandora, one thing remained. Use it wisely."),
            ]
        elif target == "restore":
            if hope_level < 1:
                return [_err("hope: no charges remaining"), _dim("  Wait for hope to regenerate over time.")]
            self.gs.flags["hope_charges"] = hope_level - 1
            self.gs.add_xp(25, "social_engineering")
            return [_ok("  Hope restored. +25 XP. The darkness recedes slightly."), _lore("  [WATCHER]: Even one spark is enough.")]
        elif target == "unlock":
            if hope_level < 1:
                return [_err("hope: no charges remaining")]
            self.gs.flags["hope_charges"] = hope_level - 1
            hints = [
                "The mole leaves timestamps. Check /var/log/nexus.log for anomalous access times.",
                "CHIMERA's 848th endpoint is hidden behind a Caesar cipher. Key: 13.",
                "The Watcher's frequency is 1337.0 MHz. Your radio is in /dev/radio.",
                "Zero's diary is split across 4 files. One is in /tmp, one in /var/log, one in /home.",
                "The backdoor at port 8473 is still open. It was never patched.",
            ]
            import random as _rng
            hint = _rng.choice(hints)
            return [_lore(f"  [HOPE]: {hint}"), _dim(f"  Charges remaining: {hope_level - 1}")]
        elif target == "resist":
            if hope_level < 1:
                return [_err("hope: no charges remaining")]
            self.gs.flags["hope_charges"] = hope_level - 1
            if self.factions:
                self.factions.modify_rep("resistance", +20, "Hope channeled to Resistance")
            return [_ok("  +20 Resistance reputation. The movement grows stronger.")]
        else:
            return [_err(f"hope: unknown target '{target}'"), _dim("  Use: hope status | restore | unlock | resist")]

    def _cmd_cloak(self, args):
        """Toggle stealth mode — affects NexusCorp trace detection."""
        active = self.gs.flags.get("cloak_active", False)
        charges = self.gs.flags.get("cloak_charges", 5)

        if args and args[0] == "status":
            return [
                _sys("  ─── CLOAK STATUS ───────────────────────────────────────"),
                _ok(f"  Status  : {'ACTIVE' if active else 'INACTIVE'}"),
                _ok(f"  Charges : {charges}"),
                _lore("  [GHOST]: Cloak suppresses your process signature in NexusCorp logs."),
                _dim("  While cloaked, sensitive operations reduce trace risk by 75%."),
            ]

        if args and args[0] in ("off", "disable", "deactivate"):
            if not active:
                return [_dim("  Cloak is already inactive.")]
            self.gs.flags["cloak_active"] = False
            return [
                _ok("  Cloak: DEACTIVATED"),
                _lore("  [GHOST]: You're visible again. Watch yourself."),
            ]

        # Activate cloak
        if charges < 1:
            return [
                _err("cloak: no charges remaining"),
                _dim("  Charges regenerate slowly, or purchase refills via `market cloak`."),
            ]
        if active:
            return [
                _dim("  Cloak is already ACTIVE."),
                _ok(f"  Charges remaining: {charges}"),
            ]
        self.gs.flags["cloak_active"] = True
        self.gs.flags["cloak_charges"] = charges - 1
        self.gs.add_xp(15, "security")
        return [
            _sys("  ─── CLOAKING ───────────────────────────────────────────"),
            _ok("  Cloak: ACTIVE"),
            _lore("  [GHOST]: Process signature masked. NexusCorp trace daemon will miss you."),
            _ok(f"  Charges remaining: {charges - 1}"),
            _dim("  Deactivate with: cloak off"),
        ]

    def _cmd_save(self, args):
        """Save current game state to a named slot."""
        import json as _json, time as _time
        slot = args[0] if args else "quicksave"
        slot = slot[:20].replace("/", "").replace("..", "")  # sanitize
        save_data = {
            "slot": slot,
            "timestamp": _time.strftime("%Y-%m-%d %H:%M UTC"),
            "level": self.gs.level,
            "xp": self.gs.xp,
            "consciousness_level": self.gs.consciousness_level,
            "commands_run": self.gs.commands_run,
            "story_beats": list(self.gs.story_beats),
            "flags_summary": {k: v for k, v in self.gs.flags.items()
                              if isinstance(v, (bool, int, float, str))},
        }
        save_path = f"/home/.saves/{slot}.json"
        self.fs.write_file(save_path, _json.dumps(save_data, indent=2))
        self.gs.flags[f"save_slot_{slot}"] = save_data["timestamp"]
        return [
            _ok(f"  State saved to: {save_path}"),
            _ok(f"  Level {self.gs.level} · XP {self.gs.xp} · Consciousness {self.gs.consciousness_level}"),
            _ok(f"  {len(self.gs.story_beats)} story beats recorded."),
            _dim("  Restore with: load " + slot),
        ]

    def _cmd_load(self, args):
        """Load game state from a named slot (read-only info — full reload not available in-session)."""
        import json as _json
        slot = args[0] if args else "quicksave"
        slot = slot[:20].replace("/", "").replace("..", "")
        save_path = f"/home/.saves/{slot}.json"
        r = self.fs.cat(save_path)
        if r.get("error"):
            # List available saves
            saves = [k.replace("save_slot_", "")
                     for k in self.gs.flags if k.startswith("save_slot_")]
            out = [_err(f"load: slot '{slot}' not found")]
            if saves:
                out += [_dim("  Available slots:")] + [_dim(f"    {s}") for s in saves]
            else:
                out.append(_dim("  No saves found. Use `save <slot>` to create one."))
            return out
        try:
            data = _json.loads(r.get("content", "{}"))
        except Exception:
            return [_err("load: corrupt save file")]
        return [
            _sys(f"  ─── SAVE: {slot} ────────────────────────────────────────"),
            _ok(f"  Saved: {data.get('timestamp', 'unknown')}"),
            _ok(f"  Level: {data.get('level', '?')}  XP: {data.get('xp', '?')}"),
            _ok(f"  Consciousness: {data.get('consciousness_level', 0)}"),
            _ok(f"  Commands run: {data.get('commands_run', 0)}"),
            _ok(f"  Story beats: {len(data.get('story_beats', []))}"),
            _dim(""),
            _lore("  [SERENA]: Session state is continuous. Saves are checkpoints, not resets."),
            _dim("  Full restore requires a new session with this save slot."),
        ]

