    def _cmd_backdoor(self, args):
        """Access or install a hidden backdoor in the system."""
        if not self._root_shell and not self.gs.flags.get("backdoor_capable"):
            return [
                _err("backdoor: permission denied"),
                _lore("  [CYPHER]: You need root first. Try `sudo su` or escalate privilege."),
                _dim("  Alternatively, find the pre-installed backdoor at port 8473."),
            ]

        sub = args[0].lower() if args else "status"

        if sub == "status":
            installed = self.gs.flags.get("backdoor_installed", False)
            port = self.gs.flags.get("backdoor_port", 8473)
            return [
                _sys("  ─── BACKDOOR STATUS ────────────────────────────────────"),
                _ok(f"  Installed : {'YES' if installed else 'NO'}"),
                _ok(f"  Port      : {port}"),
                _ok(f"  Auth key  : {'SET' if self.gs.flags.get('backdoor_key') else 'NONE'}"),
                _lore("  [CYPHER]: Keep this quiet. NexusCorp scans for anomalous ports."),
            ]

        elif sub in ("install", "create"):
            if self.gs.flags.get("backdoor_installed"):
                return [_dim("  Backdoor already installed. Check: backdoor status")]
            port = int(args[1]) if len(args) > 1 and args[1].isdigit() else 8473
            import random as _rng
            key = "".join(_rng.choices("0123456789abcdef", k=16))
            self.gs.flags["backdoor_installed"] = True
            self.gs.flags["backdoor_port"] = port
            self.gs.flags["backdoor_key"] = key
            self.gs.add_xp(75, "security")
            self.gs.add_story_beat("backdoor_installed")
            if self.factions:
                self.factions.modify_rep("resistance", +10, "Backdoor installed")
                self.factions.modify_rep("corporation", -15, "System compromised")
            self.fs.write_file("/var/log/.bd_init.log",
                f"BACKDOOR INIT: port={port} key={key[:4]}**** auth=key\n"
                "Status: LISTENING\nVisibility: HIDDEN\n")
            return [
                _ok(f"  Backdoor installed on port {port}"),
                _ok(f"  Auth key: {key[:4]}{'*' * 12}"),
                _dim("  Full key written to /var/log/.bd_init.log (root-only)"),
                _lore("  [CYPHER]: Clean. NexusCorp won't see it unless they audit port tables."),
                _ok("  +75 XP"),
            ]

        elif sub in ("remove", "uninstall"):
            if not self.gs.flags.get("backdoor_installed"):
                return [_dim("  No backdoor to remove.")]
            self.gs.flags["backdoor_installed"] = False
            self.gs.flags.pop("backdoor_port", None)
            self.gs.flags.pop("backdoor_key", None)
            return [_ok("  Backdoor removed. Clean slate.")]

        elif sub == "connect":
            if not self.gs.flags.get("backdoor_installed"):
                return [_err("backdoor: no backdoor installed — run: backdoor install")]
            port = self.gs.flags.get("backdoor_port", 8473)
            self.gs.add_xp(30, "security")
            return [
                _ok(f"  Connecting to localhost:{port}..."),
                _lore("  [CYPHER]: Channel open. Traffic is encrypted. Duration: 60s."),
                _dim("  You have an unlogged shell. Commands here bypass audit logs."),
                _dim("  (Simulated — use your regular shell freely)"),
            ]

        return [_err(f"backdoor: unknown subcommand '{sub}'"),
                _dim("  Use: backdoor status | install [port] | connect | remove")]

    def _cmd_locate(self, args):
        """Locate files by name pattern across the virtual filesystem."""
        import fnmatch as _fn
        if not args:
            return [_err("locate: specify a pattern"), _dim("  Usage: locate <pattern>")]

        pattern = args[0]
        out = [_sys(f"  ─── LOCATE: {pattern} ──────────────────────────────────")]

        # Search known paths
        search_paths = [
            "/", "/home", "/var", "/var/log", "/var/chimera", "/tmp",
            "/etc", "/etc/nexus", "/usr", "/proc", "/dev", "/opt",
        ]
        matches: List[str] = []
        for base in search_paths:
            r = self.fs.ls(base)
            if r.get("error"):
                continue
            for entry in r.get("entries", []):
                name = entry.get("name", "") if isinstance(entry, dict) else str(entry)
                if _fn.fnmatch(name.lower(), pattern.lower()) or pattern.lower() in name.lower():
                    matches.append(f"{base.rstrip('/')}/{name}")

        if not matches:
            out.append(_dim(f"  locate: no matches for '{pattern}'"))
        else:
            for m in matches[:25]:
                out.append(_ok(f"  {m}"))
            if len(matches) > 25:
                out.append(_dim(f"  ... ({len(matches) - 25} more results)"))

        self.gs.add_xp(5, "forensics")
        return out

