    def _faction_rep_event(self, event: str) -> List[dict]:
        """Apply predefined faction rep changes for named events, return notification lines."""
        if not self.factions:
            return []
        _events = {
            "root_gained":     [("resistance", +10), ("corporation", -10)],
            "mole_exposed":    [("resistance", +20), ("corporation", -15), ("shadow_council", -10)],
            "chimera_hack":    [("corporation", -20), ("resistance", +15), ("anomalous", +5)],
            "challenge_done":  [("specialist_guild", +5), ("algorithmic_guild", +5)],
            "talked_resistance": [("resistance", +5)],
            "talked_nexuscorp":  [("corporation", +5), ("resistance", -5)],
            "lore_read":       [("watchers_circle", +2)],
            "file_planted":    [("shadow_council", +5)],
            "pandora_opened":  [("resistance", +15), ("corporation", -30), ("shadow_council", +10)],
        }
        changes = _events.get(event, [])
        notifs = []
        for faction_id, delta in changes:
            try:
                self.factions.modify_rep(faction_id, delta, event)
                sign = "+" if delta > 0 else ""
                name = faction_id.replace("_", " ").title()
                notifs.append(_dim(f"  [{name}]: {sign}{delta} rep"))
            except Exception:
                pass
        return notifs

