    def _cmd_context(self, args: List[str]) -> List[dict]:
        """context — show the live ecosystem environment report (surface, services, siblings)."""
        compact = "--compact" in args or "-c" in args
        self.gs.add_xp(5, "debugging")
        try:
            import sys as _sys2, os as _os2
            _sys2.path.insert(0, str(__import__("pathlib").Path(__file__).parent.parent.parent))
            from core.environment import get_environment
            env = get_environment(refresh=True, probe=True)
            report = env.format_report(compact=compact)
            out: List[dict] = []
            for ln in report.splitlines():
                style = "system" if ln.startswith("╔") or ln.startswith("║") or ln.startswith("╚") else "dim"
                if "✓" in ln:
                    style = "success"
                elif "✗" in ln or "CRITICAL" in ln:
                    style = "error"
                elif "⚡" in ln or "warning" in ln.lower():
                    style = "warn"
                out.append({"t": style, "s": ln})
            plan = env.activation_plan()
            errors = [p for p in plan if p[0] == "error"]
            if errors:
                out += [
                    _dim(""),
                    _sys("  Run `plan` for step-by-step activation instructions."),
                ]
            return out
        except Exception as e:
            import os as _os3
            is_replit = bool(_os3.getenv("REPL_ID") or _os3.getenv("REPLIT_DEV_DOMAIN"))
            is_docker = __import__("pathlib").Path("/.dockerenv").exists()
            surface = "REPLIT" if is_replit else ("DOCKER" if is_docker else "LOCAL")
            return [
                _sys("=== ECOSYSTEM ENVIRONMENT ==="),
                _line(f"  Surface  : {surface}", "info"),
                _dim(f"  Hostname : {__import__('socket').gethostname()}"),
                _dim(""),
                _dim("  (Full report unavailable — core module loading failed)"),
                _dim(f"  Error: {e}"),
                _dim(""),
                _dim("  Type `surface` for the basic surface view."),
            ]

    def _cmd_plan(self, args: List[str]) -> List[dict]:
        """plan — show the ecosystem activation plan (what's dark, what to start)."""
        self.gs.add_xp(5, "debugging")
        try:
            _import_root = str(__import__("pathlib").Path(__file__).parent.parent.parent)
            import sys as _sys3
            if _import_root not in _sys3.path:
                _sys3.path.insert(0, _import_root)
            from core.environment import get_environment
            env = get_environment(probe=True)
            plan = env.activation_plan()
            out: List[dict] = [
                _sys("╔══════════════════════════════════════════════════════════╗"),
                _sys("║   ECOSYSTEM ACTIVATION PLAN                              ║"),
                _sys("╚══════════════════════════════════════════════════════════╝"),
                _dim(""),
            ]
            ok_items = [p for p in plan if p[0] == "ok"]
            err_items = [p for p in plan if p[0] == "error"]
            warn_items = [p for p in plan if p[0] == "warn"]
            if err_items:
                out.append(_sys("  CRITICAL — fix these first:"))
                for _, msg, cmd in err_items:
                    out.append({"t": "error", "s": f"    ✗ {msg}"})
                    if cmd:
                        out.append(_dim(f"      → {cmd}"))
                out.append(_dim(""))
            if warn_items:
                out.append(_sys("  WARNINGS (non-blocking):"))
                for _, msg, cmd in warn_items[:8]:
                    out.append({"t": "warn", "s": f"    · {msg}"})
                    if cmd:
                        out.append(_dim(f"      → {cmd}"))
                out.append(_dim(""))
            if ok_items:
                out.append(_sys("  NOMINAL:"))
                for _, msg, _ in ok_items[:10]:
                    out.append({"t": "success", "s": f"    ✓ {msg}"})
                out.append(_dim(""))
            # Surface-specific quickstart
            r = env.runtime
            out.append(_sys("  QUICKSTART:"))
            if r.is_replit:
                out += [
                    _dim("    • Game starts automatically via the DevMentor Console workflow"),
                    _dim("    • Open the Webview tab to play"),
                    _dim("    • Type `help` in the game terminal to begin"),
                ]
            elif r.is_container:
                out += [
                    _dim("    • ./scripts/cascade.sh core    — start offline core stack"),
                    _dim("    • ./scripts/cascade.sh full    — start full AI stack"),
                    _dim("    • python scripts/port_watcher.py --fix  — auto-fix dark ports"),
                ]
            elif r.is_vscode:
                out += [
                    _dim("    • Ctrl+Shift+B — DevMentor task panel"),
                    _dim("    • Run Task: Start DevMentor Server"),
                ]
            else:
                out += [
                    _dim("    • python -m cli.devmentor serve --host 0.0.0.0 --port 5000"),
                    _dim("    • python scripts/port_watcher.py --fix"),
                ]
            out += [
                _dim(""),
                _dim("  Type `context` for the full environment report."),
                _dim("  Type `surface` for the surface-specific tips."),
            ]
            return out
        except Exception as e:
            return [
                _err(f"plan: environment module unavailable — {e}"),
                _dim("  Try: python core/environment.py --plan"),
                _dim("  Or:  python scripts/port_watcher.py (port status)"),
            ]

