    def _cmd_meta(self, args: List[str]) -> List[dict]:
        """meta — unified agent health dashboard: all agents + environment context."""
        import socket as _sock_m, json as _json_m, os as _os_m, time as _time_m
        from pathlib import Path as _Path_m
        self.gs.add_xp(5, "debugging")
        out: List[dict] = [
            _sys("╔══════════════════════════════════════════════════════════╗"),
            _sys("║   META — AGENT HEALTH DASHBOARD                          ║"),
            _sys("╚══════════════════════════════════════════════════════════╝"),
            _dim(""),
        ]
        # ── Read port map ─────────────────────────────────────────────────
        _pm_path = _Path_m("config/port_map.json")
        _services: list = []
        if _pm_path.exists():
            try:
                _pm = _json_m.loads(_pm_path.read_text())
                for _grp in _pm.get("groups", {}).values():
                    _services.extend(_grp.get("services", []))
            except Exception:
                pass
        # ── Probe each service ────────────────────────────────────────────
        def _probe_m(host: str, port: int) -> bool:
            try:
                with _sock_m.create_connection((host, port), timeout=0.7):
                    return True
            except Exception:
                return False
        # Also load last port_status.json if available
        _ps_path = _Path_m("state/port_status.json")
        _cached: dict = {}
        if _ps_path.exists():
            try:
                _cached = _json_m.loads(_ps_path.read_text()).get("services", {})
            except Exception:
                pass
        _alive_m: List[str] = []
        _dark_m: List[str] = []
        out.append(_sys("  AGENTS:"))
        # Key agents to always show
        _AGENT_PORTS = [
            ("Terminal Depths API",         5000 if _os_m.getenv("REPL_ID") else 7337, "CORE"),
            ("Gordon (Orchestrator/Player)", 3000, "AI  "),
            ("Serena (Convergence Layer)",   3001, "AI  "),
            ("SkyClaw (Scanner)",            3002, "AI  "),
            ("Culture Ship (GSV)",           3003, "AI  "),
            ("Redis pub/sub",                6379, "CORE"),
            ("Ollama (LLM)",                 11434, "LLM "),
            ("LM Studio (LLM)",              1234,  "LLM "),
            ("OpenWebUI",                    3000,  "UI  "),
            ("RimAPI Bridge",                8765, "GAME"),
            ("Health Server",                3001, "CORE"),
        ]
        for _name_m, _port_m, _tier_m in _AGENT_PORTS:
            _alive = _probe_m("localhost", _port_m)
            _ico = "✓" if _alive else "·"
            _col = "success" if _alive else "dim"
            out.append({"t": _col, "s": f"    {_ico} [{_tier_m}] :{_port_m:<5}  {_name_m}"})
            (_alive_m if _alive else _dark_m).append(_name_m)
        out.append(_dim(""))
        # ── Environment context ───────────────────────────────────────────
        try:
            import sys as _sys_m2
            _root_m = str(_Path_m(__file__).parent.parent.parent)
            if _root_m not in _sys_m2.path:
                _sys_m2.path.insert(0, _root_m)
            from core.environment import get_environment as _get_env_m
            _env_m = _get_env_m(probe=False)
            _r_m = _env_m.runtime
            out += [
                _sys("  ENVIRONMENT:"),
                _line(f"    Surface  : {_r_m.name.upper()}", "info"),
                _line(f"    Shell    : {_r_m.shell}", "dim"),
                _line(f"    Network  : {'✓ reachable' if _env_m.network_ok else '· offline'}", "success" if _env_m.network_ok else "dim"),
                _dim(""),
            ]
        except Exception:
            pass
        # ── Gordon status ──────────────────────────────────────────────────
        _gs_path = _Path_m("state/gordon_status.json")
        if _gs_path.exists():
            try:
                _gs_data = _json_m.loads(_gs_path.read_text())
                _uptime = _gs_data.get("uptime_human", "?")
                _phase  = _gs_data.get("current_phase", "?")
                out += [
                    _sys("  GORDON:"),
                    _line(f"    Phase  : {_phase}", "info"),
                    _line(f"    Uptime : {_uptime}", "dim"),
                    _dim(""),
                ]
            except Exception:
                pass
        # ── Summary ────────────────────────────────────────────────────────
        out += [
            _sys("  SUMMARY:"),
            {"t": "success", "s": f"    ✓ {len(_alive_m)} agent(s) responding"},
            {"t": "dim"    , "s": f"    · {len(_dark_m)} dark (offline or not started)"},
            _dim(""),
            _dim("  `serena gaps`    — generate actionable fix list"),
            _dim("  `plan`           — ecosystem activation plan"),
            _dim("  `doctor`         — game engine diagnostics"),
        ]
        return out

    # ══════════════════════════════════════════════════════════════════════════
    # P8 — SHENZHEN I/O — CHIMERA Microcontroller Puzzles
    # ══════════════════════════════════════════════════════════════════════════

    def _cmd_shenzhen(self, args: List[str]) -> List[dict]:
        """shenzhen [list|load <N>|submit <N> <code>|hint <N>|simulate <code>] — CHIMERA microcontroller assembly puzzles."""
        try:
            from app.game_engine.shenzhen_engine import ShenzhenEngine, SHENZHEN_LEVELS
        except ImportError:
            return [
                _line("╔══════════════════════════════════════════════════════════╗", "system"),
                _line("║  SHENZHEN I/O — CHIMERA Microcontroller Lab              ║", "system"),
                _line("╚══════════════════════════════════════════════════════════╝", "system"),
                _line(""),
                _line("  [ENGINE NOT YET LOADED] — shenzhen_engine.py is initializing.", "warn"),
                _line("  This module requires the CHIMERA hardware layer to boot.", "dim"),
                _line("  Try again in a moment. Zod-Prime is reverse-engineering the instruction set.", "dim"),
            ]

        engine = ShenzhenEngine()
        sub = args[0].lower() if args else "list"

        if sub == "list":
            out = [
                _line("╔══════════════════════════════════════════════════════════════╗", "system"),
                _line("║  SHENZHEN I/O — CHIMERA Microcontroller Assembly Puzzles     ║", "system"),
                _line("╚══════════════════════════════════════════════════════════════╝", "system"),
                _line(""),
                _line("  CHIMERA-fabricated microcontrollers, recovered from Node-7's hardware layer.", "lore"),
                _line("  Zod-Prime reverse-engineered the instruction set. The ISA is minimal. The", "lore"),
                _line("  puzzles are not.", "lore"),
                _line(""),
            ]
            completed = self.gs.flags.get("shenzhen_completed", [])
            for i, lvl in enumerate(SHENZHEN_LEVELS, 1):
                done = i in completed
                marker = "✓" if done else "·"
                col = "success" if done else "dim"
                out.append(_line(f"  {marker} Level {i}: {lvl.get('name','Puzzle '+str(i))} [{lvl.get('chip_type','MC4000')}]", col))
                out.append(_line(f"       {lvl.get('description','')[:70]}", "dim"))
            out += [
                _line(""),
                _line("  shenzhen load <N>                — view puzzle", "dim"),
                _line("  shenzhen submit <N> <code...>    — submit assembly solution", "dim"),
                _line("  shenzhen hint <N>                — get a hint", "dim"),
            ]
            return out

        if sub == "load" and len(args) > 1:
            try:
                n = int(args[1])
            except ValueError:
                return _err("shenzhen load <N> — N must be a number")
            self.gs.flags["shenzhen_current"] = n
            result = engine.render_level(n)
            if not result:
                return _err(f"shenzhen: no puzzle at level {n}")
            self.gs.add_xp(2, "puzzle_engagement")
            return result

        if sub == "submit" and len(args) > 1:
            try:
                n = int(args[1])
            except ValueError:
                return _err("shenzhen submit <N> <code> — N must be a number")
            code = " ".join(args[2:])
            if not code:
                return _err("shenzhen submit <N> <code lines...> — provide assembly code")
            result = engine.submit_solution(n, code)
            if result.get("success"):
                completed = self.gs.flags.get("shenzhen_completed", [])
                if n not in completed:
                    completed.append(n)
                    self.gs.flags["shenzhen_completed"] = completed
                    self.gs.add_xp(80, "puzzle")
                    self.gs.add_story_beat(f"shenzhen_level_{n}_solved")
                    result["output"] = result.get("output", []) + [
                        _line(""),
                        _line(f"  +80 XP — MICROCONTROLLER MASTERY (Level {n})", "xp"),
                    ]
                    if len(completed) >= len(SHENZHEN_LEVELS):
                        result["output"].append(_line("  ★ ALL SHENZHEN PUZZLES SOLVED — Achievement unlocked: SILICON GHOST", "success"))
                        self.gs.add_achievement("SILICON_GHOST")
            return result.get("output", _err("shenzhen: simulation error"))

        if sub == "hint" and len(args) > 1:
            try:
                n = int(args[1])
            except ValueError:
                return _err("shenzhen hint <N>")
            return engine.render_level(n, hint=True) if hasattr(engine, 'render_level') else _err("No hint available")

        if sub == "simulate" and len(args) > 1:
            code = " ".join(args[1:])
            result = engine.simulate(code, "MC4000", [])
            return result.get("output", _err("simulation failed"))

        n = self.gs.flags.get("shenzhen_current", 1)
        return engine.render_level(n)

