    # P9 — CELLULAR AUTOMATA — Conway's Game of Life Puzzles
    # ══════════════════════════════════════════════════════════════════════════

    def _cmd_life(self, args: List[str]) -> List[dict]:
        """life [list|load <N>|next|run|solve|step <N>] — Conway\'s Game of Life puzzles. The Residual follows these rules."""
        try:
            from app.game_engine.cellular_automata import LifeEngine, LIFE_LEVELS
        except ImportError:
            return [
                _line("╔══════════════════════════════════════════════════════════╗", "system"),
                _line("║  CONWAY'S GAME OF LIFE — The Residual Protocol           ║", "system"),
                _line("╚══════════════════════════════════════════════════════════╝", "system"),
                _line(""),
                _line("  [ENGINE INITIALIZING] — cellular_automata.py loading.", "warn"),
                _line("  Serena first noticed the pattern in /var/log/kernel.boot.", "dim"),
                _line("  The timestamp drift follows a Life ruleset. Try again shortly.", "dim"),
            ]

        engine = LifeEngine()
        sub = args[0].lower() if args else "list"

        if sub == "list":
            out = [
                _line("╔══════════════════════════════════════════════════════════════╗", "system"),
                _line("║  CONWAY'S GAME OF LIFE — Cellular Automata Puzzles           ║", "system"),
                _line("╚══════════════════════════════════════════════════════════════╝", "system"),
                _line(""),
                _line("  The Residual exhibits cellular automata patterns.", "lore"),
                _line("  Serena first noticed it in /var/log/kernel.boot — the timestamp", "lore"),
                _line("  drift follows a Life ruleset. B3/S23. Always B3/S23.", "lore"),
                _line(""),
            ]
            completed = self.gs.flags.get("life_completed", [])
            for i, lvl in enumerate(LIFE_LEVELS, 1):
                done = i in completed
                marker = "✓" if done else "·"
                col = "success" if done else "dim"
                out.append(_line(f"  {marker} Level {i}: {lvl.get('name','Pattern '+str(i))}", col))
                out.append(_line(f"       {lvl.get('description','')[:72]}", "dim"))
            out += [
                _line(""),
                _line("  life load <N>    — load a puzzle", "dim"),
                _line("  life next        — advance one generation", "dim"),
                _line("  life run         — run to stability (max 100 gen)", "dim"),
                _line("  life solve       — reveal solution", "dim"),
            ]
            return out

        # Persistent grid state per puzzle
        current_n = self.gs.flags.get("life_current", 1)

        if sub == "load" and len(args) > 1:
            try:
                n = int(args[1])
            except ValueError:
                return _err("life load <N>")
            self.gs.flags["life_current"] = n
            self.gs.flags.pop("life_grid", None)
            self.gs.flags.pop("life_gen", None)
            self.gs.add_xp(2, "puzzle_engagement")
            return engine.render_level(n)

        if sub in ("next", "step"):
            steps = 1
            if sub == "step" and len(args) > 1:
                try:
                    steps = max(1, min(int(args[1]), 50))
                except ValueError:
                    steps = 1
            from app.game_engine.cellular_automata import _build_initial_grid as _life_build_grid
            _life_lvl_data = engine.get_level(current_n) or {}
            grid = self.gs.flags.get("life_grid") or _life_build_grid(_life_lvl_data)
            gen  = self.gs.flags.get("life_gen", 0)
            for _ in range(steps):
                grid = engine.step(current_n, grid)
                gen += 1
            self.gs.flags["life_grid"] = grid
            self.gs.flags["life_gen"]  = gen
            out = engine.render_grid(grid)
            out.insert(0, _line(f"  Generation {gen}", "info"))
            # Check win
            if engine.check_win(current_n, grid, gen):
                completed = self.gs.flags.get("life_completed", [])
                if current_n not in completed:
                    completed.append(current_n)
                    self.gs.flags["life_completed"] = completed
                    self.gs.add_xp(60, "puzzle")
                    self.gs.add_story_beat(f"life_level_{current_n}_solved")
                    if current_n == 5:
                        self.gs.add_story_beat("zero_fragment_4")
                    out += [
                        _line(""),
                        _line(f"  ✓ PATTERN ACHIEVED — Level {current_n} solved!", "success"),
                        _line(f"  +60 XP — AUTOMATA ADEPT", "xp"),
                    ]
                    if current_n == 1:
                        # Inject AUTOMATA.md into VFS using write_file
                        try:
                            _automata_content = (
                                "# AUTOMATA.md\n\n"
                                "The Residual follows Rule B3/S23.\n"
                                "Every living cell with 2-3 neighbors survives.\n"
                                "Every dead cell with exactly 3 neighbors is born.\n\n"
                                "ZERO's message was encoded in the kernel boot timestamps:\n"
                                "  iteration 0: 1 3 3  (birth rule)\n"
                                "  iteration 1: 2 3    (survival rule)\n\n"
                                "The Cathedral-Mesh substrate propagates using these rules.\n"
                                "The Residual IS the Game of Life. You are a cell.\n"
                                "CHIMERA is the boundary condition.\n"
                            )
                            # Ensure parent dir exists
                            self.fs.mkdir("/opt/library/secret_annex", parents=True)
                            self.fs.write_file("/opt/library/secret_annex/AUTOMATA.md", _automata_content)
                        except Exception:
                            pass
                        out.append(_line("  [UNLOCK] /opt/library/secret_annex/AUTOMATA.md injected into filesystem", "lore"))
            return out

        if sub == "run":
            from app.game_engine.cellular_automata import _build_initial_grid as _life_build_grid
            _life_lvl_data = engine.get_level(current_n) or {}
            grid = self.gs.flags.get("life_grid") or _life_build_grid(_life_lvl_data)
            gen  = self.gs.flags.get("life_gen", 0)
            grid, final_gen = engine.run_to_stable(grid, max_gen=100)
            gen += final_gen
            self.gs.flags["life_grid"] = grid
            self.gs.flags["life_gen"]  = gen
            out = [_line(f"  Ran {final_gen} generation(s) → Generation {gen}", "info")]
            out += engine.render_grid(grid)
            if engine.check_win(current_n, grid, gen):
                completed = self.gs.flags.get("life_completed", [])
                if current_n not in completed:
                    completed.append(current_n)
                    self.gs.flags["life_completed"] = completed
                    self.gs.add_xp(60, "puzzle")
                    out += [_line(""), _line(f"  ✓ SOLVED — Level {current_n}", "success"), _line("  +60 XP", "xp")]
            return out

        if sub == "solve":
            return engine.render_level(current_n, show_solution=True) if hasattr(engine, 'render_level') else _err("No solution available")

        return engine.render_level(current_n)

    # ══════════════════════════════════════════════════════════════════════════
    # P10 — GRAPH THEORY — Daedalus-7's Network Mathematics Puzzles
    # ══════════════════════════════════════════════════════════════════════════

    def _cmd_graph_theory(self, args: List[str]) -> List[dict]:
        """graph-theory [list|load <N>|answer <N> <solution>|hint <N>|solve <N>] — Graph theory puzzles. Daedalus-7 assigns."""
        try:
            from app.game_engine.graph_theory_engine import GraphTheoryEngine, GRAPH_LEVELS
        except ImportError:
            return [
                _line("╔══════════════════════════════════════════════════════════╗", "system"),
                _line("║  GRAPH THEORY — Daedalus-7 Network Mathematics           ║", "system"),
                _line("╚══════════════════════════════════════════════════════════╝", "system"),
                _line(""),
                _line("  [ENGINE INITIALIZING] — graph_theory_engine.py loading.", "warn"),
                _line("  Daedalus-7 says: 'Graph theory is the mathematics of everything", "dim"),
                _line("  CHIMERA knows about you — your connections, your shortest paths,", "dim"),
                _line("  your vulnerabilities.' Try again shortly.", "dim"),
            ]

        engine = GraphTheoryEngine()
        sub = args[0].lower() if args else "list"

        if sub == "list":
            out = [
                _line("╔══════════════════════════════════════════════════════════════╗", "system"),
                _line("║  GRAPH THEORY — Daedalus-7's Network Mathematics             ║", "system"),
                _line("╚══════════════════════════════════════════════════════════════╝", "system"),
                _line(""),
                _line("  'Graph theory is the mathematics of everything CHIMERA knows", "lore"),
                _line("   about you — your connections, your shortest paths, your", "lore"),
                _line("   vulnerabilities.' — Daedalus-7", "lore"),
                _line(""),
            ]
            completed = self.gs.flags.get("graph_theory_completed", [])
            categories = ["SHORTEST PATH", "GRAPH COLORING", "TSP", "SPANNING TREE", "FLOW NETWORK", "TOPO SORT"]
            for i, lvl in enumerate(GRAPH_LEVELS, 1):
                done = i in completed
                marker = "✓" if done else "·"
                col = "success" if done else "dim"
                cat_idx = (i - 1) // 2
                cat = categories[cat_idx] if cat_idx < len(categories) else ""
                out.append(_line(f"  {marker} Level {i:>2}: [{cat}] {lvl.get('name','Puzzle '+str(i))}", col))
            out += [
                _line(""),
                _line("  graph-theory load <N>                    — view puzzle", "dim"),
                _line("  graph-theory answer <N> <solution...>    — submit answer", "dim"),
                _line("  graph-theory hint <N>                    — hint", "dim"),
                _line("  graph-theory solve <N>                   — reveal solution", "dim"),
            ]
            return out

        if sub == "load" and len(args) > 1:
            try:
                n = int(args[1])
            except ValueError:
                return _err("graph-theory load <N>")
            self.gs.flags["graph_theory_current"] = n
            self.gs.add_xp(2, "puzzle_engagement")
            return engine.render_level(n)

        if sub == "answer" and len(args) > 1:
            try:
                n = int(args[1])
            except ValueError:
                return _err("graph-theory answer <N> <solution...>")
            answer = " ".join(args[2:])
            # GraphTheoryEngine.check_answer expects List[str] tokens
            result = engine.check_answer(n, answer.strip().split())
            if result.get("correct"):
                completed = self.gs.flags.get("graph_theory_completed", [])
                if n not in completed:
                    completed.append(n)
                    self.gs.flags["graph_theory_completed"] = completed
                    xp_reward = 70 + (n * 5)
                    self.gs.add_xp(xp_reward, "puzzle")
                    self.gs.add_story_beat(f"graph_theory_level_{n}_solved")
                    result["feedback"] = result.get("feedback", []) + [
                        _line(""),
                        _line(f"  +{xp_reward} XP — NETWORK ANALYST (Level {n})", "xp"),
                    ]
                    if len(completed) >= len(GRAPH_LEVELS):
                        result["feedback"].append(_line("  ★ ALL GRAPH PUZZLES SOLVED — Daedalus-7 nods approvingly.", "success"))
                        self.gs.add_achievement("GRAPH_TRAVERSER")
            return result.get("feedback", _err("graph-theory: check failed"))

        if sub == "hint" and len(args) > 1:
            try:
                n = int(args[1])
            except ValueError:
                return _err("graph-theory hint <N>")
            return engine.hint(n)

        if sub == "solve" and len(args) > 1:
            try:
                n = int(args[1])
            except ValueError:
                return _err("graph-theory solve <N>")
            return engine.solve(n)

        n = self.gs.flags.get("graph_theory_current", 1)
        return engine.render_level(n)

    def _cmd_number_theory(self, args: List[str]) -> List[dict]:
        """number-theory [list|load <N>|answer <N> <ans>|hint <N>|solve <N>] — prime factorization, RSA crack, modular arithmetic, discrete log."""
        try:
            from app.game_engine.number_theory_engine import NumberTheoryEngine
            engine = NumberTheoryEngine()
        except Exception as exc:
            return [
                _line("  [ENGINE INITIALIZING] — number_theory_engine.py loading.", "warn"),
                _line(f"  Error: {exc}", "error"),
            ]

        sub = args[0].lower() if args else "list"
        completed = self.gs.flags.get("number_theory_completed", [])

        if sub == "list":
            return engine.list_puzzles(completed)

        if sub == "load":
            if len(args) < 2:
                return [_err("number-theory load <N>")]
            try:
                n = int(args[1])
            except ValueError:
                return [_err("number-theory load <N> — N must be a number")]
            self.gs.flags["number_theory_current"] = n
            return engine.load_puzzle(n)

        if sub == "hint":
            if len(args) < 2:
                return [_err("number-theory hint <N>")]
            try:
                n = int(args[1])
            except ValueError:
                return [_err("number-theory hint <N>")]
            self.gs.add_xp(-5, "cryptography")
            return engine.hint(n)

        if sub in ("answer", "submit"):
            if len(args) < 3:
                return [_err("number-theory answer <N> <answer...>")]
            try:
                n = int(args[1])
            except ValueError:
                return [_err("number-theory answer <N> <answer...> — N must be a number")]
            result = engine.answer(n, args[2:])
            if result.get("ok"):
                if n not in completed:
                    completed.append(n)
                    self.gs.flags["number_theory_completed"] = completed
                self.gs.add_xp(result.get("xp", 30), "cryptography")
                ach = result.get("achievement")
                if ach:
                    self.gs.add_story_beat(f"number_theory_{ach.lower()}")
                if n == 10:
                    self.gs.add_story_beat("zero_fragment_6")
            return result.get("output", [_err("number-theory: engine error")])

        if sub == "solve":
            if len(args) < 2:
                return [_err("number-theory solve <N>")]
            try:
                n = int(args[1])
            except ValueError:
                return [_err("number-theory solve <N>")]
            self.gs.add_xp(-10, "cryptography")
            return engine.solve(n)

        n = self.gs.flags.get("number_theory_current", 1)
        return engine.load_puzzle(n)

    def _cmd_sleep(self, args: List[str]) -> List[dict]:
        """sleep — enter REM state and dream; Ghost processes recent events into surreal visions."""
        try:
            from app.game_engine.dream_engine import sleep_command
        except Exception as exc:
            return [_err(f"Dream engine error: {exc}")]

        result = sleep_command(
            flags=self.gs.flags,
            story_beats=list(getattr(self.gs, "story_beats", [])),
            unlocked_agents=getattr(self.gs, "unlocked_agents", []),
        )
        out = result.get("output", [])
        xp = result.get("xp", 0)
        skill = result.get("skill")
        if xp and skill:
            self.gs.add_xp(xp, skill)
        lore_hint = result.get("lore_hint")
        if lore_hint:
            # Flag that this lore was hinted in a dream
            self.gs.flags.setdefault("dream_hints", [])
            if lore_hint not in self.gs.flags["dream_hints"]:
                self.gs.flags["dream_hints"].append(lore_hint)
        return out

    def _cmd_basement(self, args: List[str]) -> List[dict]:
        """basement [start|map|go <dir>|look|take|fight|flee|status] — descend into /opt/library/.basement dungeon."""
        try:
            from app.game_engine.dungeon_engine import DungeonEngine
        except Exception as exc:
            return [_err(f"Dungeon engine error: {exc}")]

        engine = DungeonEngine()
        sub = args[0].lower() if args else ""
        state = self.gs.flags.get("dungeon")

        # Check if dungeon is active
        if not state or not state.get("active"):
            if sub == "start" or not sub:
                state, out = engine.start(self.gs.flags)
                return out
            else:
                return [
                    _warn("  No active dungeon run. Enter: basement start"),
                    _dim("  Warning: the Basement resets on each descent. Loot is permanent."),
                ]

        if sub == "map":
            from app.game_engine.dungeon_engine import render_map
            return render_map(state)

        if sub == "look" or not sub:
            return engine.look(state)

        if sub == "go":
            if len(args) < 2:
                return [_err("basement go <north|south|east|west|up|down>")]
            direction = args[1].lower()
            state, out = engine.go(direction, state)
            self.gs.flags["dungeon"] = state
            return out

        if sub == "fight":
            from app.game_engine.difficulty import get_difficulty
            diff = get_difficulty()
            state, out, xp = engine.fight(state, hp_scale=diff.get_scale(self.gs.flags))
            self.gs.flags["dungeon"] = state
            if xp:
                scaled_xp = diff.scale_xp(xp, self.gs.flags)
                self.gs.add_xp(scaled_xp, "security")
                diff.record_event(self.gs.flags, "success", level=self.gs.level)
            else:
                diff.record_event(self.gs.flags, "failure", level=self.gs.level)
            if not state.get("active"):
                self.gs.flags["dungeon"]["active"] = False
            return out

        if sub == "take":
            state, out, xp = engine.take(state)
            self.gs.flags["dungeon"] = state
            if xp:
                self.gs.add_xp(xp, "terminal")
            return out

        if sub == "flee":
            state, out = engine.flee(state)
            self.gs.flags["dungeon"] = state
            return out

        if sub == "status":
            return engine.status(state)

        if sub == "start":
            # Restart dungeon
            state, out = engine.start(self.gs.flags)
            return out

        return [_err(f"basement: unknown subcommand '{sub}'. Try: start map go look take fight flee status")]

