    def _cmd_missions(self, args: List[str]) -> List[dict]:
        """missions [refresh] — AI-generated procedural missions tailored to your current progress."""
        try:
            from app.game_engine.procgen_quests import QuestGenerator, render_procgen_quests
        except Exception as exc:
            return [_err(f"Missions engine error: {exc}")]

        state_dict = {
            "level": self.gs.level,
            "xp": self.gs.xp,
            "story_beats": list(getattr(self.gs, "story_beats", [])),
            "skills": self.gs.skills,
            "faction_reps": getattr(self.gs, "faction_reps", {}),
        }

        # Cache missions for 5 minutes unless 'refresh'
        cached = self.gs.flags.get("cached_missions")
        cache_ts = self.gs.flags.get("cached_missions_ts", 0)
        sub = args[0].lower() if args else ""
        if cached and (sub != "refresh") and (time.time() - cache_ts < 300):
            return render_procgen_quests(cached)

        gen = QuestGenerator()
        missions = gen.generate(state_dict, count=4)
        self.gs.flags["cached_missions"] = missions
        self.gs.flags["cached_missions_ts"] = time.time()
        return render_procgen_quests(missions)

    def _cmd_class(self, args: List[str]) -> List[dict]:
        """class [choose <name>|info <name>] — at Level 10, choose your specialization class."""
        from app.game_engine.class_system import ClassSystem, CLASS_DEFINITIONS
        cs = ClassSystem()

        sub = args[0].lower() if args else ""

        if sub == "choose":
            if len(args) < 2:
                return [
                    _err("  Usage: class choose <name>"),
                    _dim("  Run 'class' with no arguments to see available classes."),
                ]
            return cs.choose(args[1], self.gs)

        if sub == "info":
            if len(args) < 2:
                return [_err("  Usage: class info <name>")]
            name = args[1].lower()
            defn = CLASS_DEFINITIONS.get(name)
            if not defn:
                matches = [k for k in CLASS_DEFINITIONS if k.startswith(name)]
                if len(matches) == 1:
                    name = matches[0]
                    defn = CLASS_DEFINITIONS[name]
                else:
                    return [_err(f"Unknown class '{name}'. Run 'class' to see options.")]
            icon = defn.get("icon", "★")
            return [
                _sys(""),
                _sys(f"  {icon}  {defn['name'].upper()}"),
                _dim(""),
                _line(f"  {defn['description']}", "info"),
                _dim(""),
                _line(f"  Bonus skills : {', '.join(defn['bonus_skills'])}", "info"),
                _line(f"  Passive      : {defn['passive']}", "info"),
                _line(f"  Ability      : {defn['ability']}", "info"),
                _dim(f"  Unlock       : Level {defn.get('unlock_level', 10)}"),
                _dim(""),
                _dim("  To choose this class: class choose " + name),
                _dim(""),
            ]

        if sub == "prestige":
            if len(args) < 2:
                # Show prestige class options
                primary = self.gs.flags.get("player_class")
                prestige = self.gs.flags.get("prestige_class")
                if prestige:
                    defn = CLASS_DEFINITIONS.get(prestige, {})
                    primary_defn = CLASS_DEFINITIONS.get(primary, {})
                    return [
                        _ok(f"  Prestige class: {defn.get('icon','★')}  {defn.get('name', prestige)}"),
                        _ok(f"  Primary class:  {primary_defn.get('icon','★')}  {primary_defn.get('name', primary)}"),
                        _dim("  Dual-path is locked. Only rebirth can reset it."),
                    ]
                return cs.render_prestige_classes(self.gs.level, primary)
            return cs.choose_prestige(args[1], self.gs)

        # No subcommand — show class list
        current = self.gs.flags.get("player_class")
        prestige = self.gs.flags.get("prestige_class")
        out = cs.render_classes(self.gs.level)
        if current:
            defn = CLASS_DEFINITIONS.get(current, {})
            icon = defn.get("icon", "★")
            out.insert(1, _ok(f"  Primary class: {icon}  {defn.get('name', current)}"))
            out.insert(2, _dim(""))
        if prestige:
            defn = CLASS_DEFINITIONS.get(prestige, {})
            icon = defn.get("icon", "★")
            out.insert(3 if current else 1, _ok(f"  Prestige class: {icon}  {defn.get('name', prestige)} (×{cs.PRESTIGE_BONUS_FRACTION} passive)"))
            out.insert(4 if current else 2, _dim(""))
        elif current and self.gs.level >= cs.PRESTIGE_UNLOCK_LEVEL:
            out.insert(3, _line(f"  ⟁ Level {cs.PRESTIGE_UNLOCK_LEVEL} reached! Run 'class prestige' to unlock dual specialization.", "info"))
            out.insert(4, _dim(""))
        return out

