    def _cmd_http(self, args: List[str]) -> List[dict]:
        """http <GET|POST|...> <localhost-url> [json] — in-game REST client (T6); probe game APIs and local endpoints."""
        import urllib.request as _ur
        import json as _json_h
        import time as _th
        import re as _reh

        if not args:
            return [
                _sys("  ═══ HTTP — IN-GAME REST CLIENT ═══"),
                _dim("  http GET http://localhost:7337/api/health"),
                _dim("  http GET http://localhost:11434/api/tags"),
                _dim("  http GET http://localhost:8002/health"),
                _dim("  http POST http://localhost:7337/api/game/command {\"command\":\"status\"}"),
                _dim(""),
                _dim("  Only localhost endpoints are accessible from the grid."),
            ]

        method = args[0].upper()
        if method not in ("GET", "POST", "PUT", "DELETE", "PATCH", "HEAD"):
            return [_err(f"http: unknown method '{method}'")]
        if len(args) < 2:
            return [_err("http <METHOD> <url>")]

        url = args[1]
        if not _reh.match(r'https?://(localhost|127\.0\.0\.1)(:\d+)?(/.*)?$', url):
            return [
                _warn("  [SECURITY]: External URLs blocked. Only localhost endpoints accessible."),
                _dim("  http GET http://localhost:7337/api/health  — game server"),
                _dim("  http GET http://localhost:11434/api/tags   — Ollama"),
            ]

        body_raw = " ".join(args[2:]) if len(args) > 2 else None
        body_bytes = None
        if body_raw:
            try:
                body_bytes = _json_h.dumps(_json_h.loads(body_raw)).encode()
            except _json_h.JSONDecodeError:
                body_bytes = body_raw.encode()

        try:
            req = _ur.Request(url, data=body_bytes,
                headers={"Content-Type": "application/json", "User-Agent": "TD-Ghost/1.0"},
                method=method)
            t0 = _th.time()
            with _ur.urlopen(req, timeout=8) as r:
                elapsed = int((_th.time() - t0) * 1000)
                status = r.status
                raw = r.read()

            try:
                parsed = _json_h.loads(raw)
                body_str = _json_h.dumps(parsed, indent=2)[:800]
            except Exception:
                body_str = raw.decode("utf-8", errors="replace")[:600]

            if 200 <= status < 300:
                sc = "success"
            elif 300 <= status < 400:
                sc = "warn"
            else:
                sc = "error"
            out = [_sys(f"  {method} {url}"), {"t": sc, "s": f"  {status}  ({elapsed}ms)"}, _dim("")]
            for line in body_str.splitlines():
                out.append(_dim(f"  {line}"))
            out.append(_dim(f"\n  {len(raw)} bytes"))
            self.gs.add_xp(5, "networking")
            return out

        except _ur.HTTPError as e:
            return [_err(f"  HTTP {e.code} — {url}")]
        except _ur.URLError as e:
            return [_err(f"  Connection refused: {url}")]
        except Exception as e:
            return [_err(f"  http: {e}")]

    def _cmd_supply(self, args: List[str]) -> List[dict]:
        """supply [<node>] — CS4 colony supply chains; show per-node resource production rates."""
        import time as _ts

        NODE_PRODUCTION = {
            "home":            {"compute": 5,  "data": 2,  "credits": 3},
            "resistance-cell": {"compute": 15, "data": 8,  "credits": 10},
            "node-1":          {"compute": 20, "data": 10, "credits": 15},
            "nexus-gateway":   {"compute": 30, "data": 25, "credits": 20},
            "nexus-db":        {"compute": 15, "data": 40, "credits": 25},
            "chimera-control": {"compute": 50, "data": 30, "credits": 40},
            "watcher-relay":   {"compute": 10, "data": 20, "credits": 8},
            "darknet-relay-7": {"compute": 20, "data": 15, "credits": 35},
            "collector-node":  {"compute": 25, "data": 50, "credits": 30},
            "the-void":        {"compute": 0,  "data": 0,  "credits": 0},
        }

        claimed = self.gs.flags.get("claimed_nodes", [])
        fortified = self.gs.flags.get("fortified_nodes", [])

        now = _ts.time()
        last_tick = self.gs.flags.get("supply_last_tick", now)
        elapsed_h = (now - last_tick) / 3600.0
        self.gs.flags["supply_last_tick"] = now

        supply_bank = self.gs.flags.get("supply_bank", {"compute": 0.0, "data": 0.0, "credits": 0.0})
        tick_totals = {"compute": 0.0, "data": 0.0, "credits": 0.0}
        for nid in claimed:
            prod = NODE_PRODUCTION.get(nid, {"compute": 5, "data": 5, "credits": 5})
            mult = 1.5 if nid in fortified else 1.0
            for r in tick_totals:
                gain = prod.get(r, 0) * elapsed_h * mult
                tick_totals[r] += gain
                supply_bank[r] = min(supply_bank.get(r, 0) + gain, 9999.0)
        self.gs.flags["supply_bank"] = supply_bank

        if not claimed:
            return [
                _sys("  ═══ SUPPLY CHAIN NETWORK ═══"),
                _warn("  No nodes claimed. Run: nodes claim <node-id>"),
                _dim("  Claimed nodes produce compute/data/credits over time."),
            ]

        out = [_sys("  ═══ SUPPLY CHAIN NETWORK ═══"), _dim("")]
        total_c = sum(NODE_PRODUCTION.get(n, {}).get("compute", 0) * (1.5 if n in fortified else 1.0) for n in claimed)
        total_d = sum(NODE_PRODUCTION.get(n, {}).get("data", 0)    * (1.5 if n in fortified else 1.0) for n in claimed)
        total_r = sum(NODE_PRODUCTION.get(n, {}).get("credits", 0) * (1.5 if n in fortified else 1.0) for n in claimed)
        out.append(_ok(f"  RATES  ⚡{total_c:.0f}/hr  🗄{total_d:.0f}/hr  ₵{total_r:.0f}/hr"))
        out.append(_dim(""))
        for nid in claimed:
            prod = NODE_PRODUCTION.get(nid, {"compute": 5, "data": 5, "credits": 5})
            mult = 1.5 if nid in fortified else 1.0
            out.append(_line(
                f"  {nid:<22}{'⬡' if nid in fortified else ' '} "
                f"⚡{prod['compute']*mult:.0f}  🗄{prod['data']*mult:.0f}  ₵{prod['credits']*mult:.0f}",
                "info",
            ))
        if elapsed_h > 0.001:
            out += [_dim(""), _ok(f"  Accumulated: ⚡{tick_totals['compute']:.1f}  🗄{tick_totals['data']:.1f}  ₵{tick_totals['credits']:.1f}")]
        out += [
            _dim(""),
            _ok(f"  BANK  ⚡{supply_bank['compute']:.0f}  🗄{supply_bank['data']:.0f}  ₵{supply_bank['credits']:.0f}"),
            _dim("  nodes fortify <id> — multiply node output ×1.5"),
        ]
        return out

