    def _cmd_craft(self, args: List[str]) -> List[dict]:
        """craft [bench|list|components|<recipe>|use <item>] — R4 Crafting System."""
        try:
            from app.game_engine.crafting_engine import CraftingEngine
        except Exception as exc:
            return [_line(f"  Crafting engine error: {exc}", "error")]

        eng = CraftingEngine()
        sub = args[0].lower() if args else "bench"

        if sub in ("bench", ""):
            return eng.render_bench(self.gs)

        if sub == "list":
            try:
                from app.game_engine.crafting_engine import RECIPES
            except Exception:
                return [_line("  Crafting engine unavailable.", "error")]
            out = [
                _line("", "dim"),
                _line("  ── RECIPES ─────────────────────────────────────────────", "system"),
                _line("", "dim"),
            ]
            for rid, r in RECIPES.items():
                out.append(_line(f"  {r['icon']}  {r['name']:<24} → craft {rid}", "info"))
            out.append(_line("", "dim"))
            out.append(_line("  Run `craft bench` for detailed ingredients view.", "dim"))
            return out

        if sub == "components":
            return eng.render_components(self.gs)

        if sub == "use":
            if len(args) < 2:
                return [
                    _line("  Usage: craft use <item_id>", "error"),
                    _line("  View inventory: inv", "dim"),
                ]
            return eng.use_item(args[1].lower(), self.gs)

        # Treat unknown sub as a recipe id
        return eng.craft(sub, self.gs)

    # ─────────────────────────────────────────────────────────────────────────
    # INV — Full player inventory view
    # ─────────────────────────────────────────────────────────────────────────

    def _cmd_inv(self, args: List[str]) -> List[dict]:
        """inv — Show full player inventory: gear, crafted items, and components."""
        out: List[dict] = [
            _line("", "dim"),
            _line("╔══════════════════════════════════════════════════════════╗", "system"),
            _line("║  INVENTORY — Gear · Crafted Items · Components           ║", "system"),
            _line("╚══════════════════════════════════════════════════════════╝", "system"),
        ]

        # Equipped gear
        try:
            from app.game_engine.gear_system import GearSystem, GEAR_ITEMS
            gs_sys = GearSystem()
            equipped = gs_sys._equipped(self.gs)
            out.append(_line("", "dim"))
            out.append(_line("  ── EQUIPPED GEAR ────────────────────────────────────────", "system"))
            out.append(_line("", "dim"))
            if equipped:
                for cat, item_id in equipped.items():
                    item = GEAR_ITEMS.get(item_id, {})
                    icon = item.get("icon", "•")
                    name = item.get("name", item_id)
                    out.append(_line(f"  {icon}  [{cat}] {name}", "info"))
            else:
                out.append(_line("  No gear equipped. Use `gear shop` to browse.", "dim"))
        except Exception:
            pass

        # Crafted items
        try:
            from app.game_engine.crafting_engine import CraftingEngine
            eng = CraftingEngine()
            inv = eng._inventory(self.gs)
            out.append(_line("", "dim"))
            if inv:
                out += eng.render_inventory(self.gs)
            else:
                out.append(_line("  No crafted items. Use `craft bench` to start crafting.", "dim"))
        except Exception:
            pass

        # Component summary
        try:
            from app.game_engine.crafting_engine import CraftingEngine, COMPONENTS
            eng = CraftingEngine()
            comps = eng._components(self.gs)
            if any(v > 0 for v in comps.values()):
                out.append(_line("", "dim"))
                out.append(_line("  ── COMPONENTS (summary) ─────────────────────────────────", "system"))
                out.append(_line("", "dim"))
                for cid, qty in sorted(comps.items(), key=lambda x: -x[1]):
                    if qty <= 0:
                        continue
                    name = COMPONENTS.get(cid, {}).get("name", cid)
                    out.append(_line(f"    {qty:>3}×  {name}", "dim"))
                out.append(_line("", "dim"))
                out.append(_line("  Run `craft components` for full component details.", "dim"))
        except Exception:
            pass

        out.append(_line("", "dim"))
        out.append(_line("  Commands: gear loadout · craft bench · craft components", "dim"))
        out.append(_line("", "dim"))
        return out

    def _cmd_inventory(self, args: List[str]) -> List[dict]:
        """inventory — Alias for inv."""
        return self._cmd_inv(args)

