    def _cmd_nusyq(self, args: List[str]) -> List[dict]:
        """nusyq [status|manifest|quests|chronicle] — NuSyQ-Hub integration bridge status."""
        import json as _json, os as _os
        from pathlib import Path as _Path

        gs = self.gs
        subcmd = args[0].lower() if args else "status"

        def _header():
            return [
                _dim(""),
                _sys("  ╔══════════════════════════════════════════════════════════╗"),
                _sys("  ║  ΔΨΣ NuSyQ-Hub — Lattice Integration Bridge              ║"),
                _sys("  ╚══════════════════════════════════════════════════════════╝"),
                _dim(""),
            ]

        out = _header()

        if subcmd in ("status", ""):
            try:
                from nusyq_bridge import zero_token_status
                st = zero_token_status()
                chronicle_size = st.get("chronicle_size", 0)
                quests_synced  = st.get("quests_synced", 0)
                manifest_agents = st.get("manifest_agents", 0)
                hub_connected  = st.get("hub_connected", False)
            except Exception as _e:
                chronicle_size = quests_synced = manifest_agents = 0
                hub_connected = False

            manifest_path = _Path("state/agent_manifest.json")
            if manifest_path.exists():
                try:
                    mdata = _json.loads(manifest_path.read_text())
                    manifest_agents = len(mdata.get("agents", mdata if isinstance(mdata, list) else []))
                except Exception:
                    pass

            chronicle_path = _Path("state/memory_chronicle.jsonl")
            chronicle_lines = 0
            if chronicle_path.exists():
                try:
                    chronicle_lines = sum(1 for _ in chronicle_path.open())
                except Exception:
                    pass

            quest_path = _Path("state/quest_log.jsonl")
            quest_count = 0
            if quest_path.exists():
                try:
                    quest_count = sum(1 for _ in quest_path.open())
                except Exception:
                    pass

            hub_url = _os.environ.get("NUSYQ_HUB_URL", "http://localhost:8000")

            out += [
                _line("  ─── BRIDGE STATUS ───────────────────────────────────────────", "system"),
                _line(f"  Hub URL        : {hub_url}", "info"),
                _line(f"  Hub connected  : {'✓ connected' if hub_connected else '✗ offline (Docker-only — expected in Replit)'}", "success" if hub_connected else "dim"),
                _line("", "dim"),
                _line("  ─── SYNC STATE ──────────────────────────────────────────────", "system"),
                _line(f"  Agent manifest : {manifest_agents} agent(s) registered", "info"),
                _line(f"  Chronicle      : {chronicle_lines} events logged", "info"),
                _line(f"  Quest log      : {quest_count} quests synced", "info"),
                _line("", "dim"),
                _line("  ─── REST ENDPOINTS ──────────────────────────────────────────", "system"),
                _dim("  GET  /api/nusyq/status      — this view"),
                _dim("  GET  /api/nusyq/manifest    — agent manifest JSON"),
                _dim("  POST /api/nusyq/sync-quests — push challenges → NuSyQ quest log"),
                _dim("  POST /api/nusyq/chronicle   — append a chronicle event"),
                _dim("  GET  /api/nusyq/schedule    — autonomous service schedule"),
                _line("", "dim"),
                _suggest("nusyq manifest · nusyq quests · gordon status · services health"),
            ]
            gs.add_xp(5, "lore")

        elif subcmd == "manifest":
            manifest_path = _Path("state/agent_manifest.json")
            if manifest_path.exists():
                try:
                    mdata = _json.loads(manifest_path.read_text())
                    agents = mdata.get("agents", mdata if isinstance(mdata, list) else [])
                    out.append(_line(f"  Agent manifest: {len(agents)} agent(s)", "info"))
                    for a in agents[:10]:
                        name = a.get("name", a.get("id", "?")) if isinstance(a, dict) else str(a)
                        kind = a.get("kind", "agent") if isinstance(a, dict) else "agent"
                        out.append(_dim(f"    ● {name:<30} [{kind}]"))
                    if len(agents) > 10:
                        out.append(_dim(f"    … and {len(agents)-10} more"))
                except Exception as _e:
                    out.append(_line(f"  Manifest read error: {_e}", "error"))
            else:
                out.append(_dim("  No manifest yet. Run: nusyq manifest --build"))
            gs.add_xp(5, "lore")

        elif subcmd in ("quests", "quest"):
            quest_path = _Path("state/quest_log.jsonl")
            if quest_path.exists():
                try:
                    lines = quest_path.read_text().strip().split("\n")
                    out.append(_line(f"  Quest log: {len(lines)} entries", "info"))
                    for l in lines[-5:]:
                        try:
                            q = _json.loads(l)
                            out.append(_dim(f"    {q.get('id','?'):<20} {q.get('title','')[:40]}"))
                        except Exception:
                            pass
                except Exception as _e:
                    out.append(_line(f"  Quest log error: {_e}", "error"))
            else:
                out.append(_dim("  No quest log yet."))
            gs.add_xp(5, "lore")

        elif subcmd in ("chronicle", "log"):
            chronicle_path = _Path("state/memory_chronicle.jsonl")
            if chronicle_path.exists():
                try:
                    lines = chronicle_path.read_text().strip().split("\n")
                    out.append(_line(f"  Chronicle: {len(lines)} events", "info"))
                    for l in lines[-5:]:
                        try:
                            ev = _json.loads(l)
                            ts  = ev.get("timestamp", ev.get("ts", "?"))[:19] if isinstance(ev.get("timestamp", ev.get("ts","")), str) else "?"
                            tag = ev.get("tag", ev.get("type", "event"))
                            out.append(_dim(f"    [{ts}] {tag}"))
                        except Exception:
                            pass
                except Exception as _e:
                    out.append(_line(f"  Chronicle error: {_e}", "error"))
            else:
                out.append(_dim("  No chronicle yet."))
            gs.add_xp(5, "lore")

        else:
            out += [
                _line(f"  Unknown subcommand: '{subcmd}'", "error"),
                _dim("  nusyq [status|manifest|quests|chronicle]"),
            ]

        return out

