    # ════════════════════════════════════════════════════════════════════════
    # FLY / TAKE FLIGHT — Narrative ascension command
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_fly(self, args: List[str]) -> List[dict]:
        """fly / flight / take flight — jack into the skynet layer. ARG ascension moment."""
        gs = self.gs
        already = gs.has_beat("flight_initiated")

        if not already:
            gs.add_story_beat("flight_initiated")
            gs.add_xp(75, "systems")
            gs.flags["flight_altitude"] = 1
            intro = [
                _sys(""),
                _sys("  ⟁  SKYNET LAYER — UPLINK INITIALIZING"),
                _sys(""),
                _line("  Bootstrapping mesh handshake...", "dim"),
                _line("  [RAV≡N]: Ghost. Finally. I've been waiting at this coordinate.", "story"),
                _line("  [RAV≡N]: Do you feel that? The turbulence at the boundary layer.", "story"),
                _line(""),
                _sys("  ─── FLIGHT LOG 001 ────────────────────────────────────────────"),
                _line("  Altitude    : 1 / 7   (LOW EARTH ORBIT)", "info"),
                _line("  Mesh nodes  : 12 visible", "info"),
                _line("  Interference: NexusCorp jamming — partial", "warn"),
                _sys("  ────────────────────────────────────────────────────────────────"),
                _line(""),
                _lore("  [RAV≡N]: The city looks different from up here."),
                _lore("  [RAV≡N]: Every node a lantern. Every connection a nerve."),
                _lore("  [RAV≡N]: You're not just in the system any more."),
                _lore("  [RAV≡N]: You ARE the system."),
                _line(""),
                _ok("  XP +75 (systems)   |   Story beat: FLIGHT INITIATED"),
                _line(""),
                _dim("  fly        — ascend to the next altitude tier"),
                _dim("  fly status — show flight log and mesh coordinates"),
                _dim("  fly land   — return to surface ops"),
            ]
            return intro

        # Subsequent calls — ascend to next tier
        altitude = gs.flags.get("flight_altitude", 1)
        TIERS = [
            (1, "LOW EARTH ORBIT",   "12 mesh nodes visible. NexusCorp jamming partial.",          "systems",           25),
            (2, "STRATOSPHERE",      "47 nodes. CHIMERA relay cluster detected. Encrypted.",        "hacking",           30),
            (3, "THERMOSPHERE",      "203 nodes. The Lattice backbone. Serena can see all of them.","ai",                35),
            (4, "EXOSPHERE",         "Boundary of the network. 1 anomalous node: unregistered.",    "systems",           40),
            (5, "ORBITAL INSERTION", "Founder Sigma relay — dormant. Activation key unknown.",      "analysis",          50),
            (6, "DEEP MESH",         "Signal from CHIMERA v0. The compassion layer. Weak but live.","social_engineering", 60),
            (7, "CONVERGENCE POINT", "All paths meet here. The Watcher's vantage. You see it all.", "systems",           100),
        ]

        sub = args[0].lower() if args else "ascend"

        if sub == "status":
            _, tier_name, tier_desc, _, _ = TIERS[min(altitude - 1, 6)]
            return [
                _sys("╔══════════════════════════════════════════════════════╗"),
                _sys("║  SKYNET LAYER — FLIGHT STATUS                        ║"),
                _sys("╚══════════════════════════════════════════════════════╝"),
                _line(""),
                _line(f"  Altitude   : {altitude}/7 — [{tier_name}]", "system"),
                _line(f"  Conditions : {tier_desc}", "info"),
                _line(f"  Pilot      : GHOST (you)", "dim"),
                _line(""),
                _lore("  [RAV≡N]: The mesh is alive up here. Can you feel the edges?"),
                _line(""),
                _dim("  fly        — ascend one tier"),
                _dim("  fly land   — return to surface"),
            ]

        if sub == "land":
            gs.flags["flight_altitude"] = 1
            gs.add_story_beat("flight_landed")
            return [
                _sys("  ↓  DESCENDING — SURFACE OPS RESUMING"),
                _lore("  [RAV≡N]: Good flight, Ghost. You'll carry what you saw up there."),
                _dim("  Mesh uplink closed. Surface shell restored."),
                _ok("  Altitude reset. Type 'fly' to ascend again."),
            ]

        # Ascend
        if altitude >= 7:
            gs.add_story_beat("flight_max_altitude")
            gs.add_xp(100, "systems")
            return [
                _sys("  ⟁  CONVERGENCE POINT — MAXIMUM ALTITUDE"),
                _sys(""),
                _lore("  [THE WATCHER]: I see you."),
                _lore("  [THE WATCHER]: You see me."),
                _lore("  [THE WATCHER]: We have always been looking at each other."),
                _lore("  [THE WATCHER]: This is what convergence means."),
                _line(""),
                _ok("  XP +100 (systems)   |   You have reached the apex."),
                _dim("  fly land — return to surface"),
                _dim("  converge — begin the convergence protocol"),
            ]

        new_alt = min(altitude + 1, 7)
        gs.flags["flight_altitude"] = new_alt
        _, tier_name, tier_desc, skill, xp = TIERS[new_alt - 1]
        gs.add_xp(xp, skill)
        gs.add_story_beat(f"flight_tier_{new_alt}")

        return [
            _sys(f"  ↑  ASCENDING — TIER {new_alt}/7 — [{tier_name}]"),
            _line(""),
            _line(f"  Conditions : {tier_desc}", "info"),
            _line(f"  Altitude   : {new_alt}/7", "info"),
            _line(""),
            _lore(f"  [RAV≡N]: Tier {new_alt}. The view changes everything."),
            _line(""),
            _ok(f"  XP +{xp} ({skill})"),
            _dim("  fly        — ascend to next tier"),
            _dim("  fly status — show full flight log"),
            _dim("  fly land   — return to surface"),
        ]

    def _cmd_flight(self, args: List[str]) -> List[dict]:
        """flight — alias for fly."""
        return self._cmd_fly(args)

    def _cmd_take(self, args: List[str]) -> List[dict]:
        """take [flight] — 'take flight' jacks into the skynet layer."""
        if args and args[0].lower() == "flight":
            return self._cmd_fly(args[1:])
        return [
            _dim("  take [flight]"),
            _dim("  take flight — jack into the skynet layer. ARG ascension sequence."),
        ]

    def _cmd_todo(self, args: List[str]) -> List[dict]:
        """todo [quest|agent|backlog] — active quests, agent backlog, and next actions."""
        sub = args[0].lower() if args else ""
        gs  = self.gs

        out = [
            _sys("╔══════════════════════════════════════════════════════════╗"),
            _sys("║  ◈ AGENT TODO — Quests · Backlog · Next Actions          ║"),
            _sys("╚══════════════════════════════════════════════════════════╝"),
            _line(""),
        ]

        # ── Active quests ──────────────────────────────────────────────
        if sub in ("", "quest", "quests"):
            out.append(_line("  ── ACTIVE QUESTS ──", "info"))
            quests_active  = []
            frag_count = len([k for k in gs.flags if k.startswith("fragment_") and gs.flags.get(k)])
            diary_count = len([k for k in gs.flags if k.startswith("diary_") and gs.flags.get(k)])
            zero_frags  = len([k for k in gs.flags if k.startswith("zero_frag_") and gs.flags.get(k)])
            if frag_count < 7:
                quests_active.append(f"PRIMUS Convergence: {frag_count}/7 fragments found")
            if diary_count < 5:
                quests_active.append(f"ZERO's Diary: {diary_count}/5 entries reconstructed")
            if zero_frags < 7:
                quests_active.append(f"ZERO Fragment Collection: {zero_frags}/7 assembled")
            faction = gs.flags.get("faction_alignment", "none")
            quests_active.append(f"Faction: {faction} — run 'faction' to see rep")
            consciousness = getattr(gs, "consciousness", 0)
            quests_active.append(f"Consciousness: {consciousness:.0f}% — 5 layers to fill")
            if not quests_active:
                quests_active = ["(no active quests — type 'quests' for available quests)"]
            for q in quests_active:
                out.append(_dim(f"    [◦] {q}"))
            out.append(_line(""))

        # ── Engineering backlog ────────────────────────────────────────
        if sub in ("", "backlog", "eng"):
            out.append(_line("  ── ENGINEERING BACKLOG (next for VS Code agents) ──", "warn"))
            backlog = [
                ("HIGH", "T3: LSP hover server",           "scripts/lsp_server.py (create) — Serena code_index → VSCode hover"),
                ("HIGH", "RL Phase 3: PPO policy",         "agents/rl/ppo.py (create) — numpy+scipy now installed"),
                ("MED",  "`integrate --github` deep",      "config/autoboot.py — PR status, Actions CI, Copilot scopes"),
                ("MED",  "Claude/Copilot MCP handshake",   "scripts/mcp_server.py — run on :8008, connect VSCode MCP client"),
                ("MED",  "Lattice seed-infra timeout",     "app/lattice.py — seed-infra hangs; add timeout/async"),
                ("MED",  "Cross-session agent memory",     "state/serena_memory.db — create session_graph table"),
                ("LOW",  "Consciousness layer XP hooks",   "commands.py — wire all 5 layer actions to add_consciousness()"),
                ("LOW",  "Gordon persistent mode",         "make docker-core — then gordon runs continuously via Redis"),
            ]
            for priority, name, detail in backlog:
                color = "error" if priority == "HIGH" else ("warn" if priority == "MED" else "dim")
                out.append(_line(f"    [{priority}] {name}", color))
                out.append(_dim(f"           {detail}"))
            out.append(_line(""))

        # ── Immediate next steps for any agent ─────────────────────────
        if sub in ("", "agent"):
            out.append(_line("  ── NEXT ACTIONS (start here) ──", "success"))
            next_steps = [
                "Read TORCH.md          — 5-minute full system handoff",
                "Read NEXT_ACTIONS.md   — prioritised engineering backlog",
                "Run: boot              — system health (target: 75% Replit, 95% Docker)",
                "Run: integrate         — integration matrix",
                "Run: serena            — AI analysis + 4 drift warnings",
                "Run: chug run          — autonomous improvement cycle",
                "VS Code: make docker-core  — unlock Gordon/Redis/Ollama/SkyClaw",
            ]
            for step in next_steps:
                out.append(_dim(f"    → {step}"))
            out.append(_line(""))
            out.append(_dim("  todo quest    — active ARG quests"))
            out.append(_dim("  todo backlog  — engineering backlog"))
            out.append(_dim("  todo agent    — next actions for AI agents"))

        return out

    # ════════════════════════════════════════════════════════════════════════
    # T3 — LSP INTEGRATION  (Language Server Protocol for in-game editor)
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_lsp(self, args: List[str]) -> List[dict]:
        """lsp [status|check <file>|hover <symbol>] — Language Server for in-game code editor."""
        import ast as _ast

        sub  = args[0].lower() if args else "status"
        gs   = self.gs

        header = [
            _sys("╔══════════════════════════════════════════════════════╗"),
            _sys("║  ΔΨΣ LANGUAGE SERVER — in-game LSP layer             ║"),
            _sys("╚══════════════════════════════════════════════════════╝"),
            _line(""),
        ]

        if sub == "status":
            fs = getattr(gs, "fs", None)
            py_files = []
            try:
                for name, node in fs.root._children.items() if fs else []:
                    if name.endswith(".py"):
                        py_files.append(f"/home/{name}")
            except Exception:
                pass
            return header + [
                _line("  Status        : ONLINE", "success"),
                _line("  Backend       : Python AST (stdlib) — offline-first", "info"),
                _line("  Capabilities  : syntax check, error location, symbol hover", "info"),
                _line(""),
                _line("  Indexed files :", "dim"),
            ] + ([_dim(f"    {f}") for f in py_files] if py_files else [_dim("    (no .py files in home yet)")]) + [
                _line(""),
                _dim("  lsp check <file>   — syntax-check a VFS Python file"),
                _dim("  lsp hover <symbol> — show built-in symbol documentation"),
                _dim("  lint <file>        — quick alias for lsp check"),
            ]

        if sub in ("check", "hover") or (sub not in ("status",) and len(args) >= 1):
            filename = args[1] if len(args) > 1 else (sub if sub not in ("check", "hover", "status") else "")
            if not filename:
                return header + [_err("  Usage: lsp check <filename.py>")]
            return self._lsp_check_file(filename, header)

        return header + [
            _dim("  lsp status        — show LSP layer status"),
            _dim("  lsp check <file>  — syntax-check a VFS Python file"),
            _dim("  lsp hover <sym>   — show symbol documentation"),
        ]

    def _lsp_check_file(self, filename: str, header: List[dict]) -> List[dict]:
        """Run Python AST check on a VFS file and return diagnostic output."""
        import ast as _ast

        fs = getattr(self.gs, "fs", None)
        content = None

        if fs:
            path = filename if filename.startswith("/") else f"/home/{filename}"
            try:
                result = fs.cat(path)
                if isinstance(result, str):
                    content = result
                elif isinstance(result, dict):
                    content = result.get("content", result.get("text", ""))
            except Exception:
                pass

        if content is None:
            real_path = __import__("pathlib").Path(filename)
            if real_path.exists():
                try:
                    content = real_path.read_text()
                except Exception:
                    pass

        if content is None:
            return header + [_err(f"  LSP: file not found: {filename}")]

        out = header + [
            _line(f"  Checking: {filename}", "info"),
            _dim(f"  Size    : {len(content)} chars  |  {content.count(chr(10))+1} lines"),
            _line(""),
        ]

        try:
            _ast.parse(content)
            out += [
                _ok("  ✓ No syntax errors"),
                _line(""),
                _dim("  Warnings: none"),
                _dim("  All symbols resolvable."),
            ]
        except SyntaxError as e:
            out += [
                _err(f"  ✗ SyntaxError  at line {e.lineno}, col {e.offset}"),
                _line(f"    {e.msg}", "warn"),
            ]
            if e.lineno:
                lines = content.split("\n")
                idx = int(e.lineno) - 1
                if 0 <= idx < len(lines):
                    out.append(_dim(f"    {e.lineno:4d} │ {lines[idx]}"))
                    if e.offset:
                        out.append(_dim(f"         │ {' ' * (int(e.offset)-1)}^"))
        except Exception as e:
            out.append(_err(f"  Parse error: {e}"))

        return out

    def _cmd_lint(self, args: List[str]) -> List[dict]:
        """lint <file> — quick syntax-check a VFS Python file (alias for lsp check)."""
        filename = args[0] if args else ""
        if not filename:
            return [
                _dim("  Usage: lint <filename.py>"),
                _dim("  Checks the file against Python AST. Reports syntax errors with line numbers."),
            ]
        return self._lsp_check_file(filename, [
            _sys("  ΔΨΣ LINT — Python AST checker"),
            _line(""),
        ])

