            (15,  "AGENT"),    (20, "SPECIALIST"), (30, "EXPERT"),
            (40,  "HANDLER"),  (50, "DIRECTOR"),  (65, "ARCHITECT"),
            (80,  "OVERSEER"), (100,"SOVEREIGN"),  (125,"CHIMERA"),
