    def _cmd_notekeep(self, args: List[str]) -> List[dict]:
        """notekeep [add <title>|list|view <id>|tag <id> <tag>|export] — TCM-style pentest notes."""
        import time as _t
        s = self.gs
        if not hasattr(s, 'notes_db'):
            s.notes_db = []
        out = []
        sub = args[0].lower() if args else "list"
        if sub == "list":
            out.append(_sys("  ══ NOTEKEEP — Pentest Notes (TCM Security method) ══"))
            out.append(_dim("  Tools: CherryTree · OneNote · Joplin · GreenShot in-terminal"))
            out.append(_line(""))
            if not s.notes_db:
                out.append(_dim("  No notes. notekeep add <title> <content>"))
            for i, note in enumerate(s.notes_db, 1):
                tags = " ".join(f"[{t}]" for t in note.get("tags", []))
                out.append(_line(f"  [{i}] {note['title']}  {tags}", "warn"))
                out.append(_dim(f"       {note['content'][:80]}..."))
        elif sub == "add":
            if not args[1:]:
                return [_err("Usage: notekeep add <title> :: <content>")]
            rest = " ".join(args[1:])
            if "::" in rest:
                title, content = rest.split("::", 1)
            else:
                title, content = rest, "(no content)"
            s.notes_db.append({"title": title.strip(), "content": content.strip(), "tags": [], "ts": _t.time()})
            return [_sys(f"  Note saved: {title.strip()}")]
        elif sub == "view":
            idx = int(args[1]) - 1 if args[1:] and args[1].isdigit() else -1
            if idx < 0 or idx >= len(s.notes_db):
                return [_err("Invalid note ID. notekeep list")]
            note = s.notes_db[idx]
            out.append(_sys(f"  NOTE [{idx+1}]: {note['title']}"))
            out.append(_dim(f"  Tags: {' '.join(note.get('tags', [])) or 'none'}"))
            out.append(_line(""))
            for line in note["content"].split("\\n"):
                out.append(_dim(f"  {line}"))
        elif sub == "tag":
            if len(args) < 3:
                return [_err("Usage: notekeep tag <id> <tag>")]
            idx = int(args[1]) - 1
            tag = args[2]
            if 0 <= idx < len(s.notes_db):
                s.notes_db[idx].setdefault("tags", []).append(tag)
                return [_sys(f"  Tagged note {idx+1} with [{tag}]")]
        elif sub == "export":
            out.append(_sys("  ══ NOTES EXPORT ══════════════════════════════════"))
            for i, note in enumerate(s.notes_db, 1):
                out.append(_line(f"  [{i}] {note['title']}"))
                out.append(_dim(f"  {note['content']}"))
                out.append(_dim("  ---"))
            if not s.notes_db:
                out.append(_dim("  No notes to export."))
            out.append(_sys("  ══════════════════════════════════════════════════"))
        else:
            out.append(_err(f"Unknown: notekeep {sub}"))
            out.append(_dim("  notekeep list · notekeep add <title> :: <note> · notekeep view <id> · notekeep export"))
        return out

