    def _cmd_arch(self, args: List[str]) -> List[dict]:
        """arch [list|start <code>|submit <answer>|hint|status] — Low-level architecture challenges (OST2)."""
        import random as _r
        s = self.gs
        if not hasattr(s, 'arch_progress'):
            s.arch_progress = {}
        if not hasattr(s, 'active_arch'):
            s.active_arch = None
        MODULES = {
            "Arch1001": {
                "title": "x86-64 Assembly Fundamentals",
                "level": 1000, "xp": 300,
                "desc": "Registers, instructions, stack operations, calling conventions.",
                "topics": ["RAX/RBX/RCX/RDX registers", "MOV/ADD/SUB/XOR instructions",
                           "Stack: PUSH/POP", "CALL/RET", "System calls"],
                "challenge": "What register holds the return value in x86-64 Linux System V ABI?",
                "answer": "rax",
                "hint": "It's the accumulator register.",
            },
            "Arch2001": {
                "title": "ARM Assembly",
                "level": 2000, "xp": 350,
                "desc": "ARM architecture, Thumb mode, AARCH64, iOS/Android internals.",
                "topics": ["ARM vs x86 differences", "R0-R15 registers", "LDR/STR instructions",
                           "Thumb-2 encoding", "ABI and calling conventions"],
                "challenge": "In ARM64, which register is the stack pointer?",
                "answer": "sp",
                "hint": "Same abbreviation across architectures.",
            },
            "Dbg2011": {
                "title": "Intermediate Debugging",
                "level": 2000, "xp": 300,
                "desc": "WinDbg, GDB, breakpoints, memory analysis, kernel debugging.",
                "topics": ["Breakpoints (sw/hw)", "Memory examination", "Watchpoints",
                           "Call stack analysis", "Heap inspection"],
                "challenge": "What GDB command displays the call stack?",
                "answer": "bt",
                "hint": "Short for 'backtrace'.",
            },
            "RE3201": {
                "title": "Symbolic Analysis",
                "level": 3000, "xp": 500,
                "desc": "Angr, symbolic execution, constraint solving, automatic exploit generation.",
                "topics": ["Symbolic variables", "Path constraints", "SMT solvers (Z3)",
                           "Angr basics", "Concolic execution"],
                "challenge": "What tool combines concrete and symbolic execution (concolic)?",
                "answer": "angr",
                "hint": "Popular Python framework for binary analysis.",
            },
            "Arch4001": {
                "title": "UEFI Firmware Attack & Defense",
                "level": 4000, "xp": 600,
                "desc": "UEFI internals, SMM, Secure Boot bypass, firmware rootkits.",
                "topics": ["UEFI DXE drivers", "SMM (System Management Mode)", "Secure Boot chain",
                           "SPI flash", "Platform Key enrollment"],
                "challenge": "What UEFI phase initialises core platform hardware?",
                "answer": "dxe",
                "hint": "Driver eXecution Environment.",
            },
            "Dbg1015": {
                "title": "Introductory Hardware Simulation",
                "level": 1000, "xp": 250,
                "desc": "Simics simulator, hardware/software co-debugging, device emulation.",
                "topics": ["Simics basics", "Checkpointing", "Reverse execution",
                           "Hardware device debugging", "Deterministic replay"],
                "challenge": "What makes hardware simulators better than real hardware for debugging?",
                "answer": "deterministic",
                "hint": "Key property: same inputs always produce same outputs.",
            },
        }
        out = []
        sub = args[0] if args else "list"
        if sub == "list":
            out.append(_sys("╔═══════════════════════════════════════════════════════╗"))
            out.append(_sys("║   ARCHITECTURE CHALLENGES (OpenSecurityTraining2)    ║"))
            out.append(_sys("╚═══════════════════════════════════════════════════════╝"))
            out.append(_dim("  Low-level systems, assembly, firmware, and debugger mastery"))
            out.append(_line(""))
            for code, m in MODULES.items():
                done = code in s.arch_progress and s.arch_progress[code].get("complete")
                active = " ◄ ACTIVE" if s.active_arch == code else ""
                icon = "✓" if done else " "
                t = "success" if done else "dim"
                out.append(_line(f"  {icon} [{code}]  {m['title']}{active}", t))
                out.append(_dim(f"       Level {m['level']}  |  +{m['xp']} XP  |  {m['desc'][:60]}"))
            out.append(_line(""))
            out.append(_dim("  arch start <code>  ·  arch submit <answer>  ·  arch hint"))
        elif sub == "start":
            code = args[1] if args[1:] else ""
            if code not in MODULES:
                return [_err(f"Unknown module: {code}"), _dim("  arch list")]
            s.active_arch = code
            s.arch_progress.setdefault(code, {})
            m = MODULES[code]
            out.append(_sys(f"  ▶ {code}: {m['title']}"))
            out.append(_dim(f"  {m['desc']}"))
            out.append(_line(""))
            out.append(_line("  TOPICS:", "warn"))
            for topic in m["topics"]:
                out.append(_dim(f"    • {topic}"))
            out.append(_line(""))
            out.append(_sys(f"  CHALLENGE:"))
            out.append(_line(f"  {m['challenge']}"))
            out.append(_line(""))
            out.append(_dim("  arch submit <answer>  ·  arch hint"))
        elif sub == "submit":
            code = s.active_arch
            if not code or code not in MODULES:
                return [_err("No active module. arch start <code>")]
            answer = " ".join(args[1:]).lower().strip() if args[1:] else ""
            m = MODULES[code]
            if answer in m["answer"].lower() or m["answer"].lower() in answer:
                s.arch_progress[code] = {"complete": True}
                s.xp = getattr(s, 'xp', 0) + m["xp"]
                out.append(_sys(f"  ✓ CORRECT! {m['answer']}"))
                out.append(_line(f"  +{m['xp']} XP  ·  {code} complete"))
                undone = [k for k, v in MODULES.items() if k not in s.arch_progress or not s.arch_progress[k].get("complete")]
                if undone:
                    out.append(_dim(f"  Next: arch start {undone[0]}"))
                else:
                    s.xp += 300
                    ach = getattr(s, 'achievements', [])
                    if "Architecture Master" not in ach:
                        ach.append("Architecture Master")
                        s.achievements = ach
                        out.append(_sys("  ★ ACHIEVEMENT: Architecture Master — all OST2 modules complete! +300 XP"))
            else:
                out.append(_err("  Incorrect. Try again."))
                out.append(_dim("  arch hint — reveal a clue"))
        elif sub == "hint":
            code = s.active_arch
            if not code or code not in MODULES:
                return [_dim("  No active module.")]
            out.append(_dim(f"  Hint: {MODULES[code]['hint']}"))
        elif sub == "status":
            done = [k for k, v in s.arch_progress.items() if v.get("complete")]
            out.append(_sys(f"  Architecture modules: {len(done)}/{len(MODULES)} complete"))
            for code in MODULES:
                c = "✓" if code in done else "○"
                t = "success" if code in done else "dim"
                out.append(_line(f"    {c} {code}  {MODULES[code]['title']}", t))
        else:
            out.append(_err(f"Unknown: arch {sub}"))
            out.append(_dim("  arch list · arch start <code> · arch submit <answer> · arch hint · arch status"))
        return out

    def _cmd_certify(self, args: List[str]) -> List[dict]:
        """certify [list|check <name>|claim <name>] — FutureLearn/Coursera-style certificates."""
        s = self.gs
        CERTS = {
            "foundation":      {"name": "Cyber Foundation Certificate",   "require_path": "pre-security",    "require_xp": 200},
            "soc-l1":          {"name": "SOC Analyst L1 Certificate",     "require_path": "soc-analyst",     "require_xp": 600},
            "jr-pentester":    {"name": "Jr Penetration Tester Cert",     "require_path": "jr-pentester",    "require_xp": 900},
            "red-team":        {"name": "Red Team Operator Certificate",  "require_path": "red-team",        "require_xp": 1500},
            "attck-scholar":   {"name": "ATT&CK Scholar",                 "require_achievement": "ATT&CK Scholar", "require_xp": 140},
            "arch-master":     {"name": "Architecture Master Certificate","require_achievement": "Architecture Master", "require_xp": 2000},
        }
        out = []
        sub = args[0].lower() if args else "list"
        earned_certs = getattr(s, 'achievements', [])
        if sub == "list":
            out.append(_sys("  AVAILABLE CERTIFICATES (FutureLearn/Coursera-style)"))
            out.append(_line(""))
            for cid, c in CERTS.items():
                earned = c["name"] in earned_certs
                icon = "★" if earned else "○"
                t = "success" if earned else "dim"
                out.append(_line(f"  {icon} [{cid}]  {c['name']}", t))
            out.append(_line(""))
            out.append(_dim("  certify check <id>  ·  certify claim <id>"))
        elif sub == "check":
            cid = args[1].lower() if args[1:] else ""
            c = CERTS.get(cid)
            if not c:
                return [_err(f"Unknown certificate: {cid}"), _dim("  certify list")]
            out.append(_sys(f"  CERTIFICATE: {c['name']}"))
            out.append(_line(""))
            current_xp = getattr(s, 'xp', 0)
            xp_ok = current_xp >= c.get("require_xp", 0)
            out.append(_line(f"  XP requirement: {c.get('require_xp',0)}  |  Your XP: {current_xp}  {'✓' if xp_ok else '✗'}", "success" if xp_ok else "error"))
            if "require_path" in c:
                pid = c["require_path"]
                path_data = getattr(s, 'learning_paths', {}).get(pid, {})
                path_ok = len(path_data.get("completed", [])) > 0
                out.append(_line(f"  Path required: {pid}  {'✓' if path_ok else '✗'}", "success" if path_ok else "error"))
            if "require_achievement" in c:
                ach_ok = c["require_achievement"] in earned_certs
                out.append(_line(f"  Achievement required: {c['require_achievement']}  {'✓' if ach_ok else '✗'}", "success" if ach_ok else "error"))
            out.append(_line(""))
            out.append(_dim("  certify claim <id> — claim if all requirements met"))
        elif sub == "claim":
            cid = args[1].lower() if args[1:] else ""
            c = CERTS.get(cid)
            if not c:
                return [_err(f"Unknown certificate: {cid}")]
            if c["name"] in earned_certs:
                return [_dim(f"  Already earned: {c['name']}")]
            current_xp = getattr(s, 'xp', 0)
            if current_xp >= c.get("require_xp", 0):
                earned_certs.append(c["name"])
                s.achievements = earned_certs
                out.append(_sys(f"  ★ CERTIFICATE AWARDED: {c['name']}"))
                out.append(_dim("  Added to portfolio. View with: portfolio"))
                port = getattr(s, 'portfolio', [])
                port.append(f"Certificate: {c['name']}")
                s.portfolio = port
            else:
                out.append(_err(f"  Requirements not met. certify check {cid}"))
        else:
            out.append(_err(f"Unknown: certify {sub}"))
        return out

    def _cmd_peer_review(self, args: List[str]) -> List[dict]:
        """peer-review [request|<challenge_id>|report] — Agent peer review of your work (Coursera-inspired)."""
        import random as _r
        s = self.gs
        AGENTS = ["ada", "raven", "zero", "nova"]
        FEEDBACK_GOOD = [
            "Clean methodology. Recon phase was thorough.",
            "Excellent documentation. Your report would hold up in a client debrief.",
            "Strong enumeration skills. No obvious attack surface missed.",
            "Solid understanding of the vulnerability class. Good mitigation advice.",
            "Impressive lateral movement. Attribution trail was minimal.",
        ]
        FEEDBACK_IMPROVE = [
            "Recon was rushed. Passive phase should precede active scanning.",
            "Report lacks executive summary. Non-technical stakeholders need it.",
            "Missed the service on port 8080. Always enumerate all ports.",
            "No evidence of testing for authentication bypass. Include it next time.",
            "Post-exploitation notes are thin. Document your pivot path fully.",
        ]
        out = []
        sub = args[0].lower() if args else "request"
        reviewer = _r.choice(AGENTS)
        if sub == "request":
            good = _r.choice(FEEDBACK_GOOD)
            improve = _r.choice(FEEDBACK_IMPROVE)
            xp = _r.randint(20, 50)
            s.xp = getattr(s, 'xp', 0) + xp
            out.append(_sys(f"  PEER REVIEW — requested from: {reviewer.upper()}"))
            out.append(_line(""))
            out.append(_line("  ✓ WHAT WORKED WELL:", "success"))
            out.append(_dim(f"    \"{good}\""))
            out.append(_line(""))
            out.append(_line("  ⚠ AREA FOR IMPROVEMENT:", "warn"))
            out.append(_dim(f"    \"{improve}\""))
            out.append(_line(""))
            out.append(_line(f"  Reviewer: {reviewer.upper()}  |  +{xp} XP for submitting work for review"))
            out.append(_dim("  review report — request written review of your latest pentest"))
        elif sub == "report":
            out.append(_sys("  PENTEST REPORT REVIEW"))
            out.append(_dim(f"  Reviewer: {reviewer.upper()}  (Springboard mentor model)"))
            out.append(_line(""))
            items = [
                ("Executive Summary", _r.choice([True, True, False])),
                ("Scope Definition", _r.choice([True, True, True])),
                ("Methodology", True),
                ("Findings (with CVSS scores)", _r.choice([True, False])),
                ("Remediation Recommendations", _r.choice([True, False])),
                ("Appendix/Evidence", _r.choice([False, False, True])),
            ]
            score = sum(1 for _, v in items if v)
            for item, ok in items:
                icon = "✓" if ok else "✗"
                t = "success" if ok else "error"
                out.append(_line(f"    {icon} {item}", t))
            out.append(_line(""))
            out.append(_line(f"  Report Score: {score}/{len(items)}"))
            if score >= 5:
                s.xp = getattr(s, 'xp', 0) + 75
                out.append(_sys("  Strong report. +75 XP"))
            else:
                s.xp = getattr(s, 'xp', 0) + 25
                out.append(_dim("  Needs work. Improve missing sections. +25 XP"))
        elif sub in ("tutorial", "progress", "steps", "all", "log", "history"):
            # Redirect: "review tutorial" → show tutorial progress checklist
            tut = self.tut
            all_steps = tut.get_all()
            current_progress = self.gs.tutorial_step
            out.append(_sys("=== TUTORIAL REVIEW MODE ==="))
            out.append(_line("Steps completed so far:", "dim"))
            out.append(_line(""))
            for step in all_steps[:current_progress]:
                cmds_for_step = [
                    e["cmd"] if isinstance(e, dict) else e
                    for e in self.history
                    if re.search(step["match"], (e["cmd"] if isinstance(e, dict) else e), re.IGNORECASE)
                ]
                done_cmd = cmds_for_step[-1] if cmds_for_step else "(completed)"
                out.append(_line(f"  Step {step['id']:2d} [{step['section']:<12}] {step['title']:<25} → {done_cmd[:40]}", "dim"))
            if current_progress < len(all_steps):
                out.append(_line(""))
                out.append(_line(f"  Current: Step {current_progress + 1} — {all_steps[current_progress]['title']}", "success"))
            out.append(_line(""))
            out.append(_line("'review <step_id>' to re-read a step · 'review request' for peer feedback", "dim"))
        else:
            out.append(_err(f"Unknown: review {sub}"))
            out.append(_dim("  review request · review report · review tutorial"))
        return out

