    def _cmd_dice(self, args: List[str]) -> List[dict]:
        """dice [sides] [count] — Roll dice (default 1d6)."""
        sides = 6
        count = 1
        if len(args) >= 1:
            try: sides = int(args[0])
            except ValueError: pass
        if len(args) >= 2:
            try: count = int(args[1])
            except ValueError: pass
        
        # Cap to prevent abuse
        count = max(1, min(count, 10))
        sides = max(2, min(sides, 100))
        
        luck = getattr(self.gs, 'luck', 0)
        results = []
        for _ in range(count):
            roll = random.randint(1, sides)
            if luck > 0 and random.random() < (luck / 100):
                roll = min(sides, roll + random.randint(1, max(1, luck // 10)))
            results.append(roll)
        
        out = [_sys(f"  🎲 Rolling {count}d{sides}...")]
        if luck: out.append(_dim(f"  (Luck modifier: +{luck}%)"))
        
        # Simple ASCII die for d6
        if sides == 6 and count == 1:
            r = results[0]
            dice_art = {
                1: [" ┌─────────┐", " │         │", " │    ●    │", " │         │", " └─────────┘"],
                2: [" ┌─────────┐", " │  ●      │", " │         │", " │      ●  │", " └─────────┘"],
                3: [" ┌─────────┐", " │  ●      │", " │    ●    │", " │      ●  │", " └─────────┘"],
                4: [" ┌─────────┐", " │  ●   ●  │", " │         │", " │  ●   ●  │", " └─────────┘"],
                5: [" ┌─────────┐", " │  ●   ●  │", " │    ●    │", " │  ●   ●  │", " └─────────┘"],
                6: [" ┌─────────┐", " │  ●   ●  │", " │  ●   ●  │", " │  ●   ●  │", " └─────────┘"],
            }
            for line in dice_art.get(r, []):
                out.append(_line(line, "info"))
        
        out.append(_ok(f"  Result: {', '.join(map(str, results))} (Total: {sum(results)})"))
        self.gs.add_xp(2, "terminal")
        return out

