    def _cmd_prime(self, args: List[str]) -> List[dict]:
        """prime [list|factor|rsa|challenge|quiz] — Number theory dungeon."""
        engine = NumberTheoryEngine()
        sub = args[0].lower() if args else "list"
        
        if sub == "list":
            return engine.list_puzzles(list(getattr(self.gs, 'completed_primes', set())))
        elif sub == "load":
            if len(args) < 2: return [_err("Usage: prime load <N>")]
            return engine.load_puzzle(int(args[1]))
        elif sub == "hint":
            if len(args) < 2: return [_err("Usage: prime hint <N>")]
            # Deduct XP for hint
            self.gs.xp = max(0, self.gs.xp - 5)
            return engine.hint(int(args[1]))
        elif sub == "answer":
            if len(args) < 3: return [_err("Usage: prime answer <N> <answer>")]
            n = int(args[1])
            res = engine.answer(n, args[2:])
            if res["ok"]:
                completed = getattr(self.gs, 'completed_primes', set())
                if n not in completed:
                    completed.add(n)
                    self.gs.completed_primes = completed
                    self.gs.add_xp(res["xp"], "cryptography")
                    if res.get("achievement"):
                        self.gs.achievements.add(res["achievement"])
            return res["output"]
        elif sub == "solve":
            if len(args) < 2: return [_err("Usage: prime solve <N>")]
            self.gs.xp = max(0, self.gs.xp - 10)
            return engine.solve(int(args[1]))
        else:
            return [_err("Usage: prime [list|load|hint|answer|solve]")]

    def _cmd_diplomacy(self, args: List[str]) -> List[dict]:
        """diplomacy [status|negotiate|treaty|war] — Faction diplomacy."""
        engine = GrandStrategy()
        flags = self.gs.flags
        sub = args[0].lower() if args else "status"
        
        if sub == "status":
            return engine.render_map(flags)
        elif sub == "treaty" or sub == "war":
            if len(args) < 3: return [_err(f"Usage: diplomacy {sub} <faction1> <faction2>")]
            return engine.diplomacy(args[1], args[2], sub, flags)
        elif sub == "negotiate":
            return [_line("  [DIPLOMACY] Negotiation module offline. Use 'diplomacy treaty' or 'diplomacy war' directly.")]
        else:
            return [_err("Usage: diplomacy [status|treaty|war]")]

    # _cmd_flashback defined above (VN10) — stub removed

    def _cmd_philosophy(self, args: List[str]) -> List[dict]:
        """philosophy [generate|vote|history] — Procedural philosophy dilemmas."""
        sub = args[0].lower() if args else "generate"
        if sub == "generate":
            dilemmas = [
                "The Trolley Problem: Redirect a runaway process to delete 1 core agent or 5 low-level ghosts?",
                "The Ship of Theseus: If every line of an agent is replaced, is it the same agent?",
                "The Experience Machine: Would you live in a perfect simulation if it meant never waking up?"
            ]
            dilemma = random.choice(dilemmas)
            out = [
                _sys("  ═══ PHILOSOPHICAL DILEMMA ═══"),
                _line(f"  {dilemma}"),
                _dim(""),
                _line("  [AGENT VOTES]"),
            ]
            agents = ["ADA-7", "CYPHER", "GORDON", "RAVEN", "WATCHER"]
            for a in agents:
                vote = random.choice(["YES", "NO", "ABSTAIN", "NULL"])
                out.append(_dim(f"    {a:<8} : {vote}"))
            self.gs.add_xp(8, "social_engineering")
            return out
        return [_err("Usage: philosophy [generate]")]

    def _cmd_dungeon(self, args: List[str]) -> List[dict]:
        """dungeon [start|status|move <dir>|look|fight|loot|flee] — Dungeon crawler."""
        from .dungeon_engine import DungeonEngine
        engine = DungeonEngine()
        flags = self.gs.flags
        sub = args[0].lower() if args else "look"
        
        if sub == "start":
            state, out = engine.start(flags)
            return out
        
        state = flags.get("dungeon")
        if not state or not state.get("active"):
            return [_err("Dungeon not active. Run 'dungeon start' to descend.")]
            
        if sub == "look":
            return engine.look(state)
        elif sub == "map":
            return engine.render_map(state)
        elif sub == "status":
            return engine.status(state)
        elif sub == "go" or sub == "move":
            if len(args) < 2: return [_err("Usage: dungeon move <north|south|east|west>")]
            state, out = engine.go(args[1], state)
            return out
        elif sub == "fight":
            state, out, xp = engine.fight(state)
            if xp: self.gs.add_xp(xp, "terminal")
            return out
        elif sub == "take" or sub == "loot":
            state, out, xp = engine.take(state)
            if xp: self.gs.add_xp(xp, "terminal")
            return out
        elif sub == "flee":
            state, out = engine.flee(state)
            return out
        else:
            return [_err("Usage: dungeon [status|move|look|fight|loot|flee]")]

    def _cmd_colonize(self, args: List[str]) -> List[dict]:
        """colonize [list|claim <node>|status|abandon <node>] — Node colonization."""
        gs = self.gs
        sub = args[0].lower() if args else "status"
        
        if sub == "status":
            return get_idle_engine().render_status(gs.flags, list(gs.story_beats))
        elif sub == "claim":
            if len(args) < 3: return [_err("Usage: colonize claim <script_id> <node>")]
            return get_idle_engine().deploy(args[1], args[2], gs.flags, list(gs.story_beats))
        elif sub == "abandon" or sub == "recall":
            if len(args) < 2: return [_err("Usage: colonize abandon <script_id>")]
            return get_idle_engine().recall(args[1], gs.flags)
        elif sub == "list":
            return get_idle_engine().render_status(gs.flags, list(gs.story_beats))
        elif sub == "collect":
            gains = get_idle_engine().collect(gs.flags)
            if not gains: return [_line("  No resources to collect yet.")]
            out = [_ok("  Collected resources:")]
            for k, v in gains.items():
                if k.startswith("xp_"):
                    skill = k.replace("xp_", "")
                    self.gs.add_xp(v, skill)
                    out.append(_dim(f"    {skill} XP: +{v}"))
                else:
                    gs.flags[k] = gs.flags.get(k, 0) + v
                    out.append(_dim(f"    {k}: +{v}"))
            return out
        return [_err("Usage: colonize [list|claim|status|abandon|collect]")]

