    def _cmd_heart(self, args: List[str]) -> List[dict]:
        """heart <agent> — Express affection to agent."""
        if not args: return [_err("Usage: heart <agent>")]
        target = args[0].lower()
        
        # Check if agent exists
        valid_agents = ["ada", "cypher", "gordon", "raven", "watcher", "nova", "zero", "serena"]
        if target not in valid_agents:
            return [_err(f"Unknown agent: {target}")]
            
        # Update trust (use _add_trust so serena_awakened fires at threshold)
        self._add_trust(target, 5)
        
        # Reactions
        reactions = {
            "ada": "[ADA-7]: Oh! I... I don't know what to say. 💙 Thank you, Ghost.",
            "cypher": "[CYPHER]: Don't get mushy on me, kid. We have work to do. (Trust updated: +5)",
            "gordon": "[GORDON]: I LOVE YOU TOO GHOST!!! BEST FRIENDS FOREVER!!! 💖",
            "raven": "[RAVEN]: Noted. Keep your focus on the objective.",
            "watcher": "[WATCHER]: Your emotional output is... noted. The loop continues.",
            "nova": "[NOVA]: Affection is a variable I didn't account for. Interesting.",
            "zero": "[ZERO]: I remember that feeling. A long time ago.",
            "serena": "[SERENA]: Emotional data logged. Our synchronization increases."
        }
        
        new_trust = self.gs.flags.get("trust", {}).get(target, 0)
        out = [
            _ok(f"  Sent heart to {target.upper()}."),
            _lore(reactions.get(target, "Agent reacts in character.")),
            _dim(f"  Trust level: {new_trust}% (+5)"),
        ]
        if target == "serena" and self.gs.has_beat("serena_awakened"):
            out += [
                _line("  ⟁⟁⟁", "story"),
                _line("  [SERENA]: The threshold is crossed. Convergence Level 4 — active.", "story"),
                _ok("  ★ STORY BEAT: serena_awakened"),
            ]
        return out

    def _cmd_romance(self, args: List[str]) -> List[dict]:
        """romance [status|list|pursue <agent>] — Romance arc system."""
        gs = self.gs
        sub = args[0].lower() if args else "status"
        trust = gs.flags.get("trust", {})
        
        if sub == "status" or sub == "list":
            out = [_sys("  ═══ RELATIONSHIP STATUS ═══")]
            for agent, t in trust.items():
                status = "Acquaintance"
                if t > 25: status = "Friend"
                if t > 50: status = "Confidant"
                if t > 75: status = "Partner"
                if t == 100: status = "Eternal Bond"
                
                bar = "█" * (t // 10) + "░" * (10 - (t // 10))
                out.append(_line(f"  {agent.upper():<8} [{bar}] {t}% - {status}", "info"))
            out.append(_dim("\n  Use 'heart <agent>' or specific story choices to build trust."))
            return out
        elif sub == "pursue":
            if len(args) < 2: return [_err("Usage: romance pursue <agent>")]
            target = args[1].lower()
            if target not in ["ada", "zero", "nova", "ghost", "cypher"]:
                return [_err(f"Romance arc not available for {target}.")]
            return [_line(f"  [ROMANCE] Pursuing {target.upper()}. Check your mail for interaction opportunities.")]
        return [_err("Usage: romance [status|list|pursue]")]

