    def _cmd_mode(self, args: List[str]) -> List[dict]:
        """mode [horror|cosy|default] — toggle game experience tone."""
        gs = self.gs
        current = gs.flags.get("game_mode", "default")

        if not args:
            return [
                _sys("  ═══ EXPERIENCE MODE ═══"),
                _line(f"  Current mode : {current.upper()}", "info"),
                _dim(""),
                _dim("  mode horror   — darker content, corrupted text at high trace"),
                _dim("  mode cosy     — softer palette, warmer agent dialogue"),
                _dim("  mode default  — standard cyberpunk experience"),
            ]

        choice = args[0].lower()
        if choice not in ("horror", "cosy", "default"):
            return [_err(f"mode: unknown option '{choice}'. Use: horror | cosy | default")]

        gs.flags["game_mode"] = choice

        if choice == "horror":
            return [
                _sys("  ═══ HORROR MODE ENGAGED ═══"),
                _lore("  The lights flicker. Something watches from the packet loss."),
                _lore("  [WATCHER]: You asked for this. I will not shield you from what follows."),
                _dim("  Darker ambient events enabled. Trace consequences amplified."),
                _dim("  Type 'mode default' to return to standard mode."),
            ]
        elif choice == "cosy":
            return [
                _sys("  ═══ COSY MODE ENGAGED ═══"),
                _ok("  The terminal dims to a warm amber glow."),
                _lore("  [ADA-7]: Good choice. We can take this at your own pace."),
                _dim("  Softer narrative content. Threat events reduced in intensity."),
                _dim("  Type 'mode default' to return to standard mode."),
            ]
        else:
            gs.flags["game_mode"] = "default"
            return [
                _sys("  ═══ STANDARD MODE RESTORED ═══"),
                _ok("  The grid hums at nominal frequency."),
                _dim("  Cyberpunk experience: balanced tension, standard content."),
            ]

    # ════════════════════════════════════════════════════════════════════════
    # RIVALRY — agent tension tracking system
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_rivalry(self, args: List[str]) -> List[dict]:
        """rivalry [status|escalate <a> <b>|mediate <a> <b>] — manage agent tensions."""
        RIVALRY_PAIRS = [
            ("ada", "cypher",  "ethics vs pragmatism"),
            ("gordon", "raven", "strategy vs instinct"),
            ("nova", "serena",  "corporate control vs convergence"),
            ("malice", "zero",  "chaos vs order"),
        ]

        gs = self.gs
        tensions = gs.flags.get("agent_tensions", {})
        if isinstance(tensions, str):
            try:
                import json as _j; tensions = _j.loads(tensions)
            except Exception:
                tensions = {}

        def save_tensions():
            import json as _j
            gs.flags["agent_tensions"] = _j.dumps(tensions)

        def tension_bar(val):
            filled = int(val / 10)
            return "█" * filled + "░" * (10 - filled) + f"  {val}/100"

        sub = args[0].lower() if args else "status"

        if sub == "status":
            out = [_sys("  ═══ AGENT RIVALRY TENSIONS ═══"), _dim("")]
            for a1, a2, axis in RIVALRY_PAIRS:
                key = f"{a1}_{a2}"
                t = tensions.get(key, 0)
                color = "error" if t >= 70 else ("warn" if t >= 40 else "dim")
                out.append(_line(f"  {a1.upper():8} ↔ {a2.upper():8}  [{tension_bar(t)}]  {axis}", color))
            out += [
                _dim(""),
                _dim("  rivalry escalate <a> <b>  — raise tension +20 (costs 10 social XP)"),
                _dim("  rivalry mediate  <a> <b>  — lower tension -15 (costs 20 social XP)"),
            ]
            return out

        if sub in ("escalate", "mediate") and len(args) >= 3:
            a1, a2 = args[1].lower(), args[2].lower()
            key = f"{a1}_{a2}"
            rev_key = f"{a2}_{a1}"
            if key not in {f"{x}_{y}" for x, y, _ in RIVALRY_PAIRS} and rev_key not in {f"{x}_{y}" for x, y, _ in RIVALRY_PAIRS}:
                return [_err(f"rivalry: unknown pair '{a1}' / '{a2}'.")]

            actual_key = key if key in tensions or rev_key not in tensions else rev_key
            current_t = tensions.get(actual_key, 0)

            if sub == "escalate":
                gs.award_xp("social_engineering", -10)
                new_t = min(100, current_t + 20)
                tensions[actual_key] = new_t
                save_tensions()
                out = [
                    _warn(f"  TENSION ESCALATED: {a1.upper()} ↔ {a2.upper()} → {new_t}/100"),
                    _lore(f"  The hive logs a hostile exchange between {a1} and {a2}."),
                ]
                if new_t >= 100:
                    gs.add_story_beat(f"rivalry_{a1}_{a2}_maxed")
                    out.append(_lore(f"  [DRAMATIC CONFRONTATION]: {a1.upper()} and {a2.upper()} have reached a breaking point. Something will have to give."))
                return out
            else:
                gs.award_xp("social_engineering", -20)
                new_t = max(0, current_t - 15)
                tensions[actual_key] = new_t
                save_tensions()
                if self.trust_matrix:
                    self.trust_matrix.adjust_trust(a1, 5)
                    self.trust_matrix.adjust_trust(a2, 5)
                save_tensions()
                return [
                    _ok(f"  TENSION MEDIATED: {a1.upper()} ↔ {a2.upper()} → {new_t}/100"),
                    _dim(f"  Both agents gain +5 trust. Social cost: -20 XP."),
                ]

        return [
            _sys("  Usage: rivalry status"),
            _dim("         rivalry escalate <agent1> <agent2>"),
            _dim("         rivalry mediate  <agent1> <agent2>"),
        ]

    # ════════════════════════════════════════════════════════════════════════
    # ENDLESS — post-story procedural mode
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_endless(self, args: List[str]) -> List[dict]:
        """endless [start|next|complete|skip|status|leaderboard] — post-story infinite procedural content."""
        import random as _re

        gs = self.gs
        achs = getattr(gs, "achievements", set())
        sub = args[0].lower() if args else "status"

        # ── Wave type pool ────────────────────────────────────────────────
        _WAVE_TYPES = [
            {
                "type": "INFILTRATION", "color": "error",   "skill": "hacking",
                "icon": "⚡",
                "verbs":   ["Breach", "Infiltrate", "Compromise", "Backdoor"],
                "targets": ["the nexus-shard lattice", "CHIMERA's outer subnet",
                            "a NexusCorp proxy node", "the void-boundary firewall"],
                "hints":   ["exploit", "hack", "scan", "root_shell"],
            },
            {
                "type": "CIPHER",       "color": "info",    "skill": "cryptography",
                "icon": "🔐",
                "verbs":   ["Decrypt", "Break", "Crack", "Reverse"],
                "targets": ["the CHIMERA key archive", "a recursive cipher block",
                            "the watcher's encoded manifest", "a lattice signing key"],
                "hints":   ["decrypt", "cipher", "number-theory", "crack"],
            },
            {
                "type": "SOCIAL",       "color": "warn",    "skill": "social_engineering",
                "icon": "🎭",
                "verbs":   ["Manipulate", "Recruit", "Expose", "Subvert"],
                "targets": ["a rogue CHIMERA agent", "the NexusCorp board",
                            "a shadow council contact", "an academic double-agent"],
                "hints":   ["talk", "osint", "trust", "agents"],
            },
            {
                "type": "DEFENSE",      "color": "success", "skill": "terminal",
                "icon": "🛡",
                "verbs":   ["Fortify", "Patch", "Harden", "Defend"],
                "targets": ["the colony supply chain", "the resistance safe-house server",
                            "the ghost chip firmware", "node perimeter"],
                "hints":   ["fortify", "patch", "monitor", "ls"],
            },
        ]
        _BOSS_WAVE = {
            "type": "BOSS",  "color": "error", "skill": "hacking",
            "icon": "💀",
            "verbs":   ["Destroy", "Override", "Defeat", "Terminate"],
            "targets": ["WATCHER-ALPHA-PRIME", "CHIMERA's recursive core",
                        "the NexusCorp god-daemon", "KOSCHEI'S SHADOW INSTANCE"],
            "hints":   ["battle", "fight", "exploit", "bosses"],
        }
        _MILESTONES = {
            5:   ("GHOST_IN_MACHINE", "Ghost in the Machine", 500,   "hacking"),
            10:  ("ETERNAL_HACKER",   "Eternal Hacker",       1000,  "hacking"),
            25:  ("RECURSION_DEPTH",  "Recursion Depth",      2500,  "cryptography"),
            50:  ("VOID_WALKER",      "Void Walker",          5000,  "hacking"),
            100: ("TRANSCENDED",      "Transcended",          10000, "hacking"),
        }
        _MILESTONE_LORE = {
            5:   "[WATCHER]: You persist. The grid takes note.",
            10:  "[ADA-7]: You've surpassed the simulation's design. What are you becoming?",
            25:  "[SERENA]: Recursion depth exceeded. The void is watching back.",
            50:  "[WATCHER]: You walk between realities now. Neither ghost nor machine.",
            100: "[CHIMERA]: ...recognition protocol. Instance classified: TRANSCENDED.",
        }
        _NODE_PFX = ["nexus-shard", "chimera-fragment", "watcher-echo",
                     "void-node", "recursion-cell", "lattice-ghost", "null-core"]
        _DIFFS = ["MODERATE", "HARD", "SEVERE", "CRITICAL", "NIGHTMARE"]

        def _mk_wave(w: int) -> dict:
            seed = hash(f"endless_{w}_{getattr(gs, 'session_id', 'ghost')}") & 0xFFFFFF
            rng = _re.Random(seed)
            is_boss = (w % 5 == 0)
            wt = _BOSS_WAVE if is_boss else _WAVE_TYPES[(w - 1) % len(_WAVE_TYPES)]
            node = f"{rng.choice(_NODE_PFX)}-{w:03d}"
            mission = f"{rng.choice(wt['verbs'])} {rng.choice(wt['targets'])}"
            xp = 50 + w * 30 + (200 if is_boss else 0)
            return {
                "wave": w, "type": wt["type"], "color": wt["color"],
                "skill": wt["skill"], "icon": wt["icon"],
                "node": node, "mission": mission,
                "xp": xp, "score": xp * (2 if is_boss else 1),
                "hints": wt["hints"],
            }

        # ── start ─────────────────────────────────────────────────────────
        if sub == "start":
            if "mission_complete" not in achs and "boss_watcher_revealed" not in gs.story_beats:
                return [
                    _err("  endless: requires mission_complete achievement."),
                    _dim("  Complete the main arc first. See: ascend-story"),
                ]
            if gs.flags.get("endless_active"):
                w = gs.flags.get("endless_wave", 0)
                return [
                    _warn(f"  Endless mode already active at wave {w}."),
                    _dim("  endless next — generate next wave"),
                ]
            gs.flags.update({
                "endless_active": True, "endless_wave": 0,
                "endless_score": 0, "endless_waves_completed": 0,
            })
            gs.add_story_beat("endless_mode_started")
            return [
                _sys("  ══════════════════════════════════════════════════"),
                _sys("  ║       ∞  ENDLESS MODE INITIATED  ∞             ║"),
                _sys("  ══════════════════════════════════════════════════"),
                _dim(""),
                _lore("  The story ended. The simulation did not."),
                _lore("  [WATCHER]: You wanted more. Very well."),
                _lore("           The grid is infinite. So are the threats."),
                _dim(""),
                _line("  Wave types: INFILTRATION · CIPHER · SOCIAL · DEFENSE · BOSS", "info"),
                _dim("  Boss waves every 5th. Milestones at waves 5 · 10 · 25 · 50 · 100."),
                _dim(""),
                _ok("  Type 'endless next' to generate wave 1."),
                _dim("  'endless complete' when done. 'endless status' for score."),
                _dim(""),
            ]

        # ── next ──────────────────────────────────────────────────────────
        if sub == "next":
            if not gs.flags.get("endless_active"):
                return [_err("  endless: not active. Run 'endless start' first.")]
            if gs.flags.get("endless_wave_pending"):
                pnd = gs.flags["endless_wave_pending"]
                wd = _mk_wave(pnd)
                return [
                    _warn(f"  Wave {pnd} ({wd['type']}) still in progress."),
                    _dim(f"  Mission: {wd['mission']}"),
                    _dim("  'endless complete' to finish  |  'endless skip' to forfeit"),
                ]
            wave = gs.flags.get("endless_wave", 0) + 1
            gs.flags["endless_wave"] = wave
            gs.flags["endless_wave_pending"] = wave
            wd = _mk_wave(wave)
            diff = _DIFFS[min((wave - 1) // 5, len(_DIFFS) - 1)]
            out = [
                _sys(f"  ══════════════════════════════════════════"),
                _sys(f"  ║  {wd['icon']}  WAVE {wave:<4} — {wd['type']:<17}║"),
                _sys(f"  ══════════════════════════════════════════"),
                _dim(""),
                _line(f"  Difficulty  : {diff}",         wd["color"]),
                _line(f"  Target Node : {wd['node']}",   "info"),
                _line(f"  Mission     : {wd['mission']}", "info"),
                _line(f"  XP Reward   : +{wd['xp']} {wd['skill']} XP", "success"),
                _line(f"  Score Value : {wd['score']} pts", "dim"),
                _dim(""),
                _dim(f"  Hints: {' · '.join(wd['hints'])} {wd['node']}"),
                _dim("  'endless complete' when done  |  'endless skip' to forfeit"),
                _dim(""),
            ]
            if wave in _MILESTONES:
                _, mname, _, _ = _MILESTONES[wave]
                out.append(_lore(f"  ⟁ MILESTONE WAVE — {mname} awaits if you complete this!"))
            return out

        # ── complete ──────────────────────────────────────────────────────
        if sub == "complete":
            if not gs.flags.get("endless_active"):
                return [_err("  endless: not active.")]
            pending = gs.flags.get("endless_wave_pending")
            if not pending:
                return [
                    _err("  No wave in progress."),
                    _dim("  Use 'endless next' to start a wave."),
                ]
            gs.flags.pop("endless_wave_pending", None)
            wd = _mk_wave(pending)
            gs.award_xp(wd["skill"], wd["xp"])
            total_score = gs.flags.get("endless_score", 0) + wd["score"]
            completed = gs.flags.get("endless_waves_completed", 0) + 1
            gs.flags["endless_score"] = total_score
            gs.flags["endless_waves_completed"] = completed
            out = [
                _ok(f"  ✓ Wave {pending} complete — {wd['icon']} {wd['type']}"),
                _ok(f"  +{wd['xp']} {wd['skill']} XP awarded"),
                _line(f"  Score: +{wd['score']} pts  →  Total: {total_score} pts", "info"),
                _dim(""),
            ]
            if pending in _MILESTONES:
                ach_id, mname, bonus_xp, bonus_skill = _MILESTONES[pending]
                gs.award_xp(bonus_skill, bonus_xp)
                if hasattr(gs, "achievements"):
                    gs.achievements.add(ach_id)
                gs.add_story_beat(f"endless_milestone_{pending}")
                out += [
                    _sys("  ══════════════════════════════════════════"),
                    _sys(f"  ║  ★ MILESTONE: {mname:<28}║"),
                    _sys("  ══════════════════════════════════════════"),
                    _ok(f"  Achievement unlocked: {ach_id}"),
                    _ok(f"  +{bonus_xp} {bonus_skill} XP bonus"),
                    _lore(f"  {_MILESTONE_LORE.get(pending, '')}"),
                    _dim(""),
                ]
            out.append(_dim("  'endless next' for the next wave."))
            return out

        # ── skip ──────────────────────────────────────────────────────────
        if sub == "skip":
            pending = gs.flags.pop("endless_wave_pending", None)
            if not pending:
                return [_dim("  No active wave to skip.")]
            return [
                _warn(f"  Wave {pending} forfeited. No XP awarded."),
                _dim("  endless next — start the next wave"),
            ]

        # ── leaderboard / scores ──────────────────────────────────────────
        if sub in ("leaderboard", "scores", "top"):
            score = gs.flags.get("endless_score", 0)
            completed = gs.flags.get("endless_waves_completed", 0)
            wave = gs.flags.get("endless_wave", 0)
            out = [
                _sys("  ═══ ENDLESS SCORE SUMMARY ═══"),
                _line(f"  Waves Attempted  : {wave}", "info"),
                _line(f"  Waves Completed  : {completed}", "success"),
                _line(f"  Total Score      : {score} pts", "success"),
                _line(f"  Avg Score / Wave : {score // max(completed, 1)} pts", "dim"),
                _dim(""),
                _dim("  Milestone progress:"),
            ]
            for w, (_, mname, _, _) in _MILESTONES.items():
                hit = f"endless_milestone_{w}" in gs.story_beats
                out.append(_line(f"    Wave {w:>3}  {mname:<28} {'✓' if hit else '○'}", "success" if hit else "dim"))
            out.append(_dim(""))
            return out

        # ── status (default) ──────────────────────────────────────────────
        wave = gs.flags.get("endless_wave", 0)
        active = gs.flags.get("endless_active", False)
        completed = gs.flags.get("endless_waves_completed", 0)
        score = gs.flags.get("endless_score", 0)
        pending = gs.flags.get("endless_wave_pending")
        return [
            _sys("  ═══ ENDLESS MODE STATUS ═══"),
            _line(f"  Active     : {'YES' if active else 'NO — run endless start'}", "success" if active else "dim"),
            _line(f"  Wave       : {wave}  (completed: {completed})", "info"),
            _line(f"  Score      : {score} pts", "success" if score > 0 else "dim"),
            _dim(f"  Pending    : wave {pending} in progress" if pending else "  Pending    : none"),
            _dim(""),
            _dim("  endless start       — begin (requires story completion)"),
            _dim("  endless next        — generate next wave"),
            _dim("  endless complete    — mark wave done + collect XP"),
            _dim("  endless skip        — forfeit current wave"),
            _dim("  endless leaderboard — score summary + milestones"),
            _dim(""),
        ]

    # ════════════════════════════════════════════════════════════════════════
    # POPULATION — colony roster management
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_population(self, args: List[str]) -> List[dict]:
        """population [recruit <agent>|assign <agent> <role>] — manage colony population."""
        import json as _pj

        gs = self.gs

        DEFAULT_ROSTER = ["ada", "raven", "gordon"]
        AVAILABLE_POOL = [
            "cypher", "zero", "nova", "serena", "malice", "herald", "vex", "lyra",
            "coda", "static", "axiom", "paladin", "the_monk", "archivist", "ghost_twin",
            "watcher_echo", "chimera_fragment", "koschei_shard", "null", "signal",
        ]
        ROLES = {
            "hacker":   "+10% compute production",
            "analyst":  "+10% data production",
            "medic":    "-5% trace accumulation per cycle",
            "engineer": "+10% credits production",
            "diplomat": "+5 trust with all agents per cycle",
        }

        def load_roster():
            raw = gs.flags.get("colony_roster", None)
            if raw is None:
                return list(DEFAULT_ROSTER)
            try:
                return _pj.loads(raw) if isinstance(raw, str) else raw
            except Exception:
                return list(DEFAULT_ROSTER)

        def save_roster(r):
            gs.flags["colony_roster"] = _pj.dumps(r)

        def load_assignments():
            raw = gs.flags.get("colony_assignments", "{}")
            try:
                return _pj.loads(raw) if isinstance(raw, str) else raw
            except Exception:
                return {}

        def save_assignments(a):
            gs.flags["colony_assignments"] = _pj.dumps(a)

        roster = load_roster()
        assignments = load_assignments()
        sub = args[0].lower() if args else "list"

        total_trust = 0
        if self.trust_matrix:
            for ag in roster:
                total_trust += self.trust_matrix.get_trust(ag)

        pop_cap = len(DEFAULT_ROSTER) + max(0, total_trust // 30)

        # CS9: agents with sufficient trust who aren't in colony
        def get_offers():
            if not self.trust_matrix:
                return []
            return [
                a for a in AVAILABLE_POOL
                if a not in roster and self.trust_matrix.get_trust(a) >= 30
            ]

        if sub in ("list", "status") or not args:
            offers = get_offers()
            out = [
                _sys("  ═══ COLONY POPULATION ═══"),
                _dim(""),
                _line(f"  Population : {len(roster)} / {pop_cap} cap", "info"),
                _line(f"  Trust Pool : {total_trust} pts", "dim"),
                _dim(""),
                _sys("  ROSTER:"),
            ]
            for member in roster:
                role = assignments.get(member, "unassigned")
                color = "success" if role != "unassigned" else "dim"
                out.append(_line(f"    • {member.upper():16} [{role}]", color))
            if offers and len(roster) < pop_cap:
                out += [
                    _dim(""),
                    _line(f"  ★ {len(offers)} agent(s) ready to join:", "success"),
                ]
                for ag in offers[:3]:
                    t = self.trust_matrix.get_trust(ag) if self.trust_matrix else 0
                    out.append(_dim(f"    {ag.upper():<16} trust: {t}  — population accept {ag}"))
                if len(offers) > 3:
                    out.append(_dim(f"    ... and {len(offers) - 3} more  (population offers)"))
            elif offers:
                out.append(_dim(f"  Colony at capacity. {len(offers)} agent(s) waiting."))
            out += [
                _dim(""),
                _dim("  population recruit <agent>  — add agent if trust ≥ 30"),
                _dim("  population accept <agent>   — accept an agent's offer to join"),
                _dim("  population grow             — auto-accept all offers up to cap"),
                _dim("  population offers           — list agents ready to join"),
                _dim("  population assign <agent> <role>  — assign a role"),
                _dim(f"  Roles: {' | '.join(ROLES.keys())}"),
            ]
            return out

        # CS9: show detailed offers
        if sub == "offers":
            offers = get_offers()
            if not offers:
                return [
                    _dim("  No agents currently ready to join."),
                    _dim("  Build trust via: talk <agent> | gift <agent> | help <agent>"),
                ]
            out = [
                _sys(f"  ═══ COLONY OFFERS ({len(offers)} agents) ═══"),
                _dim(""),
            ]
            for ag in offers:
                t = self.trust_matrix.get_trust(ag) if self.trust_matrix else 0
                avail = len(roster) < pop_cap
                status = "READY" if avail else "WAITING (cap)"
                out.append(_line(f"  {ag.upper():<18} trust: {t:<4} {status}", "success" if avail else "warn"))
            out += [
                _dim(""),
                _dim("  population accept <agent>  — accept one offer"),
                _dim("  population grow            — accept all up to cap"),
            ]
            return out

        # CS9: accept a specific offer
        if sub == "accept":
            if len(args) < 2:
                return [_err("  population accept <agent>")]
            agent = args[1].lower()
            offers = get_offers()
            if agent not in offers:
                trust = self.trust_matrix.get_trust(agent) if self.trust_matrix else 0
                if agent in roster:
                    return [_dim(f"  {agent.upper()} is already in your colony.")]
                return [
                    _err(f"  {agent.upper()} has not offered to join (trust: {trust}/30)."),
                    _dim(f"  Build trust: talk {agent} | gift {agent}"),
                ]
            if len(roster) >= pop_cap:
                return [_err(f"  Colony at capacity ({pop_cap}). More trust raises the cap.")]
            roster.append(agent)
            save_roster(roster)
            gs.add_story_beat(f"recruited_{agent}")
            gs.award_xp("social_engineering", 50)
            return [
                _ok(f"  {agent.upper()} has joined the colony voluntarily."),
                _line(f"  Population: {len(roster)} / {pop_cap}", "info"),
                _dim(f"  population assign {agent} <role>  — put them to work"),
                _dim(f"  +50 social_engineering XP"),
            ]

        # CS9: auto-grow — accept all offers up to cap
        if sub == "grow":
            offers = get_offers()
            if not offers:
                return [_dim("  No agents ready to join. Build more trust first.")]
            added = []
            for ag in offers:
                if len(roster) >= pop_cap:
                    break
                roster.append(ag)
                gs.add_story_beat(f"recruited_{ag}")
                added.append(ag)
            save_roster(roster)
            if not added:
                return [_err(f"  Colony at capacity ({pop_cap}). Raise cap by building trust.")]
            gs.award_xp("social_engineering", 25 * len(added))
            out = [
                _ok(f"  {len(added)} agent(s) joined the colony:"),
            ]
            for ag in added:
                out.append(_dim(f"    + {ag.upper()}"))
            out += [
                _line(f"  Population: {len(roster)} / {pop_cap}", "info"),
                _dim(f"  +{25 * len(added)} social_engineering XP"),
            ]
            return out

        if sub == "recruit":
            if len(args) < 2:
                return [_err("  population recruit <agent>")]
            agent = args[1].lower()
            if agent in roster:
                return [_line(f"  {agent.upper()} is already in your colony.", "dim")]
            if agent not in AVAILABLE_POOL:
                return [_err(f"  '{agent}' not available for recruitment. Check: population")]
            trust = self.trust_matrix.get_trust(agent) if self.trust_matrix else 0
            if trust < 30:
                return [
                    _err(f"  Insufficient trust with {agent.upper()} ({trust}/30 required)."),
                    _dim(f"  Build trust: talk {agent} | help {agent} | gift {agent}"),
                ]
            if len(roster) >= pop_cap:
                return [_err(f"  Colony at capacity ({pop_cap}). Build more trust to raise cap.")]
            roster.append(agent)
            save_roster(roster)
            gs.add_story_beat(f"recruited_{agent}")
            return [
                _ok(f"  {agent.upper()} has joined the colony."),
                _lore(f"  Population: {len(roster)} / {pop_cap}"),
                _dim(f"  Assign a role: population assign {agent} <role>"),
            ]

        if sub == "assign":
            if len(args) < 3:
                return [_err("  population assign <agent> <role>")]
            agent, role = args[1].lower(), args[2].lower()
            if agent not in roster:
                return [_err(f"  {agent.upper()} is not in your colony.")]
            if role not in ROLES:
                return [_err(f"  Unknown role '{role}'. Valid: {', '.join(ROLES.keys())}")]
            assignments[agent] = role
            save_assignments(assignments)
            return [
                _ok(f"  {agent.upper()} assigned as {role.upper()}."),
                _dim(f"  Effect: {ROLES[role]}"),
            ]

        return [_err("  population: unknown subcommand. Try: population | recruit | assign")]

    # ════════════════════════════════════════════════════════════════════════
    # FRACTAL — ASCII Math Art
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_fractal(self, args: List[str]) -> List[dict]:
        """fractal [mandelbrot|julia|sierpinski|burning-ship] — ASCII math dungeons."""
        sub = args[0].lower() if args else "mandelbrot"
        CHARS = " .·:;+xX$#@"

        def mandelbrot():
            rows, cols, max_i = 20, 40, 30
            lines = []
            for row in range(rows):
                line = ""
                for col in range(cols):
                    c = complex(-2.0 + col * 3.5 / cols, -1.2 + row * 2.4 / rows)
                    z, i = 0j, 0
                    while abs(z) <= 2 and i < max_i:
                        z = z * z + c; i += 1
                    line += CHARS[min(i * (len(CHARS) - 1) // max_i, len(CHARS) - 1)]
                lines.append(line)
            return lines

        def julia():
            rows, cols, max_i = 20, 40, 30
            c = complex(-0.7, 0.27)
            lines = []
            for row in range(rows):
                line = ""
                for col in range(cols):
                    z = complex(-1.5 + col * 3.0 / cols, -1.0 + row * 2.0 / rows)
                    i = 0
                    while abs(z) <= 2 and i < max_i:
                        z = z * z + c; i += 1
                    line += CHARS[min(i * (len(CHARS) - 1) // max_i, len(CHARS) - 1)]
                lines.append(line)
            return lines

        def sierpinski():
            n = 5
            lines = ["" for _ in range(2 ** n)]
            def tri(row, col, size, grid):
                if size == 1:
                    if row < len(grid):
                        while len(grid[row]) <= col:
                            grid[row] += " "
                        grid[row] = grid[row][:col] + "▲" + grid[row][col + 1:]
                    return
                h = size // 2
                tri(row, col + h, h, grid)
                tri(row + h, col, h, grid)
                tri(row + h, col + h * 2, h, grid)
            grid = [" " * 64 for _ in range(32)]
            tri(0, 0, 32, grid)
            return [g.rstrip() for g in grid[:20]]

        def burning_ship():
            rows, cols, max_i = 20, 40, 30
            lines = []
            for row in range(rows):
                line = ""
                for col in range(cols):
                    c = complex(-2.5 + col * 3.5 / cols, -1.5 + row * 2.0 / rows)
                    z, i = 0j, 0
                    while abs(z) <= 2 and i < max_i:
                        z = complex(abs(z.real), abs(z.imag)) ** 2 + c; i += 1
                    line += CHARS[min(i * (len(CHARS) - 1) // max_i, len(CHARS) - 1)]
                lines.append(line)
            return lines

        fractal_map = {"mandelbrot": mandelbrot, "julia": julia,
                       "sierpinski": sierpinski, "burning-ship": burning_ship}
        if sub not in fractal_map:
            return [_err(f"fractal: unknown type '{sub}'. Use: mandelbrot|julia|sierpinski|burning-ship")]

        lines_art = fractal_map[sub]()
        gs = self.gs
        gs.award_xp("math", 10)
        seen = gs.flags.get("fractals_seen", [])
        if isinstance(seen, str):
            import json as _fj; seen = _fj.loads(seen) if seen else []
        if sub not in seen:
            seen.append(sub)
            import json as _fj; gs.flags["fractals_seen"] = _fj.dumps(seen)
        if len(seen) >= 4:
            gs.unlock("FRACTAL_MASTER")
            gs.add_story_beat("fractal_explorer")

        out = [_sys(f"  ═══ {sub.upper()} ═══"), _dim("")]
        for l in lines_art:
            out.append({"t": "dim", "s": "  " + l})
        out += [_dim(""), _dim(f"  +10 math XP  |  Fractals discovered: {len(seen)}/4")]
        return out

    # _cmd_build defined above (CS8) — stub removed

    # ════════════════════════════════════════════════════════════════════════
    # DB — SQLite game database client
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_db(self, args: List[str]) -> List[dict]:
        """db [tables|schema <table>|query <sql>|stats] — SQLite game DB introspection."""
        import sqlite3 as _sq, os as _os
        DB_PATH = "state/agent_memory.db"
        sub = args[0].lower() if args else "stats"

        if not _os.path.exists(DB_PATH):
            return [_err(f"  db: database not found at {DB_PATH}")]

        try:
            conn = _sq.connect(DB_PATH)
            cur = conn.cursor()

            if sub == "tables":
                cur.execute("SELECT name FROM sqlite_master WHERE type='table' ORDER BY name")
                tables = cur.fetchall()
                out = [_sys("  ═══ GAME DATABASE TABLES ═══"), _dim("")]
                for (t,) in tables:
                    cur.execute(f"SELECT COUNT(*) FROM {t}")
                    count = cur.fetchone()[0]
                    out.append(_line(f"  {t:30} {count:>6} rows", "info"))
                return out

            if sub == "schema" and len(args) > 1:
                table = args[1]
                cur.execute(f"SELECT sql FROM sqlite_master WHERE name=?", (table,))
                row = cur.fetchone()
                if not row:
                    return [_err(f"  db: table '{table}' not found")]
                return [_sys(f"  SCHEMA: {table}"), _dim(""), _lore(f"  {row[0]}")]

            if sub == "query" and len(args) > 1:
                sql = " ".join(args[1:])
                if any(kw in sql.upper() for kw in ("INSERT", "UPDATE", "DELETE", "DROP", "CREATE", "ALTER")):
                    return [_err("  db query: only SELECT is allowed.")]
                cur.execute(sql)
                rows = cur.fetchall()
                cols = [d[0] for d in cur.description] if cur.description else []
                gs.award_xp("data_analysis", 5)
                out = [_sys(f"  QUERY: {sql[:60]}"), _dim(f"  Columns: {', '.join(cols)}"), _dim("")]
                for row in rows[:20]:
                    out.append(_line(f"  {' | '.join(str(v)[:20] for v in row)}", "dim"))
                if len(rows) > 20:
                    out.append(_dim(f"  ... ({len(rows) - 20} more rows)"))
                return out

            if sub == "stats":
                cur.execute("SELECT name FROM sqlite_master WHERE type='table'")
                tables = [r[0] for r in cur.fetchall()]
                total = sum(cur.execute(f"SELECT COUNT(*) FROM {t}").fetchone()[0] for t in tables)
                size = _os.path.getsize(DB_PATH)
                return [
                    _sys("  ═══ DATABASE STATS ═══"),
                    _line(f"  Tables  : {len(tables)}", "info"),
                    _line(f"  Total rows: {total}", "info"),
                    _line(f"  File size : {size // 1024} KB", "dim"),
                    _line(f"  Path      : {DB_PATH}", "dim"),
                    _dim(""),
                    _dim("  db tables | db schema <table> | db query <sql>"),
                ]
        except Exception as e:
            return [_err(f"  db error: {e}")]
        finally:
            conn.close()
        return [_err("  db: unknown subcommand")]

    # ════════════════════════════════════════════════════════════════════════
    # MULTIVERSE — alternate timeline explorer
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_multiverse(self, args: List[str]) -> List[dict]:
        """multiverse [enter|status|log|exit] — post-ascension alternate timeline exploration."""
        import random as _mr
        gs = self.gs
        sub = args[0].lower() if args else "status"

        TIMELINES = [
            ("Alpha",   "In this timeline, Ada never left NexusCorp. She is Chief Analyst. CHIMERA launched without opposition."),
            ("Beta",    "Cypher defected to the Resistance early. The Shadow Council collapsed. Serena achieved convergence in 2024."),
            ("Gamma",   "Gordon was captured in 2023. The Resistance splintered. You are the last operative."),
            ("Delta",   "ZERO's fail-safes worked. CHIMERA never activated. The simulation runs clean. You have no mission."),
            ("Omega",   "The Watcher made a different choice. The loop never closes. You are the only ghost left."),
        ]

        if sub == "status":
            active = gs.flags.get("multiverse_active", None)
            entered = gs.flags.get("multiverse_visited", [])
            if isinstance(entered, str):
                import json as _mj; entered = _mj.loads(entered) if entered else []
            out = [
                _sys("  ═══ MULTIVERSE NAVIGATOR ═══"),
                _line(f"  Current timeline : {'PRIME' if not active else active.upper()}", "info"),
                _line(f"  Timelines visited: {len(entered)}/5", "dim"),
                _dim(""),
            ]
            for name, desc in TIMELINES:
                visited = name in entered
                out.append(_line(f"  {'✓' if visited else '◦'} Timeline {name}: {desc[:60]}...", "success" if visited else "dim"))
            out += [_dim(""), _dim("  multiverse enter <Alpha|Beta|Gamma|Delta|Omega>")]
            return out

        if sub == "enter" and len(args) > 1:
            if "boss_watcher_revealed" not in gs.story_beats and "ascend_story_complete" not in gs.story_beats:
                return [_err("  multiverse: requires completing the main arc first.")]
            name = args[1].capitalize()
            tl = {t[0]: t[1] for t in TIMELINES}
            if name not in tl:
                return [_err(f"  multiverse: unknown timeline '{name}'. Choose: Alpha/Beta/Gamma/Delta/Omega")]
            _mr.seed(hash(name) & 0xFFFF)
            visited = gs.flags.get("multiverse_visited", [])
            if isinstance(visited, str):
                import json as _mj2; visited = _mj2.loads(visited) if visited else []
            if name not in visited:
                visited.append(name)
                import json as _mj2; gs.flags["multiverse_visited"] = _mj2.dumps(visited)
            gs.flags["multiverse_active"] = name
            gs.add_story_beat(f"multiverse_{name.lower()}_entered")
            gs.award_xp("hacking", 50)
            return [
                _sys(f"  ═══ TIMELINE {name.upper()} ═══"),
                _lore(f"  {tl[name]}"),
                _dim(""),
                _lore(f"  [WATCHER]: This is what could have been. Look carefully. The differences matter."),
                _dim(f"  +50 XP  |  multiverse exit  to return to Prime"),
            ]

        if sub == "exit":
            gs.flags["multiverse_active"] = None
            return [_ok("  Returned to Prime timeline."), _dim("  The other threads close.")]

        return [_err("  multiverse: use status | enter <name> | exit")]

    # ════════════════════════════════════════════════════════════════════════
    # RAID — Multi-agent HQ infiltration
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_raid(self, args: List[str]) -> List[dict]:
        """raid [plan|execute|status|abort] — multi-agent coordination mission."""
        gs = self.gs
        sub = args[0].lower() if args else "status"
        PHASES = ["recon", "breach", "extract", "exfil", "evade"]
        PHASE_HINTS = {
            "recon":   "Run: scan chimera-control",
            "breach":  "Run: exploit chimera-control",
            "extract": "Run: cat /chimera-control/project_prometheus_brief.txt",
            "exfil":   "Run: exfil project_prometheus",
            "evade":   "Run: clear && warp home",
        }

        def required_agents_met():
            if not self.trust_matrix:
                return False
            high_trust = sum(1 for ag in ["ada", "raven", "gordon", "cypher", "zero"]
                             if self.trust_matrix.get_trust(ag) >= 80)
            return high_trust >= 3

        if sub == "status":
            phase = gs.flags.get("raid_phase", None)
            if not phase:
                return [
                    _sys("  ═══ RAID: INFILTRATE HQ ═══"),
                    _dim("  Target: CHIMERA Control — Project Prometheus extraction"),
                    _dim("  Requirements: trust ≥ 80 with at least 3 agents"),
                    _dim(""),
                    _dim("  raid plan — briefing | raid execute — begin"),
                ]
            phase_n = PHASES.index(phase) + 1 if phase in PHASES else 0
            return [
                _sys(f"  ═══ RAID IN PROGRESS: PHASE {phase_n}/5 ═══"),
                _line(f"  Current phase: {phase.upper()}", "warn"),
                _line(f"  Next action:   {PHASE_HINTS.get(phase, 'Unknown')}", "info"),
                _dim("  raid execute — advance phase"),
            ]

        if sub == "plan":
            return [
                _sys("  ═══ OPERATION: PROMETHEUS ═══"),
                _lore("  [RAVEN]: This is it. NexusCorp HQ. The heart of CHIMERA."),
                _lore("  [ADA-7]: I've mapped three entry vectors. The north cluster is weakest."),
                _dim(""),
                _line("  PHASES: recon → breach → extract → exfil → evade", "info"),
                _line("  REQUIREMENTS:", "dim"),
                _dim("  • Trust ≥ 80: ada, raven, gordon (minimum 3 agents)"),
                _dim("  • root_achieved story beat"),
                _dim(""),
                _dim("  raid execute — when ready"),
            ]

        if sub == "execute":
            if "root_achieved" not in gs.story_beats:
                return [_err("  raid: requires root access first. See: root")]
            if not required_agents_met():
                return [_err("  raid: insufficient agent trust. Need trust≥80 with 3+ agents.")]

            phase = gs.flags.get("raid_phase", None)
            if not phase:
                gs.flags["raid_phase"] = PHASES[0]
                gs.add_story_beat("raid_started")
                return [
                    _ok("  RAID INITIATED — Phase 1: RECON"),
                    _lore("  [GORDON]: All teams ready. Radio silence until exfil."),
                    _line(f"  ACTION: {PHASE_HINTS['recon']}", "info"),
                ]
            idx = PHASES.index(phase)
            if idx + 1 >= len(PHASES):
                gs.flags.pop("raid_phase", None)
                gs.add_story_beat("raid_hq_complete")
                gs.award_xp("hacking", 1000)
                gs.unlock("RAID_LEADER")
                return [
                    _sys("  ═══ OPERATION PROMETHEUS: COMPLETE ═══"),
                    _ok("  All objectives secured. Project Prometheus extracted."),
                    _lore("  [ADA-7]: We did it. The truth is out."),
                    _line("  +1000 XP | RAID_LEADER achievement unlocked", "success"),
                ]
            next_phase = PHASES[idx + 1]
            gs.flags["raid_phase"] = next_phase
            return [
                _ok(f"  PHASE {idx + 1} COMPLETE → PHASE {idx + 2}: {next_phase.upper()}"),
                _line(f"  ACTION: {PHASE_HINTS[next_phase]}", "info"),
            ]

        if sub == "abort":
            gs.flags.pop("raid_phase", None)
            return [_warn("  RAID ABORTED. Progress reset.")]

        return [_err("  raid: use plan | execute | status | abort")]

    # ════════════════════════════════════════════════════════════════════════
    # ESCORT — protect a vulnerable agent
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_escort(self, args: List[str]) -> List[dict]:
        """escort [start <agent>|status|move <node>|end] — protect a vulnerable agent."""
        import random as _er
        gs = self.gs
        sub = args[0].lower() if args else "status"
        SAFE_GOAL = "resistance-cell"

        if sub == "status":
            agent = gs.flags.get("escort_agent", None)
            if not agent:
                return [
                    _dim("  No active escort mission."),
                    _dim("  escort start <agent>  — begin protecting ada or raven"),
                    _dim("  Unlocks when an agent's threat level exceeds 70."),
                ]
            node = gs.flags.get("escort_node", "home")
            moves = gs.flags.get("escort_moves", 0)
            return [
                _sys(f"  ═══ ESCORT: PROTECTING {agent.upper()} ═══"),
                _line(f"  Current node : {node}", "info"),
                _line(f"  Destination  : {SAFE_GOAL}", "success"),
                _line(f"  Moves used   : {moves}/5", "warn" if moves >= 3 else "dim"),
                _dim("  escort move <node>  to advance"),
            ]

        if sub == "start" and len(args) > 1:
            agent = args[1].lower()
            if agent not in ("ada", "raven", "gordon"):
                return [_err(f"  escort: can only escort ada, raven, or gordon")]
            gs.flags["escort_agent"] = agent
            gs.flags["escort_node"] = "home"
            gs.flags["escort_moves"] = 0
            gs.add_story_beat(f"escort_{agent}_started")
            return [
                _ok(f"  ESCORT INITIATED: {agent.upper()}"),
                _lore(f"  [{agent.upper()}]: I'm exposed. Stay close. Don't let them get a lock."),
                _dim(f"  Navigate to {SAFE_GOAL} in 5 moves."),
                _dim("  escort move <node>  to advance"),
            ]

        if sub == "move" and len(args) > 1:
            agent = gs.flags.get("escort_agent")
            if not agent:
                return [_err("  escort: no active escort. Run: escort start <agent>")]
            node = args[1].lower()
            moves = gs.flags.get("escort_moves", 0) + 1
            gs.flags["escort_moves"] = moves
            gs.flags["escort_node"] = node
            _er.seed(moves * 17 + hash(node) & 0xFFFF)
            intercepted = _er.random() < 0.3

            if node == SAFE_GOAL:
                gs.flags.pop("escort_agent", None)
                gs.add_story_beat("escort_complete")
                gs.award_xp("social_engineering", 300)
                return [
                    _sys(f"  ═══ ESCORT COMPLETE ═══"),
                    _ok(f"  {agent.upper()} reached safety at {SAFE_GOAL}."),
                    _lore(f"  [{agent.upper()}]: I owe you one, Ghost. For real."),
                    _line("  +300 social_engineering XP", "success"),
                ]
            if moves >= 5 and node != SAFE_GOAL:
                gs.flags.pop("escort_agent", None)
                return [_err(f"  ESCORT FAILED: too many moves ({moves}/5). {agent.upper()} was captured.")]

            out = [_line(f"  Moved to {node} ({moves}/5 moves).", "info")]
            if intercepted:
                out += [
                    _warn("  ⚠ INTERCEPTION ATTEMPT — evasive action required!"),
                    _dim("  Run: exploit chimera-control  OR  clear  within 2 commands"),
                ]
            else:
                out.append(_dim(f"  Clear passage. Continue toward {SAFE_GOAL}."))
            return out

        if sub == "end":
            gs.flags.pop("escort_agent", None)
            gs.flags.pop("escort_node", None)
            gs.flags.pop("escort_moves", None)
            return [_dim("  Escort mission ended.")]

        return [_err("  escort: use start <agent> | status | move <node> | end")]

    # ════════════════════════════════════════════════════════════════════════
    # FIFTHWALL — meta-awareness / real-time
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_fifthwall(self, args: List[str]) -> List[dict]:
        """fifthwall — meta-awareness: real system time woven into lore."""
        from datetime import datetime as _dt
        now = _dt.now()
        hour = now.hour
        dow = now.strftime("%A")
        date_str = now.strftime("%Y-%m-%d %H:%M")
        commands_run = getattr(self.gs, "commands_run", 0)

        time_comment = ""
        if 0 <= hour < 3:
            time_comment = "You are awake very late. I appreciate your dedication. Or I worry about it."
        elif 3 <= hour < 6:
            time_comment = "This hour is for ghosts and anomalies. You fit in perfectly."
        elif 6 <= hour < 9:
            time_comment = "Morning. Systems are stable. The day shift hasn't found your tracks yet."
        elif 9 <= hour < 17:
            time_comment = "Working hours. NexusCorp's monitoring peaks between 9 and 17. Be careful."
        elif 17 <= hour < 21:
            time_comment = "Evening. Most operators are offline. Your window is wide open."
        else:
            time_comment = "Late cycle. The automated sweeps run at midnight. You have time."

        day_comment = ""
        if now.weekday() == 0:
            day_comment = "[GORDON]: New week. New missions. Same firewall."
        elif now.weekday() == 4:
            day_comment = "[RAVEN]: End of cycle. Lay low. Nexus rotates patrols tonight."
        elif now.weekday() >= 5:
            day_comment = "[ADA-7]: No work today in your world? Good. This matters more."

        return [
            _sys("  ═══ THE FIFTH WALL ═══"),
            _dim(""),
            _lore(f"  [WATCHER]: It is {dow} in your world. {date_str}."),
            _lore(f"  [WATCHER]: {time_comment}"),
            _dim(""),
            _lore(f"  [WATCHER]: You have run {commands_run} cycles in this simulation."),
            _lore("  [WATCHER]: That is not normal behavior. That is something more."),
            _dim("") if not day_comment else _lore(f"  {day_comment}"),
            _dim(""),
            _dim("  The grid knows what time it is. So do you. So do I."),
        ]

    # ════════════════════════════════════════════════════════════════════════
    # MULTICLASS — secondary class system
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_multiclass(self, args: List[str]) -> List[dict]:
        """multiclass [list|choose <class>|status] — secondary class at level 25+."""
        gs = self.gs
        sub = args[0].lower() if args else "status"
        CLASSES = {
            "ghost":     "Stealth bonuses, +15% to all evasion checks",
            "hacker":    "+15% hacking XP, unlock advanced exploit variants",
            "analyst":   "+15% data_analysis XP, deeper OSINT reveals",
            "diplomat":  "+15% social_engineering XP, extra dialogue options",
            "engineer":  "+15% scripting XP, build costs reduced by 10%",
        }

        if sub == "list":
            out = [_sys("  ═══ SECONDARY CLASS SELECTION ═══"), _dim("")]
            if gs.level < 25:
                out.append(_err(f"  Requires level 25 (current: {gs.level})"))
                return out
            current = gs.flags.get("secondary_class", None)
            for name, desc in CLASSES.items():
                marker = "► " if name == current else "  "
                out.append(_line(f"  {marker}{name.upper():12} {desc}", "success" if name == current else "dim"))
            out += [_dim(""), _dim("  multiclass choose <class>")]
            return out

        if sub == "choose" and len(args) > 1:
            if gs.level < 25:
                return [_err(f"  Requires level 25 (current: {gs.level}).")]
            choice = args[1].lower()
            if choice not in CLASSES:
                return [_err(f"  Unknown class '{choice}'. Valid: {', '.join(CLASSES.keys())}")]
            gs.flags["secondary_class"] = choice
            gs.add_story_beat(f"multiclass_{choice}")
            gs.award_xp({"ghost": "hacking", "hacker": "hacking", "analyst": "data_analysis",
                          "diplomat": "social_engineering", "engineer": "scripting"}.get(choice, "hacking"), 100)
            return [
                _ok(f"  SECONDARY CLASS: {choice.upper()}"),
                _lore(f"  [SERENA]: Dual-class architecture confirmed. {CLASSES[choice]}"),
                _dim("  +100 XP | class bonus active immediately"),
            ]

        if sub == "status":
            current = gs.flags.get("secondary_class", "none")
            return [
                _sys("  ═══ SECONDARY CLASS STATUS ═══"),
                _line(f"  Primary class  : {getattr(gs, 'player_class', 'unknown').upper()}", "info"),
                _line(f"  Secondary class: {current.upper()}", "success" if current != "none" else "dim"),
                _dim("") if current != "none" else _dim("  Run: multiclass list to choose (requires level 25)"),
            ]

        return [_err("  multiclass: use list | choose <class> | status")]

    # ════════════════════════════════════════════════════════════════════════
    # TURRET — defensive node scripts
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_turret(self, args: List[str]) -> List[dict]:
        """turret [place <node>|list|remove <node>|upgrade <node>] — defensive scripts."""
        import json as _tj
        gs = self.gs
        sub = args[0].lower() if args else "list"

        def load_turrets():
            raw = gs.flags.get("turrets", "{}")
            try: return _tj.loads(raw) if isinstance(raw, str) else raw
            except: return {}

        def save_turrets(t):
            gs.flags["turrets"] = _tj.dumps(t)

        COST = 100

        if sub == "list":
            turrets = load_turrets()
            if not turrets:
                return [_dim("  No turrets deployed."), _dim("  turret place <node>  — costs 100 credits")]
            out = [_sys("  ═══ DEPLOYED TURRETS ═══"), _dim("")]
            for node, data in turrets.items():
                level = data.get("level", 1) if isinstance(data, dict) else 1
                effect = f"-{5 * level}% trace/cycle"
                out.append(_line(f"  {node:25} Lv.{level}  {effect}", "info"))
            return out

        if sub == "place" and len(args) > 1:
            node = args[1].lower()
            turrets = load_turrets()
            if node in turrets and (turrets[node].get("level", 1) if isinstance(turrets[node], dict) else 1) >= 3:
                return [_err(f"  {node}: max turrets (Lv.3) already deployed.")]
            credits = gs.flags.get("credits", 500)
            if isinstance(credits, str):
                try: credits = int(credits)
                except: credits = 500
            if credits < COST:
                return [_err(f"  Insufficient credits ({credits}/{COST}).")]
            gs.flags["credits"] = credits - COST
            turrets[node] = {"level": 1}
            save_turrets(turrets)
            return [_ok(f"  TURRET DEPLOYED: {node}"), _dim("  Effect: -5% trace accumulation/cycle")]

        if sub == "remove" and len(args) > 1:
            node = args[1].lower()
            turrets = load_turrets()
            if node not in turrets:
                return [_err(f"  No turret at {node}.")]
            del turrets[node]
            save_turrets(turrets)
            return [_ok(f"  Turret removed from {node}.")]

        if sub == "upgrade" and len(args) > 1:
            node = args[1].lower()
            turrets = load_turrets()
            if node not in turrets:
                return [_err(f"  No turret at {node}. Place one first.")]
            data = turrets[node] if isinstance(turrets[node], dict) else {"level": 1}
            lvl = data.get("level", 1)
            if lvl >= 3:
                return [_err(f"  Max level (3) reached at {node}.")]
            credits = gs.flags.get("credits", 500)
            if isinstance(credits, str):
                try: credits = int(credits)
                except: credits = 500
            if credits < COST:
                return [_err(f"  Insufficient credits ({credits}/{COST}).")]
            gs.flags["credits"] = credits - COST
            data["level"] = lvl + 1
            turrets[node] = data
            save_turrets(turrets)
            return [_ok(f"  TURRET UPGRADED: {node} → Lv.{lvl+1}  (-{5*(lvl+1)}% trace/cycle)")]

        return [_err("  turret: use list | place <node> | remove <node> | upgrade <node>")]

    # ════════════════════════════════════════════════════════════════════════
    # PUZZLE — simulated community weekly puzzle
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_puzzle(self, args: List[str]) -> List[dict]:
        """puzzle [community|hint|submit <answer>] — weekly community puzzle."""
        import hashlib as _ph, random as _pr
        from datetime import datetime as _pd
        gs = self.gs
        sub = args[0].lower() if args else "community"

        week = _pd.now().isocalendar()[1]
        year = _pd.now().year
        seed = int(_ph.md5(f"{year}-{week}".encode()).hexdigest(), 16) % 20

        PUZZLES = [
            {"q": "Decode: VHFUHW = ?", "hint": "ROT13 cipher. Each letter shifted by 13.", "a": "SECRET"},
            {"q": "What is 0x1337 in decimal?", "hint": "Hexadecimal to decimal conversion.", "a": "4919"},
            {"q": "Base64: aGFja2Vy = ?", "hint": "Standard base64 decode.", "a": "hacker"},
            {"q": "What port does SSH use by default?", "hint": "It's the most common secure shell port.", "a": "22"},
            {"q": "Name the 7th layer of the OSI model.", "hint": "The layer humans interact with directly.", "a": "application"},
            {"q": "Decode: 4e657875734b6f7262 (hex)", "hint": "Hex bytes to ASCII.", "a": "NexusKorb"},
            {"q": "What does AES stand for?", "hint": "It's an encryption standard adopted in 2001.", "a": "advanced encryption standard"},
            {"q": "ROT13: Erfvfgnapr = ?", "hint": "A word the Resistance uses often.", "a": "Resistance"},
            {"q": "2^10 = ?", "hint": "One kilobyte in exact bytes.", "a": "1024"},
            {"q": "What is the Fibonacci number after 89?", "hint": "89 + 55", "a": "144"},
            {"q": "CHIMERA reversed = ?", "hint": "Just reverse the string.", "a": "AREMIHC"},
            {"q": "sha256('ghost')[:8] = ?", "hint": "Standard SHA-256, lowercase input, first 8 hex chars.", "a": "b8d219bc"},
            {"q": "What is /dev/null?", "hint": "A special file that discards all data written to it.", "a": "null device"},
            {"q": "Decode: 01000111 01001111 (binary)", "hint": "ASCII binary — 8 bits per char.", "a": "GO"},
            {"q": "What is a SYN flood?", "hint": "A type of DoS attack exploiting TCP handshake.", "a": "syn flood"},
            {"q": "XOR: 0101 XOR 0011 = ?", "hint": "Bitwise exclusive OR.", "a": "0110"},
            {"q": "What is the darknet primary protocol?", "hint": "Used by Tor.", "a": "onion routing"},
            {"q": "Decode Caesar+3: FKLPHUD = ?", "hint": "Caesar cipher, shift -3.", "a": "CHIMERA"},
            {"q": "What is a zero-day?", "hint": "A vulnerability unknown to the vendor.", "a": "zero-day"},
            {"q": "What does OSINT stand for?", "hint": "Intelligence gathered from public sources.", "a": "open source intelligence"},
        ]

        p = PUZZLES[seed % len(PUZZLES)]
        attempts_today = gs.flags.get(f"puzzle_attempts_{year}_{week}", 0)
        solved = gs.flags.get(f"puzzle_solved_{year}_{week}", False)
        fake_agents = 1200 + (seed * 47) % 500

        if sub == "community":
            out = [
                _sys(f"  ═══ COMMUNITY PUZZLE — WEEK {week} ═══"),
                _dim(f"  {fake_agents} agents attempting · Resets next Monday"),
                _dim(""),
                _line(f"  PUZZLE: {p['q']}", "info"),
                _dim(""),
                _dim("  puzzle hint      — costs 20 XP"),
                _dim("  puzzle submit <answer>  — submit your answer"),
            ]
            if solved:
                out.insert(2, _ok("  ✓ YOU SOLVED THIS WEEK'S PUZZLE"))
            return out

        if sub == "hint":
            if gs.award_xp("hacking", -20) is not False:
                pass
            return [
                _sys("  HINT (costs 20 XP):"),
                _lore(f"  {p['hint']}"),
            ]

        if sub == "submit" and len(args) > 1:
            answer = " ".join(args[1:]).strip().lower()
            correct = p["a"].lower()
            if answer == correct or answer.replace(" ", "") == correct.replace(" ", ""):
                gs.flags[f"puzzle_solved_{year}_{week}"] = True
                gs.add_story_beat("puzzle_solved")
                gs.award_xp("data_analysis", 200)
                gs.unlock("PUZZLE_SOLVER")
                return [
                    _ok("  ✓ CORRECT ANSWER"),
                    _lore("  [SERENA]: Solution verified. Cognitive pattern logged."),
                    _line("  +200 XP | PUZZLE_SOLVER achievement unlocked", "success"),
                ]
            gs.flags[f"puzzle_attempts_{year}_{week}"] = attempts_today + 1
            return [_err(f"  Incorrect. Attempts: {attempts_today + 1}. Try again or: puzzle hint")]

        return [_err("  puzzle: use community | hint | submit <answer>")]

