    # ════════════════════════════════════════════════════════════════════════
    # CYBERWARE — street-level implant system
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_cyberware(self, args: List[str]) -> List[dict]:
        """cyberware [catalog|install <id>|status|uninstall <id>|cool|slots] — street implants."""
        from app.game_engine.cyberware import CyberwareSystem, IMPLANTS, SLOTS
        cw = CyberwareSystem(self.gs)
        sub = args[0].lower() if args else "status"

        if sub in ("catalog", "shop", "list"):
            return cw.render_catalog()

        if sub == "status":
            return cw.render_status()

        if sub == "slots":
            out = [_sys("  ═══ CYBERWARE SLOTS ═══"), _dim("")]
            for slot, cap in SLOTS.items():
                used = cw.slots_used(slot)
                bar = "█" * used + "░" * (cap - used)
                out.append(_line(f"  {slot.upper():<10} [{bar}] {used}/{cap}", "success" if used < cap else "warn"))
            return out

        if sub == "install" and len(args) > 1:
            return cw.install(args[1].lower())

        if sub == "uninstall" and len(args) > 1:
            return cw.uninstall(args[1].lower())

        if sub == "cool":
            new_heat = cw._cool(15)
            self.gs.add_xp(5, "terminal")
            return [
                _ok(f"  Cooling routines executed. Heat: {new_heat:.0f}%"),
                _dim("  Thermal dampeners online. Integration sickness fading."),
            ]

        if sub in ("info", "inspect") and len(args) > 1:
            imp_id = args[1].lower()
            imp = IMPLANTS.get(imp_id)
            if not imp:
                return [_err(f"  Unknown implant '{imp_id}'. Run: cyberware catalog")]
            installed = cw.has(imp_id)
            out = [
                _sys(f"  ═══ {imp['icon']} {imp['name'].upper()} ═══"),
                _dim(""),
                _line(f"  ID     : {imp_id}", "dim"),
                _line(f"  Slot   : {imp['slot'].upper()}  |  Tier: {imp['tier']}  |  Cost: {imp['cost']} cr", "info"),
                _line(f"  Status : {'✓ INSTALLED' if installed else '○ Not installed'}", "success" if installed else "dim"),
                _dim(""),
                _line(f"  {imp['desc']}", "info"),
                _dim(""),
                _lore(f"  {imp['lore']}"),
                _dim(""),
                _dim(f"  Heat/cmd: +{imp['heat_per_cmd']}%  |  cyberware install {imp_id}"),
            ]
            return out

        return [_err("  cyberware: use catalog | install <id> | status | cool | slots | uninstall <id>")]

    # ════════════════════════════════════════════════════════════════════════
    # GHOST — active stealth protocol
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_ghost(self, args: List[str]) -> List[dict]:
        """ghost [activate|deactivate|status|ping] — active stealth mode."""
        import random as _gr
        from app.game_engine.cyberware import CyberwareSystem
        gs = self.gs
        sub = args[0].lower() if args else "status"

        cw = CyberwareSystem(gs)
        has_chip = cw.has("ghost_chip")
        aug_ghost = "ghost_protocol_available" in gs.story_beats
        can_ghost = has_chip or aug_ghost or "aug_hidden_commands" in gs.achievements

        if sub == "status":
            active = gs.flags.get("ghost_active", False)
            commands_left = gs.flags.get("ghost_commands_left", 0)
            blow_risk = gs.flags.get("ghost_blow_risk", 0.15)
            return [
                _sys("  ═══ GHOST PROTOCOL STATUS ═══"),
                _dim(""),
                _line(f"  Status       : {'ACTIVE 👻' if active else 'INACTIVE'}", "success" if active else "dim"),
                _line(f"  Ghost chip   : {'✓ installed' if has_chip else '✗ not installed'}", "success" if has_chip else "dim"),
                _line(f"  Commands left: {commands_left}" if active else "  (activate to see timer)", "warn" if active else "dim"),
                _line(f"  Blow risk/cmd: {blow_risk:.0%}" if active else "", "warn") if active else _dim(""),
                _dim(""),
                _dim("  ghost activate | ghost deactivate | ghost ping"),
            ]

        if sub == "activate":
            if not can_ghost:
                return [
                    _err("  Ghost Protocol requires:"),
                    _dim("  • cyberware install ghost_chip  (1400 cr)"),
                    _dim("  • OR: augment buy aug_hidden_commands  (prestige)"),
                ]
            if gs.flags.get("ghost_active"):
                return [_warn("  Ghost Protocol already active.")]
            gs.flags["ghost_active"] = True
            gs.flags["ghost_commands_left"] = 20 + (5 if has_chip else 0)
            gs.flags["ghost_blow_risk"] = 0.08 if has_chip else 0.15
            gs.add_story_beat("ghost_protocol_activated")
            return [
                _sys("  ═══ GHOST PROTOCOL: ONLINE ═══"),
                _lore("  [GHOST-CHIP]: Stealth envelope active. EM signature reduced."),
                _line("  Trace accumulation: -60%  |  Exploit bonus: +20%", "success"),
                _dim(f"  Duration: {gs.flags['ghost_commands_left']} commands"),
                _dim("  Risk: each command has a chance of blowing your cover."),
            ]

        if sub == "deactivate":
            gs.flags["ghost_active"] = False
            gs.flags["ghost_commands_left"] = 0
            return [_ok("  Ghost Protocol deactivated."), _dim("  EM signature normalizing.")]

        if sub == "ping":
            if not gs.flags.get("ghost_active"):
                return [_err("  Ghost Protocol not active.")]
            left = gs.flags.get("ghost_commands_left", 0)
            risk = gs.flags.get("ghost_blow_risk", 0.15)
            _gr.seed(gs.commands_run * 7 + left)
            ghost_loc = _gr.choice(["node-7", "the backbone", "void-buffer", "null-route", "proxy-chain-3"])
            return [
                _lore(f"  [GHOST-CHIP]: Pinging stealth envelope... signal coherent."),
                _line(f"  Location ghost: {ghost_loc}", "dim"),
                _line(f"  Commands left : {left}  |  Blow risk: {risk:.0%}", "warn"),
                _dim("  NexusCorp sees: nothing."),
            ]

        return [_err("  ghost: use activate | deactivate | status | ping")]

    # ════════════════════════════════════════════════════════════════════════
    # JACK-IN — neural link to node
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_jack_in(self, args: List[str]) -> List[dict]:
        """jack-in <node> — neural link: bypass normal scan/connect, +30% XP for 5 commands."""
        from app.game_engine.cyberware import CyberwareSystem
        gs = self.gs
        cw = CyberwareSystem(gs)

        has_lattice = cw.has("lattice_tap")
        has_neural_ice = False
        try:
            import json as _jij
            bag = gs.flags.get("items", "{}")
            items = _jij.loads(bag) if isinstance(bag, str) else bag
            has_neural_ice = items.get("neural_ice", 0) > 0
        except Exception:
            pass

        if not has_lattice and not has_neural_ice:
            return [
                _err("  jack-in requires neural hardware:"),
                _dim("  • cyberware install lattice_tap  (5000 cr, neural slot)"),
                _dim("  • OR: craft neural_ice and have it in inventory"),
            ]

        node = args[0].lower() if args else None
        if not node:
            return [_err("  jack-in: specify a node. Example: jack-in nexus-gateway")]

        # Consume neural_ice if no lattice_tap
        if not has_lattice and has_neural_ice:
            import json as _jij2
            bag = gs.flags.get("items", "{}")
            items = _jij2.loads(bag) if isinstance(bag, str) else bag
            items["neural_ice"] = max(0, items.get("neural_ice", 1) - 1)
            gs.flags["items"] = _jij2.dumps(items)

        gs.flags["jack_in_node"] = node
        gs.flags["jack_in_commands"] = 5
        gs.add_story_beat("jack_in_connected")
        gs.add_xp(40, "hacking")

        uplink_type = "Lattice Tap — permanent neural bridge" if has_lattice else "Neural Ice — single-use neural bridge"
        return [
            _sys(f"  ═══ JACK-IN: {node.upper()} ═══"),
            _lore(f"  [{uplink_type.split('—')[0].strip().upper()}]: Direct neural uplink established."),
            _line(f"  Node     : {node}", "info"),
            _line(f"  Uplink   : {uplink_type}", "dim"),
            _line("  Bonus    : +30% XP from all actions on this node (5 commands)", "success"),
            _dim("  jack-in status | jack-in disconnect"),
        ]

    # ════════════════════════════════════════════════════════════════════════
    # LOOT — search VFS files/nodes for items
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_loot(self, args: List[str]) -> List[dict]:
        """loot [<path>|node <node>] — scavenge VFS files or nodes for items."""
        import random as _lr, json as _lj
        gs = self.gs
        path = args[0] if args else None

        # Item pool: path-seeded drops
        LOOT_TABLES = {
            "/var/nexus-leaks": [("nexus_fragment", 0.5), ("data_shard", 0.8), ("access_key", 0.3)],
            "/home/ghost/.zero": [("zero_cipher", 0.4), ("memory_core", 0.6), ("zero_fragment", 0.3)],
            "/chimera-control": [("chimera_fragment", 0.6), ("neural_ice", 0.3), ("chimera_core_fragment", 0.2)],
            "/opt/library": [("data_shard", 0.7), ("cipher_shard", 0.4)],
            "/proc": [("trace_dust", 0.8), ("memory_shard", 0.6)],
        }

        ITEM_NAMES = {
            "nexus_fragment": "Nexus Fragment", "data_shard": "Data Shard",
            "access_key": "Access Key", "zero_cipher": "ZERO Cipher",
            "memory_core": "Memory Core", "zero_fragment": "ZERO Fragment",
            "chimera_fragment": "CHIMERA Fragment", "neural_ice": "Neural ICE",
            "chimera_core_fragment": "CHIMERA Core Fragment", "cipher_shard": "Cipher Shard",
            "trace_dust": "Trace Dust", "memory_shard": "Memory Shard",
            "ghost_protocol_chip": "Ghost Protocol Chip", "ada_private_key": "Ada Private Key",
        }

        _lr.seed(hash(path or "") + gs.commands_run)

        # Find matching loot table
        table = []
        for prefix, t in LOOT_TABLES.items():
            if path and path.startswith(prefix):
                table = t; break
        if not table:
            table = [("data_shard", 0.4), ("memory_shard", 0.5), ("trace_dust", 0.3)]

        # Load bag
        bag = gs.flags.get("items", "{}")
        try: bag = _lj.loads(bag) if isinstance(bag, str) else bag
        except: bag = {}

        dropped = []
        for item_id, prob in table:
            if _lr.random() < prob:
                bag[item_id] = bag.get(item_id, 0) + 1
                dropped.append(item_id)

        gs.flags["items"] = _lj.dumps(bag)
        gs.add_xp(10, "terminal")

        if not dropped:
            return [
                _dim(f"  Searching {path or 'current node'}..."),
                _dim("  Nothing of value. The node is clean."),
            ]

        out = [
            _sys(f"  ═══ LOOT: {path or 'current node'} ═══"),
            _dim(""),
        ]
        for item_id in dropped:
            name = ITEM_NAMES.get(item_id, item_id)
            out.append(_ok(f"  ▶ Found: {name}  ({item_id})  × {bag[item_id]} total"))
        out += [_dim(""), _dim("  items — view inventory   use <item> — consume item")]
        return out

    # ════════════════════════════════════════════════════════════════════════
    # ITEMS — view simple item bag
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_items(self, args: List[str]) -> List[dict]:
        """items — display simple item bag (drops, loot, cascade rewards)."""
        import json as _ij
        gs = self.gs
        bag = gs.flags.get("items", "{}")
        try: bag = _ij.loads(bag) if isinstance(bag, str) else bag
        except: bag = {}

        ITEM_INFO = {
            "data_shard":           ("💾", "Data Shard",          "Crafting material. Common."),
            "memory_shard":         ("🧩", "Memory Shard",        "Crafting material. Core resource."),
            "chimera_fragment":     ("☣️", "CHIMERA Fragment",    "Proof of CHIMERA access. Keep secret."),
            "access_key":           ("🔑", "Access Key",          "Opens a locked node segment."),
            "zero_cipher":          ("🔐", "ZERO Cipher",         "Encrypted. Only ZERO knows the key."),
            "neural_ice":           ("🧊", "Neural ICE",          "Single-use neural bridge. Required for jack-in."),
            "ghost_protocol_chip":  ("👻", "Ghost Protocol Chip", "Installs ghost stealth capability."),
            "ada_private_key":      ("🗝️", "Ada Private Key",    "Ada's private channel key."),
            "prometheus_data":      ("📦", "Prometheus Data",     "The truth about CHIMERA. Handle with care."),
            "cipher_shard":         ("🔡", "Cipher Shard",        "Cryptographic fragment. Puzzle component."),
            "lattice_key":          ("🔗", "Lattice Key",         "Final key. Opens the convergence layer."),
            "medkit":               ("💊", "Medkit",              "Use: reduces trace by 15%."),
            "stim_patch":           ("⚡", "Stim Patch",          "Use: +50% XP gain for next 5 commands."),
            "emp_charge":           ("💥", "EMP Charge",          "Use: wipes trace daemons on current node."),
            "trace_dust":           ("🌫️", "Trace Dust",         "Crafting: trace counter-surveillance."),
            "nova_access_key":      ("⚠️", "Nova Access Key",    "NOVA's seized credentials. Dangerous."),
        }

        if not bag or all(v == 0 for v in bag.values()):
            return [
                _sys("  ═══ ITEM BAG ═══"),
                _dim("  No items."),
                _dim("  Items drop from: loot <path>, exploit success, cascade events, puzzle rewards."),
            ]

        out = [_sys("  ═══ ITEM BAG ═══"), _dim("")]
        for item_id, qty in sorted(bag.items()):
            if qty <= 0:
                continue
            info = ITEM_INFO.get(item_id, ("•", item_id, "Unknown item."))
            out.append(_line(f"  {info[0]} {info[1]:<25} ×{qty:<3}  {info[2]}", "info"))
        out += [_dim(""), _dim("  use <item>  to consume a consumable item")]
        return out

    # ════════════════════════════════════════════════════════════════════════
    # USE — consume an item
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_use(self, args: List[str]) -> List[dict]:
        """use <item> — consume a consumable item from your bag."""
        import json as _uj
        gs = self.gs
        if not args:
            return [_err("  use: specify item. Example: use medkit")]

        item_id = args[0].lower().replace(" ", "_")
        bag = gs.flags.get("items", "{}")
        try: bag = _uj.loads(bag) if isinstance(bag, str) else bag
        except: bag = {}

        qty = bag.get(item_id, 0)
        if qty <= 0:
            return [_err(f"  use: no {item_id} in inventory. Run: items")]

        bag[item_id] = qty - 1
        gs.flags["items"] = _uj.dumps(bag)

        CONSUMABLES = {
            "medkit": lambda: [
                _ok("  Medkit consumed. Trace reduced by 15%."),
                _dim("  The pain editor notes the redundancy. You feel it anyway."),
            ] + [setattr(gs, "trace_level", max(0, getattr(gs, "trace_level", 0) - 15)) or []],
            "stim_patch": lambda: [
                _ok("  Stim Patch applied. +50% XP for next 5 commands."),
                _lore("  [OVERCLOCK]: Processing at enhanced throughput. Don't waste the window."),
            ] + [gs.flags.update({"stim_active": True, "stim_commands": 5}) or []],
            "emp_charge": lambda: [
                _ok("  EMP Charge detonated. Trace daemons on current node wiped."),
                _lore("  [GORDON]: That's a big flash. Hope nothing important was running."),
            ] + [setattr(gs, "trace_level", max(0, getattr(gs, "trace_level", 0) - 30)) or []],
            "neural_ice": lambda: [
                _dim("  Neural ICE consumed during jack-in. Cannot use directly."),
                _dim("  Use: jack-in <node>  — neural_ice will be auto-consumed."),
            ],
            "ghost_protocol_chip": lambda: [
                _ok("  Ghost Protocol Chip integrated."),
                _lore("  [FIXER]: Careful. Black market install. No warranty."),
                _dim("  ghost command now available: ghost activate"),
            ] + [gs.add_story_beat("ghost_protocol_available") or []],
        }

        if item_id in CONSUMABLES:
            result = CONSUMABLES[item_id]()
            return [r for r in result if isinstance(r, dict)]

        return [
            _dim(f"  {item_id} used."),
            _dim("  (This item has no consumable effect. It may be a quest item or crafting material.)"),
        ]

    # ════════════════════════════════════════════════════════════════════════
    # ADAPTIVE HELP — skill-aware, no exposition dumps
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_help(self, args: List[str]) -> List[dict]:
        """help [<topic>] — adaptive command reference (skill-aware)."""
        gs = self.gs
        runs = gs.commands_run
        hacking = gs.skills.get("hacking", 0)

        topic = args[0].lower() if args else None

        # ── Topic-specific help ───────────────────────────────────────────
        if topic:
            TOPICS = {
                "cyberware": [
                    _sys("  CYBERWARE — street implants"),
                    _dim("  cyberware catalog   — browse fixer market"),
                    _dim("  cyberware install <id>  — install implant (costs credits)"),
                    _dim("  cyberware status    — view installed augs + heat"),
                    _dim("  cyberware cool      — reduce heat"),
                    _dim("  cyberware slots     — slot availability"),
                    _dim("  Key implants: ghost_chip, data_eye, lattice_tap, syn_cortex"),
                ],
                "ghost": [
                    _sys("  GHOST PROTOCOL — active stealth"),
                    _dim("  Requires: ghost_chip cyberware OR prestige aug"),
                    _dim("  ghost activate    — -60% trace gen, +20% exploit success"),
                    _dim("  ghost deactivate  — return to normal"),
                    _dim("  ghost ping        — check stealth status"),
                    _dim("  ghost status      — full status"),
                ],
                "items": [
                    _sys("  ITEMS — loot + consumables"),
                    _dim("  items             — view item bag"),
                    _dim("  loot <path>       — scavenge VFS path for items"),
                    _dim("  use <item>        — consume: medkit, stim_patch, emp_charge"),
                    _dim("  jack-in <node>    — neural link (requires lattice_tap or neural_ice)"),
                ],
                "story": [
                    _sys("  STORY — narrative arcs"),
                    _dim("  arcs              — view all story arcs"),
                    _dim("  talk <agent>      — speak to: ada, gordon, raven, cypher, zero, serena"),
                    _dim("  trust <agent>     — build trust with an agent"),
                    _dim("  expose <agent>    — accuse the mole"),
                    _dim("  ascend            — trigger ascension (when ready)"),
                ],
                "hacking": [
                    _sys("  HACKING — core mechanics"),
                    _dim("  scan <node>       — enumerate vulnerabilities"),
                    _dim("  exploit <node>    — execute exploit chain"),
                    _dim("  crack <hash>      — crack a password hash"),
                    _dim("  exfil <file>      — extract sensitive data"),
                    _dim("  trace             — check your exposure level"),
                ],
                "meta": [
                    _sys("  META — fourth wall"),
                    _dim("  fifthwall         — real-time awareness (what time is it?)"),
                    _dim("  secret            — ARG clue"),
                    _dim("  watcher           — contact THE WATCHER"),
                    _dim("  introspect        — ZERO analyzes your play style"),
                    _dim("  signal            — scan transmission frequencies"),
                    _dim("  agents context    — AI agent context dump"),
                ],
                "build": [
                    _sys("  COLONY BUILDING"),
                    _dim("  build list        — available buildings"),
                    _dim("  build construct <type>  — lab/comms_hub/safehouse/relay/armory"),
                    _dim("  build status      — construction progress"),
                ],
            }
            if topic in TOPICS:
                return TOPICS[topic]
            # Natural language fallback — "help me", "help me please", etc.
            _NL_HELP_WORDS = {"me", "please", "i", "now", "with", "this", "something"}
            if topic in _NL_HELP_WORDS or all(w in _NL_HELP_WORDS for w in topic.split()):
                return self._cmd_tutorial([])
            # Unknown but not NL — partial match check
            import difflib as _dl
            close = _dl.get_close_matches(topic, list(TOPICS.keys()), n=2, cutoff=0.5)
            if close:
                return [
                    _err(f"  help: unknown topic '{topic}'"),
                    {"t": "suggest", "s": " · ".join(close), "prefix": "  Did you mean:"},
                ]
            return [_err(f"  help: unknown topic '{topic}'"),
                    _dim("  Topics: cyberware ghost items story hacking meta build")]

        # ── First encounter (0-3 commands): whisper mode ──────────────────
        if runs <= 2:
            gs.add_story_beat("help_first_seen")
            return [
                _dim(""),
                _lore("  [WATCHER]: You found the help system."),
                _lore("  [WATCHER]: Good. That means you know you don't know everything yet."),
                _dim(""),
                _dim("  Start with:  ls   pwd   whoami   status"),
                _dim("  When ready:  scan home   exploit <node>"),
                _dim("  For story:   talk ada"),
                _dim(""),
                _lore("  [WATCHER]: I'll say more when you've done more."),
                _dim(""),
            ]

        # ── New user (4-15 commands): contextual hints ────────────────────
        if runs <= 15:
            return [
                _sys("  ─── CORE COMMANDS ───────────────────────────────────────"),
                _dim(""),
                _line("  EXPLORE     : ls  pwd  cd  cat  find  stat", "info"),
                _line("  HACK        : scan <node>  exploit <node>  crack <hash>", "info"),
                _line("  STORY       : talk ada   trust ada   arcs   status", "info"),
                _line("  CYBERWARE   : cyberware catalog", "info"),
                _dim(""),
                _dim("  help <topic>  for deeper docs: cyberware ghost items story hacking"),
                _dim(f"  You've run {runs} commands. You're getting started."),
            ]

        # ── Intermediate (16-60 commands): category reference ────────────
        if runs <= 60:
            hacked = "root_achieved" in gs.story_beats
            return [
                _sys("  ─── TERMINAL DEPTHS — COMMAND GUIDE ────────────────────"),
                _dim(""),
                _line("  FILESYSTEM  : ls cd cat grep find head tail stat mv cp rm", "dim"),
                _line("  HACKING     : scan exploit crack exfil brute trace wipe", "info"),
                _line("  STORY       : talk trust expose arcs ascend status", "info"),
                _line("  CYBERWARE   : cyberware [catalog|install|status|cool]", "success"),
                _line("  COLONY      : build [list|construct|status]  turret population", "dim"),
                _line("  ITEMS       : items  loot  use  inv  craft", "dim"),
                _line("  INTEL       : osint  scan  signal  faction", "dim"),
                _line("  STEALTH     : ghost  jack-in  trace  warp", "success" if hacked else "dim"),
                _line("  SOCIAL      : trust  talk  hive  rivalry  party", "dim"),
                _line("  META        : fifthwall  secret  watcher  introspect", "dim"),
                _dim(""),
                _dim(f"  Commands run: {runs}  |  help <topic> for depth"),
                _line("  Pro tip: pipe commands —  ls | grep txt | sort", "dim"),
            ]

        # ── Veteran (61-200 commands): compact + hidden hint ─────────────
        if runs <= 200:
            return [
                _sys("  ─── VETERAN REFERENCE ───────────────────────────────────"),
                _line("  Core   : scan exploit exfil crack trace ghost jack-in warp", "info"),
                _line("  Colony : build turret population supply raid escort multiverse", "dim"),
                _line("  Intel  : osint signal faction leaderboard profile fractal db", "dim"),
                _line("  RPG    : augment cyberware multiclass attributes skills xp", "success"),
                _line("  Craft  : craft gear dungeon challenge puzzle loop", "dim"),
                _line("  Story  : arcs talk trust expose ascend prestige endless", "dim"),
                _line("  Meta   : fifthwall secret watcher neural agents onboard", "dim"),
                _dim(""),
                _dim("  Try: man <command>  for full man pages  |  help <topic>"),
                _dim("  Hidden commands await at level 25. Keep going."),
            ]

        # ── Master (200+ commands): minimal, peer-level ───────────────────
        hidden_hint = ""
        if hacking >= 60:
            hidden_hint = "  [ZERO]: At your level? Try: ./ghost_protocol.sh  if it exists."
        return [
            _sys("  ─── GHOST — YOU KNOW THIS ───────────────────────────────"),
            _line("  Everything is accessible. Type it. It probably works.", "dim"),
            _dim("  man <cmd>   |   help <topic>   |   introspect"),
            _dim(f"  {runs} commands in. You've found most of it."),
            _lore("  [WATCHER]: What are you still looking for?") if runs > 400 else _dim(""),
            _dim(hidden_hint) if hidden_hint else _dim(""),
        ]

    # ════════════════════════════════════════════════════════════════════════
    # RL — Reinforcement Learning alias (delegates to ml rl)
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_rl(self, args: List[str]) -> List[dict]:
        """rl [status|train|act] — Reinforcement learning Q-table (alias for ml rl)."""
        return self._cmd_ml(["rl"] + args)

    # ════════════════════════════════════════════════════════════════════════
    # MCP — Model Context Protocol server status
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_mcp(self, args: List[str]) -> List[dict]:
        """mcp [status|tools|call] — Model Context Protocol server status and tool catalog."""
        import urllib.request as _urlreq, json as _json

        gs = self.gs
        subcmd = args[0].lower() if args else "status"

        out = [
            _dim(""),
            _sys("  ╔══════════════════════════════════════════════════════════╗"),
            _sys("  ║  ΔΨΣ MCP — Model Context Protocol Gateway                ║"),
            _sys("  ╚══════════════════════════════════════════════════════════╝"),
            _dim(""),
        ]

        MCP_BASE = "http://localhost:5000"

        if subcmd in ("status", ""):
            try:
                req = _urlreq.Request(f"{MCP_BASE}/api/mcp/tools", headers={"Accept": "application/json"})
                with _urlreq.urlopen(req, timeout=4) as r:
                    data = _json.loads(r.read())
                tools = data.get("tools", [])
                out += [
                    _line("  ─── SERVER STATUS ───────────────────────────────────────────", "system"),
                    _line(f"  Status     : ✓ online", "success"),
                    _line(f"  Tools      : {len(tools)} registered", "info"),
                    _dim(""),
                    _line("  ─── ENDPOINTS ───────────────────────────────────────────────", "system"),
                    _dim("  GET  /api/mcp/tools               — list all tools"),
                    _dim("  POST /api/mcp/call                — call any tool by name"),
                    _dim("  stdio JSON-RPC 2.0 on stdin/stdout (VS Code / Claude Desktop)"),
                    _dim(""),
                    _line("  ─── QUICK REFERENCE ─────────────────────────────────────────", "system"),
                    _dim("  mcp tools                         — show full tool catalog"),
                    _dim("  POST /api/mcp/call {name, arguments}"),
                    _dim("  Example: read_file · write_file · grep_files · run_command"),
                    _dim("           game_command · get_memory · semantic_search"),
                    _dim(""),
                    _suggest("mcp tools · serena status · gordon status · lattice status"),
                ]
                gs.add_xp(5, "ai")
            except Exception as _e:
                out.append(_line(f"  ✗ MCP gateway error: {_e}", "error"))

        elif subcmd == "tools":
            try:
                req = _urlreq.Request(f"{MCP_BASE}/api/mcp/tools", headers={"Accept": "application/json"})
                with _urlreq.urlopen(req, timeout=4) as r:
                    data = _json.loads(r.read())
                tools = data.get("tools", [])
                out.append(_line(f"  {len(tools)} MCP tools available:", "system"))
                for t in tools:
                    name  = t.get("name", "?")
                    desc  = t.get("description", "")[:55]
                    out.append(_dim(f"    {name:<28} {desc}"))
                out += [
                    _dim(""),
                    _suggest("mcp status · POST /api/mcp/call"),
                ]
                gs.add_xp(10, "ai")
            except Exception as _e:
                out.append(_line(f"  ✗ Could not list tools: {_e}", "error"))

        else:
            out += [
                _line(f"  Unknown subcommand: '{subcmd}'", "error"),
                _dim("  mcp [status|tools]"),
            ]

        return out

    # ════════════════════════════════════════════════════════════════════════
    # TD — TouchDesigner Integration (T9)
    # ════════════════════════════════════════════════════════════════════════

    def _cmd_td(self, args: List[str]) -> List[dict]:
        """td [state|channels] — TouchDesigner integration status (T9 OSC bridge)."""
        import urllib.request as _urlreq, json as _json

        gs = self.gs
        subcmd = args[0].lower() if args else "state"

        out = [
            _dim(""),
            _sys("  ╔══════════════════════════════════════════════════════════╗"),
            _sys("  ║  T9 — TOUCHDESIGNER INTEGRATION (OSC/WebSocket Bridge)   ║"),
            _sys("  ╚══════════════════════════════════════════════════════════╝"),
            _dim(""),
        ]

        TD_BASE = "http://localhost:5000"

        if subcmd == "state":
            try:
                with _urlreq.urlopen(f"{TD_BASE}/api/td/state", timeout=4) as r:
                    data = _json.loads(r.read())
                schema = data.get("schema", "?")
                out += [
                    _line("  ─── LIVE STATE ──────────────────────────────────────────────", "system"),
                    _line(f"  Schema     : {schema}", "info"),
                    _line(f"  Player lvl : {data.get('player_level', '?')}", "info"),
                    _line(f"  XP         : {data.get('player_xp', '?')} / {data.get('xp_to_next', '?')}", "info"),
                    _line(f"  Commands   : {int(data.get('commands_run', 0))}", "info"),
                    _line(f"  Story beats: {int(data.get('story_beats', 0))}", "info"),
                    _dim(""),
                    _line("  ─── ENDPOINTS ───────────────────────────────────────────────", "system"),
                    _dim("  GET  /api/td/state        — OSC-friendly float dict (poll at 5–60 Hz)"),
                    _dim("  GET  /api/td/channels     — flat text table for TD Text DAT"),
                    _dim("  WS   /ws/td/stream        — live WebSocket push ~2 Hz"),
                    _dim(""),
                    _dim("  In TouchDesigner: httpIn CHOP → /api/td/state | or WebSocket CHOP → /ws/td/stream"),
                    _dim(""),
                    _suggest("td channels · td state · lsp status · mcp status"),
                ]
                gs.add_xp(5, "systems")
            except Exception as _e:
                out.append(_line(f"  ✗ TD state error: {_e}", "error"))

        elif subcmd == "channels":
            try:
                with _urlreq.urlopen(f"{TD_BASE}/api/td/channels", timeout=4) as r:
                    data = _json.loads(r.read())
                channels = data.get("channels", [])
                out.append(_line(f"  {len(channels)} TD channels:", "system"))
                for ch in channels[:20]:
                    name = ch.get("name", "?")
                    val  = ch.get("value", 0)
                    out.append(_dim(f"    {name:<32} {val}"))
                if len(channels) > 20:
                    out.append(_dim(f"    … {len(channels)-20} more — see GET /api/td/channels"))
                gs.add_xp(5, "systems")
            except Exception as _e:
                out.append(_line(f"  ✗ TD channels error: {_e}", "error"))

        else:
            out += [
                _line(f"  Unknown subcommand: '{subcmd}'", "error"),
                _dim("  td [state|channels]"),
            ]

        return out

    # ════════════════════════════════════════════════════════════════════════

    def to_dict(self) -> dict:
        return {
            "root_shell": self._root_shell,
            "installed_pkgs": list(self._installed_pkgs),
            "chimera_connected": self._chimera_connected,
            "chimera_exploited": self._chimera_exploited,
            "history": self.history[-200:],
        }

    @classmethod
    def from_dict(cls, d: dict, fs, gs, npcs, story, tut,
                  trust_matrix=None, factions=None, dialogue_engine=None) -> "CommandRegistry":
        registry = cls(fs, gs, npcs, story, tut, trust_matrix, factions, dialogue_engine)
        registry._root_shell = d.get("root_shell", False)
        registry._installed_pkgs = set(d.get("installed_pkgs", []))
        registry._chimera_connected = d.get("chimera_connected", False)
        registry._chimera_exploited = d.get("chimera_exploited", False)
        registry.history = d.get("history", [])
        return registry
